-- Dumping structure for table book_store.books
CREATE TABLE IF NOT EXISTS `books` (
  `id` int NOT NULL AUTO_INCREMENT,
  `isbn` varchar(20) DEFAULT NULL,
  `title` varchar(255) NOT NULL,
  `author` varchar(100) DEFAULT NULL,
  `year` int DEFAULT NULL,
  `price` decimal(10,2) DEFAULT '50000.00',
  `image` varchar(255) DEFAULT NULL,
  `description` text,
  `content` text,
  `catalog_id` int DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `category_id` int DEFAULT NULL,
  `status` varchar(20) DEFAULT 'active',
  `views` int DEFAULT '0',
  PRIMARY KEY (`id`),
  UNIQUE KEY `isbn` (`isbn`),
  KEY `fk_books_catalog` (`catalog_id`),
  KEY `idx_isbn` (`isbn`),
  CONSTRAINT `fk_books_catalog` FOREIGN KEY (`catalog_id`) REFERENCES `catalog_book` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=18 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

