	(1, NULL, '5 Múi Giờ, 10 Tiếng Bay', 'Nhật Ký Yêu Xa', NULL, 50000.00, NULL, 'Truyện tình cảm', 'Nội dung...', NULL, '2026-01-17 12:16:27', 1, 'blocked', 0),
	(2, NULL, 'Clean Code', 'Robert C. Martin', NULL, 50000.00, NULL, 'Lập trình', 'Nội dung...', NULL, '2026-01-17 12:16:27', 1, 'blocked', 0),
	(3, '3336-3321-5596', 'Facebook Maketing Từ A Đến', 'Trung Đức', 2015, 50000.00, '1772267834577-18046568.jpg', 'Facebook Marketing của Trung Đức là một cuốn sách hay, được biên\r\nsoạn rất công phu với những thông tin thật phong phú và đa dạng về mọi\r\ngôc cạnh từ đơn giản nhất đến chuyên sâu nhất được viết bằng tiếng\r\nViệt mà tôi từng đọc. về tác giả, anh là một chuyên gia về Social Media\r\nMarketing đã từng nhận được chứng chỉ của Facebook.', 'Tuy còn rất trẻ,\r\nnhưng anh không chỉ thành thạo về các kỹ thuật Facebook Marketing mà\r\ncòn là một trong số ít những chuyên gia giỏi về tư duy chiến lược cũng\r\nnhư am hiểu các quy trình Quốc tế bên lĩnh vực Social Media marketing.\r\nNgoài ra, anh còn có khả năng về hàn lâm trong Content marketing, SEO\r\nvà Digital Marketing nói chung.\r\nTôi nhận thấy rằng cuốn sách này là một hệ thống hoá sốtư liệu khổng lồ\r\nviết về Facebook, chắt lọc những gì tinh tuý nhất, bổ ích nhất cho những\r\nngười dam mê Facebook Marketing cũng như những người mới bắt đầu\r\nbước chân vào nghiên cứu hay sử dụng Facebook Marketing cho công\r\nviệc kinh doanh cá nhân hay doanh nghiệp có quy mô từ lớn đến nhỏ.\r\nChuyên gia Trung Đức đã đem đến cho bạn đọc một cuốn sách kết hợp\r\nthật tài tình giữa lối hành văn dễ hiểu với tính nghiêm túc khoa học, mở\r\nra khả năng tiếp cận dễ dàng cho bất cứ ai muốn thực hành Facebook\r\nmarketing từ cơ bản cho đến nâng cao. Cuối cùng, tôi muốn khẳng định\r\nrằng, đây là cuốn sách có tính thực tiễn cao và lượng thông tin cập nhật\r\nmới nhất về Facebook marketing theo như tôi được thấy hiện nay.\r\n\r\nVà tôi tin rằng bất kể ai may mắn khi cầm cuốn sách này trên tay đều\r\ncó thể ứng dụng một cách nhanh chóng và đầy đủ cho mọi công việc về\r\nFacebook Marketing của mình.\r\nXin chân thành cám ơn chuyên gia Trung Đức về việc làm kịp thời và\r\nđầy tính trách nhiệm này!', NULL, '2026-01-17 12:16:27', 2, 'active', 0),
	(4, '2586-2521-9653', 'Tỷ Phú Bán Giày', 'Tony Hsieh', 2021, 50000.00, '1772266390301-450666254.jpg', 'Tư Duy Làm Giàu', 'Đầu tiên người ta không thèm để ý đến bạn, sau đó người ta chế nhạo bạn, tiếp đến\r\nngười ta tấn công bạn, rồi cuối cùng thì bạn thắng.', NULL, '2026-01-17 12:33:55', 1, 'active', 0),
	(5, '2586-2563-4456', 'Nhà Giả Kim', 'PAULO COELHO', 2011, 50000.00, '1772265662989-481833089.jpg', '', 'Nội dung...', NULL, '2026-01-17 12:33:55', 1, 'active', 0),
	(6, '3336-3321-4432', 'Đắc Nhân Tâm', 'Dale Carnegie', 2000, 50000.00, '1772264645258-752956981.jpg', 'Kỹ năng sống', 'Tác phẩm đã\r\nđược chuyển ngữ sang hầu hết các thứ tiếng trên thế giới và có\r\nmặt ở hàng trăm quốc gia. Đây là quyển sách duy nhất về thể\r\nloại self-help liên tục đứng đầu danh mục sách bán chạy nhất\r\n(Best-selling Books) do báo The New York Times bình chọn suốt 10\r\nnăm liền. Riêng bản tiếng Anh của sách đã bán được hơn 15\r\ntriệu bản trên thế giới. Tác phẩm có sức lan tỏa vô cùng rộng\r\nlớn – dù bạn đi đến bất cứ đâu, bất kỳ quốc gia nào cũng đều có\r\nthể nhìn thấy. Tác phẩm được đánh giá là quyển sách đầu tiên\r\nvà hay nhất, có ảnh hưởng làm thay đổi cuộc đời của hàng triệu\r\nngười trên thế giới.', NULL, '2026-01-17 12:33:55', 1, 'active', 0),
	(7, '2586-2521-4885', 'Tử Huyệt Cảm Xúc', 'Roy Garn', 2006, 50000.00, '1772265278046-513576792.jpg', 'Cảm Xúc', 'Tôi đang nói đến nhân vật được chọn làm hình bìa cho quyển sách\r\nnày: người anh hùng Achilles trong thần thoại Hy Lạp.\r\nĐây là một cuốn sách viết về Tử Huyệt Cảm Xúc - những “điểm yếu\r\nchết người” trong tính cách của mỗi chúng ta. Tử Huyệt Cảm Xúc có thể\r\ngiúp chúng ta đạt được hạnh phúc và thành công tột đỉnh, nhưng cũng có\r\nthể khiến chúng ta... rơi vào bi kịch như Achilles!', NULL, '2026-01-17 12:34:00', 1, 'active', 0),
	(8, '2586-3321-4456', 'Tư Duy Tích Cực Tạo Thành', 'NAPOLEON HILL - W. CLEMENT STONE', 2011, 50000.00, '1772265039135-941001385.jpg', 'Tư Duy', 'Bạn đang cầm trong tay một cuốn sách như vậy. Đây\r\nkhông chỉ là một tác phẩm kinh điển về chủ đề tự rèn luyện\r\nvà phát triển bản thân, mà còn là một người bạn chí thân\r\ncó thể chia sẻ mọi rắc rối của bạn, cũng như mang đến cho\r\nbạn những lời khuyên hữu ích.', NULL, '2026-01-17 12:34:00', 3, 'active', 0),
	(9, '3336-3321-4456', 'Dám Chấp Nhận', 'ERNIE CARWILE', 2010, 50000.00, '1772264104171-560003006.jpg', 'Kỹ năng sống', '', NULL, '2026-01-17 12:34:00', 3, 'active', 0),
	(11, NULL, 'Sách Lập Trình Node.js', 'FPT Poly', NULL, 50000.00, '1768658985538-905171397.jpg', 'Sách rất hay', 'Nội dung chi tiết...', NULL, '2026-01-17 14:09:45', 1, 'blocked', 0),
	(12, NULL, 'Sách Lập Trình Node.js', 'FPT Poly', NULL, 50000.00, '1768694977075-374339499.jpg', 'Sách rất ok', 'Nội dung chi tiết...', NULL, '2026-01-18 00:09:37', 1, 'blocked', 0),
	(13, NULL, 'Sách Dầu Mỏ, Tiền Bạc Và Quyền Lực', 'Thế Giới', NULL, 408000.00, '1769320161958-702163407.webp', 'blue-checkTổng quan về lịch sử ngành công nghiệp dầu mỏ và tác động toàn cầu.\r\nblue-check\r\nPhát hành bởi Omega Plus, đảm bảo hàng chính hãng.\r\nblue-check\r\nKích thước sách (16x24cm) và số trang (1268) cho phép tìm hiểu sâu.', 'Cuốn sách Dầu mỏ, Tiền bạc & Quyền lực khắc họa toàn cảnh lịch sử ngành công nghiệp dầu mỏ - cuộc giao tranh giành quyền lực và sự giàu có xung quanh vấn đề dầu mỏ. Cuộc chiến này đã làm rung chuyển nền kinh tế toàn cầu, phản ánh hậu quả của các cuộc chiến tranh đồng thời thay đổi vận mệnh nhân loại nói chung và các quốc gia nói riêng. Dầu mỏ, Tiền bạc & Quyền lực là một bức tranh về lịch sử thế kỷ XX, cũng là về ngành công nghiệp dầu mỏ. Bức họa khổng lồ này tái hiện lịch sử từ khi người ta khoan giếng dầu đầu tiên ở Pennsylvania, trải qua hai cuộc đại chiến, tới khi Iraq xâm lược Kuwait và chiến dịch Bão táp sa mạc. Bối cảnh được mở rộng từ những người liều lĩnh, những kẻ lừa đảo tới những ông vua dầu mỏ, từ cựu Thủ tướng Anh Winston Churchill, và quốc vương Saudi Arabia Ibn Saud, tới Tổng thống Mỹ George Bush và Saddam Hussein, cựu Tổng thống Iraq. Là cuốn sách tiêu biểu về các vấn đề nhức nhối trong lĩnh vực dầu mỏ, Dầu mỏ, Tiền bạc & Quyền lực cung cấp cho chúng ta những nhận thức cơ bản không chỉ riêng lĩnh vực này mà còn về thế kỷ của chúng ta.\r\nGiá sản phẩm trên Tiki đã bao gồm thuế theo luật hiện hành. Bên cạnh đó, tuỳ vào loại sản phẩm, hình thức và địa chỉ giao hàng mà có thể phát sinh thêm chi phí khác như phí vận chuyển, phụ phí hàng cồng kềnh, thuế nhập khẩu (đối với đơn hàng giao từ nước ngoài có giá trị trên 1 triệu đồng).....', NULL, '2026-01-25 05:49:21', 1, 'active', 0),
	(14, NULL, 'TRÂN TRỌNG CHÍNH MÌNH', 'PATRICIA SPADARO', NULL, 5555555.00, '1769419639902-808254343.jpg', 'vv', 'Cuốn sách hay này đề cập đến những nghịch lý bất biến trong các quan hệ xã hội, mà quan trọng nhất là nghịch lý giữa trao đi và nhận lại, đã được nhiều nhà hiền triết từ phương Đông tới phương Tây truyền giảng suốt bao đời nay. Qua phân tích và trích dẫn nhiều lời dạy thánh hiền, tác giả đã lật đổ những lầm tưởng về “cái tôi”, khẳng định tầm quan trọng của việc thấu hiểu và yêu thương bản thân, giúp mỗi chúng ta biết trân trọng chính mình để từ đó, biết trân trọng mọi người.', NULL, '2026-01-26 09:27:19', 1, 'active', 0),
	(15, '978-604-1-13465-6', 'Cây Cam Ngọt Của Tôi', 'José Mauro de Vasconcelos', 2020, 50000.00, '1769746493683-284984325.webp', 'Cây Cam Ngọt Của Tôi là một câu chuyện cảm động về tuổi thơ, tình thân và những tổn thương lặng thầm của một cậu bé nghèo ở Brazil, nơi nỗi buồn và niềm vui đan xen qua trí tưởng tượng trong trẻo và trái tim nhạy cảm.', 'Cây Cam Ngọt Của Tôi (Meu Pé de Laranja Lima) là tiểu thuyết nổi tiếng của nhà văn Brazil José Mauro de Vasconcelos, kể về tuổi thơ của cậu bé Zezé – một đứa trẻ thông minh, giàu trí tưởng tượng nhưng lớn lên trong nghèo khó và thiếu thốn tình yêu thương.\r\n\r\nZezé sống trong một gia đình đông con, cha thất nghiệp, mẹ vất vả mưu sinh. Cậu thường xuyên bị hiểu lầm, bị mắng chửi và đánh đập chỉ vì quá nghịch ngợm và nói nhiều. Trong thế giới khắc nghiệt ấy, Zezé tìm thấy niềm an ủi nơi cây cam ngọt trong vườn – người bạn tưởng tượng lắng nghe, chia sẻ và che chở cho những cảm xúc non nớt của cậu.\r\n\r\nCâu chuyện không chỉ khắc họa nỗi đau của một đứa trẻ thiếu thốn tình cảm, mà còn tôn vinh sức mạnh của sự cảm thông, tình yêu thương và khả năng chữa lành của những mối quan hệ chân thành. Với giọng văn giản dị, chân thật nhưng đầy ám ảnh, cuốn sách khiến người đọc vừa mỉm cười, vừa lặng người suy ngẫm về tuổi thơ, gia đình và cách con người đối xử với nhau.\r\n\r\nCây Cam Ngọt Của Tôi là cuốn sách dành cho mọi lứa tuổi – trẻ em để thấu hiểu cảm xúc của chính mình, người lớn để nhìn lại tuổi thơ và học cách yêu thương dịu dàng hơn.', NULL, '2026-01-30 04:14:53', 3, 'active', 0),
	(16, NULL, 'Chiến Thắng Con Quỷ Trong Bạn', 'Napoleon Hill', 2013, 50000.00, '1772008961908-173826712.jpg', '', '', NULL, '2026-02-25 08:42:41', 3, 'active', 3),
	(17, '2586-3321-2574', '101 Tình Huống Nhân Sự Nan Giải', 'PAUL FALCONE', 2022, 50000.00, '1772266834677-882713427.jpg', '', 'Một trong những chìa khóa mở ra cánh cửa thành công cho doanh nghiệp là\r\nyếu tố con người. Đây là yếu tố mang tính quyết định đối với khả năng phát\r\ntriển bền vững của tổ chức. Bất cứ khía cạnh nào trong công việc cũng phải\r\nlấy con người làm nền tảng, bởi con người chi phối và tác động mạnh mẽ\r\nđến mọi vấn đề xảy ra trong môi trường công sở. Với tư cách nhà quản lý\r\nnhân sự, bạn nên nhận thức được tầm quan trọng của nhân tố này để từ đó có\r\nnhững chính sách cũng như quy định phù hợp, nâng cao và phát triển hơn\r\nnữa nhân tố con người, phục vụ những mục tiêu lâu dài của tổ chức.\r\nTuy nhiên, quản lý con người luôn là một bài toán khó, gây đau đầu với\r\nnhiều nhà điều hành, lãnh đạo. Làm sao để phát triển và thúc đẩy nhân viên,\r\ngiúp họ cải thiện và nâng cao hiệu suất công việc, đồng thời có những bước\r\nthăng tiến tích cực; làm thế nào để giải đáp những thắc mắc của họ, đưa ra\r\nnhững câu trả lời thấu đáo về các vấn đề, giải quyết những mâu thuẫn phát\r\nsinh trong công việc, giữa các đồng nghiệp với nhau, giữa cấp trên với cấp\r\ndưới... Có quá nhiều vấn đề xoay quanh “con người” mà bạn không thể\r\nlường trước cũng như xử lý hết được.\r\nCổ nhân có câu “Lời nói chẳng mất tiền mua, lựa lời mà nói cho vừa lòng\r\nnhau”. Theo đó, những vấn đề nan giải đều có thể được giải quyết thông qua\r\ncác cuộc nói chuyện, trao đổi với cung cách và ngôn từ vừa nhẹ nhàng mềm\r\nmỏng, lại mạnh mẽ, dứt khoát; quan trọng hơn cả, nội dung của cuộc đối\r\nthoại phải giúp nhân viên nhận thức được những sai lầm của họ trong công\r\nviệc và các mối quan hệ, từ đó có sự điều chỉnh thích hợp. Theo đó, xuyên\r\nsuốt 101 tình huống thường gặp tại nơi làm việc trong 101 tình huống nhân\r\nsự nan giải, với tư cách một nhà quản lý, bạn sẽ có thể tìm được những gợi\r\nmở và lời giải thích hợp, tháo gỡ những khó khăn trong công tác quản lý của\r\nmình. Bạn sẽ biết cách nói chuyện với nhân viên cấp dưới bằng sự tôn trọng,\r\nthấu hiểu; điều quan trọng không chỉ là nói gì mà là nói như thế nào, theo\r\ncách thức ra sao.\r\nCuốn sách được thiết kế và cấu trúc như một cuốn cẩm nang, cung cấp cho\r\nbạn các chỉ dẫn thiết thực và hữu ích nhất để đương đầu và xử lý những cuộc\r\nnói chuyện vô cùng khó khăn với nhân viên về các vấn đề tế nhị trong môi\r\ntrường làm việc. Bên cạnh những tình huống rất thân quen và thường gặp\r\nnhư trang phục, giờ giấc đi làm, cho đến những vấn đề khó khăn hơn như vệ\r\nsinh cơ thể, sức khỏe cá nhân, hay những vấn đề vô cùng nhạy cảm như quấy\r\nrối tình dục nơi công sở, hoặc các vấn đề\r\nluôn nhận được rất nhiều sự quan tâm như thăng tiến, lương thưởng hay sa\r\nthải, tinh giản biên chế...\r\nLà chuyên gia hàng đầu về nhân sự, từng giữ cương vị giám đốc nhân sự\r\ntrong nhiều tổ chức uy tín như Time Warner Cable, Paramount Pictures, tác\r\ngiả Paul Falcone đã gói gọn và tổng kết nhiều năm kinh nghiệm của mình\r\nqua 101 tình huống cụ thể và đầy thiết thực. 101 tình huống nhân sự nan giải\r\ncũng đồng thời là cuốn sách thuộc Bộ sách Amacom do Alpha Books xuất\r\nbản và đã trở nên quen thuộc, hữu ích đối với bạn đọc. Alpha Books trân\r\ntrọng giới thiệu tới độc giả cuốn sách này với mong muốn bạn − những nhà\r\nquản lý nhân sự − sẽ có thêm nguồn tham khảo hữu ích, hỗ trợ đắc lực trong\r\nnhững cuộc đối mặt đầy thử thách với nhân viên của mình.\r\nHơn nữa, cuốn sách hứa hẹn không chỉ trở thành người bạn đồng hành đầy\r\nthân thiết với bạn, mà còn là một tài liệu thiết thực giúp bảo vệ bạn và công\r\nty khỏi những rắc rối có thể gặp phải nếu ứng xử không khéo léo với nhân\r\nviên. Nhờ đó, cả bạn lẫn công ty sẽ xây dựng được một hình ảnh tốt đẹp hơn\r\ntrong mắt nhân viên cũng như khách hàng, đối tác, nâng cao được vị thế và\r\nchỗ đứng của công ty bạn trong thế giới kinh doanh.\r\nChúc các bạn thành công!\r\n', NULL, '2026-02-28 08:20:34', 4, 'active', 7);

