INSERT INTO `chapters` (`id`, `book_id`, `chapter_number`, `title`, `content`, `created_at`) VALUES
	(2, 15, 1, 'KHÁM PHÁ NHIỀU ĐIỀU', 'Chúng tôi đi xuống phố, tay trong tay, chẳng có gì phải vội.\nTotoca đang dạy tôi về cuộc sống. Và điều đó khiến tôi thực sự hạnh\nphúc, được anh trai nắm tay và dạy nhiều điều. Nhưng là dạy về\nnhững điều thuộc thế giới bên ngoài. Bởi vì ở nhà, tôi học hỏi bằng\ncách tự mày mò khám phá và tự làm, tôi mắc lỗi nhiều và vì mắc lỗi,\ntôi thường bị ăn đòn. Cho tới tận trước đây không lâu, tôi vẫn chưa\nbị ai đánh bao giờ. Nhưng rồi mọi người nghe được chuyện này,\nchuyện nọ và bắt đầu nói tôi là quỷ, là quái vật, là tiểu yêu tóc hung.\nTôi không muốn biết về điều đó. Nếu không phải đang ở bên ngoài\nthì tôi đã bắt đầu hát. Hát thú vị lắm. Ngoài ca hát, Totoca còn biết\nlàm điều khác nữa: anh có thể huýt sáo. Nhưng dù cố gắng đến\nmức nào tôi cũng chẳng thể bắt chước anh huýt sáo được, chẳng\nâm thanh nào bật ra cả. Để an ủi tôi, anh bảo chuyện đó cũng bình\nthường thôi, rằng tôi chưa có cái miệng của người huýt sáo. Nhưng\nvì không thể hát thành lời, tôi hát thầm ở trong lòng. Thoạt đầu điều\nđó thật kỳ cục, nhưng về sau tôi cảm thấy hát như thế thực sự thú\nvị. Và lúc này, tôi đang nhớ lại một bài hát mẹ thường hát khi tôi còn\nbé xíu. Mẹ đứng bên chậu giặt, mảnh khăn buộc quanh đầu để che\nnắng. Với chiếc tạp dề ôm quanh thắt lưng, mẹ đứng đó hết giờ này\nđến giờ khác, dầm tay trong nước, khiến xà phòng nổi cơ man nào\nlà bọt. Sau đó mẹ vắt kiệt nước khỏi quần áo và đem ra dây, phơi\nlên, kẹp lại và kéo chiếc dây phơi lên cao. Mẹ làm thế với tất cả\nquần áo. Mẹ giặt thuê cho nhà bác sĩ Faulhaber để kiếm thêm chút ít\ngiúp trang trải chi phí sinh hoạt. Mẹ cao, gầy, nhưng rất đẹp. Da mẹ\nrám nắng, tóc thẳng và đen. Khi mẹ không cột tóc lên, tóc mẹ xõa\nđến tận thắt lưng. Nhưng tuyệt nhất là khi mẹ hát, và tôi hay quanh\nquẩn bên mẹ học lỏm.\nChàng thủy thủ ơi, chàng thủy thủ ơi Chàng thủy thủ của nỗi\nbuồn ơi Vì chàng Ngày mai em sẽ chết...\nNhững con sóng xô bờ Quăng mình lên bờ cát Chàng ra khơi rồi\nChàng thủy thủ ơi...\nTình yêu của chàng Chẳng được nổi một ngày Tàu nhổ neo rồi\nTàu ra khơi...\nNhững con sóng xô bờ...\nBài hát đó luôn khiến lòng tôi dâng trào một nỗi buồn khó hiểu.\nTotoca giật tay tôi. Tôi bừng tỉnh. “Sao thế Zezé?” “Không sao ạ.\nEm đang hát thôi mà.” “Hát ư?” “Vâng.” “Vậy chắc anh điếc rồi.”\nAnh ấy không biết con người ta có thể hát thầm ư? Tôi im lặng.\nNếu anh không biết thì tôi cũng chẳng định dạy anh đâu.\nChúng tôi đã tới lề đường quốc lộ Rio-São Paulo. Trên đường\nquốc lộ, có đủ mọi loại xe. Xe tải, xe con, xe ngựa, xe đạp.\n“Này,Zezé, chuyện quan trọng đây này. Trước hết chúng ta phải\nquan sát thật kỹ một chiều, sau đó nhìn chiều kia. Bây giờ sang\nđường nào.”\nChúng tôi chạy sang đường.\n“Em có sợ không?”\nTôi sợ, nhưng tôi lắc đầu.\n“Chúng mình cùng làm lại nào. Sau đó anh muốn xem em đã biết\ncách hay chưa.”\nChúng tôi chạy trở lại phía bên kia đường. “Bây giờ em sang\nđường đi. Đừng ngập ngừng, bởi vì em lớn rồi mà.”\nTim tôi đập nhanh hơn.\n“Nào. Sang đi.”\nTôi chạy sang đường, gần như nín thở. Tôi đợi một chút và anh\nra hiệu cho tôi quay trở về chỗ anh.\n“Lần đầu mà làm được thế là tốt đấy. Nhưng em đã quên một\nđiều. Em phải nhìn cả hai phía xem có xe đang chạy tới không.\nKhông phải lúc nào anh cũng có mặt ở đây để ra hiệu cho em đâu.\nChúng ta sẽ thực hành thêm trên đường về nhà nhé. Nhưng giờ thì\nđi thôi, vì anh muốn chỉ cho em một thứ.”\nAnh cầm tay tôi và chúng tôi lại bắt đầu bước đi, thong thả. Tôi\nkhông cách nào thôi nghĩ về một cuộc trò chuyện cách đây ít lâu.\n"Totoca." “Gì cơ?”\n“Anh đã cảm nhận được tuổi chín chắn chưa?” “Thứ vớ vẩn gì\nvậy?”\n“Bác Edmundo nói đấy. Bác nói em khôn trước tuổi và rằng\nchẳng bao lâu nữa em sẽ đến tuổi chín chắn. Nhưng em chẳng cảm\nthấy có gì khác cả.”\n“Bác Edmundo bị ngớ ngẩn đấy. Bác ấy luôn nhồi những thứ vớ\nvẩn vào đầu em.”\n“Bác ấy không ngớ ngẩn đâu. Bác ấy khôn ngoan đấy chứ. Và\nkhi lớn lên em muốn trở nên khôn ngoan, thành nhà thơ và thắt nơ\nbướm. Một ngày nào đó em sẽ được chụp ảnh chân dung thắt nơ\nhẳn hoi.”\n“Tại sao lại thắt nơ?”\n“Bởi vì anh không thể trở thành nhà thơ nếu không thắt nơ. Khi\nbác Edmundo cho em xem ảnh các nhà thơ trong cuốn tạp chí đó,\nem thấy ai cũng thắt nơ cả.”\n“Zezé, em phải thôi đi, đừng tin mọi điều bác ấy nói với em nữa.\nBác Edmundo hơi biêng biêng đấy. Bác ấy còn hơi xạo nữa.”\n“Bác ấy là đồ chó đẻ ư?”\n“Em đã bị tát lệch mặt vì nói bậy quá nhiều mà chưa chừa à! Bác\nEdmundo không như vậy. Anh nói biêng biệng cơ mà. Nghĩa là hơi\nhâm hâm.”\n“Anh bảo bác ấy là kẻ nói xạo mà.”\n“Đó là hai chuyện hoàn toàn khác.”\n“Không, có khác gì đâu. Hôm nọ cha kể về ông Labonne với bác\nSeverino, bạn chơi bài của cha, và cha nói, “Lão chó đẻ ấy là một kẻ\nnói xạo trời đánh thánh vật.” Và chẳng ai tát chả lệch mặt cả.”\n“Người lớn nói thế thì không sao.”\nChúng tôi không nói gì trong vài phút.\n“Bác Edmundo không... Mà biêng biêng có nghĩa là gì, anh\nTotoca?”\nAnh giơ ngón tay chỉ lên đầu, quay quay ngón tay vẽ thành\nnhững vòng tròn trong không khí.\n“Không, bác ấy không phải vậy. Bác ấy tốt lắm. Bác ấy dạy em\nnhiều điều, và chỉ đánh em có mỗi một lần, lại còn chẳng đánh mạnh\nnữa.”\nTotoca giật mình.\n“Bác ấy đánh em à? Khi nào?”\n“Khi em hư thật và bị Gloria tống đến nhà bà. Bác ấy muốn đọc\nbáo nhưng không tìm thấy kính. Bác tìm hết chỗ cao đến chỗ thấp\nvà nổi điên thực sự. Bác hỏi bà kính của bác ở đâu nhưng bà không\nbiết. Hai người lục tung cả nhà lên để tìm. Thế rồi em nói em biết\nkính của bác ở đâu và nếu bác cho em ít tiền để mua bi thì em sẽ\nnói cho bác biết. Bác đi đến chỗ để áo khoác và lấy ra một ít tiền.\n“Mang kính ra đây thì bác đưa tiền cho mày.” “Em đến chỗ rương\nđựng quần áo lấy cái kính ra. Bác nói, Ra là mày, đồ ranh con!” Bác\nphát vào lưng em và cất béng tiền đi.”\nTotoca cười phá lên.\n“Em đến đó để khỏi bị ăn đòn ở nhà thế mà lại bị đánh ở đó. Đi\nnhanh chân lên một chút, nếu không chúng ta sẽ chẳng bao giờ đến\nnơi được đâu.”\nTôi vẫn đang nghĩ về bác Edmundo. “Totoca, trẻ con nghỉ hưu\nphải không?” “Gì cơ?”\n“Bác Edmundo chẳng làm gì cả mà vẫn có tiền. Bác không làm\nviệc, nhưng Tòa Thị chính vẫn trả tiền cho bác hằng tháng.”\n“Thì sao?”\n“À thì, trẻ con chẳng làm gì. Trẻ con ăn, ngủ và được cha mẹ\ncho tiền.”\n“Nghỉ hưu khác chứ, Zezé. Người nghỉ hưu đã làm việc trong\nmột thời gian dài rồi, tóc đã ngả bạc, chân chậm mắt mờ như bác\nEdmundo rồi. Nhưng đừng nghĩ về những thứ khó nhằn ấy nữa.\nNếu em muốn học nhiều điều từ bác ấy thì tốt thôi. Nhưng khi đi với\nanh thì không nhé. Hãy cư xử như những đứa con trai khác. Em\nthậm chí có thể chửi thề, nhưng đừng nhét đầy đầu những thứ khó\nnhằn. Nếu không anh sẽ không đi chơi với em nữa đâu.”\nTôi xị mặt xuống và không muốn nói chuyện nữa. Tôi cũng\nchẳng muốn hát. Chú chim nhỏ ca hát bên trong tôi đã bay mất rồi.\nChúng tôi dừng lại và Totoca chỉ tay về phía ngôi nhà. “Nó đấy.\nThích không?”\nĐó là một ngôi nhà bình thường. Màu trắng với những ô cửa sổ\nmàu xanh dương. Toàn bộ cửa nẻo đều đóng im ỉm và im ắng như\ntờ.\n“Có ạ. Nhưng tại sao chúng ta phải chuyển đến đây chứ?”\n“Thay đổi cũng tốt mà.”\nChúng tôi đứng trông qua hàng rào, nhìn cây xoài phía bên này\nvà cây me ở phía bên kia.\n“Em là đứa hay chạy lăng xăng, nhưng em không biết nhà mình\nđang có chuyện gì đâu. Cha thất nghiệp rồi, đúng không? Đã sáu\ntháng kể từ khi cha choảng nhau với ông Scottfield và bị đuổi việc.\nEm có biết bây giờ Lala đang làm việc ở nhà máy không? Còn mẹ\nthì sắp đi làm ở thành phố, trong xưởng English Mill đấy, biết không?\nGiờ thì em biết rồi đấy, đồ ngốc ạ. Ở cái nhà mới này, ta sẽ tiết kiệm\nđược tiền thuê nhà... Cái nhà kia thì cha nợ tám tháng tiền thuê nhà\nrồi. Em còn quá nhỏ nên không phải lo lắng về những chuyện buồn\nnhư thế. Nhưng anh sẽ phải giúp thật lực, xắn tay vào hỗ trợ việc\nnhà.”\nAnh đứng im lặng một lát.\n“Totoca, họ sẽ mang con báo đen và hai con sư tử cái tới đây\nchứ?”\n“Dĩ nhiên. Và lão gia nhân này sẽ phải tháo dỡ cái chuồng gà.”\nAnh nhìn tôi bằng ánh mắt thương xót, trìu mến.\n“Anh chính là người sẽ dỡ vườn thú và lắp ghép nó lại ở đây.”\nTôi thở phào. Bởi vì nếu không tôi sẽ phải kiếm thứ gì đó mới mẻ\nđể chơi với em trai út Luis của tôi.\n“Em đã thấy anh là người bạn như thế nào của em rồi, đúng\nkhông Zezé? Này, em sẽ chẳng mất mát gì nếu nói cho anh biết em\nđã làm chuyện đó như thế nào...”\n“Totoca, em thề là em không biết. Em thực sự không biết.”\n“Em nói dối. Ai đó đã dạy em học.”\n“Em chẳng học gì cả. Chẳng ai dạy em hết. Trừ phi quỷ sứ dạy\nem trong giấc ngủ. Jandira nói quỷ sứ là cha đỡ đầu của em.”\nTotoca bối rối. Anh thậm chí còn cốc đầu tôi mấy cái, cố bắt tôi\nphải nói cho anh biết. Nhưng tôi không biết mình đã làm được\nchuyện đó như thế nào.\n“Chẳng ai tự học cái đó được.”\nNhưng anh không biết phải nói gì bởi vì chẳng ai thực sự nhìn\nthấy người nào dạy tôi học gì hết. Đó là một bí ẩn.\nTôi nhớ lại chuyện xảy ra một tuần trước. Nó đã khiến cả nhà tôi\nxôn xao. Chuyện bắt đầu tại nhà bà tôi, khi tôi ngồi cạnh bác\nEdmundo đang đọc báo.\n“Bác ơi.”\n“Gì vậy, con trai?”\nBác kéo cặp kính xuống chóp mũi, như cái cách mọi người lớn\nthường làm khi họ đã già.\n“Mấy tuổi bác học đọc?”\nKhoảng tầm sáu, bảy tuổi.”\n““Trẻ năm tuổi có thể học đọc không bác?”\n“Bác nghĩ là có. Nhưng chẳng ai thích dạy chúng đâu bởi vì\nchúng còn quá nhỏ.”\n“Bác học đọc như thế nào ạ?”\n“Như mọi người khác thôi, với những người đọc mẫu. Đọc bờ a\nbaº.”\n“Ai cũng phải học đọc theo cách đó ạ?”\n“Theo bác biết thì ai cũng học như thế cả.”\n“Tất cả mọi người ư?”\nBác nhìn tôi, ngạc nhiên.\n“Này,Zezé, đó là cách mọi người học đọc. Bây giờ hãy để yên\ncho bác đọc nốt. Ra sân sau mà tìm ổi đi.”\nBác đẩy kính lên và cố tập trung đọc. Nhưng tôi không chịu đi.\n“Tiếc quá!”\nNghe thấy tiếng cảm thán chân thật ấy, bác lại kéo kính xuống\nthấp.\n“Trời đất quỷ thần ơi. Cháu định ngồi dai như đỉa đây đấy à?”\n“Chỉ là cháu đã đi cả một quãng đường xa như thế tới đây để nói\nvới bác một điều.”\n“Thôi được rồi, vậy thì nói đi.”\n“Không. Không phải vậy. Trước hết cháu cần biết ngày lĩnh\nlương hưu tới đây của bác là ngày nào.”\n“Ngày kia, bác nói, vừa nhìn tôi vẻ dò xét vừa cười tủm tỉm.\n“Ngày kia là thứ mấy hả bác?”\n“Thứ Sáu.”\n“Ừm, thứ Sáu bác có thể mang từ thành phố về cho cháu một\ncon Vua Bạc không ạ?”\n“Nói từ từ xem nào,Zezé. Vua Bạc là gì?”\n“Là con ngựa trắng nhỏ cháu nhìn thấy trong rạp chiếu bóng.\nChủ của nó là Fred Thompson. Nó là ngựa đã được thuần dưỡng\nrồi.”\n“Cháu muốn bác mang về cho cháu một con ngựa nhỏ kéo xe\nư?”\n“Không ạ. Cháu muốn con ngựa kiểu có đầu gỗ và bộ dây cương\ncơ. Ngựa kiểu bác gắn cái đuôi vào rồi chạy vòng quanh ấy ạ. Cháu\ncần phải luyện tập vì sau này cháu sẽ đóng phim.”\nBác cười phá lên.\n“Bác hiểu rồi. Và nếu bác kiếm nó cho cháu, thì bác đượC gì\nnào?”\n“Cháu sẽ làm một việc gì đó cho bác ạ.”\nCháu thơm bác một cái nhé?”\n“ “Cháu không thích thơm thiếc lắm đâu ạ.” “Vậy thì ôm nhé?”\nTôi nhìn bác Edmundo và thật lòng cảm thấy tội nghiệp cho bác.\nCon chim nhỏ bên trong tôi nói một điều gì đó. Và tôi nhớ lại một\nchuyện tôi đã nghe người ta nói rất nhiều lần, rằng bác Edmundo\nsống ly thân với vợ và họ có năm đứa con. Nhưng bác sống một\nmình, đi lại chậm chạp lắm... Có lẽ bác đi chậm vì nhớ các con\nchăng? Con bác chẳng bao giờ đến thăm bác.\nTôi đi vòng qua bàn và ôm bác thật chặt. Tôi cảm thấy đám tóc\nbạc của bác cọ vào trán mình. Tóc bác mềm thật đấy.\n“Đây không phải vì con ngựa đâu ạ. Cháu sẽ làm cho bác một\nviệc khác Cơ. Cháu sẽ đọc.”\n“Gì cơ,Zezé? Cháu biết đọc ư? Ai dạy cháu?” “Chẳng ai cả.”\n“Cháu nói dối.”\nTôi đi ra, và nói vọng vào từ ngoài cửa,“Thứ Sáu bác hãy mang\nngựa về cho cháu và bác sẽ thấy cháu có biết đọc hay không?”\nSau đó, khi đêm xuống và chị Jandira đã thắp đèn dầu lên bởi vì\ncông ty điện đã cắt điện nhà chúng tôi do chưa thanh toán hóa đơn,\ntôi đứng nhón chân ngắm “ngôi sao” ấy. Đó là bức tranh vẽ trên một\nmảnh giấy, hình một ngôi sao với lời nguyện cầu ở bên dưới mong\nngôi sao phù hộ cho nhà chúng tôi.\n“Jandira, chị nhấc em lên được không? Em sẽ đọc những chữ\nkia.”\n“Nói phét đủ rồi đấy,Zezé. Chị đang bận.”\n“Cứ nhấc em lên một tí thôi rồi em sẽ cho chị xem. “Này,Zezé,\nnếu định giở trò gì thì mày liệu hồn.” Chị nhấc tôi lên phía sau cánh\ncửa.\n“Nào, đọc đi. Chị đang muốn xem đây.”\nVậy là tôi đọc, đọc thật. Tôi đọc câu cầu nguyện, cầu Chúa phù\nhộ cho gia đình chúng tôi và bảo vệ chúng tôi khỏi những linh hồn\nhiểm ác.\nJandira đặt tôi xuống. Miệng chị há hốc.\n“Zezé, mày đã thuộc lòng câu đó phải không? Mày lừa chị phải\nkhông?”\n“Jandira, em thề. Em có thể đọc mọi thứ.”\n“Chẳng ai không học mà lại biết đọc cả. Là bác Edmundo dạy\nmày phải không? Hay bà?”\n“Chẳng ai cả.”\nChị chạy đi lấy một tờ báo và tôi đọc không sai chữ nào. Chị kêu\nré lên và gọi Glória. Gloria trở nên lo lắng và đi gọi Alaíde. Trong\nvòng mười phút, hàng xóm của chúng tôi đã xúm lại để xem chuyện\nlạ.\nĐó chính là chuyện Totoca muốn tôi nói cho anh biết. “Bác ấy đã\ndạy em và hứa cho em con ngựa nếu em học được.”\n“Không phải vậy.”\n“Anh sẽ hỏi bác ấy.”\n“Anh đi mà hỏi. Em không biết giải thích chuyện đó như thế nào,\nTotoca ạ. Nếu biết, em đã nói với anh.”\n“Vậy thì đi thôi. Rồi mày sẽ thấy. Khi mày cần gì đó...”\nAnh giận dữ chộp tay tôi và bắt đầu lôi tôi về nhà. Rồi anh nghĩ\nra một cách để trả thù.\n“Đáng đời mày chưa! Mày học quá sớm, đồ ngốc ạ. Giờ thì mày\nsẽ phải bắt đầu đến trường vào tháng Hai.” Đó là ý tưởng của\nJandira. Nhờ thế nhà tôi sẽ yên bình suốt cả buổi sáng, còn tôi thì sẽ\nbiết thế nào là lễ độ.\n“Lại học cách sang đường đi. Đừng tưởng khi mày đi học thì anh\nsẽ là vú em của mày, lần nào cũng đưa mày sang đường nhé. Nếu\nmày thông minh như vậy, thì mày cũng có thể học đượC việc này.”\n“Đây, ngựa đây. Giờ thì đọc cái này xem nào.”\nBác mở tờ báo ra và chỉ cho tôi một câu trong một mẩu quảng\ncáo thuốc chữa bệnh.\n“Thuốc có trong tất cả các hiệu thuốc và các cửa hàng dượC uy\ntín,” tôi đọc.\nBác Edmundo chạy ra gọi bà từ sân sau vào.\n“Mẹ ơi. Nó thậm chí đọc đúng cả từ hiệu thuốc này.” Cả hai\nngười bắt đầu đố tôi đọc những câu khác và tôi đọc được hết.\nBà bắt đầu lẩm bẩm gì đó tôi nghe không hiểu.\nBác Edmundo đưa cho tôi con ngựa và tôi lại ôm bác. Sau đó\nbác nâng cằm tôi và nói bằng giọng ngập ngừng, “Cháu rồi sẽ tiến\nxa, khỉ con ạ. Không phải ngẫu nhiên tên cháu lại là José. Cháu sẽ\nlà mặt trời và các vì sao sẽ sáng lấp lánh quanh cháu.”\nTôi không hiểu bác nói gì và tự hỏi liệu có đúng là bác hơi biêng\nbiệng hay không.\n“Cháu không hiểu được chuyện đó đâu. Đó là câu chuyện về\nJoseph1\n. Khi nào cháu lớn hơn một chút, bác sẽ kể cho cháu nghe.”\nTôi mê mẩn các câu chuyện. Chuyện càng khó hiểu thì tôi càng\nthích.\nTôi vỗ vỗ con ngựa nhỏ của mình một lúc lâu rồi ngước lên nhìn\nbác Edmundo, nói, “Bác có nghĩ tuần tới cháu sẽ lớn hơn một chút\nkhông, bác?”', '2026-02-25 03:32:42'),
	(3, 15, 2, 'MỘT CÂY CAM NGỌT', 'Trong gia đình tôi, mỗi đứa lớn đều phải trong một đứa em.\nJandira trông Gloria và một người em gái khác - đã bị đưa đến miền\nBắc làm con nuôi để được nuôi nấng cho tử tế. Totoca là đứa em\ncưng của Jandira. Lala là người trông nom tôi, mãi cho đến dạo gần\nđây. Sau đó thì chị hết thích tôi. Tôi nghĩ chị đã chán phát ớn tôi rồi\nhoặc đã yêu mê mệt bạn trai chị, một anh chàng bảnh bao diện quần\nthụng áo khoác lửng giống như ca sĩ. Cái thời anh chị còn thường\nđưa tôi đi dạo (bạn trai chị gọi là “tản bộ”) vào các ngày Chủ nhật,\nanh thường mua cho tôi một ít kẹo thật ngon để tôi không kể cho ai\nbiết chuyện của hai người. Tôi thậm chí không thể hỏi bác Edmundo\nxem “tản bộ” có nghĩa là gì, nếu không cả nhà sẽ phát hiện ra.\nHai người anh chị nữa của tôi bị chết yểu và tôi chỉ nghe nói về\nhọ mà thôi. Mọi người kể anh chị là hai em bé người da đỏ thuộc bộ\ntộc Apinajé, da đen lắm, có mái tóc đen thẳng. Bởi vậy nên anh chị\nmới được đặt cho những cái tên của người da đỏ. Chị tên là Aracy,\ncòn anh là Jurandyr.\nSau đó em trai Luís của tôi ra đời. Gloria là người trông nom nó\nnhiều nhất, sau đó đến tôi. Thằng bé thậm chí không cần ai phải\ntrông, bởi vì trên đời này chẳng có bé trai nào ngoan ngoãn, yên\nlặng và dễ thương hơn nó.\nChính vì thế, khi nó nói bằng giọng nhỏ nhẹ, sõi ơi là sõi, đúng\nlúc tôi đang bước chân ra đường, tôi thay đổi ý định ngay tức thì.\n“Zezé ơi, anh đưa em đi vườn thú nhé? Hôm nay có vẻ trời sẽ\nkhông mua đâu, anh nhỉ?”\nCưng quá đi mất. Nó nói sõi quá. Thằng bé đó sau này không\nphải của vừa đâu; thể nào nó cũng sẽ tiến xa cho xem.\nTôi ngắm nhìn ngày đẹp trời, nhìn bầu trời xanh thăm thẳm,\nchẳng nỡ lòng nào nói dối. Bởi vì đôi khi, nếu đang không vui, tôi sẽ\nnói, “Luís, em điên à. Nhìn xem, cơn dông sắp kéo đến kia kìa!”\nLần này tôi cầm bàn tay nhỏ bé của nó và chúng tôi bước ra sân\nsau bắt đầu cuộc phiêu lưu.\nSân sau được chia thành ba khu vui chơi. Một là vườn thú. Một\nkhu là châu Âu, kết thúc chỗ hàng rào nhỏ ngay ngắn của Julio. Tại\nsao lại là châu Âu ư? Ngay cả chú chim nhỏ trong tôi cũng không\nbiết. Chúng tôi chơi trò đi cáp treo lên núi Sugarloaf. Chúng tôi mang\ncái hộp đựng cúc áo ra và xâu hết cúc lại bằng một sợi dây. (Bác\nEdmundo gọi thứ dây đó là thừng. Tôi cứ nghĩ “thừng” là đứa con\ntrai, nhưng bác giải thích con trai là “thằng” cơ). Sau đó chúng tôi\nbuộc một đầu dây vào hàng rào và một đầu kia vào ngón tay Luis.\nChúng tôi đẩy hết cúc lên tít đầu dây và để chúng trượt từ từ, từng\nchiếc từng chiếc một. Mỗi toa cáp treo đều chở đầy những người\nchúng tôi biết. Có một cái đen sì chở Biriquinho. Chẳng có gì là lạ\nkhi nghe thấy một giọng nói vọng qua hàng rào, “Zezé, mày đang\nphá hàng rào của bà phải không?”\n“Không đâu, bà Dimerinda. Bà cứ ra đây mà xem này.”\n“Ồ, bà thích xem cảnh này đấy. Chơi ngoan với em trai mày. Như\nthế chẳng hay hơn à?”\nCó lẽ như thế hay hơn thật, nhưng khi “cha đỡ đầu” là quỷ dữ\ncủa tôi huých tôi một cái, thì chẳng có gì hay hơn chuyện giở trò tinh\nquái...\n“Bà sẽ cho cháu một cuốn lịch làm quà Giáng sinh như năm\nngoái chứ ạ?”\n“Mày đã làm gì với cuốn lịch bà cho vậy hả?”\n“Bà cứ vào trong mà xem, bà Dimerinda. Nó ở ngay phía trên túi\nbánh mì đấy ạ.”\nBà bật cười và hứa sẽ sang xem. Chồng bà làm việc tại cửa\nhàng bách hóa tổng hợp của ông Chico Franco.\nTrò chơi còn lại là Luciano. Ban đầu Luis thực sự sợ nó, cứ túm\nlấy quần tôi giật, đòi đi khỏi chỗ đó. Nhưng Luciano là bạn tôi. Mỗi\nkhi nhìn thấy tôi, nó đều rít lên rõ to. Gloria cũng không thích nó và\nbảo rằng loài dơi là ma cà rồng hút máu trẻ con.\n“Không phải vậy đâu, Gló. Luciano không giống như vậy đâu. Nó\nlà bạn em mà. Nó biết em.”\n“Em và cái kiểu cuồng động vật của em, suốt ngày nói chuyện\nvới con nọ, con kia...”\nKhó khăn lắm tôi mới thuyết phục được Luis tin rằng Luciano\nkhông phải một con vật. Đối với chúng tôi, Luciano là một chiếc máy\nbay đang bay đến căn cứ không quân Afonso.\n“Nhìn này, Luis.”\nVà Luciano thích thú bay quanh chúng tôi như thể nó hiểu chúng\ntôi nói gì. Mà nó hiểu thật.\n“Nó là một chiếc máy bay. Nó đang...”\nTôi ngừng lại. Tôi phải bảo bác Edmundo nói cho tôi nghe từ đó\nlần nữa mới được. Tôi không biết từ đó là “nháo lộn”, “nhào lộn” hay\n“nhạo lộn”. Một trong những từ đó. Nhưng tôi không thể dạy em\nmình một từ không chính xác.\nNhưng bây giờ nó muốn sang vườn thú.\nChúng tôi đến gần cái chuồng gà cũ. Trong chuồng, hai con gà\nmái lông sáng màu đang mổ mổ xuống đất, còn con gà mái đen già\nkhụ thì lành đến nỗi chúng tôi còn có thể gãi đầu nó.\n“Trước tiên chúng mình mua vé đã. Nắm tay anh nào, bởi vì trẻ\ncon dễ bị lạc ở chỗ đông người như thế này lắm. Nhìn xem, ngày\nChủ nhật ở đây thật nhộn nhịp phải không?”\nLuis nhìn quanh, thấy khắp nơi toàn người là người, bèn nắm\nchặt tay tôi.\nTại quầy vé, tôi ưỡn bụng và hắng giọng, ra vẻ quan trọng. Tôi\ncho tay vào túi quần và hỏi người phụ nữ ở quầy,“Miễn vé đến mấy\ntuổi nhỉ?”\n“Năm.”\n“Vậy thì cho một vé người lớn.”\nTôi bứt hai chiếc lá cam làm vé và chúng tôi bước vào. “Con trai,\ntrước hết chúng ta sẽ đến xem những con chim đẹp như thế nào\nnhé. Nhìn kìa, những con vẹt thường, vẹt đuôi dài, vẹt Nam Mỹ với\nđủ mọi màu sắc kìa. Những con lông sặc sỡ ở đằng kia là vẹt Nam\nMỹ đó.”\nMắt em tôi lồi ra vì thích thú.\nChúng tôi đi loanh quanh, ngắm nghía mọi thứ. Chúng tôi nhìn\nngó nhiều đến nỗi tôi còn để ý thấy Gloria và Lalá ở đằng sau mọi\nthứ khác, đang ngồi trên ghế băng bóc cam. Lalá đang nhìn tôi... Có\nkhi nào các chị đã phát hiện ra chăng? Nếu vậy thật thì chuyến thăm\nvườn thú đó sẽ kết thúc kèm theo một cú phát ra trò vào mông ai đó.\nVà ai đó ấy chỉ có thể là tôi mà thôi.\n“Tiếp theo là gì vậy, Zezé, giờ chúng ta sẽ xem gì hả anh?”\nTôi lại hắng giọng và lấy lại điệu bộ vừa rồi. “Ra đằng kia xem\nkhỉ nào. Bác Edmundo gọi chúng là linh trưởng.”\nChúng tôi mang mấy quả chuối theo và ném cho lũ khỉ. Chúng\ntôi biết mình không được phép làm thế, nhưng những người trông\ncoi vườn thú còn đang bận túi bụi bởi có quá đông khách tham\nquan.\n“Đừng đến gần quá, nếu không chúng sẽ ném vỏ chuối vào\nngười em đấy, nhóc ạ.”\n“Em muốn xem sư tử.”\n“Đi ngay và luôn nào.”\nTôi liếc nhìn sang chỗ có hai “linh trưởng” khác đang ăn cam. Từ\nchuồng sư tử, tôi có thể nghe thấy hai con ấy đang nói gì.\n“Đây rồi.”\nTôi chỉ tay vào hai con sư tử màu vàng, đích thị là sư tử châu\nPhi. Luis nói nó muốn vỗ đầu con báo đen một cái.\n“Em điên à, nhóc? Báo đen là con vật đáng sợ nhất vườn thú.\nNó được đưa tới đây vì đã cắn đứt cánh tay của mười tám người\ndạy thú rồi ăn hết đấy.”\nLuis có vẻ sợ hãi, vội rụt tay lại.\n“Báo đen đến từ một rạp xiếc hả anh?” “Đúng.”\n“Rạp xiếc nào vậy, Zezé? Thế mà trước đây anh chưa bao giờ\nnói cho em biết.”\nTôi suy nghĩ lung lắm. Tôi có biết ai có tên phù hợp để đặt cho\nmột rạp xiếc không nhỉ?\n“À! Nó đến từ rạp xiếc Rozemberg\n“Đó không phải tiệm bánh ạ?”\nCàng ngày càng khó lừa thằng em tôi. Nó càng ngày càng khôn.\n“Cũng có tiệm bánh tên như thế. Ngồi xuống ăn trưa thôi. Chúng\nta đã đi bộ nhiều rồi.”\nChúng tôi ngồi xuống và giả vờ ăn. Nhưng tại tôi ngứa ngáy, cứ\ndỏng lên hóng hai chị nói chuyện.\n“Chúng mình nên học tập nó, Lalá ạ. Xem đấy, nó kiên nhẫn với\nthằng Luís biết bao.”\n“Ừ, nhưng Luis có làm những chuyện mà nó vẫn làm đâu. Đó là\nnhững việc xấu xa chứ không phải trò tinh nghịch.”\n“Vậy nên trong máu nó mới có quỷ, nhưng nó ngộ nghĩnh đấy\nchứ. Không ai ở ngoài phố có thể tức giận với nó, dù nó làm gì...”\n“Nó mà đi qua chỗ chị thì sẽ không thoát khỏi cảnh bị phết roi\nđâu. Một ngày nào đó nó sẽ được dạy cho một bài học.”\nTôi nhìn Gloria bằng ánh mắt thương xót. Chị luôn đến giải cứu\ntôi và lần nào tôi cũng hứa với chị sẽ không tái phạm.\n“Để sau đi. Bây giờ thì đừng. Bọn chúng đang chơi yên mà.”\nChị đã biết hết rồi. Chị biết tôi đã lội qua mương sang sân sau\nnhà bà Celina. Tôi mê mẩn cái dây phơi quần áo đung đưa cả đống\ncánh tay với ống chân trong gió. Lúc đó quỷ dữ bảo tôi rằng tôi có\nthể làm cho tất cả những cánh tay, ống chân kia lộn tùng phèo cùng\nlúc. Tôi đồng ý rằng cảnh đó hẳn sẽ hết sức buồn cười. Tôi tìm thấy\nmột mảnh thủy tinh sắc ở dưới mương, bèn trèo lên cây cam, kiên\nnhẫn cắt cái dây phơi.\nTôi suýt ngã theo cái dây. Có tiếng kêu thất thanh và mọi người\nchạy túa ra.\n“Giúp tôi với, dây phơi bị đứt rồi.”\nNhưng một giọng người không biết phát ra từ đâu tru tréo.\n“Đó là thằng con nhà ông Paulo đấy, thằng ranh con phá hoại đó.\nTôi nhìn thấy nó cầm mảnh thủy tinh leo lên cây cam kia kìa.”\n“Zezé?"\n* * *\n“Gì vậy, Luis?”\n“Sao anh biết nhiều về vườn thú thế?”\n“Anh đã đến thăm vô số vườn thú rồi mà.” ”\nTôi nói xạo. Tất cả những gì tôi biết đều là do bác Edmundo kể\ncho nghe. Bác thậm chí đã hứa một ngày nào đó sẽ đưa tôi đến\nvườn thú. Nhưng bác đi quá chậm nên khi hai bác cháu đến nơi thì\nchắc vườn thú chẳng còn ở đó nữa. Totoca đã từng đến vườn thú\nmột lần cùng với cha.\n“Vườn thúanh thích nhất là RuaBarõodeDrummond, Vila Isabel.\nEm có biết nam tước Drummond là ai không? Tất nhiên em chẳng\nbiết đâu. Em còn bé quá chưa biết những chuyện như thế này đâu.\nNgài nam tước chắc chắn rất thân với Chúa. Bởi vì chính ngài đã\ngiúp Chúa phát minh ra trò xổ số, cái trò mà họ bán những tấm vé\ntại quán Đói Khổ và tại vườn thú ấy. Khi nào em lớn hơn...” Các chị\ntôi vẫn đang ở đó.\n“Khi em lớn hơn thì sao cơ?”\n“Em hỏi nhiều quá đấy, nhóc. Khi nào em đủ lớn, anh sẽ dạy em\nvề các con vật trong xổ số2 và các số của chúng. Phải đến số hai\nmươi cơ. Từ số hai mươi đến số hai mươi lăm, anh biết là có một\ncon bò cái, một con bò đực, một con gấu,một con nai và một con hổ.\nAnh không biết chúng được xếp theo thứ tự như thế nào, nhưng anh\nsẽ học để không dạy nhóc sai.”\nThằng bé đã phát chán trò chơi rồi.\n“Zezé, hát bài “Ngôi nhà nhỏ cho em nghe đi.” “Chúng ta đang ở\nvườn thú, đúng không? Ở đây đang đông người quá.”\n“Không. Chúng ta đã ra khỏi vườn thú rồi mà.”\n“Bài đó dài lắm đấy. Anh chỉ hát một đoạn em thích thôi nhé.”\nTôi biết đó là đoạn về những con ve. Tôi hít căng lồng ngực.\nTôi sống trong một ngôi nhà trên đỉnh đồi Dưới chân nhà vườn\ncây trái trải ra. Một nếp nhà nho nhỏ Đứng bên thềm tôi có thể nhìn\nra tận biển xa.\nTôi bỏ vài đoạn.\nTrong đám cây cọ lạ lũ ve sầu hát thánh ca.\nMặt trời lên nhuộm những cánh buồm vàng ruộm Trong khu\nvườn, một chú chim sơn ca.\nTôi ngừng hát. Các chị vẫn đang ngồi đó đợi tôi. Tôi nảy ra một\ný: Tôi sẽ hát cho đến khi đêm xuống. Tôi sẽ bám trụ ở đây lâu hơn\ncác chị.\nChẳng may mắn được đến thế. Tôi hát hết cả bài đó, hát lại lần\nnữa, rồi hát bài “Vì tình yêu thoáng qua của em”, thậm chí cả bài\n“Ramona”. Hai phiên bản khác nhau của bài “Ramona” mà tôi biết...\nMà các chị vẫn không nhúc nhích. Đến lúc đó thì tôi cải rồi. Tốt hơn\nnên để chuyện này kết thúc thôi. Tôi đi đến chỗ Lalá.\n“Nào, chìa mông ra đây.”\nTôi quay người lại, giơ mông ra cho chị, cắn chặt rằng vì Lala\nđang cầm dép trên tay.\nĐó là ý tưởng của mẹ.\n"Hôm nay tất cả chúng ta sẽ đi xem nhà.”\nTotoca dẫn tôi ra một chỗ và thì thầm, “Nếu mày nói với bất cứ ai\nrằng chúng mình đã đến đó rồi, thì mày sẽ lãnh đủ.”\nNhưng tôi chẳng hề có ý định ấy.\nCả nhóm chúng tôi đi ra đường. Gloria nắm tay tôi và được lệnh\nkhông được rời mắt khỏi tôi dù chỉ một phút. Còn tôi nắm tay Luís.\n“Khi nào chúng ta chuyển đến đó hả mẹ?” Gloria hỏi.\n“Sau Giáng sinh hai hôm, chúng ta sẽ phải gói ghém đồ đạc,” mẹ\nnói, giọng buồn buồn.\nMẹ có vẻ rất mệt mỏi. Tôi thực lòng thấy thương mẹ. Mẹ đã làm\nlụng cả đời. Mẹ làm việc từ khi lên sáu, khi nhà máy được xây dựng.\nNgười ta để mẹ ngồi lên một chiếc bàn và mẹ phải làm sạch và lau\nkhô các dụng cụ. Hồi đó, mẹ còn quá bé, đến nỗi tè dầm cả ra vì\nkhông thể tự xuống khỏi bàn được. Đó là lý do mẹ chưa bao giờ\nđược đến trường, cũng như chưa bao giờ học đọc học viết. Khi mẹ\nkể cho tôi nghe chuyện đó, tôi buồn đến mức đã hứa rằng khi nào\nthành nhà thơ và trở nên thông thái, tôi sẽ đọc thơ của tôi cho mẹ\nnghe.\nDấu hiệu Giáng sinh xuất hiện trên khắp các cửa hàng của hiệu.\nÔng già Noel đã được vẽ lên trên mọi ô cửa kính trưng bày. Mọi\nngười đều đã mua thiệp, để tránh việc đến cận ngày mới đổ xô đi\nmua. Tôi có một niềm hy vọng mong manh rằng lần này, Chúa Hài\nĐồng sẽ được sinh ra trong trái tim tôi. Dù gì đi nữa, có lẽ tôi cũng\nsẽ tiến bộ hơn chút ít khi đã đến tuổi chín chắn. “Nó đây.”\nMọi người đều thích nó. Nhà mới nhỏ hơn nhà cũ một chút. Với\nsự giúp sức của Totoca, mẹ tháo sợi dây thép buộc cổng và chúng\ntôi chạy ùa vào. Glória buông tay tôi ra, quên bẵng mất chị đã sắp\nthành thiếu nữ. Chị chạy tới chỗ cây xoài và choàng tay quanh thân\nnó. đầu tiên.”\n“Cây xoài là của chị. Chị đến chỗ nó Totoca làm như thế với cây\nme. Chẳng còn gì cho tôi. Tôi nhìn Glória, suýt khóc. “Thế còn em\nthì sao, Gló?”\n“Chạy ra sau nhà xem sao. Chắc phải còn những cây khác nữa\nđấy, đồ ngốc.”\nTôi chạy đi, nhưng chỉ thấy cỏ mọc dài và cả đám những cây\ncam già cỗi đầy gai. Bên cạnh rãnh nước là một cây cam ngọt nhỏ.\nTôi thất vọng quá. Các anh chị em của tôi đã chạy khắp nhà\nnhận phòng ngủ cả rồi.\nTôi giật giật váy của Glória.\n“Chẳng có gì khác cả.”\n“Em chẳng biết quan sát gì cả. Đợi một phút. Chị sẽ tìm một cây\ncho em.”\nNgay sau đó chị ra vườn với tôi. Chị chăm chú nhìn những cây\ncam.\n“Em không thích cây kia sao? Cây đó đẹp mà.” Tôi không thích\ncây này, cũng chẳng thích cây kia, chẳng thích cây nào trong đám\nấy. Chúng nhiều gai quá. “Em thích cây cam ngọt hơn đám cây xấu\nxí này.” “Ở đâu cơ?”\nTôi dẫn chị đi xem cây cam.\n“Cây cam nhỏ xinh quá này! Nó không có một cái gai nào. Nó\ntrông rất đặc trưng, đến mức nhìn từ xa ta cũng có thể nhận ra nó là\nmột cây cam ngọt. Nếu chị bé như em, chị cũng chẳng muốn cây\nkhác đâu.” một cây to co.”\n“Nhưng em muốn\n“Nghĩ kỹ mà xem, Zezé. Cây này vẫn còn nhỏ. Nó sẽ lớn lên\nthành một cây to - em và nó sẽ cùng lớn lên. Em và nó sẽ hiểu nhau\nnhư anh em. Em có thấy cái cành kia không? Nó là cành duy nhất,\nđúng vậy thật, nhưng nó hơi giống một con ngựa được sinh ra chỉ\nđể cho em vậy.”\nTôi cảm thấy mình thực sự bị đối xử bất công. Chuyện này khiến\ntôi nhớ đến cái vỏ chai rượu Scotch Có hình các thiên thần mà\nchúng tôi đã có lần nhìn thấy. Khi ấy, Lalá nói, “Thiên thần này là\nem.” Gloria chọn một thiên thần và Totoca cũng chọn một. Nhưng\ncòn tôi thì sao? Đến cuối cùng, tôi là cái đầu thấp bé ở phía sau tất\ncả những thiên thần khác, gần như không có cánh. Thiên thần\nScotland thứ tự thậm chí còn không phải một thiên thần hoàn\nchỉnh... Tôi luôn là kẻ cuối cùng. Mai sau lớn lên, tôi sẽ cho họ thấy.\nTôi sẽ mua nguyên cả cánh rừng nhiệt đới Amazon, và tất cả những\ncái cây cao chọc trời sẽ là của tôi. Tôi sẽ mua một cửa hàng đầy\nnhững cái chai in hình thiên thần và không ai lấy đưỢC một mảnh\ncánh nào ở đấy.\nHờn dỗi, tôi ngồi bệt xuống đất và để nỗi tức giận của mình tựa\nvào cây cam nhỏ. Glória mỉm cười bỏ đi.\n“Em sẽ không tức giận lâu đâu, Zezé ạ. Rồi em sẽ thấy chị nói\nđúng thôi.”\nTôi cầm một cái que cào cào lên mặt đất và vừa bắt đầu ngừng\nsụt sịt thì nghe thấy một giọng nói cất lên từ đâu đó, gần trái tim\nmình.\n“Tớ nghĩ chị cậu nói đúng đấy.”\n“Mọi người luôn đúng. Chỉ có tớ là chẳng đúng bao giờ.”\n“Không phải vậy đâu. Nếu ngắm kỹ tớ, cậu sẽ thấy.”\nGiật mình, tôi lồm cồm nhổm dậy và nhìn kỹ cây cam nhỏ. Thật\nkỳ lạ, vì tôi luôn nói chuyện với mọi thứ, nhưng tôi cứ nghĩ chính chú\nchim nhỏ trong tôi đã khiến cho mọi thứ trò chuyện với tôi.\n“Nhưng có thật là cậu biết nói không?”\n“Cậu không nghe thấy tớ nói sao?”\nVà nó bật cười khúc khích. Tôi suýt la lên và ù té chạy. Nhưng\nsự tò mò đã giữ tôi ở lại.\n“Làm sao cậu có thể nói được?”\n“Cây cối trò chuyện với vạn vật. Nói bằng lá, bằng cành, bằng\ngốc rễ. Cậu có muốn thấy điều đó không? Áp tai vào thân của tớ đi,\nrồi cậu sẽ nghe thấy tiếng tim tớ.”\nTôi do dự một lát, nhưng nhìn kích cỡ của cây cam, nỗi sợ trong\ntôi tan biến. Tôi áp tại vào thân cây và nghe thấy tiếng tích... tích...\n“Thấy không?”\n“Hãy nói với tớ xem nào. Mọi người đều biết cậu có thể nói được\nà?”\n“Không. Chỉ mình cậu thôi.”\n“Thật không?”\n“Tớ thề đấy. Hồi xưa, một bà tiên bảo tớ rằng, khi một cậu bé\ngiống như cậu làm bạn với tớ, thì tớ sẽ nói được và sẽ rất vui.”\n“Vậy cậu sẽ đợi chứ?”\n“Gì cơ?”\n“Đợi tớ chuyển tới đây. Phải mất hơn một tuần đấy. Cậu sẽ\nkhông quên cách nói chuyện chứ?”\n“Tớ không bao giờ quên đâu. Có nghĩa là, chỉ riêng với cậu thôi.\nCậu có muốn thử xem cưỡi tớ thì sẽ êm như thế nào không?”\n“Bằng cách nào...?”\n“Ngồi lên cành của tớ đi.”\nTôi làm theo.\n“Nào, lắc lư người và nhắm mắt lại.”\nTôi làm như cây cam nói.\n“Cậu nghĩ sao? Cậu đã bao giờ có con ngựa nào oach hon\nchua?"\n“Chưa từng. Tuyệt quá. Tớ sẽ cho em tớ con ngựa Vua Bạc.\nCậu sẽ thực sự thích thằng bé cho xem.” Tôi trèo xuống, thấy yêu\ncây cam nhỏ của mình.\n“Này, tớ định thế này nhé. Bất cứ khi nào có thể, thậm chí trước\nkhi chúng tớ chuyển tới đây, tớ sẽ đến trò chuyện với cậu. Bây giờ\ntớ phải đi đây. Mọi người đã ra Cổng chuẩn bị về rồi.”\n“Nhưng bạn bè không tạm biệt nhau kiểu ấy đâu.” “Suyt! Chị tớ\nđến đấy.”\nGloria đến đúng lúc tôi đang ôm cái cây.\n“Tạm biệt nhé, bạn của tôi. Bạn là sinh vật đẹp nhất trên đời!”\n“Chẳng phải chị đã nói với em như thế rồi sao?”\n“Đúng vậy. Bây giờ nếu chị muốn đổi cây xoài hay cây me lấy\ncây của em thì em cũng không đổi đâu.” Chị dịu dàng vuốt tóc tôi.\n“Zezé, Zezé..."\nChị em tôi nắm tay nhau rời khỏi đó.\n“Gló, cây xoài của chị bị câm thì phải, chị có nghĩ vậy không?”\n“Còn quá sớm để nói gì, nhưng có vẻ như vậy thật.” “Thế còn\ncây me của Totoca?”\n“Nó hơi kỳ một chút, sao thế?”\n“Em không biết có nên nói cho chị biết hay không. Nhưng một\nngày nào đó em sẽ kể cho chị nghe về một điều kỳ diệu, Gló ạ.”', '2026-02-25 04:14:55'),
	(4, 16, 1, 'CUỘC GẶP GỠ ĐẦU TIÊN VỚI ANDREW CARNEGIE', 'Trong suốt hơn một phần tư thập kỷ, tôi chỉ có một mục tiêu chính là thiết\nlập nên một triết lý về các nguyên tắc dẫn đến cả thành công và thất bại để\ngiúp đỡ những người không có động lực và cơ hội tham gia vào dạng nghiên\ncứu này.\nCông việc của tôi bắt đầu vào năm 1908, nó là kết quả của một cuộc phỏng\nvấn từ trước đó với Ngài Andrew Carnegie đã quá cố. Tôi đã nói rõ ràng với\nNgài Carnegie rằng tôi mơ ước được theo học tại trường Luật và trong đầu\ntôi đã hình thành ý tưởng sẽ phỏng vấn những người thành công nhất, tìm ra\ncon đường dẫn đến thành công của họ và viết những câu chuyện về những\nkhám phá đó cho các tạp chí. Vào cuối buổi gặp đầu tiên giữa chúng tôi,\nNgài Carnegie đã hỏi liệu tôi có đủ dũng cảm để thực hiện một gợi ý mà ông\nmuốn đưa ra cho tôi hay không. Tôi đã trả lời ông rằng lòng dũng cảm là tất\ncả những gì tôi có và tôi sẵn sàng nỗ lực hết sức mình để thực hiện bất cứ\ngợi ý nào ông đưa ra.\nSau đó, ông nói với tôi rằng: “Cho đến lúc này, ý tưởng viết các câu chuyện\nvề những người thành công rất đáng khen và tôi không hề có ý định làm cậu\nnản lòng. Nhưng tôi phải nói với cậu rằng nếu cậu muốn kéo dài công việc\nnày, không chỉ với những người hiện đang còn sống, mà với cả những thế hệ\nsau nữa, thì cậu phải dành một khoảng thời gian rất dài để sắp xếp tất cả các\nnguyên nhân dẫn đến cả thành công cũng như thất bại.\nCó hàng triệu người trên thế giới này không có ý niệm gì, dù là nhỏ nhất về\nnhững nguyên nhân dẫn đến thành công hay thất bại. Trường lớp dạy mọi\n\nngười thực hành mọi thứ, trừ các nguyên tắc để có được thành công. Họ yêu\ncầu những người trẻ tuổi dành từ bốn tới tám năm để tích lũy những kiến\nthức trừu tượng nhưng không dạy họ phải làm gì với những kiến thức đó.\nThế giới này đang cần một triết lý thực tế và dễ hiểu về thành công, triết lý\nđó được thiết lập từ kinh nghiệm thực tế của những người đàn ông và phụ nữ\ncủa Trường Đại học vĩ đại mang tên Cuộc sống. Trong lĩnh vực triết học, tôi\nchưa từng thấy có thứ triết lý nào có bất cứ nét tương đồng nào - dù là nhỏ\nnhất với thứ triết lý mà tôi đang có trong đầu. Có rất ít các nhà triết học có\nkhả năng dạy mọi người về nghệ thuật sống.\nVới tôi, dường như đây là cơ hội để thử thách một chàng trai trẻ tham vọng\nnhư cậu, nhưng chỉ có tham vọng thôi thì chưa đủ để thực hiện nhiệm vụ\nnày. Người đảm nhận nó phải có đồng thời cả lòng dũng cảm và sự kiên trì.\nCông việc này đòi hỏi ít nhất 20 năm nỗ lực không ngừng, trong khi đó\nngười đảm trách nó phải kiếm sống từ những việc khác, vì kiểu nghiên cứu\nnày sẽ không bao giờ có lợi nhuận ngay và thường thì những người có đóng\ngóp cho nền văn minh của chúng ta qua các công trình kiểu như thế này phải\nđợi một trăm năm hoặc hơn thế sau đám tang của mình mới được ghi nhận vì\nnhững công việc mình làm.”\nLƯU Ý với ĐỘC GIẢ: Sharon Lechter bổ sung phần bình luận dưới dạng\ntrình bày đặc biệt như sau:\n20 năm làm việc mà không hề được trả một đồng và không được bất kì\nai ghi nhận? Bạn sẽ phản ứng thế nào với “lời mời” này? Như ông trình\nbày bên dưới, Napoleon Hill đã chấp nhận thử thách của Carnegie và\nvới một lá thư giới thiệu từ Carnegie, ông bắt đầu phỏng vấn những\n“người khổng lồ” của thời kỳ đó, bao gồm Theodore Roosevelt\n[10]\n,\n\nThomas Edison, John D. Rockfeller\n[11]\n, Henry Ford, Alexander\n\nGraham Bell\n[12]\n, King Gillette\n[13]\nvà rất nhiều những người khác nữa.\nSau hơn 20 năm nghiên cứu, nỗ lực của ông cuối cùng cũng được đền\nđáp và được thể hiện qua việc xuất bản nhiều cuốn sách, trong đó có\ntám tập sách Luật Thành công (Law of Success) và Think and Grow\nRich - 13 nguyên tắc nghĩ giàu, làm giàu. Think and Grow Rich - 13\nnguyên tắc nghĩ giàu, làm giàu được công nhận rộng rãi là công trình có\n\nảnh hưởng sâu sắc trong lĩnh vực tự phát triển bản thân, cuốn sách đã\ngiới thiệu mọi nguyên tắc cần thiết mà đến ngày nay vẫn được coi là nền\ntảng trong các bài giảng của các chuyên gia về phát triển cá nhân. Think\nand Grow Rich - 13 nguyên tắc nghĩ giàu, làm giàu bản thân nó đã là\nmột đề tài nghiên cứu trong các nguyên tắc ông đưa ra. Có thể nói rằng\nbản thảo Chiến thắng Con Quỷ trong bạn được viết vào thời điểm sau\nkhi Think and Grow Rich - 13 nguyên tắc nghĩ giàu, làm giàu phát hành\nmột năm vì cuốn sách này có thể hé lộ một “cái tôi khác” của Napoleon\nHill và ông đã vượt qua sự thất bại và sử dụng thành công các nguyên\ntắc ông đã miêu tả trong Think and Grow Rich - 13 nguyên tắc nghĩ\ngiàu, làm giàu. Chiến thắng Con Quỷ trong bạn sẽ tiết lộ cho bạn biết sự\ntỉnh thức trong tâm hồn của Napoleon Hill và mỗi chúng ta có thể học\nđược gì từ cuộc chạm trán của ông với Con Quỷ.\n“Nếu cậu nhận công việc này, cậu nên phỏng vấn không chỉ một vài người\nđã thành công mà còn phải phỏng vấn rất nhiều người từng thất bại nữa. Cậu\nnên phân tích thật tỉ mỉ hàng ngàn người được xếp vào hàng ‘thất bại’, ý tôi\nnói ‘thất bại’ ở đây là những người đi đến chương cuối của cuộc đời họ trong\nnỗi thất vọng vì không đạt được mục tiêu mà họ khao khát. Nghe có vẻ mâu\nthuẫn nhưng cậu sẽ học được cách làm thế nào để thành công từ những thất\nbại hơn những thứ được gọi là thành công. Họ sẽ dạy cậu những gì cậu\nkhông nên làm.\nSuốt chặng đường đến khi cậu hoàn thành công việc này, nếu cậu thành\ncông, cậu sẽ có một khám phá khiến cậu vô cùng ngạc nhiên. Cậu sẽ phát\nhiện ra rằng nguyên nhân dẫn đến thành công không phải thứ gì riêng rẽ\nhoặc tách biệt khỏi con người, đó là một sức mạnh vô hình trong tự nhiên mà\nphần lớn con người không bao giờ nhận thấy, một sức mạnh có thể được gọi\nchính xác là ‘cái tôi khác’. Đáng chú ý là ‘cái tôi khác’ này hiếm khi lộ diện\ntrừ những trường hợp khẩn cấp khi con người bị đẩy đến những nghịch cảnh\nhoặc thất bại tạm thời.\nKinh nghiệm đã dạy tôi rằng một người đang đến rất gần với thành công khi\nnhững thứ mà anh ta gọi là ‘thất bại’ xảy đến, bởi đây chính là dịp để anh ta\nbuộc phải tư duy. Nếu tư duy đúng đắn, cùng với sự kiên trì, anh ta sẽ khám\nphá ra rằng những thứ được gọi là thất bại đó thực ra chỉ là một dấu hiệu\nnhắc anh ta phải trang bị lại cho bản thân mình một kế hoạch hoặc một mục\nđích mới. Phần lớn những thất bại thực sự đều bắt nguồn từ những giới hạn\nmà con người tự đặt ra trong tâm trí mình. Nếu có đủ dũng cảm để đi thêm\n\nmột bước nữa, họ sẽ nhận ra sai lầm của mình.”\n“Phần lớn những thất bại thực sự đều bắt nguồn từ những giới hạn mà\n\ncon người tự đặt ra trong tâm trí mình.”\n\nMột tư duy tiêu cực và tự ti có thể là trở ngại lớn nhất trên con đường đi đến\nthành công. Với tình hình kinh tế đang đi xuống như hiện nay, có quá nhiều\nngười cả đời mọi chuyện luôn suôn sẻ, giờ đây, lần đầu tiên phải đối mặt với\nnhững vấn đề tài chính nghiêm trọng. Rào cản lớn nhất khiến họ chưa phục\nhồi lại được chính là nỗi sợ hãi và tự ti bắt nguồn từ những trải nghiệm gần\nđây của họ. Bạn có để tình hình kinh tế đang đi xuống hiện nay tác động đến\nbạn không? Bạn có để nỗi tự ti và hành vi tự phá hủy bản thân ngăn bạn đạt\nđược ước mơ của mình không? Có phải bạn chính là kẻ thù tồi tệ nhất của\nbản thân mình? Trong cuốn Think and Grow Rich - 13 nguyên tắc nghĩ giàu,\nlàm giàu; Napoleon Hill đã kể lại câu chuyện về R. U. Darby - một người\nđào vàng. Vì quá thất vọng khi mạch quặng vàng đột nhiên biến mất, Darby\nđã bán lại quyền khai thác mỏ với giá rẻ mạt cho một người bán đồng nát ở\nthị trấn. Người bán đồng nát đó đã mời các chuyên gia về mỏ đến tư vấn và\nhọ phát hiện ra rằng chỉ cần đào thêm một quãng độ ba bước chân nữa thôi,\nDarby sẽ tìm lại được mạch quặng. Giá như kiên trì thêm chút nữa, Darby đã\ngiàu to nhưng anh đã từ bỏ giấc mơ của mình trong khi chỉ còn cách mỏ\nvàng có ba bước chân. Nhưng thay vì bị gục ngã bởi sai lầm của mình,\nDarby đã học từ trải nghiệm đó và tiếp tục xây dựng nên một đế chế trong\nngành bảo hiểm. Bạn có từ bỏ mục tiêu của mình ngay trước khi đạt được\nnhững thành công vĩ đại, khi bạn chỉ còn cách mỏ vàng có ba bước chân\nkhông? (Trong cuốn sách Cách mỏ vàng ba bước chân [Three Feet from\nGold], bạn có thể tìm đọc về rất nhiều tấm gương đã kiên trì vượt qua các\nhoàn cảnh khó khăn trong thời đại hiện nay.)\nBắt đầu một cuộc đời mới\n\nNhững lời Ngài Carnegie nói đã định hình lại toàn bộ cuộc sống của tôi và\ngieo vào lòng tôi một mục tiêu cháy bỏng, mục tiêu ấy luôn không ngừng\nthúc đẩy tôi dù lúc ấy tôi hoàn toàn mơ hồ và không hiểu ông có ý gì khi\nnhắc đến cụm từ “cái tôi khác”.\nTrong suốt quá trình nghiên cứu nguyên nhân dẫn đến thất bại và thành\ncông, tôi đã có đặc quyền được phân tích hơn 25.000 người được đánh giá là\n“thất bại” (cả đàn ông lẫn phụ nữ) và hơn 500 người được phân loại là\n\n“thành công”. Nhiều năm trước, tôi đã bắt đầu có ý niệm đầu tiên về “cái tôi\nkhác” mà Ngài Carnegie đã nhắc đến. Đúng như ông ấy đã nói, tôi đã khám\nphá ra điều đó sau hai bước ngoặt lớn trong cuộc đời mình - hai tình huống\nkhẩn cấp buộc tôi phải tư duy để vượt qua được những khó khăn tôi chưa\ntừng gặp phải bao giờ.\nCông việc nghiên cứu của tôi cần góp nhặt rất nhiều dữ liệu, nó thực sự đòi\nhỏi nhiều năm lao động miệt mài. Để giúp các bạn thấy được bức tranh toàn\ncảnh, tôi sẽ quay lại bước ngoặt đầu tiên trong hai bước ngoặt lớn và từng\nbước mang khám phá ấy đến với các bạn.\nKhi tìm ra 17 nguyên tắc thành công và 30 nguyên nhân thất bại, tôi tưởng\nrằng mình đã hoàn thành nhiệm vụ xây dựng nên một triết lý hoàn chỉnh về\nthành công cá nhân. Nhưng thực ra, đó là một kết luận chủ quan và sai lầm\ncủa bản thân tôi. Vì lúc đó, công việc của tôi chỉ mới chập chững bắt đầu.\nVới 17 nguyên tắc thành công và 30 nguyên nhân thất bại, tôi mới chỉ dựng\nđược một bộ khung cho triết lý đó và bộ khung ấy cần phải được “đắp” thêm\nrất nhiều ví dụ và trải nghiệm thực tế. Hơn nữa, nó còn cần có “tâm hồn” để\nthôi thúc con người đối diện với khó khăn chứ không phải né tránh nó.\n“Tâm hồn” - thứ còn thiếu đó, như sau này tôi mới phát hiện ra, nó chỉ đến\nsau khi tôi khám phá được “cái tôi khác” qua hai bước ngoặt lớn trong cuộc\nđời mình.\nQuá trình tìm ra “cái tôi khác” của tôi cũng là một câu chuyện dài. Dù có\ntham vọng viết sách nhưng lúc đầu tôi quyết tâm sẽ kiếm tiền bằng nghề\nkhác. Tôi quyết định sẽ làm trong ngành quảng cáo và tôi đã trở thành người\nphụ trách quảng cáo cho Đại học Mở rộng LaSalle tại Chicago. Mọi chuyện\nđều thật tuyệt vời trong vòng một năm, rồi tôi đột nhiên thấy vô cùng chán\nghét công việc đó và xin từ chức.\nSau đó tôi tham gia vào việc kinh doanh một chuỗi cửa hàng cùng với Cựu\nchủ tịch của Đại học Mở rộng LaSalle và tôi trở thành Chủ tịch Công ty Kẹo\nBetsy Ross. Nhưng thật không may, ít nhất là vào thời điểm đó tôi thấy\nchuyện đó thật xui xẻo, tôi bất đồng quan điểm với cộng sự của mình và\nchuyện đó lại khiến tôi xin rút lui khỏi vị trí mình đang đảm nhận.\nSự quyến rũ của ngành quảng cáo đã ăn sâu vào máu tôi và tôi quyết định sẽ\ntiếp tục làm công việc đó bằng việc mở một trường đào tạo về quảng cáo và\n\nbán hàng - một bộ phận nằm trong trường Cao đẳng Kinh doanh Bryant &\nStratton.\nCông việc đào tạo rất xuôi chèo mát mái và chúng tôi kiếm được cả bộn tiền\nkhi nước Mỹ tham gia vào Chiến tranh Thế giới lần thứ nhất. Nhưng để đáp\nlại thôi thúc mãnh liệt từ bên trong mà không ngôn từ nào diễn tả được, tôi\nđã rời khỏi trường, gia nhập vào quân đội của chính phủ Mỹ, dưới sự chỉ đạo\ncủa Tổng thống Woodrow Wilson\n[14]\nvà để lại công việc kinh doanh tưởng\n\nchừng như hoàn hảo kia dần tan vỡ.\nVào ngày ký hiệp định chấm dứt Chiến tranh thế giới lần thứ nhất\n(11/11/1918), tôi bắt đầu xuất bản tạp chí Nguyên tắc Vàng. Dù tôi chẳng có\nmột xu tiền vốn nào nhưng tạp chí vẫn phát triển rất nhanh và sớm được phát\nhành rộng rãi trên toàn quốc với nửa triệu bản in mỗi kỳ, đến cuối năm đầu\ntiên trong lịch sử hoạt động, tạp chí đã lãi 3.516 đô la.\nTheo đánh giá chính xác thì 3.156 đô la vào năm 1918 sẽ có giá trị tương\nđương với 45.000 đô la theo Chỉ số giá tiêu dùng trung bình hàng năm được\nbiên soạn bởi Cục Thống kê Lao động Liên bang Mỹ và 202.000 đô la khi\nlấy tổng sản lượng nội địa theo giá cả thị trường hiện hành chia cho đầu\nngười. Đó là con số không hề nhỏ cho năm đầu tiên kinh doanh tạp chí... Bởi\nkhi đó có tới 80 đến 90% các tờ báo mới thất bại và thậm chí cả những tờ\nbáo thành công nhất cũng phải mất từ ba đến năm năm mới bắt đầu có lãi.\nVài năm sau, một người có kinh nghiệm dày dạn trong ngành xuất bản đã\nbảo tôi rằng bất cứ ai có kinh nghiệm trong ngành xuất bản và phân phối các\ntạp chí trên cả nước cũng sẽ nghĩ rằng để bắt đầu xuất bản một tạp chí như\nthế phải có vốn liếng ít nhất là nửa triệu đôla.\nNhưng cuối cùng thì tôi cũng chia tay tạp chí Nguyên tắc Vàng. Chúng tôi\ncàng thành công, tôi lại càng bất mãn, cuối cùng, vì những cơn bực mình\nchồng chất với các cộng sự, tôi tặng không cả tạp chí cho họ và rút khỏi nó.\nLần này có lẽ tôi đã quăng cả một gia tài nhỏ chứ chẳng chơi.\nĐây chỉ là sự khởi đầu của tình yêu Napoleon Hill dành cho tạp chí. Sau\nNguyên tắc Vàng, ông xuất bản Tạp chí Napoleon Hill. Sau này, ông còn là\nbiên tập viên của tạp chí Thành Công - một tạp chí hiện vẫn đang được xuất\nbản.\n\nSau đó, tôi mở một trường đào tạo nhân viên bán hàng. Nhiệm vụ đầu tiên\ncủa tôi là đào tạo một đội quân bán hàng gồm 3000 người cho một chuỗi cửa\nhàng, tôi nhận được 10 đô la cho mỗi nhân viên tham dự khóa đào tạo của\nmình. Trong vòng gần sáu tháng, tôi đã kiếm được khoảng hơn 30.000 đô la\nmột chút. Chừng nào còn dính líu đến tiền bạc, mọi nỗ lực của tôi vẫn chỉ\nđược đền đáp bằng những thành công về mặt tiền bạc. Tôi lại cảm thấy\n“nóng ruột”. Tôi không hạnh phúc. Có một sự thật ngày càng rõ ràng là\nchẳng có số tiền nào làm tôi thấy hạnh phúc cả.\nDù không có bất cứ một lý do hợp lý nào, cho dù là nhỏ nhất; tôi vẫn quyết\nđịnh từ bỏ công việc giúp tôi dễ dàng kiếm được nhiều tiền ấy. Bạn bè và các\ncộng sự đều nghĩ rằng tôi thật điên rồ và cho đến bây giờ, điều họ nói vẫn\nđúng.\nRõ ràng là tôi sẵn sàng đồng ý với họ, nhưng tôi không thể làm khác được.\nTôi tìm kiếm hạnh phúc nhưng chưa tìm thấy nó. Ít nhất thì đó là lời giải\nthích duy nhất tôi có thể đưa ra cho những hành động không bình thường của\nmình. Ai có thể hiểu bản thân tôi hơn chính mình được chứ?', '2026-02-28 07:37:22'),
	(5, 16, 2, 'MỘT THẾ GIỚI MỚI MỞ RA TRƯỚC MẮT TÔI', 'Rõ ràng là tôi đã vừa mới được sinh ra thêm lần nữa, bởi trong tôi không còn\nbất cứ nỗi sợ hãi nào. Lòng dũng cảm trong tôi dâng đầy chưa từng có. Dù\nvẫn chưa được chỉ dẫn về việc tôi có thể tìm thấy số tiền mình cần bằng cách\nnào hay từ đâu nhưng tôi có niềm tin tuyệt đối rằng số tiền đó đang chờ tôi ở\nphía trước, rõ ràng đến mức tôi có thể mường tượng ra cảnh tôi sở hữu nó\nnhư thế nào.\nTrong suốt cuộc đời mình, hiếm khi nào tôi có lòng tin đến mức này. Đó là\nmột cảm giác rất khó miêu tả lại với người khác. Không có từ ngữ nào thích\nhợp để diễn tả về nó - chỉ những ai từng trải qua chuyện giống như thế mới\ncó thể hiểu được mà thôi.\nTôi lập tức làm theo những gì được hướng dẫn. Mọi cảm giác rằng tôi đang\ntheo đuổi một nhiệm vụ bất khả thi đã tan biến hết. Tôi bắt đầu gọi điện thoại\ncho từng cái tên xuất hiện trong đầu mình mà tôi biết rằng họ có khả năng tài\nchính để giúp tôi 25.000 đô la tôi cần, bắt đầu với Henry Ford và tiếp tục với\ntoàn bộ danh sách kéo dài hơn 300 người. “Cái tôi khác” của tôi chỉ nói:\n“Hãy cứ tiếp tục tìm kiếm đi.”\n\nSau giờ khắc đen tối nhất, bình minh sẽ đến\n\nNhưng sự kiên nhẫn của tôi cũng có giới hạn. Danh sách những người tôi\nquen biết đã cạn kiệt và tôi cũng không còn chút sức lực nào nữa. Tôi đã làm\nviệc rất lâu, tôi hoàn toàn tập trung trí óc vào danh sách những cái tên đó\nnhưng vì hai ngày tới còn ở đây, tôi không làm việc nữa mà tranh thủ chợp\n\nmắt lấy vài giờ.\nTôi dựa lưng vào ghế, nhắm mắt lại và ngủ mơ màng được khoảng vài phút.\nTôi bật dậy bởi dường như cả căn phòng vừa mới nổ tung. Bởi tôi vừa mới\nsực nhớ đến cái tên Albert L. Pelton... và kèm theo đó là một kế hoạch mà\ntôi biết chắc rằng nhờ nó mà tôi sẽ thành công trong việc nhờ Ngài Pelton\nxuất bản những cuốn sách của mình. Tôi chỉ nhớ rằng Ngài Pelton là chủ\nmột doanh nghiệp từng quảng cáo trên tạp chí Nguyên tắc Vàng mà trước\nđây tôi từng xuất bản.\nTiềm thức của Napoleon Hill đã nhắc đến một cái tên người quen là nguồn\nđầu tư tiềm năng, dù đó chỉ là một người từng quảng cáo trên tạp chí của\nông. Bạn có ấn tượng với mọi người bạn từng gặp gỡ và mọi người bạn gặp\ncũng đều có ấn tượng về bạn. Bạn chẳng bao giờ biết được khi nào bất cứ\nngười quen nào đó của bạn có thể trở thành một đối tác làm ăn. Mạng lưới\ncủa bạn có sức mạnh vô cùng lớn.\nTôi gửi một bức điện đi, đề tên người nhận là Ngài Pelton ở Merriden, bang\nConnecticut và miêu tả kế hoạch như thể nó mới được nhét vào tay tôi vậy.\nÔng gửi lại cho tôi một bức điện với nội dung rằng hôm sau ông sẽ tới\nPhiladelphia gặp tôi.\nKhi ông đến, tôi đã cho ông xem bản thảo gốc về triết lý của tôi và giải thích\nngắn gọn rằng về sứ mệnh của triết lý đó. Ông lật qua bản thảo trong vài\nphút, sau đó nhìn lên tường vài giây và nói: “Tôi sẽ xuất bản các cuốn sách\ncủa anh.”\nVậy là hợp đồng đã được ký, tôi nhận được một khoản tiền bản quyền trả\ntrước, ông giữ bản thảo và ông mang chúng theo về Meriden.\nLúc đó tôi đã không hỏi ông rằng điều gì khiến ông quyết định sẽ xuất bản\nsách của tôi khi thậm chí ông chưa đọc qua bản thảo, nhưng tôi biết rằng ông\nđã tài trợ cho tôi số tiền mình cần, ông in sách cho tôi, ông giúp tôi bán hàng\nngàn bộ sách cho các khách hàng của ông ở tất cả các nước nói tiếng Anh\ntrên khắp thế giới.\n\n“Cái tôi khác” bù đắp cho tôi\n\nBa tháng sau ngày Ngài Pelton đến gặp tôi ở Philadelphia, một bộ sách đầy\n\nđủ được đặt trên bàn, ngay trước mặt tôi và thu nhập từ tiền bán sách đã bắt\nđầu đáp ứng đủ cho mọi nhu cầu thường ngày của tôi. Các sinh viên của tôi\ntrên toàn thế giới giờ đã có bộ sách này trong tay.\nSố tiền bản quyền đầu tiên tôi nhận được từ tiền bán sách là 850 đôla. Khi tôi\nmở chiếc phong bì mới được chuyển đến, “cái tôi khác” nói với tôi rằng:\n“Giới hạn duy nhất của bạn do chính bạn tạo ra!”\n\n“Giới hạn duy nhất của bạn do chính bạn tạo ra!”\n\nLiệu câu nói này có đúng với bạn như đúng với tôi không? Trong rất nhiều\nlần, tôi chính là kẻ thù tồi tệ nhất của bản thân mình và thu mình lại một\ncách không cần thiết chỉ vì thiếu tự tin. Napoleon Hill muốn tất cả chúng ta\nkhám phá ra “cái tôi khác” để có thể vươn tới tiềm năng lớn nhất trong mỗi\nngười.\nTôi không dám chắc rằng mình thực sự hiểu “cái tôi khác” là gì nhưng tôi\nbiết rằng những người đã tìm thấy nó, tin tưởng vào nó sẽ không bao giờ thất\nbại hoàn toàn.\nSau hôm Ngài Pelton tới Philadelphia gặp tôi, “cái tôi khác” đã cho tôi một ý\ntưởng để giải quyết vấn đề tài chính trước mắt. Tôi chợt lóe lên một ý tưởng\nrằng các phương pháp kinh doanh ô tô phải có sự thay đổi mạnh mẽ và\nnhững người bán ô tô trong tương lai nên học cách bán ô tô thay vì chỉ là\nnhững người đi mua lại và đổi những chiếc ô tô đã qua sử dụng - như phần\nlớn những người kinh doanh ô tô đang làm vào thời điểm đó.\nTôi còn xuất hiện ý nghĩ rằng những người trẻ tuổi vừa mới tốt nghiệp và cả\nnhững người chưa biết gì về những mánh lới cũ của ngành kinh doanh ô tô\nnày sẽ là những “nguyên liệu” dễ nhào nặn nhất để tạo nên thế hệ nhân viên\nbán xe mới.\nÝ tưởng đó rõ ràng và ấn tượng đến mức tôi đã lập tức gọi điện thoại đường\ndài cho Giám đốc kinh doanh của hãng General Motors\n[17]\nvà giải thích\nngắn gọn về kế hoạch của tôi với ông ấy. Ông quá ấn tượng với kế hoạch đó\nvà liền giới thiệu tôi đến chi nhánh Tây Philadelphia của Hãng Ô tô Buick -\ncông ty này thuộc quyền sở hữu của Earl Powell và do ông quản lý. Tôi đến\ngặp ông Powell và giải thích kế hoạch của mình với ông. Ông giữ tôi lại để\n\nhuấn luyện 15 sinh viên vừa mới tốt nghiệp và đã được chọn lọc kỹ càng, họ\nchính là những người thực hiện kế hoạch của tôi.\nThu nhập từ công việc ấy thừa đủ để giúp tôi trang trải tất cả chi phí trong ba\ntháng sau đó, cho đến khi tôi nhận được lợi tức từ việc bán sách, trong đó\ngồm cả chi phí cho dãy phòng đắt đỏ tôi đã thuê mà lúc đầu tôi đã rất lo lắng\nkhông biết lấy tiền ở đâu ra để trả.\n“Cái tôi khác” trong tôi đã không làm tôi thất vọng. Tôi đã có số tiền mình\ncần vào đúng thời điểm, như thể tôi có thể đoán trước chuyện đó vậy. Đến\nlúc này tôi đã hoàn toàn tin tưởng rằng chuyến đi tới Philadelphia của mình\nkhông thể nào là một nhiệm vụ ngớ ngẩn được, vì lý trí của tôi đã nói với tôi\nrằng mọi chuyện sẽ như thế trước khi tôi rời Tây Virginia.\nTừ lúc đó cho tới ngay giây phút này, mọi thứ tôi cần đều đến với tôi dù cả\nthế giới đang trải qua thời kỳ suy thoái về kinh tế\n[18]\nvà không phải ai cũng\nđược đáp ứng những nhu cầu tối thiểu nhất của cuộc sống. Dù đôi khi những\nthứ mang tính “vật chất” mà tôi cần đến hơi muộn một chút nhưng thành thật\nmà nói, “cái tôi khác” luôn gặp tôi ở ngã tư và chỉ cho tôi biết mình nên đi\ncon đường nào.\n“Cái tôi khác” không tuân theo bất cứ tiền lệ nào, nó cũng không có bất kỳ\ngiới hạn nào và luôn tìm được cách đi đến cuối con đường. Có thể nó sẽ gặp\nnhững thất bại tạm thời chứ không bao giờ hoàn toàn thất bại. Tôi có thể\nkhẳng định điều đó chắc chắn như việc tôi đang viết những dòng chữ này\nvậy.\n“Cái tôi khác” có thể “gặp những thất bại tạm thời chứ không bao giờ\n\nhoàn toàn thất bại.”\n\nĐã bao nhiêu lần chúng ta để những thất bại tạm thời ảnh hưởng đến mình\nnhư thể chúng ta đã hoàn toàn thất bại, thay vì học từ thất bại đó và đứng dậy\nđi tiếp? Như Napoleon Hill đã nói trong cuốn sách, trong suốt cuộc hành\ntrình của mình, ông đã phải lùi bước rất nhiều lần nhưng mỗi lần như thế,\nông đều tìm được “hạt mầm” của những lợi ích lớn hơn và tiếp tục đi tới\nnhững thành công lớn hơn.\nTôi cũng đồng thời hy vọng rằng một số nhà triệu phú đang bị tổn thương\n\nbởi nền kinh tế suy thoái và những chuyện không mấy dễ chịu khác sẽ khám\nphá ra thực thể kỳ lạ này bên trong con người họ - thực thể mà tôi vẫn gọi là\n“cái tôi khác” và khám phá đó sẽ dẫn đường chỉ lối cho họ như nó đã dẫn\nđường chỉ lối cho tôi đến gần hơn với sức mạnh có thể giúp họ vượt qua\nnhững trở ngại và làm chủ mọi khó khăn, thay vì để chúng chế ngự mình. Có\nmột sức mạnh vĩ đại trong “cái tôi khác” đang chờ bạn khám phá. Hãy tìm\nkiếm nó thật chân thành và rồi bạn sẽ thấy nó.\nCông trình của Napoleon Hill được xuất bản trong thời kỳ Đại Suy thoái và\ntrên thực tế, nó đã giúp hàng triệu người tìm thấy niềm hy vọng và lòng dũng\ncảm để sống với niềm tin rằng họ sẽ tìm thấy con đường dẫn đến thành công\ncủa riêng mình. Tôi tin rằng chúng ta có thể thấy có rất nhiều nét tương đồng\ngiữa thời kỳ của ông và thời kỳ của chúng ta hiện nay. Đó là những giai đoạn\nđầy căng thẳng và chúng ta phải tìm thấy ý chí và sức mạnh nội tại bên trong\nmình. Với tình hình kinh tế bất ổn hiện nay, mọi người đang lựa chọn - hay\nbuộc phải lựa chọn - để tìm ra những con đường mới cho bản thân cũng như\ncho gia đình mình và rất nhiều người đã đạt được những thành công vĩ đại.\nHọ sẽ trở thành nhân vật chính trong những câu chuyện vĩ đại về thành công\nmà chúng ta sẽ được đọc trong vài năm nữa. Liệu chính bạn có được góp mặt\ntrong những câu chuyện ấy hay chỉ là một nhân vật phụ ở bên lề câu chuyện\nmà thôi?\n\nTrong cái rủi có cái may\n\nTôi đã có thêm một khám phá nữa, đó là kết quả của sự khai tâm “cái tôi\nkhác” trong tôi, rằng mọi vấn đề dù khó khăn đến đâu cũng đều có cách giải\nquyết.\n“Mọi vấn đề dù khó khăn đến đâu cũng đều có cách giải quyết.”\nKhi đang ở tâm bão, bạn sẽ rất khó nhận thấy điều này, tuy nhiên khi sự\nviệc đã qua rồi, bạn sẽ thấy điều đó luôn đúng.\nTôi cũng khám phá ra rằng trong mỗi thất bại tạm thời, mỗi sai lầm hay mỗi\nnghịch cảnh, luôn có một hạt mầm lợi ích tương đương.\nNhưng các bạn nên lưu ý rằng, tôi không nói đến “bông hoa” thành công\ntrọn vẹn, viên mãn mà là “hạt giống” - nơi từ đó bông hoa kia sẽ nảy mầm và\nsinh sôi nảy nở. Tôi biết nguyên tắc này không có ngoại lệ nào hết. Có thể\n\nkhông phải lúc nào bạn cũng trông thấy hạt giống mà tôi nói nhưng bạn có\nthể chắc chắn rằng nó luôn ở đó, dưới dạng thức này hay dạng thức khác mà\nthôi.\nTôi không làm ra vẻ rằng mình hiểu hết về tất cả những nguồn lực kỳ lạ đã\nkhiến tôi rơi vào tình trạng nghèo khó và thiếu thốn, lấp đầy bản thân mình\nbằng nỗi sợ hãi và sau đó lại cho tôi một cuộc sống mới ngập tràn niềm tin\nmà thông qua đó, tôi lại có đặc quyền để giúp đỡ thêm 10.000 người khác\nđang trượt ngã. Nhưng tôi biết rằng có một sức mạnh nào đó đã đến với cuộc\nđời tôi và tôi đang làm mọi thứ có thể để giúp những người khác cũng có thể\n“giao tiếp” với nó.\nTrong suốt một phần tư thế kỷ nghiên cứu về nguyên nhân dẫn đến thành\ncông và thất bại của con người, tôi đã khám phá ra rất nhiều nguyên tắc thật\nsự hữu ích với tôi và những người khác. Nhưng điều gây ấn tượng nhất với\ntôi lại là mọi nhà lãnh đạo xuất sắc nhất tôi từng nghiên cứu đều có lúc bị\nbao vây bởi đầy rẫy khó khăn và gặp phải những thất bại tạm thời trước khi\n“cán đích”.\n“Mọi nhà lãnh đạo xuất sắc nhất tôi từng nghiên cứu đều có lúc bị bao\nvây bởi đầy rẫy khó khăn và gặp phải những thất bại tạm thời trước khi\n\n‘cán đích’.”\n\nSai lầm và thất bại tạm thời là một phần trong hành trình kiếm tìm\nthành công thực sự.\nTừ Chúa Giê-su cho tới Edison, những người đạt được thành công vĩ đại\nnhất chính là những người đã đối mặt với nhiều dạng thất bại tạm thời khó\nchịu nhất. Dường như điều đó là minh chứng cho kết luận rằng Thượng đế\nđã có một kế hoạch, hay một quy luật nào đó đẩy con người phải vượt qua\nnhiều trở ngại trước khi cho họ quyền lãnh đạo hay đạt được thành công\ntrong cuộc sống.\nTôi không hề mong muốn phải trải nghiệm lại cảm giác mình từng có trong\nđêm Giáng sinh định mệnh năm 1923 ấy, khi tôi đi dạo quanh ngôi trường ở\nTây Virginia và tham gia vào cuộc chiến đấu chống lại nỗi sợ hãi, nhưng tôi\ncũng không đánh đổi kiến thức mà mình có được từ những trải nghiệm ấy\nlấy bất cứ thứ của cải nào trên thế gian này.\n\nVới tôi, niềm tin bắt đầu có ý nghĩa mới\n\nTôi phải nhắc lại rằng tôi không biết chính xác “cái tôi khác” này là gì,\nnhưng tôi biết về nó đủ để hoàn toàn tin cậy vào nó trong những thời điểm\nkhó khăn - khi khía cạnh lý trí thông thường trong tôi dường như không thể\ngiúp tôi vượt qua khó khăn.\nCuộc suy thoái kinh tế bắt đầu vào năm 1929 đã khiến hàng triệu người trở\nnên khổ sở, nhưng chúng ta cũng đừng quên rằng chính nó cũng mang đến\nrất nhiều điều may mắn, ít nhất là nó giúp chúng ta nhận ra rằng bị ép không\nlàm việc còn tệ hơn việc bị ép phải làm việc rất nhiều. Nếu phân tích theo\nkhía cạnh cuộc suy thoái đã thay đổi được bao nhiêu con người thì có vẻ\ncuộc suy thoái kinh tế này vẫn là một điều may mắn hơn là một lời nguyền\nđáng sợ. Điều tương tự cũng đúng với mọi trải nghiệm khiến thói quen của\ncon người thay đổi và buộc họ phải chuyển hướng sang “cái tôi khác” vĩ đại\nđể giải quyết vấn đề của mình.\n“Bị ép không làm việc còn tệ hơn việc bị ép phải làm việc rất nhiều. Nếu\nphân tích theo khía cạnh cuộc suy thoái đã thay đổi được bao nhiêu con\nngười thì cuộc suy thoái kinh tế này vẫn là một điều may mắn hơn là một\n\nlời nguyền đáng sợ.”\n\nLiệu Napoleon Hill có quá khắt khe khi viết như vậy không hay ông chỉ\nnhìn xa hơn hậu quả trước mắt của khủng hoảng kinh tế? Liệu những\nkhó khăn trong nền kinh tế của chúng ta hiện nay có thể là một điều\nmay mắn được không? Liệu những thử thách về kinh tế - như bị mất\nviệc chẳng hạn - có thể được gọi là “trong cái rủi có cái may”? Nếu nó\nđánh thức được tinh thần kinh doanh và sự sáng tạo ra những ngành\nnghề kinh doanh mới thì có thể câu trả lời sẽ là “Đúng”.\nThời gian tôi lẩn tránh ở Tây Virgina chắc chắn là sự trừng phạt nghiêm\nkhắc nhất trong cuộc đời tôi nhưng chính trải nghiệm đó đã mang lại cho tôi\nnhững điều may mắn xuất hiện dưới dạng những kiến thức cần thiết và\nchúng còn hơn cả sự đền bù cho những đau khổ mà tôi phải trả. Để có kiến\nthức, tôi buộc phải trải nghiệm, đó là điều không thể tránh được. Quy luật về\nsự bù trừ mà Emerson đã định nghĩa rất rõ ràng khiến kết quả này vừa hợp lẽ\ntự nhiên lại vừa cần thiết.\nRalph Waldo Emerson đã giải thích về quy luật bù trừ bằng những\n\nthuật ngữ rất rõ ràng: “Bạn sẽ luôn gặt hái được gì đó từ những thứ bạn\nmất và bạn cũng sẽ luôn mất đi thứ gì đó cho những thứ bạn đạt được.”\nTrong tạp chí chuyên đề ngày mùng 8 tháng Một năm 1826 của mình,\nông còn viết rằng: “Tất cả những gì chúng ta biết là một hệ thống bù\ntrừ. Khuyết điểm của người này sẽ được bù trừ ở người khác. Mọi đau\nkhổ đều được bù đắp, mọi hy sinh sẽ được đền đáp, mọi món nợ đều sẽ\nđược trả.”\nTôi không có cách nào biết được trong tương lai tôi sẽ thất vọng bởi các thất\nbại tạm thời như thế nào. Tuy nhiên, tôi biết rằng không gì có thể khiến tôi\ntổn thương sâu sắc như những chuyện xảy ra trong quá khứ vì ít nhất thì giờ\ntôi đang thay mặt cho cả “cái tôi khác” của mình nữa.\nVì “cái tôi khác” này đang điều khiển tôi nên tôi đã có kiến thức khả dụng\nmà tôi tin chắc rằng tôi sẽ không bao giờ khám phá ra nếu thực thể sợ hãi\ntrước kia của tôi còn đang chiếm ưu thế. Và tôi đã học được một điều rằng:\nMột người có thể vượt qua được những khó khăn tưởng như không thể vượt\nqua nếu họ quên chúng đi một thời gian và giúp đỡ những người gặp phải\nnhững khó khăn lớn hơn.\n\nGiá trị của việc Cho đi trước khi Nhận lại\n\nTôi chắc rằng mọi nỗ lực của chúng ta nhằm giúp đỡ những người đang gặp\nkhó khăn đều được đền đáp xứng đáng. Không phải lúc nào sự đền đáp ấy\ncũng đến từ những người chúng ta trực tiếp giúp đỡ, nhưng nó sẽ đến, theo\ncách này hoặc cách khác. Động cơ duy nhất truyền cảm hứng để tôi viết\ncuốn sách này là tôi chân thành mong muốn được giúp đỡ những người khác\nbằng cách chia sẻ với họ thật nhiều để giúp họ chuẩn bị chấp nhận vận may\nkỳ diệu như nó đã đến với tôi khi tôi khám phá ra “cái tôi khác” của mình.\nThật may là vận may này không thể đo đếm được bằng bất cứ thuật ngữ nào\nliên quan đến vật chất hay tiền bạc, bởi nó tuyệt vời hơn mọi thứ thuộc phạm\ntrù vật chất hay tiền bạc.\nNhững vận may liên quan đến vật chất hay tiền bạc, nói theo cách dễ hiểu\nnhất, được tính bằng số dư trong tài khoản ngân hàng. Số dư trong tài khoản\nngân hàng của bạn không thể lớn hơn số tiền trong cả ngân hàng đó được.\nCòn vận may mà tôi đang nói đến kia lại được đo đếm không chỉ bởi sự bình\nyên và mãn nguyện mà còn lớn hơn thế rất nhiều - như thể nó tập hợp sức\nmạnh của mọi lời cầu nguyện vậy.\n\n“Cái tôi khác” đã dạy tôi phải tập trung vào mục đích của mình và quên đi kế\nhoạch làm sao để đạt được nó trong lúc cầu nguyện. Ý tôi không phải là\nchúng ta có thể đạt được các mục tiêu về vật chất mà chẳng cần có bất cứ kế\nhoạch nào hết. Điều tôi muốn nói là sức mạnh có khả năng biến ý nghĩ hay\nước muốn của một người thành hiện thực bắt nguồn từ Trí tuệ Vô hạn\n[19]\n-\nthế lực biết rõ hơn về kế hoạch của người cầu nguyện hơn chính người đang\ncầu nguyện.\nChúng ta có thể nói về trường hợp này theo một cách khác, dù rằng nó có vẻ\nkhông được khôn ngoan cho lắm, rằng khi cầu nguyện, hãy tin tưởng và giao\nkế hoạch phù hợp nhất để đạt được mục tiêu của lời cầu nguyện cho Đại\ntrí\n[20]\n. Những trải nghiệm của tôi trong việc cầu nguyện thường xuyên dạy\ntôi rằng tất cả những kết quả từ việc cầu nguyện là một kế hoạch (trong\ntrường hợp lời cầu nguyện được đáp lại), một kế hoạch thích hợp nhất cho\nviệc đạt được mục tiêu của lời cầu nguyện thông qua các phương tiện tự\nnhiên và hữu hình. Kế hoạch đó phải được thực hiện thông qua sự tự nỗ lực\ncủa bản thân mỗi người.\nTôi chưa từng thấy bất cứ lời cầu nguyện nào mang lại hiệu quả với một tâm\ntrí được trang trí bằng màu sắc của nỗi sợ hãi, dù là nhạt nhất.\nLiệu cầu nguyện có phải là một phần cuộc sống của bạn không? Bạn có\n“tin tưởng và giao kế hoạch phù hợp nhất để đạt được mục tiêu của lời\ncầu nguyện cho Đại trí”? Bạn có thừa nhận rằng nếu muốn thành công\nthì bạn phải bắt tay vào hành động hay không?\nCách cầu nguyện mới\n\nTừ khi quen với “cái tôi khác” trong mình, cách cầu nguyện của tôi đã thay\nđổi so với thời gian trước đó. Trước kia tôi chỉ cầu nguyện khi đối mặt với\nkhó khăn, thách thức. Còn giờ thì bất cứ khi nào có thể, tôi đều cầu nguyện,\ntrước khi khó khăn kịp đến với tôi. Và giờ tôi không cầu xin có thêm tài sản\nhay gặp thêm nhiều điều may mắn nữa mà tôi biết ơn vì những gì mình đã\ncó. Và tôi nhận ra rằng cách cầu nguyện này tốt hơn so với cách trước đây\ntôi từng thực hiện.\nDường như Trí tuệ Vô hạn cũng không mấy khó chịu khi tôi nói lời cảm ơn\n\nvà thể hiện lòng biết ơn của mình vì những may mắn tôi được ban tặng. Lần\nđầu tiên thực hành cầu nguyện theo cách thể hiện lòng biết ơn vì những gì\nmình đã có, tôi đã vô cùng ngạc nhiên khi nhận ra mình đã sở hữu những tài\nsản vô cùng lớn mà chưa từng cảm thấy biết ơn vì điều đó.\nChẳng hạn như, tôi nhận ra rằng mình sở hữu một cơ thể khỏe mạnh chưa\ntừng ốm đau nặng bao giờ. Tôi có một trí tuệ được cân bằng bởi lý trí. Tôi có\ntrí tưởng tượng sáng tạo có thể giúp tôi làm nhiều việc có ích cho rất nhiều\nngười. Tôi vô cùng may mắn khi được tự do cả về thể xác lẫn tinh thần. Tôi\ncó một khao khát bất diệt được giúp đỡ những người kém may mắn hơn\nmình.\nTôi nhận ra tôi đã đạt được mục tiêu lớn nhất của con người - hạnh phúc, dù\nnền kinh tế suy thoái hay không suy thoái.\nCuối cùng, nhưng tất nhiên đó không phải là phát hiện ít giá trị nhất, tôi nhận\nra rằng tôi có đặc quyền được tiếp cận với Trí tuệ Vô hạn, hoặc với mục đích\nbiết ơn vì những gì tôi đã có, hoặc để xin được có được nhiều chỉ dẫn hơn.\nMỗi độc giả của cuốn sách này cần kiểm kê lại những tài sản không thể nhìn\nthấy được của mình. Một lần kiểm kê như thế có thể giúp bạn có cơ hội sở\nhữu những tài sản vô giá.', '2026-02-28 07:38:03'),
	(6, 6, 1, 'ĐỂ QUYỂN SÁCH NÀY MANG ĐẾN KẾT QUẢ  TỐT NHẤT', '1. Một yêu cầu rất quan trọng để bạn đạt được hiệu quả\ncao nhất từ quyển sách này là: Một khao khát mãnh liệt, một\nquyết tâm mạnh mẽ muốn thay đổi, muốn cải thiện khả năng\nđối nhân xử thế và hoàn thiện chính mình.\nĐể có được một khát khao mãnh liệt như vậy, hãy nghĩ\nrằng việc hiểu biết và vận dụng thành công những nguyên tắc\nnày sẽ giúp bạn có một cuộc sống giàu có về tinh thần lẫn vật\nchất, có được thành công và hạnh phúc hơn. Bạn cũng có thể tự\nlặp đi lặp lại rằng: “Uy tín, giá trị và hạnh phúc của tôi phần lớn tùy\nthuộc vào khả năng ứng xử của tôi với mọi người xung quanh”.\n2. Bạn nên đọc nhanh toàn bộ quyển sách để có được cái\nnhìn tổng quát về nội dung chính. Sau đó, bạn đọc lại thật kỹ\ntừng chương. Về lâu dài, điều này sẽ tiết kiệm được thời gian,\n\n21\n\ngiúp bạn có được sự thay đổi lớn trong nội tâm và thu được\nnhững kết quả mỹ mãn.\n3. Trong khi đọc, bạn nên dừng lại suy ngẫm về điều vừa\nđọc, tự hỏi xem bằng cách nào và khi nào thì có thể ứng dụng\ntừng gợi ý thiết thực đó.\n4. Hãy chuẩn bị sẵn bút màu, bút chì, bút mực, thước hay\nmột vật gì có thể dùng để đánh dấu. Khi bạn tìm thấy một ý\ntưởng mà bạn nghĩ là có thể ứng dụng ngay được, hãy tô màu,\ngạch dưới hay đánh dấu theo cách riêng của bạn, hoặc dán một\nmảnh giấy nhỏ làm dấu. Điều này sẽ giúp cho việc đọc sách trở\nnên thú vị hơn. Ngoài ra, khi cần đọc lại, bạn sẽ nhanh chóng\ntìm thấy những điểm cần quan tâm một cách dễ dàng hơn.\n5. Tôi có quen biết một giám đốc hành chính của một\ncông ty bảo hiểm. Tất cả các hợp đồng bảo hiểm phát hành\nhàng tháng bà đọc qua đều giống hệt nhau. Thế nhưng cứ hết\ntháng này sang tháng khác, suốt mười lăm năm đương chức, bà\nấy đã đọc không sót một hợp đồng nào. Tại sao thế? Bởi vì kinh\nnghiệm đã dạy cho bà biết rằng, đây là cách tốt nhất để bà luôn\nnhớ được rõ ràng những điều khoản trong đầu.\nTôi đã từng mất gần hai năm ròng rã để viết một quyển\nsách về cách diễn thuyết trước công chúng nhưng thỉnh thoảng\ntôi vẫn phải đọc lại để nhớ những gì chính tôi đã viết trong\nquyển sách của mình.\nVì vậy, nếu muốn có được lợi ích thực sự lâu dài từ quyển\nsách này, tôi đề nghị bạn nên đọc đi đọc lại nhiều lần. Sau khi\n\n22\nHOW TO WIN FRIENDS & INFLUENCE PEOPLE\n\nđọc thật kỹ lưỡng, mỗi tháng bạn nên dành một vài giờ để xem\nlại quyển sách và đặt nó ở vị trí dễ nhìn thấy nhất trên bàn làm\nviệc của mình. Hãy luôn nhớ rằng việc ứng dụng những nguyên\ntắc đã học chỉ có thể trở thành thói quen một khi chúng ta có\nmột kế hoạch thực hành, ứng dụng, có ghi nhận và điều chỉnh\nthật sát sao và liên tục\n6. Học một ý tưởng, cách thức mới là một quá trình tích\ncực và chủ động. Chúng ta cần phải học bằng thực hành. Cho\nnên, nếu muốn làm chủ các nguyên tắc trong quyển sách này thì\nbạn cần phải thực hành. Bạn hãy tận dụng mọi cơ hội để ứng\ndụng những điều đã học được. Nếu không làm thế bạn sẽ nhanh\nchóng quên đi. Chỉ những kiến thức được ứng dụng mới được\nkhắc ghi thật sự vào trong trí nhớ.\nTuy nhiên, tôi biết không phải lúc nào cũng có thể dễ dàng\nứng dụng những nguyên tắc này. Tôi biết rõ điều đó bởi vì chính\ntôi vẫn thường thấy khó ứng dụng những điều mà tôi đã biết\nvào cuộc sống hàng ngày như tôi đã từng dự định. Ví dụ, khi\nbạn không hài lòng với ai thì bạn thường có khuynh hướng phê\nphán và chỉ trích hơn là tìm cách hiểu hoàn cảnh và quan điểm\ncủa người ấy. Thường thì tìm thấy sai lầm dễ dàng hơn tìm thấy\nđiều đáng để khen ngợi và nói về điều bạn muốn dễ dàng hơn\nlà nói về điều người khác muốn, v.v. Cho nên, khi đọc quyển\nsách này, ngoài việc tìm kiếm những ý tưởng, thông tin mới,\nbạn còn cần tìm cách tạo nên những thói quen mới, thực hiện\nmột cách sống, cách ứng xử và suy nghĩ mới. Điều này đòi hỏi\nthời gian và phải có sự quyết tâm, kiên trì tập luyện hàng ngày.\n\n23\n\nĐ Ắ C N H Â N T Â M\n\nNhư vậy, nếu bạn thường xuyên đọc đi đọc lại quyển sách\nnày và xem đó như một cẩm nang về cách cải thiện những mối\nquan hệ với con người và xã hội, quyển sách sẽ rất hữu ích cho\nbạn. Mỗi lúc bạn đối diện với một vấn đề phức tạp - như mắc\nmột lỗi lầm trong ứng xử, bị một đồng nghiệp hay một người\nbạn hiểu sai, khi cần đối xử với một đứa bé ngỗ nghịch, hòa giải\nnhững bất đồng trong đời sống gia đình hay phải làm hài lòng\nmột khách hàng đang bực bội - thì bạn nên ứng dụng linh động\nnhững nguyên tắc đó. Tôi nghĩ rằng chắc chắn chúng sẽ đem lại\nnhững kết quả kỳ diệu cho bạn.\n7. Bạn có thể đề nghị một người bạn hay người thân quan\nsát mình và có thể tặng người đó một món quà nhỏ mỗi lần\nngười ấy bắt gặp bạn vi phạm một nguyên tắc ứng xử nào đó.\nHãy biến việc thực hành những nguyên tắc này thành một trò\nchơi sinh động, thú vị.\n8. Có lần, chủ tịch một ngân hàng nổi tiếng ở Wall Street\nnói về hệ thống câu hỏi tự kiểm tra rất hiệu quả mà ông dùng\nđể tự điều chỉnh cách ứng xử của mình. Mặc dù trình độ học\nvấn không cao nhưng ông đã trở thành một trong những nhà tài\nchính uy tín nhất ở Mỹ. Ông thú nhận rằng, hầu hết mọi thành\ncông mà ông có được đều là nhờ thường xuyên ứng dụng\nphương pháp đó. Dưới đây là nguyên văn lời tâm sự của ông:\n“Đã bao năm qua tôi giữ một quyển sổ ghi chép mọi cuộc hẹn\nmà tôi phải thực hiện trong tuần. Gia đình tôi không bao giờ có kế\nhoạch nào cho tôi vào buổi tối thứ bảy vì họ biết tôi luôn dành thời\n\n24\nHOW TO WIN FRIENDS & INFLUENCE PEOPLE\n\ngian này cho cho quá trình “khai sáng”, tự kiểm điểm và nhìn nhận\nlại bản thân mình. Sau khi ăn, tôi mở quyển lịch hẹn và suy nghĩ về\nmọi cuộc phỏng vấn, thảo luận và gặp gỡ đã diễn ra trong tuần và tự\nhỏi mình:\n“Tôi đã phạm những sai lầm gì?”\n“Tôi làm được điều gì đúng và tôi có thể hoàn thiện hơn việc đó\nbằng cách nào?”\n“ Tôi học được những bài học gì từ kinh nghiệm này?”\nTôi luôn cảm thấy rất khó chịu trong những lần tự kiểm hàng\ntuần đó và thường rất ngạc nhiên trước những lỗi lầm hay sơ xuất ngu\nxuẩn của mình. Tuy nhiên, theo ngày tháng, những lầm lỗi này đã\ndần dần ít hẳn đi. Đôi khi, tôi cũng có dịp tự khen thưởng mình khi\nkhông nhận thấy lỗi lầm nào. Cách tự phân tích và kiên định tự giáo\ndục mình liên tục từ năm này sang năm khác đã giúp ích cho tôi\nnhiều hơn bất cứ điều gì khác. Nó không chỉ giúp tôi nâng cao khả\nnăng ra quyết định hiệu quả mà còn giúp tôi rất nhiều trong mọi mối\ngiao tiếp. Tôi không thể có lời khuyên nào tốt hơn thế”.\nBạn cũng có thể dùng một hệ thống câu hỏi tương tự để\nkiểm tra cách ứng dụng những nguyên tắc được đề cập trong\nquyển sách này. Làm như vậy bạn sẽ có hai điều lợi. Thứ nhất,\nbạn sẽ thấy mình tham dự vào một quá trình tự rèn luyện, tự\nhọc hỏi, tuy vất vả nhưng rất có ý nghĩa và có giá trị lâu dài với\nbản thân. Thứ hai, bạn sẽ thấy khả năng ứng xử của mình với\nmọi người sẽ ngày càng hoàn thiện.\n\n25\n\nĐ Ắ C N H Â N T Â M\n\n9. Bạn có thể dùng một cuốn sổ nhỏ để ghi lại diễn tiến\nnhững hiệu quả mà bạn đã ứng dụng từ quyển sách này. Bạn\nhãy ghi thật kỹ, cụ thể tên người, thời điểm và kết quả. Làm\nnhư thế sẽ thôi thúc bạn cố gắng hơn nữa, những ghi chú này\nsẽ trở thành những kỷ niệm rất thú vị khi bạn ngẫu nhiên đọc\nlại nó trong một buổi tối thảnh thơi nào đó ở nhiều năm sau...\nTóm lại, để đạt được hiệu quả tốt nhất từ quyển sách này,\nbạn nên:\nPhát triển niềm khao khát sâu sắc và mạnh mẽ là sẽ làm\nchủ cho bằng được những nguyên tắc kỳ diệu về cách ứng\nxử trong mối quan hệ giữa người với người.\nĐọc nhanh để nắm tổng quát và sau đó đọc từng\nchương thật kỹ trước khi đọc chương tiếp theo.\nKhi đọc, bạn nên thường xuyên dừng lại để chiêm\nnghiệm và tự hỏi xem làm thế nào để có thể ứng dụng\ntừng nguyên tắc vào cuộc sống hàng ngày của mình.\nGạch dưới mỗi ý tưởng hay và quan trọng.\nĐọc lại quyển sách này vào thời gian rảnh mỗi tháng.\nTận dụng mọi cơ hội để ứng dụng những nguyên tắc\nnày. Hãy dùng quyển sách như một cẩm nang giúp bạn\ngiải quyết những vấn đề hàng ngày.\nTạo nên một trò chơi thú vị cho việc thực tập của mình\nbằng cách tặng một người thân nào đó một món quà nhỏ\n\n26\nHOW TO WIN FRIENDS & INFLUENCE PEOPLE\n\nmỗi khi người ấy bắt gặp bạn vi phạm một trong những\nnguyên tắc.\nMỗi tuần hãy kiểm tra lại những tiến bộ mà bạn đạt\nđược. Tự hỏi xem mình đã phạm những sai lầm gì, đạt\nđược những tiến bộ gì, rút ra được những bài học gì cho\ntương lai.\nGhi lại thời gian và cách thức cụ thể mà bạn đã ứng\ndụng những nguyên tắc này vào cuốn sổ nhỏ.', '2026-02-28 07:45:15'),
	(7, 6, 2, '“MUỐN LẤY MẬT THÌ ĐỪNG PHÁ TỔ ONG”', 'Ngày 07 tháng 05 năm 1931.\nTiếng huyên náo và tiếng chân chạy rầm rập trên đường\nphố New York. Cảnh sát đang rượt đuổi một tên tội phạm nguy\nhiểm. Cuối cùng, sau rất nhiều nỗ lực và quyết tâm, cảnh sát đã\ntóm được Crowley “Hai Súng”, một tên giết người hàng loạt,\nngay tại nơi mà hắn không ngờ đến: nhà người yêu của hắn trên\nđại lộ West End.\nMột trăm năm mươi cảnh sát và mật vụ bao vây tòa nhà\ncao nhất, nơi hắn ẩn náu. Họ chọc thủng mái nhà, phun khói\n\n31\n\nvà bố trí cả súng máy tại các cửa sổ của những cao ốc xung\nquanh. Âm thanh chát chúa của những tràng súng máy và súng\nngắn vang lên liên tục trong hơn một giờ đồng hồ. Bên trong\ncăn phòng ở tầng cao nhất ấy, Crowley ẩn người sau những\nchiếc ghế bành độn bông dày, quyết liệt chống trả lực lượng\ncảnh sát bằng những tràng súng liên thanh. Nhưng cuối cùng,\ntên tội phạm có tài thiện xạ này cũng phải đầu hàng.\nCảnh sát trưởng New York, ông E. P. Mulrooney nhấn\nmạnh rằng tên Crowley “Hai Súng” là một trong những tên tội\nphạm nguy hiểm và tàn ác nhất trong lịch sử tội phạm ở thành\nphố đông dân nhất nước Mỹ này. Một điểm rất đáng lưu ý về\ncon người Crowley là: “Chỉ một lý do cỏn con, thậm chí không cần\ncó lý do nào, hoặc đơn giản để giải sầu, hắn cũng có thể chĩa súng vào\nngười khác và bóp cò”. Tuy nhiên, đó là suy nghĩ của cảnh sát.\nRiêng tên tội phạm máu lạnh này lại không nghĩ như thế. Khi\nbên ngoài cảnh sát tìm mọi cách để bắt hắn thì trong phòng,\nCrowley đang viết một bức thư. Bức thư còn dính vệt máu đỏ.\nVà, đây là những gì Crowley đã viết: “Dưới lớp áo này là một trái\ntim mệt mỏi nhưng dịu dàng – một trái tim không hề làm tổn thương\nai”. Đọc những dòng này, ai chẳng thấy lòng mình xúc động\nnhưng sự thật thì lại trái ngược với những gì hắn viết. Chỉ vài giờ\ntrước đó, Crowley đã nã súng vào một cảnh sát giao thông khi\nanh ấy chặn xe hắn để kiểm tra bằng lái. Khi viên cảnh sát ngã\ngục xuống, Crowley đã nhảy ra khỏi xe, chộp khẩu súng ngắn\ncủa nạn nhân và lạnh lùng bồi thêm một phát nữa vào thân\nhình đang run rẩy hấp hối. Crowley bị kết án tử hình. Trên ghế\n\n32\nHOW TO WIN FRIENDS & INFLUENCE PEOPLE\n\nđiện ở nhà tù Sing Sing, hắn còn ngụy biện rằng: “Phải chăng\nđây là sự trừng phạt mà tôi phải chịu vì đã giết người? Không! Đây\nlà sự trừng phạt mà tôi phải chịu chỉ vì tôi cần tự bảo vệ mình”.\nThật kỳ lạ là một kẻ thủ ác rõ ràng như vậy lại không chịu\nnhìn nhận tội lỗi của mình.\nTôi có trao đổi thư từ qua lại với Lewis Lawes, viên cai ngục\nnhà tù Sing Sing (là nơi giam giữ những tên tội phạm nguy hiểm\nnhất ở New York). Lewis Lawes tâm sự: “Rất hiếm phạm nhân ở\nSing Sing tự xem mình là người xấu. Họ nghĩ họ cũng là những con\nngười bình thường như anh và tôi. Họ có thể kể cho anh nghe tại sao\nhọ phá một két sắt hay nhanh tay bấm cò súng. Hầu hết bọn họ đều\ntìm cách đưa ra những lý lẽ dối trá để bào chữa cho những hành vi\nphạm pháp và vô lương tâm của mình. Họ kiên quyết cho rằng không\ncó lý do gì để bỏ tù họ cả”.\nNếu như Al Capone(3), “Hai Súng” và những tay anh chị\nthuộc các băng đảng xã hội đen không bao giờ thừa nhận tội\nác tày trời của mình thì liệu những con người bình thường có\ndễ dàng tự nhìn nhận những sai lầm hết sức đời thường của\nmình không?\nJohn Wanamaker, người sáng lập chuỗi cửa hàng bán lẻ\nmang tên ông, từng thừa nhận rằng: “Cách đây ba mươi năm, tôi\nhiểu rằng mắng nhiếc người khác là ngu ngốc. Tôi đã gặp nhiều rắc\nrối tưởng như không thể chịu đựng trước khi hiểu được một sự thật\nhiển nhiên là Thượng đế trao cho mỗi người một đặc điểm riêng,\n\n33\n\nĐ Ắ C N H Â N T Â M\n\n(3) Al Capone: Trùm tội phạm khét tiếng của Mỹ đầu thế kỷ 20.\n\nkhông ai giống ai. Và, chính vì vậy, tôi không thể đòi hỏi mọi người\nhành xử giống nhau và mọi người đều biết tự phê phán mình khi họ\nlàm một điều gì đó không tốt”.\nQuả là Wanamaker tài ba đã sớm rút ra được bài học đó\ntrong khi tôi phải mất cả một phần ba thế kỷ mày mò tìm kiếm\nmới bắt đầu hiểu ra rằng có đến 99% trong chúng ta không bao\ngiờ tự phê phán mình vì bất cứ điều gì, cho dù chúng ta có sai\nlầm đến đâu đi nữa.\nChỉ trích là vô bổ, nó chỉ gây ra thái độ chống đối và bào\nchữa. Chỉ trích còn có thể trở nên nguy hiểm vì nó chạm vào\nlòng kiêu hãnh cố chấp của con người, gây tổn thương tới ý thức\nvề tầm quan trọng của họ và kết cuộc chỉ tạo nên sự tức giận,\ncăm thù. Chỉ trích còn gây phản ứng chối bỏ trách nhiệm, đồng\nthời phát sinh tâm lý chán nản và nhụt chí trong khi lỗi lầm vẫn\nkhông được giải quyết.\nB. F. Skinner, nhà tâm lý học nổi tiếng thế giới đã chứng\nminh qua thực nghiệm rằng một con thú nuôi được khen vì\nhành vi tốt sẽ học nhanh và nhớ tốt hơn một con thú bị trừng\nphạt vì hành vi xấu. Những công trình nghiên cứu gần đây cho\nthấy phát hiện này cũng đúng với con người.\nNhà tâm lý học lỗi lạc Hans Selye cho biết: “Nỗi sợ bị lên\nán ở con người cũng lớn như việc khao khát được tán thưởng”. George\nB. Johnston ở Enid, Oklahoma, là người phụ trách về an toàn\nlao động cho công nhân trong một công ty thiết kế. Trách nhiệm\nquan trọng của ông là làm sao cho các công nhân đội nón bảo\n\n34\nHOW TO WIN FRIENDS & INFLUENCE PEOPLE\n\nhộ mỗi khi họ làm việc ở công trường. Ông kể lại rằng, mỗi khi\nbắt gặp công nhân không đội nón bảo hộ, ông thường dùng\nquyền lực ép buộc họ phải tuân theo quy định. Họ miễn cưỡng\nchấp nhận. Thế nhưng ngay khi ông quay lưng, họ lại cất nón\nđi. Sau khóa huấn luyện tại trung tâm chúng tôi, ông quyết định\nthử một cách tiếp cận khác. Khi thấy một vài công nhân không\nđội nón bảo hộ, ông hỏi họ phải chăng chiếc nón không thích\nhợp hay có điều gì đó không ổn. Sau đó ông nhắc rằng khi làm\nviệc họ nên đội nón bảo hộ để khỏi bị tổn thương hay gặp nguy\nhiểm khi có sự cố ngoài ý muốn xảy ra. Kết quả là số công nhân\nchấp nhận đội nón đã tăng lên mà không có sự phản đối hay\nthái độ khó chịu nào nảy sinh.\nCó thể dễ dàng tìm thấy vô số thất bại do tính cách hay\nphê phán chỉ trích của con người trong suốt chiều dài lịch sử\ncủa mọi dân tộc. Bản chất con người là thế. Những kẻ gây ác, chê\ntrách người khác không bao giờ tự chê trách và nhìn lại mình.\nVà, những lời chỉ trích giống như chim bồ câu đưa thư, bao giờ\ncũng quay trở về nơi xuất phát. Có một điều rất nguy hiểm là\nnhững người mà ta chỉ trích, lên án, chắc chắn đều sẽ tìm lý lẽ\ntự biện hộ cho mình và kết án ngược lại chúng ta.\nVào buổi sáng ngày 15 tháng 4 năm 1865, Tổng thống\nAbraham Lincoln bị John Wilkes Booth ám sát trong căn phòng\ncủa một nhà trọ bình dân đối diện với con đường đi từ nhà hát\nFord. Nhìn Lincoln bằng ánh mắt kính trọng lẫn tiếc thương sâu\nsắc, Bộ trưởng Quốc phòng Stanton thốt lên: “Đây là nhà lãnh\nđạo tuyệt vời nhất của thế giới tự cổ chí kim”.\n35\n\nĐ Ắ C N H Â N T Â M\n\nBí quyết nào đã tạo nên những thành công của Lincoln\ntrong vai trò lãnh đạo như thế? Theo tôi, chính cách ông đối xử\nvới mọi người đã giúp ông nhận được những tình cảm đặc biệt\nvà lòng tin yêu hết mình của họ. Tuy nhiên, tính cách đó không\nphải do trời phú mà chính là do ông rèn luyện mà có.\nÍt ai biết rằng trước đây, anh chàng Lincoln khi còn ở thung\nlũng Pigeon Creek bang Indiana không chỉ thích chỉ trích cay\nnghiệt mà còn thường viết những bức thư và bài thơ chế nhạo\nngười khác rồi rải ra đường cho mọi người cùng đọc. Cũng ít ai\nbiết rằng, luật sư xuất sắc Lincoln ở Springfield, bang Illinois, rất\nhay phê phán công khai đối thủ của mình bằng các bài viết đăng\ntrên những tạp chí địa phương. Sự kiêu ngạo và ngông cuồng đó\ncó thể sẽ còn kéo dài hơn nữa, nếu như không có một ngày...\nĐó là một ngày mùa thu năm 1842, chàng trai trẻ hiếu\nthắng đã chế giễu một chính khách kiêu ngạo tên là James Shields\nbằng một bài viết không ký tên đăng trên tạp chí Springfield. Cả\nthành phố cười nhạo James. Thế là, James sục sôi căm phẫn.\nBằng mọi giá, ông ta phải tìm cho ra kẻ viết bài báo nọ. Ông phi\nngựa đuổi theo Lincoln và ném găng thách Lincoln đấu kiếm vì\ndanh dự. Lincoln không thích đấu kiếm, thậm chí ông đã từng\nđấu tranh chống lại hủ tục này, nhưng trong hoàn cảnh đó, ông\nkhông thể tránh né nếu muốn bảo toàn danh dự. Lincoln được\nphép chọn vũ khí. Vì có cánh tay rất dài nên ông chọn thanh\ntrường kiếm của kỵ binh và học đấu kiếm cấp tốc từ một người\nbạn tốt nghiệp trường West Point. Đến hẹn, ông và James ra một\nbãi cát bên sông Mississippi. May mắn thay, vào phút cuối,\n\n36\nHOW TO WIN FRIENDS & INFLUENCE PEOPLE\n\nnhững người giúp việc của họ đã giúp cả hai cái đầu đang hừng\nhực sát khí hiểu ra mọi việc và chấm dứt được cuộc đọ kiếm một\nmất một còn.\nChỉ đến khi đối diện với ranh giới giữa sự sống và cái chết\ncủa chính mình và người khác Lincoln mới thấy trải nghiệm đó\nkhủng khiếp như thế nào. Cuộc đấu kiếm chết người bất thành\nđó đã dạy ông một bài học vô giá về cách cư xử với người khác.\nTừ đó trở đi, Lincoln không bao giờ viết thư lăng mạ bất kỳ ai,\nkhông bao giờ chế nhạo ai và gần như không bao giờ chỉ trích\nai về bất cứ điều gì nữa.\nTrong suốt cuộc nội chiến ở Mỹ, Lincoln đã từng đề cử các\nviên tướng McClellan, Pope, Burnside, Hooker, Meade cầm đầu\nđạo quân Potomac. Mỗi vị tướng đều từng phạm những sai lầm\nkhủng khiếp khiến cho Lincoln nhiều lần rơi vào tình thế tuyệt\nvọng. Một nửa đất nước kịch liệt lên án những viên tướng bất\ntài này. Chỉ riêng Lincoln luôn tỏ thiện chí và không hề chỉ trích\nbất kỳ ai trong số họ. Một trong những câu ông thường hay nói\nlà: “Chúng ta không nên kết án người khác để chính mình không bị\nkết án”.\nKhi bà Lincoln và nội các của ông lên án gay gắt người dân\nmiền Nam, Lincoln đã khuyên rằng: “Đừng chỉ trích họ. Vì có thể,\nchúng ta cũng sẽ hành xử như thế trong những hoàn cảnh tương tự”.\nCó đôi lần, suýt nữa chính Lincoln cũng lên tiếng chỉ trích\nngười khác. Nhưng ông đã không chỉ trích mặc dù ông hoàn\ntoàn có lý do chính đáng để làm điều đó.\n37\n\nĐ Ắ C N H Â N T Â M\n\nTrận Gettysburg diễn ra trong ba ngày đầu tháng 7 năm\n1863. Đêm 4 tháng 7, tướng Lee, thuộc quân đội miền Nam, bắt\nđầu rút quân về phía Nam trong khi cơn bão mang đến những\ntrận mưa như trút nước. Phía trước ông và đoàn quân bại trận là\ndòng sông Potomac đang thét gào, nước cuồn cuộn sủi bọt trắng\nxóa. Phía sau là một đạo quân liên minh chiến thắng đang rượt\nđuổi. Lee bị kẹt ở giữa và hầu như không còn đường thoát. Từ bộ\nchỉ huy, Lincoln lập tức nhận ra đây là cơ hội vàng để bắt gọn\nđạo quân của tướng Lee và chấm dứt chiến tranh. Thế là, Lincoln\nra lệnh cho tướng Meade ngừng triệu tập hội đồng chiến tranh mà\nlập tức lên đường tấn công Lee. Lincoln đã chuyển lệnh bằng điện\ntín và sau đó còn cử một đặc phái viên đến gặp Meade yêu cầu\nphải hành động ngay lập tức.\nNhưng tướng Meade đã làm gì? Ông ta làm ngược lại lệnh\ncủa tổng thống: triệu tập cuộc họp hội đồng chiến tranh. Không\nchỉ có vậy, ông ta còn do dự kéo dài thời gian, rồi đánh điện tín\ntừ chối mệnh lệnh của Lincoln. Sáng hôm sau nước rút, tướng\nLee vượt sông Potomac với lực lượng toàn vẹn.\nLincoln tức giận điên người, ông gào lên với Robert - con\ntrai mình: “Trời ơi! Cha không thể hiểu nổi! Chúng ta chỉ cần chìa\ntay ra là tóm gọn tất cả. Vậy mà tất cả những gì cha nói và làm đều\nkhông thể khiến cho quân đội tấn công ngay vào kẻ địch. Trong hoàn\ncảnh thuận lợi đó, bất kỳ viên tướng nào cũng có thể đánh bại Lee. Nếu\ncha có ở đó, có lẽ cha đã đánh tướng Meade ngay một trận”.\nTrong nỗi cay đắng và thất vọng tột cùng, Lincoln viết thư\n\n38\nHOW TO WIN FRIENDS & INFLUENCE PEOPLE\n\ncho Meade. Thời kỳ này, Lincoln cực kỳ bảo thủ và rất khó thay đổi\nsuy nghĩ của mình. Chính vì thế bức thư Lincoln viết cho Meade\nvào năm 1863 chứa đầy những lời lẽ trách móc nặng nề nhất:\n“Tướng quân thân mến!\nTôi không tin là ông không nhận ra hiểm họa trong việc để Lee\nchạy thoát vừa rồi. Ông ta gần như đã nằm trọn trong tay chúng ta.\nVà nếu bắt được Lee, cuộc nội chiến này có thể đã kết thúc. Thế mà,\nông đã để vuột mất cơ hội ngàn vàng và cuộc chiến này không biết sẽ\ncòn kéo dài đến bao giờ. Nếu thứ Hai tuần trước ông không thể chiến\nthắng Lee trong những điều kiện thuận lợi như thế thì bây giờ và về\nsau, ông có thể làm gì để tấn công được Lee ở phía Nam con sông,\ntrong khi ông chỉ còn 2/3 lực lượng mà ông đã từng có? Chẳng có lý\ndo gì tôi có thể hy vọng ông xoay chuyển được tình hình. Ông đã hoàn\ntoàn đánh mất cơ hội ngàn năm có một. Tôi không thể diễn tả được\nnỗi thất vọng và tức giận của tôi lúc này đối với ông!”.\nCác bạn nghĩ Meade đã làm gì khi đọc bức thư này?\nMeade đã không làm gì cả vì ông ta không bao giờ được\nđọc bức thư đó! Đơn giản bởi vì Lincoln đã không gửi nó đi.\nNgười ta tìm thấy nó trong những tập hồ sơ của Lincoln sau khi\nông qua đời.\nTheo phỏng đoán của tôi – chỉ là phỏng đoán thôi – sau\nkhi viết bức thư này, Lincoln đã nhìn ra ngoài cửa sổ và nhẹ\nnhàng tự nhủ: “Khoan đã! Có thể mình không nên vội vã như vậy.\nChẳng khó gì khi ta ngồi ở đây trong cảnh bình yên của Nhà Trắng\nđể ra lệnh cho Meade tấn công. Nhưng giả sử ta đang ở Gettysburg\n\n39\n\nĐ Ắ C N H Â N T Â M\n\ntuần vừa rồi, tận mắt nhìn thấy cảnh máu đổ kinh hoàng như Meade\nđã nhìn thấy, tai nghe tiếng la hét kêu gào của những đồng đội đang\nhấp hối như Meade đã nghe, thì có lẽ ta cũng sẽ không còn muốn tấn\ncông nữa. Và hơn nữa, nếu như ta có tính nhút nhát, do dự của\nMeade, có lẽ ta cũng sẽ làm đúng như điều ông ta đã làm. Dẫu sao,\nsự việc đã rồi, nước đã chảy qua cầu. Nếu bức thư này được gửi đi, ta\nsẽ hả giận phần nào nhưng Meade có thể tìm cách tự bào chữa hoặc\nquay lại kết án ta. Điều đó sẽ gây ra những phản ứng tiêu cực, cản\ntrở năng lực của Meade sau này với tư cách là tổng tư lệnh và biết\nđâu, tai hại hơn nữa là vì thế mà ông ta có thể bị buộc phải rời khỏi\nquân đội. Đây là một sai lầm rõ ràng và chắc chắn Meade sẽ tự nhận\nra sau này”.\nCó lẽ chính vì những suy nghĩ như vậy mà Lincoln gạt bức\nthư qua một bên. Ông đã học từ kinh nghiệm cay đắng rằng\nnhững lời phê phán và chỉ trích gay gắt hầu như bao giờ cũng\nmang đến kết quả tiêu cực.\nTheodore Roosevelt kể lại rằng, khi phải đối diện với\nnhững vấn đề rắc rối, ông thường ngả người ra ghế và ngước\nnhìn bức chân dung khổ lớn của Lincoln treo trong phòng làm\nviệc của mình ở Nhà Trắng rồi tự hỏi: “Lincoln sẽ làm gì nếu trong\nhoàn cảnh này? Ông sẽ giải quyết vấn đề như thế nào?”.\nĐại văn hào Mark Twain từng có lần viết thư cho một người\nlàm ông tức điên rằng: “Điều mà anh cần làm lúc này là một giấy\nphép để tự mai táng. Anh chỉ cần thông báo, tôi sẽ lo được ngay”. Một\nlần khác, ông viết thư cho một nhà xuất bản về việc người sửa\n\n40\nHOW TO WIN FRIENDS & INFLUENCE PEOPLE\n\nbản in muốn chỉnh sửa lỗi chính tả và cách chấm câu của ông:\n“Sau này đừng có mà sửa gì trên những tác phẩm của tôi và bảo tay\nsửa bản thảo ấy hãy giữ lại những ý tưởng điên rồ trong cái đầu tệ hại\ncủa hắn cho đến chết đi”. Việc viết những bức thư nặng tính chỉ\ntrích, mỉa mai thậm tệ như thế làm cho Mark Twain cảm thấy dễ\nchịu hơn. Những lời lẽ cay nghiệt đó giúp ông giải tỏa được cơn\ngiận. Nhưng may mắn là chúng không gây thiệt hại gì bởi một\nđiều đơn giản là phu nhân của Mark Twain đã kín đáo giữ tất cả\nchúng lại. Những lá thư đó không bao giờ đến tay người nhận.\nCó người nào bạn đang muốn họ thay đổi và sửa mình để\ntiến bộ hơn không? Tôi hoàn toàn ủng hộ việc này. Nhưng tại\nsao lại không bắt đầu từ bản thân mình? Thay đổi chính mình\nlà một việc có ích và thực tế hơn nhiều so với việc thay đổi người\nkhác và khả năng thành công cũng cao hơn rất nhiều. Khổng Tử\ntừng nói: “Đừng chỉ trích mái nhà hàng xóm nhiều tuyết trong khi\ncửa nhà mình lại không sạch”.\nNếu như bạn muốn bị ai đó oán hờn dai dẳng hàng chục\nnăm trời và thậm chí có khi đến lúc chết bạn vẫn còn bị thù hận\nthì hãy tặng cho người ấy những lời phê phán, chỉ trích cay độc,\ncho dù bạn biết chắc chắn những lời chỉ trích đó là đúng.\nThực ra, con người rất hiếm khi suy xét đúng sai rõ ràng\nbằng lý trí. Con người thường hay hành xử theo cảm xúc, thành\nkiến và nhất là cộng thêm lòng kiêu hãnh vốn có của mình nữa.\nLối chỉ trích gay gắt đã khiến cho Thomas Hardy, một\ntrong những tiểu thuyết gia lừng lẫy của văn học Anh phải vĩnh\n\n41\n\nĐ Ắ C N H Â N T Â M\n\nviễn từ bỏ việc viết tiểu thuyết. Cách phê bình cực đoan cũng\ntừng đẩy Thomas Chatterton, nhà thơ Anh, đến chỗ tự sát.\nBenjamin Franklin, một người thô lỗ khi còn trẻ, đã trở\nthành một nhà ngoại giao tài năng đến mức được chọn làm\nđại sứ Mỹ ở Pháp. Khi được hỏi về bí quyết thành công, ông\nđáp: “Tôi không nói xấu ai mà chỉ nói những điều tốt đẹp tôi được\nbiết về họ”.\nBất cứ người thiếu suy nghĩ nào cũng có thể chỉ trích, oán\ntrách và than phiền người khác. Và hầu hết những người thiếu\nsuy nghĩ đều làm thế. Nhưng phải là người biết tự chủ và có\nmột tâm hồn bao dung, rộng lượng mới có thể hiểu và biết tha\nthứ cho người khác.\nVĩ nhân thường biểu lộ sự vĩ đại của mình trong cách đối\nxử với những con người nhỏ bé. Câu chuyện dưới đây là một\nminh chứng cụ thể.\nBob Hoover là phi công lái máy bay trình diễn nổi tiếng ở\nMỹ. Trong một lần bay thử, khi ông vừa cất cánh và lấy được độ cao\nthì cả hai động cơ của chiếc máy bay đột ngột ngừng hoạt động.\nNhờ kinh nghiệm và tài năng khéo léo, ông đã đưa được máy bay\nđáp xuống đất. Mặc dù không có thiệt hại về nhân mạng nhưng\nchiếc máy bay gần như hư hỏng hoàn toàn. Hành động đầu tiên\ncủa Hoover sau khi đáp khẩn cấp là kiểm tra bình nhiên liệu của\nmáy bay. Đúng như điều ông đã phỏng đoán, bình xăng của chiếc\nmáy bay cánh quạt thời Thế chiến thứ hai đó không hề chứa xăng\n- mà thay vào đó là đầy dầu phản lực. Sở dĩ máy bay khởi động lúc\n\n42\nHOW TO WIN FRIENDS & INFLUENCE PEOPLE\n\nđầu được là nhờ phần xăng còn sót lại trước đó. Khi trở về sân bay,\nngay lập tức ông đi tìm người thợ máy đã phục vụ máy bay của\nông. Anh chàng thợ máy trẻ tuổi đang lo sợ và hối hận đến mức\ngần như cuồng trí. Khi Hoover đến gần, gương mặt thất thần và\nhoảng sợ của anh ta ràn rụa nước mắt. Anh ta biết mình vừa gây\nnên một lỗi lầm không thể tha thứ: làm hỏng một chiếc máy bay\nrất đắt tiền và suýt chút nữa đã giết chết ba mạng người.\nNgười ta có thể tưởng tượng một cơn nổi giận lôi đình và\nnhững lời mắng nhiếc thậm tệ từ người phi công tài ba đầy lòng\nkiêu hãnh sắp sửa trút xuống người thợ máy đó. Nhưng không,\nHoover đã dùng đôi tay to lớn của mình ôm choàng vai người\nthợ máy ấy và nói: “Tôi tin chắc rằng anh sẽ không bao giờ lặp lại\nsai sót này nữa. Để minh chứng cho lòng tin của tôi đối với anh, tôi\nmuốn rằng sáng mai anh tiếp tục chuẩn bị cho chiếc F-51 của tôi”.\nTôi tin rằng bạn có thể hình dung sự xúc động và cảm kích vô\nbờ bến của người thợ máy đối với Hoover sau nghĩa cử bao\ndung đó.\nCha mẹ thường có xu hướng trách mắng con cái. Tuy\nnhiên, trước khi bạn la mắng con mình lần sau, xin hãy đọc bài\n“Cha đã quên”. Bài viết này xuất hiện lần đầu trong tờ báo People’s\nHome Journal.\n“Cha đã quên” là một sáng tác ngắn viết ra trong giây phút\ncảm xúc chân thành, tác động mạnh mẽ vào nhiều độc giả đến\nmức được yêu cầu in lại hàng năm. Ngay sau khi xuất hiện lần\nđầu, bài viết nổi tiếng này đã được đăng trên khắp các tờ báo nước\n\n43\n\nĐ Ắ C N H Â N T Â M\n\nMỹ, được dịch ra nhiều ngôn ngữ khác nhau, được truyền bá rộng\nrãi trong các trường học, nhà thờ, trên các diễn đàn và đã phát\ntrong vô số chương trình truyền thanh, truyền hình. Một điều khá\nthú vị là các tạp chí định kỳ của nhiều trường trung học và cao\nđẳng cũng sử dụng bài viết này. Đôi khi một điều nhỏ bé cũng có\nthể tạo nên những ảnh hưởng lớn lao kỳ diệu. Bài viết này thực\nsự đã tạo nên một phép lạ với những bậc cha mẹ trong gia đình.', '2026-02-28 07:46:34'),
	(8, 7, 1, 'Thôi Miên Cảm Xúc – Bí Mật của Mọi Mối Quan Hệ Thành Công', 'Chỉ mới cách đây vài phút thôi, trong khi bạn mở quyển sách này, hẳn\nlà bạnđang suy nghĩ đến vấn đề nào khác, đúng chứ?\n\nVậy thì ngay bây giờ, bạn đang nghĩ gì nào? Ý tôi là ngay tại giây phút\nnày!\nThôi nào. Bạn nên thành thật với bản thân mình. Hãy làm ơn ngừng\nđọc và trả lời câu hỏi của tôi. Một cách trung thực.\nHẳn là bạn đang bận suy nghĩ về một vấn đề nào khác trước khi đọc\nđến câu hỏi của tôi phải chứ? Chính xác là thế! Luôn có điều gì đó tung\nhoành trong đầu chúng ta, từng giây từng phút một!\nTôi thường đặt câu hỏi, “Bạn đang nghĩ về điều gì?” như một cách để\nbắt đầu bài giảng của mình trong các khóa huấn luyện, các buổi họp nhóm\nvà trò chuyện cá nhân. Và các câu trả lời tôi nhận được thì muôn hình vạn\ntrạng, nhưng điều thú vị nhất chính là phần lớn chúng chả liên quan gì đến\nchủ đề buổi học ngày hôm đó cả!\nTrong một lớp học ca tối ở thành phố New York, một nữ họ viên tóc\nhung hung cao ráo đã trả lời câu hỏi đó như sau: “ Tôi đang nghĩ đến cái\nđèn phòng ngủ ở nhà”. Khi tôi hỏi vì sao, chị ta nói tiếp: “ cái đèn đó đang\nchiếm trọn đầu óc tôi đến nỗi tôi không thể tập trung nghe bài giảng của\nthầy được. Thầy thấy đó, tôi đi tàu điện ngầm đến đây, và khi nhìn thấy cửa\ntàu điện đóng lại, tôi mới sực nhớ ra là mình chưa tắt đèn ngủ trước khi đi.\nÔng xã tôi kĩ tính và tiết kiệm lắm. Ổng mà về nhà thấy cái đèn bật sáng\nchoang trong khi tôi đang đi vắng thế này, ổng sẽ nổi trận lôi đình mất!”\nMột học viên nam mặc com-lê xanh chỉnh tề trả lời rằng: “Sếp tôi\nmuốn tôi phải làm xong một bản báo cáo quan trọng trước bốn giờ chiều\nngày mai. Tôi đang không biết làm thế nào để hoàn thành nó kịp thời hạn\nđây!” Một phụ nữ chừng năm mươi tuổi có vẻ ngoài tròn trịa thì trả lời\n\nrằng: “ Hôm qua tôi có mua một chiếc đầm dạ hội màu xanh lá cây rất đẹp\nđể mặc cho buổi tiệc quan trọng tối nay. Tôi hy vọng là nó không quá\nchật!”\nMột phụ nữ khác chừng ba mươi tuổi chưa chồng thì không giấu nổi\nsự lúng túng. Cô trả lời một cách thành thật rằng cô đang nghĩ về cú điện\nthoại của một bà dì vào tối hôm trước. “Dì ấy muốn làm mai cho tôi với\nông hàng xóm của dì ấy.”\nMột quý ông tóc hoa râm và có giọng nói trầm thì trả lời với vẻ lo lắng\nrằng: “ Tôi sắp đi gặp một anh bạn cũ; anh ta nợ tôi bốn mơi đô-la đã hơn\nmột năm mà vẫn chưa trả. Tôi không biết nên nhắc khéo anh ta thế nào sao\ncho không phải mất lòng nhau!” Trong một buổi học khác, một anh chàng\ntrẻ tuổi tóc hoe, vai ngang và đến từ miền nam đã trả lời tôi rằng: “ Ngồi\ntrong này ngột ngạt quá. Tôi đang nghĩ lẽ ra mình nên rời khỏi đây để đi\nhẹn hò với cô nàng xinh đẹp mà tôi vừa gặp hôm qua, như thế sẽ thú vị hơn\nnhiều.”\nNhiều năm đã trôi qua, tôi đã nghe hằng hà cơ số câu trả lời như thế\ncho câu hỏi “ Bạn đang nghĩ về điều gì ngay lúc này?” từ các học viên của\nmình. Và bạn có ngạc nhiên không khi phần lớn những câu trả lời chẳng ăn\nnhập gì đến bối cảnh lúc đó, hay chủ đề, hay bài giảng mà tôi sắp trình bày\ncho họ?\nKhông. Chả có gì đáng ngạc nhiên cả.\nVề cơ bản, tất cả chúng ta bất kể già trẻ gái trai, đều không ngừng suy\nnghĩ miên man về đủ thứ chuyện trên đời trong cuộc sống hàng ngày: từ\nnhững mối quan tâm, thái độ và nhu cầu cá nhân cho đến những nỗi lo\n\nlắng, thú vui, hy vọng, nỗi sợ những mong muốn và hồi ức khác nhau của\nmỗi người. Còn với những khoảng thời gian còn lại trong ngày, tâm trí\nchúng ta thường trong trạng thái trống rỗng hoặc mù mờ nhằm mục đích\nlàm dịu cảm xúc.\nNhững điều trên cho thấy mọi người hoàn toàn có thể lắng nghe bạn,\nvấn đề chỉ là họ không thích mà thôi.\nHẳn là bạn đã từng ít nhiều trải nghiệm tình huống đại loại thế này:\nMột người nọ nói với bạn rằng, “ Tôi đã bảo anh phải làm như thế này kia\nmà. Bộ anh không nhớ à?” Và bạn trả lời, “Thực lòng là tôi không nhớ\nmình đã nghe anh nói như thế!”\nNgười kia nói thật và bạn cũng chẳng nói dối. Vấn đề chỉ đơn giản là:\nbạn đã không nghe người kia nói gì vì lúc đó, tâm trí bạn đang bận rộn với\nmớ bòng bong những mối lo toan khác. Vì vậy mà bạn đã không nhớ gì cả.\nBạn bắt đầu lo lắng ư? Không cần phải thế.\nViệc kiểm soát những phản ứng của bản thân sao cho người khác phải\nlắng nghe và thuận theo những ngôn từ và hành động của bạn trong mọi\nhoàn cảnh cũng là một nghệ thuật cần phải được học hỏi và rèn luyện chứ\nkhông tự nhiên mà có.\nVì sao ư?\nVì khả năng làm cho người khác phải lắng nghe bạn có thể trở thành\nvốn quý một thứ vũ khí lợi hại giúp bạn gặt hái thành công và làm được\nmọi điều mình muốn trong cuộc sống.\n\nKỹ năng này giúp bạn cải thiện và nâng tầm phong thái, tính cách và\nquyền uy của bản thân trong các cuộc giao tiếp và thuyết phục. Mức độ\nthành công của bạn trong cuộc sống, trong các mối quan hệ cá nhân trong\ncông sở cũng như trong sự nghiệp – thậm chí trong cả sức khỏe của bạn –\nphụ thuộc vào khả năng vận dụng và phát huy nghệ thuật này của bạn trong\nmọi hoàn cảnh như thế nào.\nKỹ năng làm cho người khác phải lắng nghe mình sẽ giúp bạn dễ dàng\nthành công trong mọi việc, hạnh phúc trong tình yêu-hôn nhân và hình\nthành một thái độ sống tích cực.\nMột khi thành thạo nghệ thuật này, bạn cũng sẽ dễ được thăng tiến,\nbiết cách gia tăng doanh thu cho công ty và thu nhập cho bản thân. Mọi\nngười sẽ yêu quý bạn, còn bạn sẽ có một cuộc sống thoải mái và thú vị\nhơn.\nLàm thế nào để bạn làm chủ được kĩ năng tuyệt diệu này?\nBạn có thể làm được điều đó ngay bây giờ!\nBạn nên bắt đầu từ đâu?\nHãy nhớ, đầu óc của tất cả chúng ta luôn bận rộn với những mối bận\ntâm khác nhau, và chúng là những “ông ba bị” đáng ghét đang kìm hãm\ncuộc sống và thành công của chúng ta.\nVì sao chúng ta thất bại trong giao tiếp?\nTrong giao tiếp hàng ngày của con người, cứ 100 từ được thốt lên thì\n99 từ không được lắng nghe...mặc dù khả năng đọc của mọi người đều\nbình thường và như nhau.\n\nLiệu đối phương có thực sự lắng nghe khi chúng ta đang nói?\nThông thường thì đối phương sẽ nhìn thẳng vào mắt chúng ta để nghe\nchúng ta nói – nhưng chúng ta chẳng thể nào biết được họ đang nghĩ gì\ntrong đầu. Họ chỉ cần vô tình hoặc cố tình nghĩ đến dù chỉ là một mối bận\ntâm nào khác ngoài những gì chúng ta nói, tình trạng đàn gảy tai trâu là\nkhó tránh khỏi.\nKhả năng xuyên thủng hàng rào Những mối bận tâm để thâm nhập tâm\ntrí của bất kì ai chính là quyền năng vô song mà chúng ta có thể và nên sở\nhữu để thành công trong cuộc sống.\nMột khi chúng ta biết cách thâm nhập được vào tâm trí của mọi người,\nchúng ta sẽ giao tiếp hiệu quả hơn, kinh doanh thành công hơn, yêu đời\nhơn, hạn chế được nguy cơ tự tử của bản thân và người khác, đánh bại\nđược kẻ cướp, làm cho người khác phải phá lên cười trước mọi câu chuyện\ntếu lâm mình kể, làm cho khán giả phải vỗ tay trước màn trình diễn của\nmình, tận hưởng hạnh phúc trong tình yêu và xử lý được mọi phản ứng\nyêu-ghét của dư luận.\nCách duy nhất để vận dụng hành động hoặc ngôn từ nhằm phá vỡ hàng\nrào Những mối bận tâm của bất kì ai trong bất kỳ tình huống nào chính là\nsử dụng thuật thôi miên cảm xúc.\nThôi Miên Cảm Xúc là gì?\nThôi miên cảm xúc là khả năng thúc đẩy và xui khiến người khác phải\nlắng nghe mình.\nGiao tiếp bằng thuật thôi miên cảm xúc chính là chiếc chìa khóa tối\nthượng của bạn để thành công!\n\nNgày hôm đó, tôi là một trong những hành khách đầu tiên của một\nchiếc xe buýt chạy vào giờ cao điểm. bác tài xế Tom nhận ra tôi.\n“Lại thêm một đêm tôi thở dài ngao ngán vì không biết làm thế nào để\nyêu cầu hành khách dạt ra hai bên rìa xe buýt và chừa lối đi ở giữa cho\nngười mới lên xe” – bác Tom chán nản – “ Tôi đã thuyết phục họ đến khản\ncổ suốt hơn mười lăm năm lái xe nhưng chẳng ai nghe!”\nNghe đến đây, tôi cười thầm trong bụng, đề nghị bác tài xế đăng kí\nmột khóa huấn luyện thôi miên cảm xúc cho tôi đứng lớp.\nMột tuần sau đó, chính tôi cũng phải ngạc nhiên trước sự tiến bộ của\nbác Tom trong việc lĩnh hội thuật thôi miên cảm xúc mà tôi giảng dạy.\nBác Tom là học viên có thái độ học tập nghiêm túc nhất trong khóa\nhọc. Bác không chỉ áp dụng thuật thôi miên cảm xúc trong công việc, trong\ncuộc sống hàng ngày và các mối quan hệ, mà còn sử dụng thành thạo kỹ\nthuật này trong những tình huống khó khăn hoặc nan giải.\nHai tháng trôi qua. Trong một buổi tối nọ, tôi lại có cơ hội được ngồi\nchiếc xe buýt của bác Tom.\n“Muốn biết tôi làm thế nào để khiến bà con phải dạt ra hai bên rìa xe\nchứ?” – bác cười khi nhìn thấy tôi.\nHiển nhiên là tôi muốn biết.\nVới một nụ cười ấm áp, bác Tom nói lời chào một cách thân thiện và\nniềm nở với mọi hành khách lên xe.\n\nVà trong khi hành khách cứ mải mê lấp đầy khoang trước và lối đi\ngiữa của xe buýt vì những mối bận tâm xa xăm trong đầu họ, bác tài xế\nquay đầu lại. Bằng một giọng nói trầm ấm, bác yêu cầu hành khách:\n“ Hai bên rìa xe buýt còn rất nhiều chỗ trống, mọi người hãy ngồi ở đó\ncho thoải mái nhé, những người bạn của tôi!”\nCác hành khách đều nghe thấy và di chuyển ngay lập tức!\nLà con người, chúng ta giao tiếp với nhau bằng ngôn từ và hành động.\nKhi được lồng ghép trong ngôn từ hoặc hành động của chúng ta, thuật\nthôi miên cảm xúc có thể làm nên nhiều điều kì diệu. Nó có thể dẫn đến\nmột cuộc hôn nhan hạnh phúc, hàn gắn một mối quan hệ đổ vỡ, khởi đầu\nmột chiến dịch bán hàng hiệu quả, bắt đầu một cuộc tranh luận bổ ích, hoặc\ngiúp bác tài xử lí thành công một vấn đề nan giải!\nQuyền năng vô song của bạn\nBettty sở hữ đôi mắt long lanh, gương mặt xinh đẹp, thân hình hấp dẫn\nnhư hoa hậu và một ông bố giàu sụ. Cô ấy cùng bốn người bạn gái khác\ncủa mình đang thi nhau xem ai sẽ cưa đổ được anh chàng nọ tên Jim. Cả\nBetty lẫn bốn cô nàng còn lại đều tham gia cuộc thi này với thái độ nghiêm\ntúc và sự nỗ lực thật sự.\nẤy vậy mà cuối cùng Jim chọn kết hôn với Ophelia, cô nàng học kém\nnhất, ngực phẳng nhất, đi dép thấp nhất và gia cảnh khiêm tốn nhất.\nCả Betty và mấy cô nàng kia đều khóc thét lên sững sờ: “ Cô ta có gì\nhay ho hơn bọn tôi?”\n\nCác cô gái tội nghiệp không nhận ra rằng một gương mặt đẹp hay một\nthân hình bốc lửa đúng là có thể thu hút cánh mày râu ngay từ cái nhìn đầu\ntiên, nhưng việc anh ta có sóng đôi cùng bạn hay không lại phụ thuộc vào\nkhả năng thôi miên cảm xúc của những cuộc nói chuyện và hành động sau\nđó. Để có thể nên vợ nên chồng, đàn ông và phụ nữ phải giao tiếp được với\nnhau. Những gì nàng nói với chàng và những gì chàng tỉ tê với nàng – kết\nhợp với những hành động và phản hồi cảm xúc thích hợp – mới chính là\nđiều kiện tiên quyết dẫn đến quyết định kết hôn giữa hai người.\nOphelia có quyền không xinh đẹp, không thông minh và không có “\nnhà mặt phố, bố làm to”, vì những điều đó chẳng cần thiết.\nBí kíp chiến thắng của cô ấy chính là thuật thôi miên cảm xúc: cô ấy\nthâm nhập được vào tâm trí không ngừng bận rộn của Jim. Cô ấy không chỉ\nnói cho Jim biết những điều mà mình muốn nói, mà cô còn chia sẻ với anh\nnhững điều anh muốn nghe. Bằng cách làm cho Jim muốn lắng nghe mình,\ncô đã dần dần khiến anh muốn quan tâm chăm sóc...cho chính cô ấy. Jim\nthậm chí còn phóng về nhà hét to đầy tự hào rằng: “ Mẹ ơi, Ophelia thật\nkhác biệt so với những cô gái khác!”\nBetty, Ophelia và ba cô gái kia đều tham gia một cuộc thi. Nhưng hãy\nnhớ, mọi cuộc thi thố trong cuộc sống này – đặc biệt là trong hôn nhân đại\nsự - đều có chung một đích đến duy nhất là thâm nhập thành công vào tâm\ntrí con người!\nSự nghiệp, kinh doanh, dịch vụ và các vấn đề của con người cũng\ntương tự. Để trở thành người chiến thắng, bạn cần trang bị cho mình một\nquyền năng vô song – chính là thuật thôi miên cảm xúc của bạn – để bắn\n\nphá những mối bận tâm trong tâm trí mọi người nhằm gây dựng lợi thế\ncạnh tranh.\nĐó chính là bí kíp để đắc nhân tâm và thu phục lòng người, mà việc\nOphelia “cưa đổ” được Jim là một ví dụ.\nThi thoảng trong cuộc sống, bạn có thể bắt gặp những đối tượng khó\nchinh phục – những người có đầu óc Bận Rộn đến nỗi việc phá tan những\nmối lo toan của họ gần như là điệp vụ bất khả thi. Kỳ thực, với thuật thôi\nmiên cảm xúc, không gì là không thể.\nCó một người phụ nữ chừng 45 tuổi diện quần áo trông rất thời trang\nđang trèo lên thành một cây cầu với ý định tự tử. Chỉ trong chốc lát, cảnh\nsát và hàng trăm người hiếu kỳ bao vây khu vực quanh cầu. Suốt hai mươi\nphút căng thẳng, viên cảnh sát cùng những người dân xung quanh liên tục\ngào thét :” Đừng nhảy!”\nNhưng người phụ nữ nọ vẫn đứng trên thành cầu khóc lóc và kêu than\nrằng mình bị chồng bỏ và lũ trẻ không còn nghe lời cô nữa. Cô không còn\ngì để mất.\nCô ấy cởi áo khoác và chuẩn bị nhảy. Khi đó, viên cảnh sát nọ bỗng\ndưng yêu cầu đám động yên lặng. Ông lấy tay bịt mồm bịt mũi mình và nói\nvới người phụ nữ đó:” Bà muốn nhảy thì cứ việc. Nhưng tôi nói trước là ở\ndưới đó nướ sông hôi hám bẩn thỉu lẵm đó!”\nNgay sau câu nói ấy của viên cảnh sát, người phụ nữ bất ngờ ngoan\nngoãn bước xuống và chạy đến viên cảnh sát. Cụm từ “ nước sông hôi hám\nbẩn thỉu” đã phát huy tác dụng.\n\nNhững cụm từ đơn giản đó có quyền năng gì mà lại đánh bại được\nhàng trăm lời cầu khẩn gào thét của các cảnh sát và đám dông trong việc\nthuyết phục người phụ nữ ấy không tự tử nữa? Câu trả lơi: Chúng có khả\nnăng thôi miên cảm xúc đối với bà ta. Chúng khiến bà ta lắng nghe. Và khi\nbà ấy lắng nghe, nghĩa là chúng ta đã vượt qua được những mối bận tâm\nkhác trong tâm trí người phụ nữ ấy khiến bà ta đổi ý!\nVậy thì cụm từ “ nước dưới sông hôi hám bẩn thỉu” đó có thể tác dụng\nvới một người đàn ông hay một người phụ nữ khác trong một tình huống\nkhác tương tự hay không? “Có” hoặc “Không” – câu trả lời tùy thuộc vào\nmô thức cảm xúc của người trong cuộc.\nMỗi người trong chúng ta sở hữu mô thức cảm xúc với độ mãnh liệt\nkhác nhau. Tuy nhiên, khi phân nhóm các mô thức cảm xúc này, chúng ta\nsẽ có được những phản ứng gần như công thức đối với sự thôi miên cảm\nxúc nhất định. Thôi miên cảm xúc có quyền năng vô song trong việc thu\nhút sự chú ý và khiến cho người trong cuộc thay đổi quyết định, nên nó có\nthể được áp dụng trong bất kì hoàn cảnh, tình huống, sản phẩm, hay dịch\nvụ nào; khi đó, phản ứng được tạo ra gần như ngay lập tức.\nThậm chí, sự ngay lập tức này mang tính sống còn.\nVào nửa đêm mùa đông nọ, đó là lần đầu tiên mà cặp vợ chồng trẻ kia\ngây gổ đến mức độ trầm trọng. Anh chồng không chịu phụ vợ rửa bát đĩa,\ntrong khi cô vợ liên tục thúc ép anh ta phải làm.Sau vài lời qua tiếng lại, họ\nbắt đầu la hét, mắng chửi và đe dọa nhau, thậm chí đập bàn đập ghế loạn xạ\ntrong nhà. Tiếng ồn không chỉ bất ngờ đánh thức đứa con tám tháng tuổi\ncủa hai người đang say giấc ở phòng bên, mà còn đánh động cả hàng xóm\n\nxung quanh trong tòa nhà chung cư, khiến một người trong số họ gọi điện\nbáo cảnh sát. Cô vợ ra mở cửa và để cho cảnh sát vào nhà.\nMấy người hàng xóm cũng hiếu kì kéo đến xem vụ việc. Thấy cảnh sát\nvà đám đông ập đến, người chồng bắt đầu hoảng sợ. Anh ta phóng vào\nphòng ngủ của con và bế xốc đứa bé bằng một tay. Trước mặt đám đông,\nanh ta từng bước di chuyển về phía sau và dùng tay còn lại để mở cửa sổ.\nKhi cánh cửa sổ được kéo lên và gió lùa vào, anh ta cảnh báo đám\nđông, “ Nếu các người tiến thêm một bước, tôi sẽ ném đứa bé này ra cửa\nsổ!”\nCảnh sát và đám đông biết rằng anh ta sẽ làm thật. Họ dừng bước.\nNgười vợ lo sợ tột độ. Đôi mắt cô chăm chú nhìn đứa bé bỏng như thể\nmuốn trổ ra khỏi đầu.\nĐúng lúc ấy, một bé trai chừng 12 tuổi bất ngờ bước vào hiện trường\nvà nói rằng, “ Chú ném con mình qua cửa sổ đã là độc ác lắm rồi, chú định\nđể mặc em bé bị cảm lạnh nữa sao?”\nanh chồng bỗng rơm rớm nước mắt nhìn con mình. Sau đó anh ta đóng cửa\nsổ, giao lại đứa bé cho cô vợ và cúi đầu nhận lỗi. Trong trường hợp này,\nhình ảnh em bé sơ sinh bị cảm lạnh gây ra một phản ứng xúc cảm nơi\nngười cha, khiến anh ta dừng ngay hành động đang làm.\nNhờ vậy mà một vụ xung đột nan giải đã được giả quyết êm thấm!\nChuyện xảy ra có phải do hai vợ chồng có vấn đề về tâm lý hoặc tâm\nthần không? Không hề. Họ chỉ đang bực dọc, bị điều khiển bởi những cảm\nxúc tiêu cực. Nguyên nhân của mâu thuẫn là do họ đã phản ứng một cách\n\nquá cảm tính và bản năng đối với những kích thích đến từ lời nói và hành\nđộng của người kia.\nMâu thuẫn tương tự hoàn toàn có thể xảy ra với bạn hay tôi – nếu\nchúng ta không làm chủ cảm xúc và để sự bực dọc lấn lướt.\nHãy nhớ: Cứ mỗi ngày hay mỗi giờ trôi qua, tất cả chúng ta đều và\nđang thực hiện vô số những phản ứng xúc cảm khác nhau để phản hồi\nnhững lời nói và hành động của người khác. Nhiều người trong chúng ta\nchỉ đơn giản là không kiểm soát được giới hạn của những cuộc cãi vã xung\nđột với những ai khiêu khích mình, khiến cho mâu thuẫn chẳng những\nkhông được hòa giải mà còn trở nên trầm trọng hơn.\nKhoảng 97% trong số chúng ta có một cuộc sống tương đối “ bình\nlặng” do không phải rơi vào những tình huống căng thẳng gây kích thích\ncảm xúc. Một người bình thường vốn quen chăn ấm nệm êm như thế nếu\nrơi vào những tình huống ngàn cân treo sợi tóc, chẳng hạn như bị dồn đến\nđường cùng đến mức tự tử, túng quá làm liều, hoặc các tệ nạn xã hội, người\nđó sẽ rất dễ tổn thương và trượt dài theo những cái bẫy đó. Khi mà những\nhoàn cảnh, số phận hoặc thời điểm trùng hợp ngẫu nhiên đó hợp lực với\nnhau để kích thích cảm xúc của một người đến mức báo động, nạn nhân sẽ\nbuộc lòng có những phản ứng nhất định mang tính cảm xúc và bản năng\nđối phó hoặc tự vệ.\nBạn nghĩ lại xem, có bao nhiêu lần trong ngày mà chúng ta gặp gỡ\nnhau – dù vô tình hay hữu ý, ở trường hay trên xe buýt, giờ làm việc hay\ngiờ giải lao – mà không có một tí phản ứng hay ấn tượng gì? Và trong một\nkhoảnh khắc bất chợt, một tình huống ngoài dự kiến và khơi dậy ấn tượng\ntrong bạn: một nụ cười của ai đó, sự nhất trí hoặc phê bình của đồng\n\nnghiệp, hoặc một cái nhíu mày của cấp trên. Ngay cả những phản ứng xúc\ncảm nhỏ nhoi thế thôi cũng đủ sức khiến bạn yêu thương thân thiện hay ác\ncảm với một người nào đó.\nCuộc sống có rất nhiều trường hợp mà trong đó, một anh chàng và cô\nnàng quen biết nhau, chơi thân với nhau Tử nhở đến lớn suốt nhiều năm\ntrời nhưng chưa bao giò có suy nghĩ rằng mình sẽ nên vợ nên chồng. Vậy\nmà, chỉ trong một khoảnh khắc bất chợt nào đó, người này vô tình nói với\nngười kia một câu nhận xét mà người kia chết mê chết mệt. Ping! Lần đầu\ntiên trong đời họ chạm được vào trái tim của nhau và thế là tèng téng teng\n– tình yêu bắt đầu nảy nở.\nNhững anh chàng và cô nàng đó là ai vậy?họ chỉ là những con người\nrất bình thường... là những sinh vật muôn đời chịu sự chi phối của cảm\nxúc và bản năng. Nhưng nếu các bạn cảm xúc bị kích thích vượt quá giới\nhạn an toàn...họ có thể dần dần hình thành những phản ứng tiêu cực chẳng\nhạn như tự tử - gioongs như người phụ nữ trên thành cầu nọ, hoặc dọa ném\ncon ra cửa sổ - như anh chồng trong ví dụ tôi vừa chia sẻ ở trên.\nVà những điều đó hoàn toàn có thể xảy đến với bạn.\nĐây chính là lí do vì sao việc học cách kiểm soát, hiểu thấu những\nđộng cơ và phản ứng xúc cảm của chính mình quan trọng đến dường nào.\nĐây cũng chính là lí do vì sao quyền năng làm chủ cảm xúc – của chính\nbạn cũng như người khác – chính là chiếc chìa khóa quyết định sự thành\ncông và hạnh phúc của mỗi người. Và cuối cùng, nó là lý do vì sao mà\nthuật thôi miên cảm xúc cần phải được giảng dạy, ứng dụng và chia sẻ cho\ncàng nhiều người càng tốt.\n\nTrong một mối quan hệ bất kỳ, dù là giữa vợ chồng với nhau, giữa\nngười bán hàng và khách mua hàng, giữa bác sĩ và bệnh nhân, giữa mẹ và\ncon, thôi miên cảm xúc hiện hữ ở mọi tình huống.\nMẹ của bé Sue 5 tuổi đang rất cáu. Chẳng là cô bé vừa nghịch phá đến\nnỗi làm vỡ một chiếc lọ hoa màu xanh ngọc đắt tiền. “ Con có biết là cái\nbình hoa đó bằng mấy chục tháng tiền lương của ba mẹ ko?” – bà mẹ bắt\nđâu fđay nghiến. “ Không được lại gần đó.” – bà ấy chống tay lên hông.\n“Sue, đi mở ngăn kéo lấy cho mẹ cái thắt lưng của ba con. Mẹ phải đánh\nđòn con thì con mới chừa.” – bà mẹ quát mắng. “ Mẹ sẽ làm mông con\nsưng đỏ càng lâu càng tốt, để Tử rày về sau con phải luôn nhớ lời mẹ và\nkhông được làm vỡ đồ đạc trong nhà nữa. Đi mau. Lấy cho mẹ cái thắt\nlưng!”\nCô bé hoảng dợ chạy đi.\nLát sau, Sue trở lại với một cây búa.\n“Mẹ ơi” – cô bé khóc – “ Mẹ có thể đánh con bằng cái này được\nkhông?”\nBà mẹ nhìn cây búa và nhìn vào đôi mắt của đứa con gái bé bỏng rồi\nngoảnh mặt đi. Người phụ nữ ấy nghẹn ngào giọng nói: “ Sue, về phòng đi\ncon và nhớ đừng làm vỡ đồ đạc nữa nhé!”\nHình ảnh cây búa đã khơi gợi lại phản ứng xúc cảm nơi người mẹ,\nkhiến bà cảm thấy có lỗi vì ý định đánh con mình bằng thắt lưng dù hành\nđộng đó chưa xảy ra.\nMột tình huống nhỏ nhưng đủ sức thay đổi trạng thái cảm xúc của bà\nmẹ chỉ trong phút chốc!\n\nKinh doanh bán hàng cũng là những tình huống giao tiếp tương tự.\nKhông cảm xúc, miễn bán buôn!\nBốn cửa hàng nội y trong cùng một dãy phố đều bày bán những chiếc\náo ngủ có kiểu dáng tương tự nhau. Một trong số bốn cửa hàng trưng bày\nhai bộ áo ngủ với giá mỗi áo là “3,95$ - giá gốc 5$”. Mặc dù cửa hàng này\ncó vị trí, địa thế thuận lợi nhất trong bốn cửa hàng và người qua lại đều\nnhìn thấy hai chiếc áo ngủ đó, nhưng suốt hơn ba tuần vẫn không thấy ai\nmua. Chủ cửa hàng quyết định thực hiện một chút thay đổi. Thay vì để lại\ngiá gốc như trước, thẻ ghi giá trên mỗi áo chỉ ghi độc một con số “3,95$”.\nNgoài ra, hai chiếc áo còn được trưng bày kèn với hai bảng chú thích nhỏ:\nmột chiếc áo “ Dành cho Thiên Thần” và chiếc còn lại “ Dành cho Kẻ Tội\nNhân”.\nChỉ trong vòng ba ngày, cả hai dòng áo ngủ đó được bán sạch, đến nỗi\nchủ cửa hàng phải đặt thêm mới có đủ áo để bán. Gần như mọi khách hàng\nbước chân vào cửa hàng đều mua một trong hai chiếc áo đó – hoặc cả hai –\nvì không muốn người bán hàng đoán già đoán non mình là “Thiên Thần”\nhay “Kẻ Tội Nhân”.\nCon người thích mua sắm nhưng lại ghét bị dụ dỗ chèo kéo, nên bạn\ncó hàng tá cơ hội để áp dụng thuật thôi miên cảm xúc hiệu quả nhất chính\nlà tên của bạn!\nMột bà nội trợ tìm kiếm dịch vụ bọc nệm ghế sofa vì muốn thay lại\ntoàn bộ bọc ghế trong nhà. Cô tham khảo rất nhiều mẩu quảng cáo và danh\nbạ điện thoại. Có hơn mười nhà cung cấp dịch vụ bọc nệm ghế đã liên lạc\nvới cô. Cả mười hãng đua ra giá cả dịch vụ, chất liệu vải bọc và tiện ích\nvận chuyển tương đương nhau. Bà nội trợ nọ cũng có đủ danh thiếp của cả\n\nmười nhà cung cấp dịch vụ. Nhưng một danh thiếp trong số đó đã gây ấn\ntượng đặc biệt với cô:” Danh thiếp này sẽ giúp cô nhớ đến tôi – và nó sẽ\nkhiến cô phá lên cười! Cô thấy đó, tên tôi là ‘Wolf’. Wolf chỉ là tên, chứ\nkhông phải bản chất của tôi!” Đúng thật là cả hai vợ chồng bà nội trợ nọ\nđều cười toe toét khi đọc tấm danh thiếp này.\nVài ngày sau, trong khi cô vợ vẫn còn đắn đo suy nghĩ xem mình nên\nchọn nhà cung cấp nào, cô nhớ ngay đến ‘Wolf’ và gọi anh ta. Anh chàng\nnày đã thành công trong việc xuyên thủng những mối bận tâm khác của bà\nnội trợ nọ, khiến cô chú ý và nhớ đến mình trong tâm trí.\nWolf đã bán hàng thành công... đến nỗi chồng cô đó cũng phải nhớ\nđến tên anh!\nNgôn từ là những đứa trẻ tinh nghịch và khôn ngoan. Ngay khi chúng\nvừa rời khỏi mồm miệng chúng ta, chúng đứng qua một bên để xem những\ngì diễn ra tiếp theo. Chúng không bao giờ ra về tay không, vì chắc chắn sẽ\nluôn có một điều gì đó xảy ra với một ai đó sau khi lời nói được thốt ra. Ai\nđó trong trường hợp này chính là Người Nghe, tức đối phương hay đối\ntượng giao tiếp của chúng ta. Người này hoặc sẽ tiếp tục lo ra và không chú\ný vì ngôn từ chúng ta thiếu sức hút, hoặc sẽ chăm chăm lắng nghe chúng ta\nđến Từng câu Từng chữ nếu như sự thôi miên cảm xúc trong ngôn từ của\nchúng ta quá mạnh mẽ và đầy thuyết phục!\nMột anh chàng nọ bay Tử Philadelphia đến West Coast trong một\nchuyến công tác. Trong lịch trình của mình, anh ta dành nửa ngày ghé qua\nLas Vegas, Nevada để được tham quan sòng bạc và để có dịp về nhà “\nchém gió” với bạn bè người thân mình vừa được đi đánh bạc ở khu phố ăn\n\nchơi nổi tiếng đất nước Mỹ. Vì quỹ công tác có hạn, nên anh ta tự quy định\nvới mình rằng chỉ được đánh bạc mười đo-la mà thôi.\nTại sòng bạc Las Vegas, anh đổi một tờ tiền năm đô-la của mình thành\nnăm đồng bạc. Anh đặt năm đồng bạc vào tay phải, và mười lăm đồng bạc\nvào tay trái. Anh tham gia vào một bàn chơi bài, trong đầu tự nhắc nhở\nmình không được cược quá năm đô-la kiểu “ được ăn cả, ngã về không!”\nĐể chắc chắn rằng mình sẽ không vung tay quá trán, anh bỏ hết mười lăm\nđồng bạc tương đương mười lăm đô-la vào túi áo.\nNgười chia bài là một phụ nữ trung niên có nhiệm vụ coi sóc Tử sáu\nđến bảy tay chơi. Nhìn thấy anh chàng người Philadenphia nọ đang bước\nđến, bà ấy nhanh nhảu đáp:” lại đậy tham gia nào anh bạn. Chào mừng tay\nchơi cự phách của chuáng ta ngày hôm nay!” Câu nói đơn giản đó làm anh\nchàng nọ thấy khí thế quá, đút tay vào túi áo lôi toàn bộ số tiền mình đang\ncó ra bàn đặt cược. Anh ta đã vét sạch hai mươi đô-la để chơi bài chỉ vì\nmột câu chào mới.\nVà anh ta mất sạch.\nTính chất thôi miên cảm xúc trong lời nói của người phụ nũ đã mạnh\nhơn và đánh bại khả năng cưỡng lại sức cám dỗ Tử trò chơi của anh ta!\nKhông còn gì nghi ngờ nữa!\nTrong Từng giây, Từng phút, Từng giờ trôi qua, tất cả mọi người đều\nBận Rộn trong tâm trí. Dù họ đang đói hay đang khát, vui hay buồn, đam\nmê hay hoảng sợ, bạn vẫn phải luôn nỗ lực để làm họ nghe mình kể cả khi\nhọ nói họ vẫn đang nghe bạn.\n\nNgay cả người bạn thân nhất của bạn cũng không ngoại lệ. Anh ta\nhoặc cô ta vẫn có thể nhìn bạn đắm đuối trong khi tâm hồn họ đang bay\nbướm ở một nới nào đó cách xa nghìn dặm.\nNếu anh ta hoặc cô ta bất chợt yêu cầu bạn “ Im lặng nào”, đừng nổi\nnóng. Thậm chí bạn nên cảm ơn bạn mình. Đó là một lời khuyên đúng đắn!\nBạn đang nói chuyện nhưng anh ta hoặc cô ta không thực sự lắng\nnghe, thế thì im lặng há chẳng tốt hơn sao?\nTuy nhiên, bạn hoàn toàn có thể làm cho mọi người phải lắng nghe\nmình, một cách nhanh chóng và dễ dàng nhờ lồng ghép sự thôi miên cảm\nxúc trong lời nói của mình.\nDù bạn đang nói, đang bán hàng, biểu diễn hay đang viết, hãy luôn ghi\nnhớ trong đầu bạn rằng tất cả mọi người luôn bận rộn trong tâm trí của họ.\nĐể khiến họ lắng nghe hoặc phản hồi, bạn phải làm sao phá vỡ được\nNhững Mối Bận Tâm trong đầu họ bằng một nhân tố thôi miên cảm xúc\nphù hợp.\nBất kể bạn là ai, làm nghề gì, sống ở đâu, “ quyền năng lắng nghe”\ntrong giao tiếp chính là chiếc chìa khóa đầu tiên bạn phải có để giải phóng\nđược tính cách, kỹ năng thuyết phục và phong thái hấp dẫn của mình.\nCon người phải giao tiếp để sống. Và giao tiếp được thực hiện bằng\nngôn từ và hành động.\nĐộng cơ đằng sau những ngôn từ và hành động đó quyết định kết quả\nxấu hoặc tốt, quyết định ai là bạn và ai là thù, người yêu hay dĩ vãng, một\nphi vụ bán hàng thành công hay một cú lỗ nặng. Đây chính là nguyên lý tối\nthượng của giao tiếp: Việc đầu tiên và trước nhất bạn phải làm với đối\n\nphương hay người nghe chính là phá vỡ được những mối bận tâm và thâm\nnhập vào tâm trí họ, Tử việc tạo ấn tượng tốt, thôi miên, thuyết phục, ghi\nnhớ, dạy dôc khuyên nhủ, tạo sức ảnh hưởng và chỉ đạo họ.\nĐó cũng chính là cách mà người khác dùng để gây ấn tượng, thôi\nmiên, thuyết phục, ghi nhớ, dạy dỗ khuyên nhủ, tạo sức ảnh hưởng và chỉ\nđạo chúng ta!\nEva dụ dôc Adam bằng lời ngon tiếng ngọt, khiến chàng không thể\ncưỡng lại và ăn trái cấm. Cuộc sống ngày nay đầy rẫy những phiên bản\nkhác nhau của Eva, Adam và trái cấm. Nhưng điều duy nhất không đổi vẫn\nlà sức mạnh của sự thôi miên cảm xúc. Nó vẫn là lý do vì sao mọi người\nmuốn lắng nghe bạn, bất kể bạn nói chuyện gì Tử trên trời dưới đất, về\nnhững trái táo, tôn giáo, bóng chày cho đến bọn buôn lậu ớt Jamaica.\nMuốn làm tổn thương ai đo ư? Dễ lắm, bạn chẳng cần phải nhọc công\nkiếm một cái dùi cui hay một cái chùy nặng nề để làm điều đó. Chỉ cần nói\nvới người đó vài lời có chứa một hay vài yếu tố phản thôi miên cảm xúc.\nRồi những lời nói tiêu cực đó sẽ xuyên thủng mọi mối bận tâm trong đầu\nhọ, thâm nhập vào tâm trí họ rồi yên vị ở đó. Và bạn sẽ thấy, chẳng có thứ\nthần dược nào có thể chữa lành những tổn thương tinh thần đó cả.\nMặt khác, điều tôi muốn nói ở đây là: Đắc nhân tâm là chuyện không\ntưởng nếu không có thôi miên cảm xúc.\nChỉ cần biết cách giao tiếp bằng thôi miên cảm xúc, bạn sẽ thành công\nlớn trong mọi việc!\nChứ không như gia đình nhà Smith dưới đây.\n\nBà Smith nói với chồng: “ Cưng ơi, khi nào anh ra cửa hàng, tiện thể\nmua cho em một cân bơ”. Ông Smith ra cửa hàng mua thuốc lá và trở về\nnhà mà không có bơ. Bà Smith nổi giận: “ Sao anh chẳng bao giờ nghe lời\nem vậy!” bà ấy bắt đầu ca cẩm.\n“ Anh có nghe em dặn gì đâu?” Ông Smith trả lời.\nChỉ có thế mà hai vợ chồng đã to tiếng với nhau. Ngày hôm đó, mấy\nđứa trẻ nhà Smith phải chịu trận suốt bữa ăn. Nguyên một buổi tối gia đình\nquây quần đầm ấm đã bị phá hủy chỉ vì một cân bơ.\nÍt người nhận ra rằng ngôn từ chính là nguồn cơn của mọi mối quan hệ\nthất bại và gia đình tan vỡ Các luật sư và chuyên gia hòa giải đều đồng ý\nrằng phần lớn các cặp vợ chồng chia tay nhau đều vì những lí do rất nhỏ\nnhặt cỏn con.\nKỳ thực, những “ chuyện cỏn con” là biểu hiện của một vấn đề nghiêm\ntrọng hơn: thất bại trong việc giao tiếp với nhau bằng thôi miên cảm xúc.\nThay vì làm chủ cảm xúc, người trong cuộc trở thành nô lệ cho cảm xúc và\nvô tình đẩy mâu thuẫn vượt quá giới hạn cho phép!\nCó phải ông Smith bị điếc nên mới không nghe bà Smith nói? Không\nhề.\nGiọng bà Smith có vấn đề nên ông Smith không nghe thấy? Không\nphải.\nVậy thì tại sao sự giao tiếp giữa họ lại thất bại?\n\nLý do: ông Smith đang bận rộn trong tâm trí. Bà thì cứ nói, nhưng ông\nthì cứ ko nghe. Bà vợ đã không làm gì để đánh động tâm trí bận rộn của\nông chồng trước khi đưa ra yêu cầu.\nThú vị nhỉ? Hai người họ đã đầu gối tay ấp với nhau 12 năm; trước đó,\nbà đã hẹn hò với ông không dưới 4 năm. Mười sáu năm làm bạn gái và bạn\nđời chồng mình, bà ấy vẫn không biết gì về chồng mình ư?\nĐến nỗi không biết làm thế nào để hấp dẫn cảm xúc của chồng, thúc\ngiục ông ấy mua chỉ một cân bơ ở ngay cái cửa hàng mà ông ta ghé mua\nthuốc lá.\nCòn ông Smith thì sao?\nÔng còn kém giao tiếp hơn cả vợ.\nCũng như nhiều người khác, ông ấy có mắt như mù, có tai như điếc.\nTâm trí của ông ấy quá bận rộn.\nVà bạn cũng vậy.\nHãy nhớ, ngôn từ có cảm xúc!\nMọi Tử ngữ đều có cảm xúc.\nChúng được sử dụng với con người – cũng chính là những sinh vật có\ncảm xúc – và tự chúng cũng có khả năng gây phản ứng.\nKhi hàng xóm của bạn bình phẩm rằng, “ Con gái anh là một đứa trẻ\nngoan – nhưng không được sáng dạ cho lắm”, câu nói đó hẳn là sẽ khiến\nbạn chú ý ngay lập tức. Câu nói xấc xược khiến bạn bực tức. Bạn cảm thấy\nđau đớn kể cả khi gã hàng xóm thực sự nói đúng.\n\nNếu một người quan sát bạn và phán to lên rằng bạn “ là đồ keo kiệt\nbủn xỉn”, chắc mẩm là bạn không vui tí nào bất kể câu nhận xét đó đúng\nhay sai.\nTương tự, bạn cũng sẽ có những phản ứng xúc cảm nhất định khi\nngười khác nói điều gì tốt đẹp về bạn, chẳng hạn như “ bạn trông rất khỏe\nkhoắn”, hoặc “ bạn rất xinh đẹp”, hoặc “bạn trông trẻ hơn mười tuổi!”\nNhững phản ứng đó thuộc về mô thức cảm xúc của bạn, và chúng xuất\nhiện kể cả trong những tình huống nguy hiểm. Bạn đang đi bộ băng qua\nđường thì một chiếc xe tải nhào đến bạn. Bạn thấy nguy hiểm đang cận kề,\nvà thế là bạn phản ứng bằng cách nhảy ra khỏi hướng di chuyển của xe tải.\nChứ nếu bạn nhìn thấy chiếc xe tải còn xa với một khoảng cách an toàn,\nhẳn là bạn đã thong dong đi bộ tiếp.\nLần nữa, phản ứng xúc cảm là một quá trình hai chiều, liên quan đến\nbạn lẫn tài xế xe tải! Khi tình huống nguy hiểm xảy ra, những động cơ và\nphản ứng xúc cảm sẽ được kích thích và khơi dậy ở cả hai người.\nGiả sử bạn đang được bác sĩ khám bệnh. Bác sĩ muốn kiểm tra khả\nnăng phản xạ của bạn, nên yêu cầu bạn ngồi bắt chéo chân. Rồi ông ta lấy\nmột cây búa y khoa gõ vào đầu gối bạn? Ông ta thực hiện mọt cú gõ chính\nxác, và bạn phản xạ ngay lập tức bằng một cú đá chân. Nếu bác sĩ gõ nhầm\nvị trí thì sao? Sẽ không có phản xạ, hoặc bạn sẽ rất đau.\nNgôn từ và lời nói cũng gây ra hiệu ứng tương tự. Một số Tử ngữ có\nthể tác dunjg với những người khác, nhưng chưa chắc đã thuyết phục được\nbạn bởi mô thức cảm xúc của bạn khác biệt với họ. Nhưng nếu có những\n\nngôn từ hay lời nói nào đó chạm vào “tim đen” hay những vấn đề nhạy\ncảm nào đo của bạn, bạn sẽ có phản ứng hoặc tốt hoặc xấu!\nHiển nhiên, lời nói và ngôn từ của bạn cũng có khả năng gây hiêu\njuwngs tương tự lên những người mà bạn trò chuyện.\nTrong một buổi diễn thuyết nọ với khoảng năm trăm khách tham gia\ngồm cả nam lẫn nữ, chỉ sau mười phút đầu tiên, người diễn giả hào hứng và\ntập trung vào những gì ông ta nói.\nMột người đàn ông điển trai với nước da ngăm đen ngồi ở hàng ghế\nthứ bảy đặc biệt chăm chú lắng nghe phần trình bày của vị diễn giả. Suốt\nTử đầu buổi đến giờ, anh ta gật đầu lia lịa.\nĐến một cao trào nọ, người diễn giả bắt đầu cao giọng và nói :”Đừng,\nđừng bao giờ quên điều tôi vừa nói – Nếu không, hẳn là các anh chị vùi\nđầu vào cát giống như những gã Ả-Rập lén lút trong bóng đêm...”\n“Không!” – lần đầu tiên người khán giả ở hàng ghế số bảy không đồng\ntình. Vẻ giận duex hiện rõ trên khuôn mặt anh ta:” Tôi không thích câu nói\nđó của ông. Tôi là một người Ả-Rập!”\nLời nói đó của vị diễn giả voohaij với người khác,nhưng lại động\nchạm đến anh chàng Ả-Rập này. Sự chú ý bất ngờ chuyển hướng Tử người\ndiễn giả sang vị khách đặc biệt, còn những khán giả còn lại vừa được\nthưởng thức hiệu ứng mà tôi gọi là quyền năng cảm xúc ngôn từ.\nHẳn là người diễn giả nọ cũng vừa nhận được bài học đáng nhớ!\nVà bạn hoàn toàn có thể liên hệ câu chuyện này với những tình huống\nđơn giản nhất trong cuộc sống.\n\nBạn đang tản bộ trên đường phố. Bạn nhìn thấy cô bạn Martha đang đi\nvề phía mình. Bạn gọi cô ấy:” Xin chào, Martha!” Martha đáp lại lời chào\ncủa bạn, “Xin chào, Gerry!” và tiếp tục đi. Bạn cũng tiếp tục đi đường của\nmình. Hoạt cảnh kết thúc. Bạn vừa nhận được Tử Martha một phản ứng mà\nbạn trông đợi.\nGiả sử khi bạn nói “Xin chào, Martha!” nhưng Martha không đáp lại,\nthậm hcis chẳng nhìn ra bạn do tâm trí cô ấy đang bạn suy nghĩ về những\nvấn đề khác, bạn sẽ phản ứng như thế nào? Hẳn là bạn sẽ dừng lại, nhìn\ntheo sau cô ấy và lầm bầm:” Quái, cái coo Martha này! Cô ta vừa xẹt\nngang qua mà không thèm chào một tiếng, trong khi chúng ta đã quen biết\nnhau hơn mười năm! Kể Tử khi chồng cô ta trúng số mua được chiếu xe\nCadillac và hai cái bãi xe rộng thênh thang, cô ta càng lúc càng trở nên\nkhinh khỉnh và chảnh chẹ thế đấy. Hãy đợi đấy, mình sẽ méc lai chuyện\nnày với Helen!”\nBạn thấy nghiêm trọng chứ: chỉ vì Martha quên một câu chào hỏi đơn\ngiản mà cả chồng của Martha, tiền của anh ta, vụ trúng số, hai cái nhà xe\nvà chiếc Cadillac vô tội cũng bị vạ lây. Ngôn từ - và cả sự biến thiếu thốn\nngôn từ - là những thực thể có cảm xúc. Và những người sử dụng chúng\ncũng thế, kể cả khi họ chưa bao giờ quen biết nhau.\nMột anh chàng lạ mặt vui tính nào đó bỗng dừng bước trước mặt bạn\nvà tôi và nói:” Xin chào!” Ngay lập tức, chúng ta đáp lại bằng lời chào kèm\nmột nụ cười tương tự. Nhưng một giây sau đó, cả tôi và bạn nhìn nhau\nchưng hửng:” Có vẻ như gã đó biết chúng ta, nhưng hắn là ai vậy?”\nHoặc chính bạn có thể thử nghiệm trò này, bắt tay một cô nàng lạ mặt\nbạn thấy trên đường. Cô ấy sẽ không hiểu tại sao bạn lại làm thế. Cô có thể\n\nquay lại ném cho bạn một cái nhìn kì lạ. Cũng có thể cô ấy sẽ bắt tay đáp\nlại bạn. Anh chàng vui tính kia cũng tương tự!\nMột khi tìm hiểu sâu về Thuật thôi miên cảm xúc, bạn sẽ nhận ra rằng\ncảm xúc của chúng ta luôn phản ứng ở mọi tình huống liên quan đến bản\nthân chúng ta. Chẳng hạn, trong bất kì tình huống hay hoàn cảnh nào liên\nquan đến thể diện, sự công nhận( được gọi là tử huyệt danh tiếng trong\nchương bảy), bạn luôn muốn mình trông thật chỉnh tề và nghiêm túc trước\nmặt người khác, kể cả khi đó chỉ là một đám đông người dưng nước lã,\nđúng chứ?\nCách đây vài năm, một người bán hàng có thể dễ dàng gia tăng doanh\nthu của mình lên, kiếm thêm được vài ngàn đô-la vào thu nhập trung bình\ncủa bản thân chỉ nhờ biết bắt tay thân thiện với khách hàng và nở một nụ\ncười có thể kích thích cảm xúc tích cực của bất kì ai.\nMột nhà bán lẻ ti vi và đồ gia dụng nọ đã thành công nhờ câu khẩu\nhiệu “ Nơi bạn có thể mua một cái bắt tay trìu mến”. Vào thới bấy giờ, thị\ntrường ti vi và ddienj gia dụng cạnh tranh vô cùng khốc liệt với giá cả các\ncửa hàng so găng nhau Từng chút một, chính những yếu tố nhân bản như\ncá tính doanh nghiệp và sự thân thiện sẽ là lợi thế cạnh tranh to lớn giúp\ndoanh nghiệp nổi bật giữa đám đông.\nThời đó, ý tưởng “Cái bắt tay” được ưa chuộng trong mọi mẩu quảng\ncáo cũng như trong những thiết kế trưng bày của kính tại các cửa hiệu. Bạn\ncó thể nhìn thấy những ý tưởng như “Kế hoạch tín dụng bắt tay” hay “Một\ncái bắt tay làm nên tất cả” ở khắp nơi, Tử việc mua một cái lò nướng bánh\ncho đến máy giặt. Nó chính là một yếu tố giúp người tiêu dùng nhớ đến\nmột của hàng và giúp làm nên một cuộc mua bán thành công. Một khi bạn\n\nphá vỡ được những mối bận tâm khác của khách hàng, thâm nhập được vào\ntâm trí của họ và gây được dự chú ý , mọi cuộc giao tiếp và giao dịch sẽ trở\nnên dễ dàng hơn bao giờ hết. Đây là lý do vì sao kĩ năng sử dụng ngôn từ,\nhành động một cách thuyết phục và có cá tính rất cần thiết cho những ai\nmuốn trở thành những chuyên gia bán hàng bậc thầy.', '2026-02-28 07:56:52'),
	(9, 7, 2, 'Thuật Thôi Miên Cảm Xúc – Mẫu thức chung và duy nhất của mọi cuộc giao tiếp thành công', 'Thôi miên cảm xúc là một kỹ thuật giao tiếp giúp bạn thấu hiểu bản\nthân mình hơn , Từ đó kiểm soát và làm chủ được những phản hồi của\nngười khác đối với mọi hành động và ngôn từ của bạn .\n\nKỹ thuật này là kết quả hơn mười bảy năm nghiên cứu và thử nghiệm\nvới hàng nghìn đối tượng nghiên cứu thuộc đủ mọi đối tượng và nghề\nnghiệp . Các cuộc thử nghiệm được thực nghiệm cả trên nhóm lẫn cá nhân .\nTổng hợp Tử vô số những nhân tố gây xao nhãng tâm trí của các đối tượng\nnghiên cứu chúng tôi đã tổng kết được Bốn điểm Thôi miên cảm xúc chung\nnhất – hay còn gọi là Tử Huyệt Cảm Xúc – có khả năng gây sự chú ý và\nkhuấy động tâm trí bất kỳ ai trong mọi trường hợp .Thông qua những Tử\nHuyệt Cảm Xúc này , bạn có thể vận dụng Thuật thôi miên cảm xúc trong\nmọi tình huống giao tiếp cần đến những ngôn từ và hành động thích hợp để\nđạt được kết quả mong muốn.\n\nVới kỹ thuật này , bạn có thể thôi miên cảm xúc người khác một cách\ncó chủ đích và không phụ thuộc vào sự tình cờ hay may rủi .\nPhần lớn con người chúng ta ít suy nghĩ nhiều trong giao tiếp hàng\nngày ; chúng ta thường bị đưa đẩy bởi cảm xúc và cảm nhận nhiều hơn là\nlý trí hay đúng sai ! Chính những cảm xúc hay cảm nhận này vừa kích\nthích lại vừa kiềm hãm giao tiếp .\nDo vậy để giao tiếp thành công , bạn có nhiệm vụ sử dụng Thuật Thôi\nMiên Cảm Xúc để xuyên thấu những cảm xúc và cảm nhận đó bằng cách\nđánh trúng Tử Huyệt Cảm Xúc của đối phương với những ngôn từ hoặc\nhành động chính xác . Khi đó bạn sẽ làm cho họ phải lắng nghe bạn . Đây\nchính là mẫu thức chung của mối quan hệ thành công là chìa khóa giúp bạn\nmở ra cuộc sống tốt đẹp và thành đạt hơn !\nBa nguyên tắc chủ đạo của Thuật Thôi Miên Cảm Xúc .\n1. Tất cả mọi người điều bạn rộn\n\n2. CHỦ ĐỂ GIAO TIẾP tác động đến ĐỐI PHƯƠNG khi và chỉ khi\nđiểm Thôi Miên Cảm Xúc thích hợp có khả năng thâm nhập tâm trí đối\nphương được kích hoạt .\n3. Điểm Thôi Miên Cảm Xúc thích hợp của mỗi người luôn nằm ở đâu\nđó trong“ Bộ Tứ Huyệt Cảm Xúc”\nTử Huyệt Bản Thân\nTử Huyệt Tiền Bạc\nTử Huyệt Tình Yêu\nTử Huyệt Danh Tiếng\n\nTrong tiếng Anh , cụm từ “ Bộ Tứ Tử Huyệt” đã được sử dụng trong\nmột thời gian dài , trở nên phổ biến và dễ nhớ . Thuật Thôi Miên Cảm Xúc\nquyết định lằn ranh mong manh giữa “Thành công và thất bại” cũng như\ntính sống còn của mọi cuộc giao tiếp giữa con người với con người .Bất\nchấp mức độ phức tạp của cuộc giao tiếp , điểm Thôi Miên Cảm Xúc của\nmỗi người không bao giờ nằm ngoài bộ Tứ Tử Huyệt gồm Bản Thân Tiền\nBạc Tình Yêu và Danh Tiếng.\nCách duy nhất để bạn khiến cho đối phương hoặc đám đông khán giả\nphải lắng nghe chính mình là cung cấp một lý do đủ lớn để họ làm việc đó\n.Và bạn sẽ không bao giờ tìm ra được lý do này nếu không thể xác định\nđược ít nhất một trong bốn Tử Huyệt có thể liên kết những gì bạn nói với\nnhững cảm nhận và cảm xúc của người nghe. Một khi bạn đã không thể\nlàm cho những người này hướng sự chú ý về phía bạn , họ sẽ tiếp tục rong\nchơi trong tâm trí của mình và lắng nghe bản thân họ chứ không phải là\nbạn !\n\nToàn bộ Bộ Tứ Huyệt Cảm Xúc trên đều hiện hữu trong mỗi người\nchúng ta , trong mọi chủ đề và đối tượng , trong mọi cá nhân và tập thể.\nChúng là những bản năng bẩm sinh của con người , và bạn không thể\nchống lại hay tống khứ chúng đi.\nTrong mỗi tình huống nhất định , sẽ có một Tử Huyệt Cảm Xúc trội\nhơn những cái còn lại và trở thành lý do vì sao đối phương hoặc khán giả\nphải lắng nghe hoặc nể sợ bạn ! . Đôi khi Tử Huyệt này có mối liên hệ\nphần nào với Tử Huyệt khác , nhưng một điều chắc chắn là rất hiếm khi\nxảy ra trường hợp có nhiều hơn hai Tử Huyệt nổi trội cùng một lúc gắn kết\ndiễn giả và khán giả , nhà văn và độc giả hoặc người nói và người nghe.\nThêm một quy luật tối quan trọng nữa là, bạn chỉ có thể xui khiến\nngười khác lắng nghe mình khi và chỉ khi bản thân bạn cũng phải là người\nbiết lắng nghe. Trong cuộc sống có quá nhiều thứ khiến cho tâm trí chúng\nta bận rộn và rối bời, một chuyên gia giao tiếp hay thuyết phục phải có khả\nnăng lắng nghe người khác chân thành thì mới có thể khám phá, nhận diện\nvà thấu hiểu những nỗi lo toan bận rộn của người khác.\nCứ thử quan sát cuộc sống cũng như mọi hoạt động giao tiếp chung\nquanh mình một cách có ý thức, bạn sẽ nhận thấy quyền năng và tầm ảnh\nhưởng vô cùng của Bộ Tứ Tử Huyệt Cảm Xúc đối với sự thành đạt của con\nngười rõ rang như thế nào. Việc ứng dụng Thuật Thôi Miên Cảm Xúc vào\ncuộc sống sẽ dần dần cải thiện và nâng tầm tính cách, kỹ năng thuyết phục,\nsức khỏe và phong thái của bạn một cách đáng kể theo thời gian. Khả năng\ntưởng tượng và quyền năng sáng tạo của bạn sẽ được giải phóng, động lực\nthành công của bạn sẽ được khai thông, và bạn sẽ trở thành con người tuyệt\ndiệu mà mình hằng mong ước!\n\nBa mối liên kết then chốt trong Thuật Thôi Miên Cảm Xúc\nTôi sẽ giúp bạn tổng kết lại ba mối liên kết quan trọng trong Thuật\nThôi Miên Cảm Xúc bằng sơ đồ sau:\n\nMột khi áp dụng thuật thôi miên cảm xúc, chúng ta sẽ nhận ra được sự\nkhác biệt lớn giữa việc cố gắng giao tiếp một cách khiên cưỡng và giao tiếp\nthành công một cách tự nhiên. Sự khác biệt đó chính là việc bạn có tạo ra\nđược những Tử Huyệt Cảm Xúc thích hợp hay không. Bạn thậm chí có thể\náp dụng điiều này để tự bảo vệ bản thân, tài sản hoặc cứu mạng chính mình\ntrong những tình huống nguy hiểm!\nSau khi kết thúc phần trình diễn của mình trong một chương trình\ntruyền hình ở New York, quý ông R. đi tàu điện ngầm để đến bãi đỗ ô-tô\ncủa mình. Ông lái ô-tô qua phố Bowery để về nà.\n\nNHỮNG MỐI BẬN TÂM\n\nMỐI QUAN HỆ GIỮA CHỦ ĐỀ GIAO TIẾP\nVÀ ĐỐI TƯỢNG LẮNG NGHE\n\nBỘ TỨ TỬ HUYỆT CẢM XÚC\n Bản thân\n Tình Yêu\n Tiền Bạc\n Danh Tiếng\n\nLúc đó đã là 9 giờ đêm, phố Bowery vắng vẻ không một bóng người.\nKhi ông R. giảm tốc độ và tiến đến một ngã tư có đèn giao thông, ông\nnhìn thấy một gã đàn ông cao to với bộ dạng bặm trợn bất thình lình xuất\nhiện trong màn đêm và tiến gần đến phía trái xe của ông. Ngay lúc đó, tín\nhiệu giao thông chuyển sang đèn đỏ. Ông R. buộc lòng phải dừng xe.\nGã đàn ông lạ mặt dùng hai bàn tay to kềnh của mình nắm chặt lấy cửa\nxe ngay bên tay lái của ông R. và ông có thể nghe thấy giọng nói ngạo\nnghễ của hắn:” Chú mày nghĩ sao nếu tao xin vài đồng để kiếm chút cháo?\nCả buổi tối hôm nay tao chưa có gì bỏ bụng cả.”\nGiọng nói của hắn nghe rất đáng sợ, còn chung quanh hì vắng như\nchùa Bà Đanh – điều kiện hết sức thuận lợi cho một vụ cướp. Tên này mà\nthò tay vào được bóp tiền của ông R thì ông chỉ có nước bó tay. Tuy nhiên,\nông R. đã bình tĩnh chọn cách sử dụng thứ vũ khí cá nhân lợi hại nhất của\nmình – Thuật Thôi Miên Cảm Xúc bằng ngôn từ!\nKhông thèm quay sang nhìn tên trộm, ông R. vẫn nhìn thẳng con\nđường phía trước và hét lớn:\n“Thưa chỉ huy, tôi phải tập trung đuổi theo chiếc xe phía trước. Tôi\nđang làm nhiệm vụ, vậy nhé!”\nGã lạ mặt biến mất ngay lập tức!\nCâu nói “Tôi đang làm nhiệm vụ” khiến anh ta sợ hãi còn hơn cả ông\nR. sợ hắn.\nGã nghe thấy cụm từ đó. Chúng đã thâm nhập tâm trí của gã ngay lập\ntức và khiến gã phải hành động ngay!\n\nGiống như hầu hết những tên tội phạm khác, gã không muốn bị bắt và\nrất sợ dính dáng đến cảnh sát. Câu la lớn của ông R. với ý chỉ rằng ông\ncũng là một cảnh sát đã tạo nên một hiệu ứng cảm xúc mãnh liệt trong\nngười gã, đến nỗi gã còn lầm bầm một câu xin lỗi trong miệng trước khi bỏ\nchạy vào bóng tối!\nTrong những phần tiếp theo của cuốn sách, chúng ta sẽ hiểu hơn về vai\ntrò của Tử Huyệt Bản Thân trong việc khiến cho tên cướp hụt đó phải lắng\nnghe và thay đổi ý định ngay lập tức. Có thể ý định di cướp của hắn xuất\nphát tự động cơ tiền bạc, nhưng cuối cùng , nỗi sợ bị bắt bỏ tù ( thuộc động\ncơ Bản Thân) lại gây hiệu ứng cảm xúc mạnh mẽ hơn quyết tâm ăn cướp\ncủa hắn.\nTrong tình huống này cũng như mọi tình huống khác của cuộc sống\nluôn luôn hàm chứa một nhân tố gây chú ý chủ đạo mà bạn phải tìm ra\nđược để chiếm ưu thế. Nó luôn hiện hữu trong mọi sự tương tác, nhưng bạn\nphải làm thế nào để phát hiện ra nó kịp thời?\nVới thuật thôi miên cảm xúc, mọi chuyện đều có thể.\nMột học viên cũ của tôi Từng nhiều năm làm công việc quản lí các họt\nđộng trại hè thiếu thiếu nhi. Những người quản lí và trưởng nhóm hướng\nđạo sinh ở đây thường được lụa chọn và đề bạt dựa trên tiêu chí về kinh\nnghiệm cá nhân và những thành tích nhất định trong các hoạt động đoàn\nđội.\nTrong một trại hè nọ, cậu quản lý này kể cho tôi nghe về Charlie, một\ntrưởng nhóm hướng đạo sinh trong trại. Charlie được bình chọn là cầu thủ\nbóng chày xuất sắc nhất trong các trường đại học ở mỹ. Tất cả các cậu bé\n\ntrong trại đều thích mê những buổi hướng dẫn chơi bóng chày của Charlie\nvà thường tụ họp sôi nổi về tài năng và danh tiếng của cậu ấy, trừ một em\ntên Ronie.\nRonnie là một hướng đạo sinh khá giỏi trong trại. Em có thành tích\nxuất sắc trong mọi hoạt động, trừ bóng chày. Dù đã cố gắng hết sức,\nCharlie vẫn lực bất tong tâm trong việc làm cho cậu bé này tiến bộ hơn với\nmôn bóng chày. “Tôi không biết làm thế nào để em ấy hứng thú”, anh ta\nthan phiền với học viên cũ của tôi. “Ronnie không thích nghe tôi nói. Em\nấy cứ lơ là, vênh váo và kích động những cậu bé khác tẩy chay tôi. Tôi xin\nphép loại em ấy ra khỏi lớp bóng chày, nếu không cậu ấy sẽ tiếp tục đầu\ntêu và làm hư các bạn khác mất thôi.”\nSau bữa trưa hôm ấy, viên quản lý gọi Ronnie vào phòng làm việc của\nmình.\n“Chuyện gì xảy ra với em vậy?” người quản lí hỏi. “Thầy thấy em học\nrất tốt với những thầy cô khác, chỉ trừ mỗi Charlie. Em thừa biết thầy ấy là\nmột trong những cầu thủ bóng chày tài năng nhất của các trường đại học\nmà. Sao em không nghĩ rằng mình sẽ có thể học hỏi được rất nhiều điều\nhay Tử Charlie?”\n“Ôi không thầy ơi!” Ronnie đáp. “Em chẳng học được gì cả!”\n“Tại sao?”\nCậu bé mười ba tuổi đứng thẳng người với tư thế chống nạnh và trả lời\nmột cách chắc nịch: “ Một tín đồ của đội Giant thì làm sao có thể dạy dỗ\nmột người hâm mộ đội Dodger được?”\nSau đó, viên quản lý có một buổi nói chuyện riêng với Charlie.\n\nSáng hôm sau, trong tiết học bóng chày, Charlie nói với đội của\nRonnie:” Các em đều biết tôi hâm mộ đội Giant. Các em cũng biết là đội\nGiant và đội Dodger có một mối thù truyền kiếp và không đội trời chung\ntrong các giải vô địch bóng chày. Tuy nhiên, dù là một người ham mộ\nGiant đi nữa, tôi vẫn phải thừa nhận rằng đội Dodger có nhiều kỹ thuật sở\ntrường hay hơn nhiều so với Giant trên sân đấu. Điển hình là kỹ thuật ném\nbóng và phòng ngự kép...”\nRonnie hào hứng ngay lập tức. Lần đầu tiên trong trại, cậu bé muốn\nđược nghe Charlie chia sẻ nhiều hơn. Kể Tử sau đó, Charlie và Ronnie trải\nqa kì trại hè như những người bạn thân thiết, và khả năng chơi bóng chày\ncủa Ronnie tiến bộ rõ rệt.\nNhư chúng ta đã thấy, có một lí do cảm xúc lấp đầy tâm trí Ronnie\nkhiến cậu không muốn đội trời chung với Charlie. Khi rào cản này được\nphá bỏ bang những Tử ngữ đánh động Tử Huyệt Danh Tiếng – cũng chính\nlà điểm Thôi Miên Cảm Xúc nổi trội của Ronnie, cậu bé ngay lập tức lắng\nnghe và thuận theo.\nViên quản lý trại hè kiêm học viên cũ của tôi đã dành rất nhiều thời\ngian quan sát những hành vi và cách giao tiếp của Ronnie. Kết quả cho\nthấy động lực lớn nhất của cậu bé khi làm bất kì điều gì hoặc khi lắng nghe\nngười khác chính là để được mọi người công nhận – một yếu tố thuộc\nphạm trù Danh Tiếng!\nVào một mùa bóng nọ, khu vực khan đài sân vận động của đội Yankee\nchật kín người. Trận đấu hấp dẫn đến nỗi nhiều cổ động viên nửa đứng nửa\nngồi trên ghế, còn nhiều người khác thậm chí tràn lan cả lối đi và các bậc\ncầu thang để xem cho rõ. Ngay trước lúc cao trào của trận đấu, một anh\n\nchàng bán hàng rong mặc áo màu trắng cố gắng xuyên qua đám đông nhằm\ntiến đến khu vực cầu thang để bán hàng thuận tiện hơn.\nKhông người nào chịu nhường lối cho cậu ta cả.\nAnh bán hàng rong giữ chặt chiếc giỏ hàng và la lớn:” Làm ơn cho tôi\nđi qua!” Không một người nào di chuyển dù chỉ một chút, thế là anh chàng\ntiếp tục hét lớn: “ Nước sôi, nước sôi đây! Cẩn thận kẻo bỏng. Cho tôi đi\nqua nào!” Vân chảng có ai tránh đường cho cậu ta di chuyển. Sau vài lần\ngào thét , anh bán hàng rong bỏ cuộc và và đành rời khỏi chỗ đó để tìm lối\nđi khác dẫn đến khu vực cầu thang.\nMột cổ động viên nọ đã quan sát sự việc Tử đầu đến cuối. Ông này\nbèn gọi anh bán hàng rong lại và thì thầm vào tai anh vài điều. Sau đó, anh\nbán hàng nhún vai với vẻ mặt vui mừng và quay trở lại đám đông ban nãy.\nLần này, anh băng băng tiên tới, tay nắm chạt giỏ hàng và la lớn:”MÙ TẠT\nĐÂY! Làm ơn cho tôi đi qua. NẾU KHÔNG MÙ TẠT RƠI BẨN ÁO\nBÂY GIỜ!”\nNgay lập tức, những ai nghe thấy cau đó đều hoản hốt vì tâm trí của họ\nđã được thâm nhập thành công vào đúng nơi và đúng thời điểm. Họ ngay\nlập tức nhường lối cho anh bán hàng rong đi qua. Bạn thấy đấy, mặc dù\nđám đông khan giả đạng bận tận hưởng trận đấu – một thú vui hấp dẫn\nthuộc phạm trù Bản Thân, họ vẫn là những sinh vật đầy ắp những cảm xúc\nkhác nhau. Ban đầu, anh bán hàng rong dọa” Nưới sôi” ám chỉ rủi ro bị\nbỏng. Đây cũng là một yếu tố thuộc về sự an toàn Bản Thân, nhưng nó lại\nkhông phải Tử Huyệt chủ đạo của khán giả ở nơi đó và tại thời điểm đó.\n\nSự việc xảy ra ở sân vận động Yankee, nơi có rất nhiều xúc xích được\nbày bán. “Mù tạt” là một Tử đáng sợ trong hoàn cảnh đó, vì nó đồng nghĩa\nvới nguy cơ quần áo bị vấy bẩn không tẩy rửa được, chi phí giặt ủi tốn kém\nvà nỗi sợ phải mang bộ dạng hôi hám dơ bẩn trước mặt thiên hạ nếu mù tạt\nrơi vào người. Câu chuyện đã rõ. Tử Huyệt Danh Tiếng (sợ bẩn quần áo)\nchính là điểm thôi miên cảm xúc chủ đạo của đám đông khán giả này, với\nmột chút liên quan đến Tiền Bạc( chi phí giặt ủi). Chỉ cần bị đánh trúng Tử\nHuyệt Cảm Xúc chủ đạo, hàng trăm người tự nguyện nhường lối cho anh\nbán hàng rong hiên ngang đi qua.\nMột khi ngôn từ được thốt ra,\nĐối tượng sẽ có phản ứng, hoặc không!\nChỉ một hay vài Tử ngữ nhỏ nhắn đơn giản nhưng chính xác vẫn dư\nsức tạo nên hiệu ứng vô song về mặt ý nghĩa. Chúng có thể gây nên cả một\ncơn bùng nổ cảm xúc liên hoàn không thua gì bom nguyên tử!\nTrong khi đó vài lời hay ý đẹp được kết hợp chuẩn xác với giọng nói\nvà hành dộng phù hợp sẽ giúp khởi đầu một mối quan hệ lãng mạn và\nkhiến cho trái tim chúng ta loạn nhịp. Những Tử ngữ tiêu cực chính là\nnguồn cơn của mọi phiền muộn, hoài nghi và đau khổ. Trái lại chi cần vài\nngôn từ tích cực là có thể vực dậy cả một tinh thần đang xuống dốc, giúp\nchúng ta tự tin hơn, dũng cảm, trung thành và tử tế hơn.Ngôn từ âu yếm\ndịu dàng giúp khơi dậy tình yêu. Những lời nói dè bỉu chê bai có thể làm\ngiọt nước tràn ly, gây ra những phản ứng giận dữ và chống đối. Nói năng\nthiếu suy nghĩ tất yêu dẫn đến nghi ngờ và thù hận.\nBạn đã nói chuyện với mọi người như thế nào trong ngày hôm nay?\n\nNhững lời bạn nói có khiến cho họ khóc, cười, hy vọng, lo âu, hoài\nnghi, hoặc ưa thích, xem thường, tránh xa bạn hơn không? Hay họ chẳng\ncó phản ừng gì cả?\nNghĩ đi nào!\nNhững lời nói và ngôn từ mà bạn thốt ra ngày hôm nay có hiệu quả\nhay chưa? Bạn khơi dậy được những phản hồi như ý muốn Tử đối phương\nbằng cách nắm bắt chính xác tử huyệt cảm xúc chủ đạo của họ?\nBạn hoàn toàn có thể. Thành công của bạn không phụ thuộc vào việc\nbạn có chọn đúng đối tượng hay không. Bài học quan trọng ở đây là, mỗi\nmột con người và mỗi một nhóm người đều sẽ sẵn sàng dỏng tai lắng nghe\nlại một cách chăm chú một khi bạn khai phá được hiệu quả của thuật thôi\nmiên cảm xúc. Với nó, bạn có thể tìm được đúng tử huyệt cảm xúc của\nngười nghe trong bất kỳ hoàn cảnh hay tình huống nào.\nBất kể bạn là ai đi chăng nữa, bạn sẽ chẳng nên cơm cháo gì được nếu\nkhông thể xui khiến một người nào đó làm điều gì đó cho bạn. Điều gì đó ở\nđây là một phản ứng xúc cảm đối với ngôn từ và hành động của bạn trong\nmột lần hoặc nhiều lần với một hoặc vài Tử tử huyệt cảm xúc thuộc về bộ\ntứ. Bạn không chỉ làm được điều này một lần, mà là vô số lần trong suốt\ncuộc đời mình.\nVề bản chất người thành đạt là người biết vận dụng khéo léo những\nngôn từ và hành động của chính mình để tự chúng đưa anh ta tới những\nđỉnh cao mà anh ta muốn! Chúng giúp anh ta đạt được những mục tiêu của\nmình thông qua những sự thôi miên cảm xúc hiệu quả, thâm nhập tâm trí\n\nthành công và tạo nên nhiều phản ứng tích cực Tử những người khác xung\nquanh anh ta.\nĐiều này đúng cả trong những hội ngồi lê đôi mách, “Cô ta vừa không\nxinh đẹp lại chẳng có gì hay ho, vậy mà lại cưới được ông chồng đại gia\nhoành tráng thế kia!” Và, “Hắn Từng nghèo rớt mồng tơi lại vừa chẳng\nquan biết ai ra hồn. Vậy mà bây giờ hắn đang là chủ doanh nghiệp lớn kia\nkía!” Hoặc, “ Con bé này hồi nhỏ cứ hễ đi thi là bị loại ngay từ vòng gửi xe\nđạp. Vậy mà bây giờ trở thành ngôi sao truyền hình mới ghê chứ!”\nMột cựu học viên của tôi cũng khởi nghiệp Tử con số 0 theo đúng\nnghĩa đen. Cậu ta được sinh ra trong một gia đình nghèo thuộc một thị trấn\nkém phát triển. Cậu ta ít học, không có lấy một mối quan hệ nào ra hồn mà\ncòn mắc phải tật nói ngọng. Nhưng cậu đã có một cuộc sống thú vị và\nthành công chỉ nhờ vào biệt tài thôi miên cảm xúc mọi người. Những ai đã\ntừng gặp cậu ta dù chỉ một lần đều luôn có cảm giác như đã biết cậu ta Tử\nthuở nào, thân thiết đến độ họ liên tục mời cậu tham gia những sự kiện\ntrọng đại hoặc đến những nơi chốn thú vị.\nBí kíp của anh chàng này nằm ở một câu nói mà cậu ta không ngần\nngại thốt ra những khi thấy phù hợp:”Tôi rất hân hạnh được làm quen với\nanh. Dù tôi chỉ vừa biết anh, nhưng tôi chắc chắn rằng anh hẳn là con\nngười thú vị nhất tôi Từng gặp.”\nNhững người kia hiển nhiên là dâng trào cảm xúc mỗi khi nghe câu\nnói đó, và họ khao khát được gặp lại cậu học viên cũ của tôi lần nữa.\nTheo thời gian, số lượng những mối quan hệ của cậu ta cứ tang dần; và\nsự nghiệp của cậu cũng thăng hoa Từ đó.\n\nVào một ngày Chủ nhật nọ, anh cựu học viên này của tôi đến tham dự\nmột buổi hòa nhạc cùng với một người bạn. Khi người bạn kia nói rằng\nmình không thích chương trình hòa nhạc này, cậu ta nhớ ngay ra bài học đã\nđược lĩnh hội về thuật thôi miên cảm xúc. Khi hai người họ chia tay ra về,\ncậu ta nói ngay với người bạn đi cùng: “Hẳn là buổi hòa nhạc này đã không\nđược như chúng ta mong đọi. Nhưng những chuyến du lịch thú vị vừa rồi\ncủa anh ở Canada mà anh kể cho tôi nghe sẽ khiến tôi lâng lâng cả tháng\ncho mà xem. Nhờ có anh mà tôi vừa được trải qua một trong những buổi\ntối chủ nhật tuyệt vời nhất đời mình!”\nKỳ thực, toàn bộ câu nói trên chỉ là một cách nói khác của “Cảm ơn\nanh vì buổi tối hôm nay!” Nhưng anh cựu học viên của tôi đã khéo léo lồng\nghép một điểm thôi miên cảm xúc đánh vào huyệt tử danh tiếng của người\nnghe và khiến người đó cảm mến mình. Hãy nhớ, hầu như tất cả chúng ta –\ntrong tận đáy lòng – đều khao khát được mọi người công nhận và ngưỡng\nmộ trong mọi việc.\nNhìn chung, “Cảm ơn” là một trong những Tử ngữ có quyền năng thôi\nmiên cảm xúc mạnh nhất trong giao tiếp hàng ngày, Tử các giao dịch buôn\nbán cho đến những cuộc trò chuyện cá nhân. Phần lớn chúng ta đều mong\nmuốn được người khác cảm ơn và thừa nhận công sức Tử những việc nhỏ\nnhặt nhất.\nTrong một dãy phố ở Chicago, có hai sạp báo cách nhau chỉ mười bốn\nthước và cùng bán những loại báo và tạp chí giống nhau. Người chủ của\nsạp báo thứ nhất rất kiên nhẫn và chịu khó, ông nhiệt tình nói “Cảm ơn”\nvới bất kì ai đến mua báo kể cả trong lúc cao điểm hoặc đông khách nhất.\n\nCòn người bán báo kia thì lạnh lùng hô “Người kế tiếp” hoặc “Anh/chị\nmuốn đọc gì?”\nSuốt gần một năm, nhờ câu “Cảm ơn” mà mỗi ngày người bán báo thứ\nnhất đạt được doanh số gấp bốn lần so với người thứ hai dù cả hai người có\nlượng khách hàng tiềm năng tương đương nhau. Người đi đường sẵn sàng\nđi bộ thêm mười bốn thước nữa – kể cả khi họ đang vội – chỉ dể được nghe\ntiếng “Cảm ơn” Tử người bán báo thứ nhất!\nỞ thành phố New York, các sạp báo lại dùng một cách khác để thôi\nmiên cảm xúc khách hàng nhằm tăng doanh số của họ. Thay vì thối tiền dư\ncho khách bằng tiền xu lẻ, họ thay thế chúng bằng những đồng xu được\ndùng làm vé đi tàu điện ngầm có giá trị tương đương. Nhiều khách bộ hành\nsẵn sàng mua báo để nhận được những đồng xu đó một cách nhanh chóng\nthay vì mất thời gian đứng xếp hàng đợi mỏi mòn ở các quầy vé đi tàu điện\nngầm để mua chúng. Do vậy, sáng kiến của những người bán báo không\nchỉ giúp khách đi tàu điện ngầm tiết kiệm được thời gian và sức khỏe, mà\ncòn giúp cả người bán vé tàu không phải mất công sức đổi tiền lẻ để thối\nlại cho khách. Đây đều là những lợi ích thuộc phạm trù bản thân!\nĐôi khi sự khác biệt giữa việc chọn nhầm điểm thôi miên cảm xúc gây\nthất bại và việc tác động đúng tử huyệt dẫn đến thành công chỉ đơn thuần là\ncách sắp xếp chữ nghĩa.\nMột vị giáo sĩ Từng kể tôi nghe một câu chuyện về hai anh chàng mục\nsư là bạn thân của nhau. Cả hai đều nghiện thuốc lá nặng. Mỗi người họ\nphải viết đơn xin phép gửi cha xứ. Một trong hai người viết là: “ Liệu con\ncó thể hút thuốc khi cầu nguyện?” Cha xứ không đồng ý. Anh chàng còn\n\nlai viết:” Liệu con có thể cầu nguyện trong khi hút thuốc?” Cha xứ cho\nphéo ngay!\nQuyền năng của cảm xúc bao trùm cuộc sống của chúng ta mạnh mẽ\nđén nỗi chúng ta thường xuyên nghe, nhòn, nói, và làm bất kì điều gì khiến\ncho bản thân mình vui mà không mảy may nghĩ xem vì sao chúng ta lại\nnghe, nhìn, nói, và làm những việc đó.\nNếu một bộ com-lê hay một chiếc đầm giúp chúng ta “cảm thấy” mình\ntrông như một tỉ phú hay bà hoàng, chúng ta yêu ngay những bộ cánh đó và\nkhông còn quan tâm đến chất lượng hay giá cả của chúng đắt rẻ ra sao.\nNgay lúc đó, kể cả khi có một bộ cánh khác rẻ hơn, có chất lượng tốt hơn\nnhưng lại không cho chúng ta cảm giác huy hoàng đó, chúng ta chẳng thèm\nđếm xỉa đến nó.\n“Tôi nghĩ mình không có thành kiến với màu sắc, cũng chẳng phân\nbiệt đẳng cấp giàu nghèo sang hèn”, Mark Twain Từng nói. “Điều duy nhất\ntôi quan tâm là con người vấn luôn là con người. Thế là đủ, vì anh ta không\nphải thứ gì khác tệ hơn!”\nMark Twain đã đúng.\nCon người luôn muốn mình nhìn thấy hoặc nghe thấy những gì tác\nđộng lên họ về mặt cảm xúc.\nĐiều này luôn đúng bất kêt bạn muốn tác động một người, hai người,\nba người, ba mươi nghìn người hay thậm chí ba mươi triệu người.\nAnh chàng Redmond O’Hanlon đến tù sở cảnh sát New York sẽ chứng\nminh chi bạn thấy quy luật trên lợi hại như thế nào. Anh là một trong\nnhững người chơi đầu tiên của trò chơi truyền hình “Ai muốn làm triệu\n\nphú” lúc bấy giờ. Nhờ trả lời được câu hỏi về văn hào William\nShakespeare, anh dành được 16.000$. Trong kỳ phát sóng tuần kế tiếp, anh\nphải quay trở lại để quyết định trước người dẫn chương trình và khán giả\nrằng mình có ở lại chơi tiếp hay không, để có cơ hội lấy 32.000$ ở câu hỏi\nkế tiếp.\nNhiều tờ báo và giới truyền thông khắp nước Mỹ liên tục đưa tin và\ncập nhật hình ảnh về viên cảnh sát O’Hanlon. Người dân xôn xao bàn tán\nvề anh – người hiện là cha của năm đứa trẻ, sống bằng đồng lương ba cọc\nba đồng của nghề cảnh sát. Anh sẽ mất trắng giải thưởng đang có nếu trả\nlời sai câu hỏi trị giá 32.000$. Liệu anh ta sẽ chọn phương án an toàn, dừng\ncuộc chơi và mang về số tiền thưởng 16.000$, hay chơi tiếp để có cơ hội sở\nhữu 32.000$?\nCâu chuyện về O’Hanlon đánh động cảm xúc của hơn 30.000.000\nngười trên toàn nước Mỹ lúc bấy giờ. Dù mỗi người dân là một cá thể khác\nnhau, nhưng tất cả họ đều quan tâm đến sự kiện một phần ivf cảm xúc Bản\nThân của họ được đánh động, số khác vì Tiền Bạc, một số người lại quan\ntâm đến khía cạnh Tình Yêu và gia đình trong câu chuyện, và cũng có\nnhiều người theo dõi câu chuyện vì Danh Tiếng. Chính những phản ứng\nđông đảo và mạnh mẽ này khiến cho buổi phát sóng hôm đó của chương\ntrình “Ai muốn làm triệu phú” trở thành chương trình TV có lượt người\nxem nhiều nhất nước Mỹ lúc bấy giờ.\nO’Hanlon thừa biết rằng hàng triệu người dân Mỹ đang mong anh\nngừng cuộc chơi để bảo toàn số tiền thưởng, còn hàng triệu người khác\nmuốn anh chơi tiếp để có cơ hội giành giả cao hơn. Và anh đã có một câu\ntrả lời khôn ngoan:”Một mặt, tôi tự nhận mình là một người tự nghiên cứu,\n\nhọc hỏi và hâm mộ Shakespeare. Vì thế, tôi rất háo hức muốn biết cảm giác\nchiến thắng với giải thưởng lớn hơn như thế nào, và điều này thực sự khiên\ntôi muốn chơi tiếp. Nhưng mặt khác, tôi chỉ là một viên cảnh sát bình\nthường, đang sống cùng năm đứa con dễ thương và một người vợ tuyệt vời\ntrong một căn nhà trả góp bằng đồng lương công nhân viên chức. Vì lý do\nnày, tôi quyết định dừng cuộc chơi tại đây và mang về giải thương\n16.000$”\nGần như tất cả mọi người theo dõi chương trình đều ủng hộ quyết định\ncủa O’Hanlon, kể cả những người trước đó đã hy vọng anh chơi tiếp!\nVài năm sau đó, vào thời kì mà các chương trình trò chơi truyền hình\nbắt đầu giảm sức hút và lắm tai tieengsvif có quá nhiều người chơi thắng\ngiải trên 100.000$, câu trả lời chân thành của viên cảnh sát O’Hanlon vẫn\nđược nhớ đến và kuwu truyền trong tâm trí người dân như một tấm gương\nlớn về tự trọng!\nMỗi người chúng ta là một cá thể khác nhau với những mối quan tâm\nriêng biệt. Chúng ta có những quan điểm khác nhau về đủ thứ trên đời, từ\nthuốc lá, đàn ông, đàn bà, thời trang, mũ nón cho đến tình dục, xe cộ, phim\nảnh, tôn giáo, bằng hữu, cà vạt, máy giặt.\nNhưng dù khác biệt cách mấy, tất cả chúng ta vẫn là con người. Đó\nchính là nguyên lý cơ bản nhất và là nguồn cội của Bộ tứ tử huyệt cảm xúc\ntrong mỗi chúng ta. Những nhu cầu, động lực hay điểm yếu của chúng ta\nvề bản thân, tình yêu, tiền bạc và danh tiếng cắm sâu bên trong bản năng\ncủa chúng ta đến nỗi chúng ta luôn hành động trước cả khi bộ não kịp suy\nnghĩ và nhận thức đúng, sai, lợi và hại. Chỉ cần những ngôn từ và hành\nđộng của chúng ta đánh động được cảm xúc của người khác, chúng ta sẽ có\n\ncơ hội lý tưởng để thuyết phục họ thuận theo mình, thậm chí khiến họ mở\nlòng chấp nhận tất tần tật những gì chúng ta nói một cách vô tư không đắn\nđo.\nOwen D. Young Từng khuyên rằng:” Người nào có khả năng đặt mình\ntrong hoàng cảnh người khác, thấu hiểu được những suy nghĩ tâm tư của họ\nthì không cần phải lo lắng về bất kỳ điều gì của tương lai; vì người đó chắc\nchắn sẽ thành công.”\nLời khuyên này đặc biệt đúng với phụ nữ thời nay – những người được\ntrời ban cho sự nhạy cảm cao độ, đã và đang ngày cangfkhawngr định vị\nthế quan trọng của mình trong công sở cũng như trên thương trường.\nTrong một khu dân cư ở bang Ohio nước Mỹ, có một cửa hàng bán đồ\ndùng học tập và văn phòng nọ đã đổi chủ đến bảy lần trong bốn năm. Mỗi\nmột người chủ đó đã đến đây, cố gắng thu hút và giữ chân khách hàng bằng\nđủ cách: các chương trình khuyến mãi, giảm giá và quà tặng liên tục, trình\nbày lại các tủ kính và kệ trừng bày thật bắt mắt. Nhưng tất cả họ vẫn thất\nbại trong việc tăng doanh số. Khách háng vẫn cứ thích đến mua ở một\nchuỗi cửa hàng bách hóa cách xa chỗ đó bốn trăm nét.\nNgười chủ thứ tám của cửa hàng học cụ là một đôi vợ chồng. Người\nchồng là thương binh, gặp khó khăn trong việc giao tiếp. Người vọ nooit\nbật với nụ cười tỏa nắng và có khả năng nhớ tên tất cả các khách đến mua\nhàng bất kể là người mới hay khách quen. Cũng như những người chủ\ntrước, những ngày đầu bán hàng của đôi vợ chồng này rất vắng khách.\nNhưng chính câu chào của bà vợ đã dần dần tạo nên sự khác biệt. Đó\nkhông phải là một câu “ Chào buổi sáng” vô hồn như chúng ta thường\nnghe. Đó là những câu chào khác nhau được dành riêng cho Từng khách\n\nnhư “Xin chào Julie!” hoặc “Buổi sáng tốt lành nhé ông Brown!” Bà ấy cá\nnhân hóa mối quan hệ của mình với Từng khách hàng và ông chồng bắt\nchiếc làm theo. Bất kỳ khách nào đặt chân vào cửa tiệm của ông bà cũng\ncảm thấy mình được chào đón niềm nở và trở thành người quan trọng, mặc\ndù có thể học chỉ đến đó để mua vài thứ đồ lặt vặt hoặc dùng bốt điện\nthoại. Thế là tiếng lành đồn xa.\nTrong câu chuyện trên, uy tín( thuộc phạm trù Danh Tiếng) và sự\nthuận tiện( thuộc phạm trù Bản Thân) đã Thôi Miên Cảm Xúc người mua\ntốt hơn so với việc giảm giá trong quá trình cải thiện dich vụ của một cửa\nhàng nhỏ nhằm đáp ứng nhu cầu của khách hàng. Cần nhớ, khách hàng\ncũng là con người. Hãy đánh động chính xác vào Tử huyệt cảm xúc của họ,\nrồi sẽ trung thành với bạn mãi mãi!\nNgày nay, với những nguyên tắc liên quan đến đối nhân xử thế, sản\nphẩm và dich vụ càng lúc càng đồng nhất với nhau hơn. Mọi cuộc cạnh\ntranh trên thương trường cũng như trong cuộc sống thực chất đều là những\ncuộc ganh đua xem ai là người có thể thâm nhập sâu hơn vào tâm trí đối\nphương, người nghe, khách hàng, bệnh nhân, khán giả, vân vân và vân vân.\nVà bạn sẽ không thể lamg được điều này nếu không nắm bắt được đúng\nhướng cảm xúc của đối tượng mình nhắm đến.\nLời nói và hành động là những phương thức giao tiếp phổ biến hơn cả.\nTuy nhiên, vẫn có nhiều trường hợp mà ngôn ngữ viết lại là công cụ hiệu\nquả trội hơn trong việc thâm nhập tâm trí con người, đánh động cảm xúc\ncủa họ và tạo ra một chuỗi hiệu ứng liên hoàn thú vị.\n\nVào khoảng 8 giờ sáng thứ hai nọ, trong lúc tôi đang mòn mỏi chờ xe\n\nbuýt, một học viên cũ của tôi đề nghị chở tôi đến ga tàu điện ngầm bằng ô-\ntô của mình.\n\n“Thật may là gặp được em ở đây”, tôi nói, “Xe buýt hôm nay trễ nải\nquá, khiến thầy cũng trễ giờ đi làm luôn.”\n“Thầy đừng lo”, anh ta đáp. “Em bảo đảm sẽ đưa thầy đến ga tàu điện\nngầm đúng giờ”.\n“Trong tình trạng tắc đường thế này sao?”\n“Thầy cứ lên xe thì biết”, cậu ta trả lời với nụ cười đầy ẩn ý. “Chỉ cần\ntác động vào điểm thôi miên cảm xúc thích hợp là chuyện gì cũng xong –\nchính thầy vẫn luôn dạy tụi em thế mà.”\nĐường giao thông lúc bấy giờ ngập xe tải và ô-tô bốn bánh. Thế là cậu\nhọc trò cũ của tôi đưa tay báo hiệu trước khi rời khỏi lề đường, khiến cho\ntất cả các xe khác đi chậm lại, thậm chí dừng hẳn lại để nhường lối cho\nchúng tôi đi! Khi chúng tôi tiến đến phần đường tắc nghẽn nghiêm trọng,\ncậu ấy alwpj lại động tác ra hiệu ban nãy. Suốt một quãng đường đi dài hai\nmươi phút, các xe khác liên tiếp nhường đường cho chúng tôi đi một cách\nkì diệu. Cậu học trò vui tính bỗng chốc trở thành “Ông hoàng đường phố”,\nkhông xe nào dám động đến.\nKhi gần đến ga tàu điện ngầm, cậu ấy ra hiệu bằng tay trái, tất cả các\nxe đang chạy ngang hàng hoặc phía sau chúng tôi đều đi chậm lại hoặc\ndừng hẳn, để sau đó tôi có thể xuống xe an toàn! Không một chiếc xe tải\nnào dám hùng hổ vượt qua chúng tôi khi ấy.\n\nChỉ khi tôi nhìn thấy cậu ấy lái xe ra về, tôi mới khám phá ra lý do.\nMột tấm bảng ghi chữ đỏ nổi bật được dán ngay dưới của kính phía sau xe.\nCậu học trò cũ của tôi – một tay lái lụa có bằng ô-tô trên 15 năm – đã in lên\nđó ba chữ có sức thôi miên cảm xúc hoành tráng đến nỗi bất kì bác tài nào\nkhác trên đường nhìn thấy cũng phải ái ngại.\nĐó là ba chữ: XE TẬP LÁI\nKhông cần biết các xe khác đnag vội vàng hay hùng hổ cỡ nào. Chỉ\ncần họ nhìn thấy ba chữ trên, nỗi lo sợ về tai nạn giao thông và sự an toàn\nbản thân kèm nỗi sợ mất tiền bạc không nhỏ ngay lập tức trỗi dậy!\nCòn bạn, bạn có e ngại không nếu nhìn thấy ba chữ đó khi lái xe trên\nđường?\nSự thực là, cậu học trò cũ của tôi gắn tấm bảng đó lên xe vì một lí do\nchính đáng. Chẳng là trước đó một năm, vợ cậu ta muốn tập lái xe ô-tô.\nMột người nào đó đã tặng cô ấy một quyển cẩm nang lái xe mà trong đó có\nđoạn’...Chân thắng là bạn, chân ga là thù...” Sau khi cậu học trò cũ của tôi\nxin được giấy phép tập lái cho vợ mình, cậu ta đảm nhiệm luôn việc huấn\nluyện lái xe và ngồi ngay bên cạnh cô ấy để hướng dẫn. Có lẽ do ảnh\nhưởng Tử nội dung cuốn cẩm nang nên vô cớ cô cợ cứ liên tục đạp thắng,\nkhiến cho anh chồng nhiều phen khiếp vía vì việc thắng gấp có thể khiến\ncậu ta đâm đầu nứt sọ vào kính xe phía trước bất kỳ lúc nào. Để đảm bảo\nan toàn cho cả hai và những người đi đường khác, cậu ta bèn ứng dụng\nthuật thôi miên cảm xúc để tìm ra giải pháp: dán tấm bảng XE TẬP LÁI\nphía sau xe.\n\nSau lần chở tôi đến ga tàu điện ngầm đúng giờ một cách ngoạn mục\ngiữa tình hình kẹt xe, cậu học viến cũ của tôi quyết định tháo dỡ tấm bảng\nXE TẬP LÁI khỏi xe. Cậu thấy rằng việc lạm dụng nó sẽ khiến mọi người\nnghi ngờ về động cơ thực sự của cậu!', '2026-02-28 07:58:09'),
	(10, 5, 1, 'Dẫn nhập', 'Nhà giả kim cầm lên một quyển sách mà ai đấy trong đoàn người đã mang đến. Lật qua những trang sách, ông ta thấy câu chuyện về Narcissus.\n\nNhà giả kim biết về huyền thoại của Narcissus, một chàng trai trẻ hàng ngày quỳ bên một hồ nước để trầm tư về vẽ đẹp của chính mình. Anh ta quá say mê về mình, một buổi sáng nọ, chàng trai rơi vào hồ nước và chết đuối. Nơi chàng ngã xuống, một bông hoa được sinh ra, và được gọi là narcissus – hoa thủy tiên.\n\nNhưng không phải tác giả của quyển sách đã kết thúc quyển sách như vậy.\n\nÔng ta nói rằng khi Thủy Tiên chết, những nữ thần của rừng xanh đã xuất hiện và thấy rằng hồ vốn là chứa nước ngọt đã biến thành hồ nước mặn.\n\n“Tại sao hồ nước khóc?” những nữ thần hỏi.\n\n“Tôi khóc cho Thủy Tiên,” hồ nước trả lời.\n\n“À, chẳng có gì ngạc nhiên khi hồ nước khóc cho Thủy Tiên,” họ nói, “vì mặc dù chúng tôi luôn luôn đeo đuổi chàng ta trong rừng thẩm, hồ nướcmột mình có thể có thể trầm tư về vẻ đẹp của anh ta gần bên bên tay.”\n\n“Nhưng …Thủy Tiên có xinh đẹp không?” hồ nước hỏi.\n\n“Ai có thể hơn hồ nước để biết việc này? Những nữ thần nói trong sự ngạc nhiên. “Xét cho cùng, mỗi ngày, bên cạnh bờ của hồ nước mà chàng trai trẻ quỳ xuống để suy tư về anh ta!”\n\nHồ nước im lặng một chốc. Sau cùng nó nói:\n\n“Tôi khóc cho Thủy Tiên , nhưng chưa bao giờ tôi để ý rằng Thủy Tiên xinh đẹp. Tôi khóc bởi vì, mỗi lần chàng ta quỳ xuống bên cạnh bờ của tôi, tôi có thể thấy, sâu trong đôi mắt ấy, phản chiếu vẻ đẹp của chính tôi.”\n\n“Một câu chuyện tình thật tuyệt “, nhà giả kim nghĩ như thế.\n\nClifford E. Lander chuyển dịch\n\n****\n\nChàng trai tên là Santiago. Bụi rơi lả chả khi chàng trai cùng đàn cừu tiến vào một ngôi nhà thờ bỏ hoang. Mái nhà đã rơi rớt từ lâu, một cây sung dâu to lớn đã mọc nơi mà tượng thánh từng ngự chốn ấy.\n\nChàng ta quyết định dừng chân nơi đây một đêm. Chàng trai đã nhìn để chắc là cả đàn cừu đã đi vào qua cánh cổng đổ nát, rồi thì dựng một vài thanh gỗ chắn ngang để phòng ngừa những con cừu chạy lạc trong đêm. Không có những con cáo ở trong vùng này, nhưng đã một lần có những con cừu lạc mất trong đêm, và chàng trai ta phải mất cả ngày hôm sau để tìm chúng.\n\nChàng trai đã quét sàn bằng chiếc áo khoác của mình và nằm xuống, dùng quyển sách mà cậu ta vừa đọc xong để gối đầu. Chàng đã tự nói với chính mình rằng chàng sẽ bắt đầu đọc những quyển sách dày hơn: chúng sẽ lâu hết hơn và sẽ là những chiếc gối thoải mái hơn.\n\nTrời vẫn còn tối khi chàng thức dậy, và nhìn lên, chàng có thể thấy những vì sao xuyên qua nữa mái nhà thờ đổ nát.\n\nChàng muốn ngủ thêm một tí nữa, chàng trai nghĩ như thế. Chàng đã có một giấc mơ giống như một tuần trước đây, và một lần nữa chàng đã thức dậy khi giấc mơ chưa chấm dứt.\n\nChàng trai ngồi dậy, và cầm lấy cây gậy chăn cừu, bắt đầu đánh thức đàn cừu vẫn còn yên giấc. Chàng trai chú ý rằng, chẳng bao lâu khi chàng tỉnh giấc , hầu hết đàn cừu cũng bắt đầu cựa quậy thức dậy. Hình như có một năng lực huyền bí hòa quyện cuộc sống của chàng với đàn cừu, người đã chăn dắt chúng hai năm qua, hướng dẫn chúng qua những vùng thôn dã để tìm thức ăn và nước uống. “Chúng đã quá quen và quá biết thời khắc của mình”, chàng lẩm bẩm như thế. Nghĩ về điều ấy một lúc, chàng nhận thấy rằng có thể có một cách khác: là chàng đã quá quen thuộc với thời khắc của chúng.\n\nNhưng cũng có những con nào đấy cần một thời gian dài hơn để thức dậy. Chàng phải thúc từng con một với cây gậy chăn cừu, gọi tên mỗi con. Chàng luôn luôn tin rằng mỗi con cừu có thể hiểu những gì chàng nói. Vì vậy có những lần chàng đọc cho chúng nghe những phần trong những cuốn sách đã gây ấn tượng với chàng, hay khi chàng nói với chúng về sự cô đơn hay hạnh phúc của một người chăn cừu trên những cánh đồng. Thỉnh thoảng chàng có thể bình phẩm với chúng về những sự việc chàng đã thấy ở những thôn xóm mà chúng đã qua.\n\nNhưng vài ngày vừa qua, chàng đã chỉ nói với chúng một duy nhất một điều: cô thiếu nữ, con gái của người thương gia sống trên làng mà chúng sẽ đến trong khoảng ba, bốn ngày tới. Chàng chỉ đến làng ấy một lần vào năm trước. Người thương gia chủ của một gian hàng đồ khô, và ông ta luôn luôn yêu cầu, những con cừu phải được cắt lông trước mắt ông ta, để ông ta không bị gian dối. Một người bạn đã nói với chàng về cửa hàng ấy, và chàng trai đã đưa đàn cừu đến đấy.\n\n“Tôi muốn bán một ít lông cừu”, chàng trai nói với người thương gia.\n\nCửa hàng rất bận rộn, và ông chủ yêu cầu người chẳn cừu phải đợi đến chiều. Vì vậy chàng ngồi trên bậc thang của cửa hàng và lấy quyển sách từ trong túi xách ra đọc.\n\n“Tôi không biết, những người chăn cừu có thể đọc sách”. một giọng thiếu nữ vang lên phía sau lưng chàng trai.\nCô gái thuộc loại đặc biệt của vùng Andalusia, Tây Ban Nha, với mớ tóc đen bay bồng bềnh, và đôi mắt mơ huyền gợi nhớ lại những kẻ chinh phục Ma-rốc.\n\n“Ô, thường thì tôi học nhiều ở những con cừu của tôi hơn là từ những quyển sách”, cậu ta trả lời. Suốt hai tiếng đồng hồ họ nói chuyện với nhau, cô ta nói rằng cô ta là con gái người thương gia, và nói chuyện về đời sống trong làng, nơi mà ngày này cũng giống như những ngày khác. Người chăn cừu kể cho cô ta nghe về vùng thôn dã của Andalusia, và liên hệ với những mẫu chuyện về những thị trấn khác nhau mà chàng đã từng qua. Thật là một thay đổi thích thú từ nói chuyện với những con cừu đến nói chuyện với một cô gái.\n\n“Làm thế nào cậu học đọc?” cô gái hỏi.\n\n“Cũng giống như mọi người,” chàng trai nói. “Ở trường”.\n\n“Ồ, nếu cậu biết đọc, tại sao cậu chỉ là một người chăn cừu.\n\nChàng trai lẩm bẩm một câu trả lời cho phép chàng lẫn tránh đáp lại câu hỏi của cô gái. Chàng trai chắc rằng cô bé sẽ không bao giờ hiểu được. Chàng trai lãng sang kể những câu chuyện về những cuộc hành trình của chàng, và sự rạng rở của cô gái, đôi mắt Ma-rốc mở rộng với sợ hãi và kinh ngạc. Thời gian trôi qua, chàng trai tự thấy mình ao ước rằng , ngày này đừng bao giờ chấm dứt, và ba cô gái sẽ mãi bận rộn để chàng có thể chờ đợi trong ba ngày. Chàng nhận ra rằng, chàng cảm thấy những điều gì mà chàng chưa từng kinh nghiệm trước đây: khát vọng một nơi dừng chân vĩnh viễn cho cuộc sống. Với cô bé với mái tóc đen tuyền, những ngày tháng của chàng sẽ không bao giờ giống như trước nữa.\n\nNhưng cuối cùng người thương gia xuất hiện, ông ta bảo chàng trai cắt lông những con cừu. Ông ta trả tiền mớ lông cừu và bảo chàng trai chăn cừu sẽ trở lại năm tới.\n\n°°°\n\nVà giờ đây chỉ còn ba bốn ngày nữa là chàng sẽ trở lại làng mình. Chàng trai thích chí, nhưng cùng lúc cũng không thấy thoải mái: có thể cô bé đã quên chàng. Hàng khối người chăn cừu đã đến cửa hàng để bán lông cừu.\n\n“Chẳng hề gì”, chàng trai nói với đàn cừu. “Mình biết những cô gái khác ở những nơi khác”.\n\nNhưng trong con tim, chàng trai biết rằng có vấn đề. Và chàng ta biết rằng những người chăn cừu giống như những thủy thủ và giống như những người du hành, hay thương gia đường trường, luôn luôn tìm thấy một thị trấn nơi có những người làm cho họ quên đi những thích thú, vô tư lự dong ruỗi với cuộc đời.\n\nHoàng hôn đang buông xuống, và chàng trai hướng đàn cừu về phía mặt trời mọc. Chúng chẳng bao giờ phải đắn đo suy nghĩ quyết định, chàng trai nghĩ. Có thể đấy là tại sao chúng luôn luôn ở gần bên mình.\n\nChúng duy chỉ quan tâm đến thức ăn và nước uống. Cho đến khi nào chàng trai vẫn có thể tìm thấy những đồng cỏ tốt nhất ở Andalusia, chúng vẫn sẽ là bạn của chàng. Vâng, những ngày của chúng thì luôn luôn giống nhau, với sự dường như không chấm dứt của những giờ khắc giữa bình minh và hoàng hôn; và chúng chẳng bao giờ đọc một quyển sách trong tuổi trẻ của chúng, và không hiểu gì khi chàng kể cho chúng nghe những khung cảnh của phố thị. Chúng chỉ bao gồm có thức ăn và nước uống, và trong trao đổi, chúng thông thường cho những bộ lông của chúng, bầy đàn của chúng và – một lần trong đời – thịt của chúng.\n\nNếu mình trở thành một hung thần hôm nay, và quyết định giết chúng, từng con một, chúng sẽ trở nên cảnh giác chỉ sau khi hầu hết bầy đàn của chúng bị tàn sát, chàng trai nghĩ như vậy. Chúng tinh tưởng mình, và chúng quên bản năng chính chúng thế nào, bởi vì mình hướng dẫn chúng để nuôi dưỡng.\n\nChàng trai ngạc nhiên với suy nghĩ của mình. Có thể nhà thờ, với cây dâu sung mọc trong ấy, đã ám ảnh. Nó là nguyên nhân để chàng có một giấc mơ lần thứ hai giống như lần trước, và nó làm chàng cảm thấy giận dỗi đối với đàn cừu trung thành của chàng. Chàng trai uống một ít rượu vang còn lại từ bửa ăn tối đêm trước, và kéo chiếc áo khoác sát với thân thể hơn. Chàng biết rằng một vài giờ nữa với mặt trời ló dạng ở chân mây, hơi ấm trở nên gay gắt hơn, chàng không thể lùa đàn cừu xuyên qua cánh đồng. Nó là thời gian tất cả những người Tây Ban Nha yên giấc suôt mùa hè. Nóng bức cho đến khi trời sẩm tối, và đấy là thời gian chàng phải mang nặng chiếc áo khoác của mình. Nhưng khi nghĩ để phàn nàn sức nặng của nó, chàng nhớ rằng, nhờ chiếc áo khoác, chàng mới có thể chống chọi với cái lạnh của hoàng hôn.\n\nChúng ta phải chuẩn bị cho sự thay đổi, chàng trai nghĩ, và cảm ơn chiếc áo khoác nặng và ấm.\n\nChiếc áo khoác có mục tiêu và lợi ích của nó, và chàng trai cũng thế. Mục tiêu trong đời sống là để du hành, và, sau hai năm đi bộ qua vùng Andalusia, chàng đã biết tất cả những phố thị trong vùng. Chàng dự tính trong chuyến viếng thăm này, để giải thích cho cô bé làm thế nào một người chăn cừu có thể dễ dàng học đọc. Đấy là chàng tham dự học ở một trường đạo cho đến khi chàng mười sáu tuổi. Bố mẹ chàng muốn chàng trở thành một tu sĩ, và đấy là nguyên nhân tự hào của một gia đình nông dân bình thường. Họ làm việc vất vả chỉ vì thực phẩm và nước uống, giống như đàn cừu. Chàng đã học tiếng La-tinh, Tây Ban Nha, và triết học. Nhưng từ lúc nhỏ, chàng muốn biết thế giới, và điều này quan trọng đối với chàng trai hơn là biết về Đấng Tạo Hóa -Thượng đế và học về tội lỗi của loài người. Một buổi chiều, trong một lần thăm viếng gia đình, chàng tập trung hết cam đảm nói với bố chàng rằng chàng không muốn trở thành một tu sĩ mà chàng muốn du hành.\n\n“Này con, người từ mọi miền trên khắp thế giới đã đi qua ngôi làng này”, người cha nói. “Họ đến để tìm những thứ mới, nhưng khi họ rời đi họ vẫn căn bản là một người như khi họ đến. Họ leo lên những ngọn núi để thấy những lâu đài, và họ kết luận rằng quá khứ thì tốt đẹp hơn chúng ta bây giờ. Họ có tóc vàng, hay da sạm nắng, nhưng căn bản, họ cũng giống như những người đang sống tại đây.”\n\n“Nhưng con muốn thấy những lâu đài trên thành phố nơi họ sống,” chàng trai giải thích.\n\n“Những người đấy, khi họ thấy đất đai của chúng ta, nói rằng họ muốn sống nơi đây mãi mãi,” cha chàng tiếp tục.\n\n“Ô, con muốn thấy đất đai của họ và xem họ sống thế nào,” chàng trai bé nói.\n\n“Những người đến đây có rất nhiều tiền để chi dụng, vì thế họ có thể dùng để cho những cuộc du hành,” cha chàng nói, “Đối với chúng ta, những người duy nhất có thể du hành là những kẻ chăn cừu.”\n\n“Tốt thôi, thế thì con sẽ là một người chăn cừu!”\n\nCha chàng không nói gì nữa. Ngày hôm sau, ông ta giao cho người con trai một cái túi nhỏ chứa bên trong là ba đồng tiền vàng cổ Tây Ban Nha.\n\n“Cha nhặt được chúng vào một ngày trên cánh đồng. Cha muốn nó là một phần của tài sản thừa kế của con. Nhưng hãy dùng chúng để mua một đàn cừu cho con. Đưa chúng đến những cánh đồng, và một ngày nào đấy con sẽ học được rằng vùng thôn dã của chúng ta là tuyệt diệu nhất, và những người đàn bà của chúng ta là xinh đẹp nhất.”\n\nVà ông ta cầu nguyện, hổ trợ năng lực cho cậu con trai của ông. Chàng trai có thể thấy cái nhìn chăm chăm của cha chàng một sự khao khát có thể, tự chính ông ta, du hành vào thế giới – một khao khát vẫn đang sống động, mặc dù cha chàng phải chôn vùi nó, trải qua hàng năm trời, gánh nặng của khó khăn vì nước để uống, thực phẩm để ăn, và vẫn cùng một nơi để ngủ trong đời sống của ông ta.', '2026-02-28 08:04:28'),
	(11, 5, 2, 'Nhà Giả Kim', 'Chân trời đã ửng hồng, và đột nhiên mặt trời xuất hiện. Chàng trai nghĩ lại mẫu đối thoại với bố mình, và cảm thấy vui vẻ; chàng đã thấy nhiều lâu đài và gặp nhiều thiếu nữ (nhưng không có ai được như cô gái chàng đã gặp lần trước đây). Chàng có một chiếc áo khoác, một quyển sách mà chàng có thể đổi quyển sách khác, và một đàn cừu. Nhưng quan trọng nhất là, chàng có thể sống hàng ngày như chàng mong ước. Nếu chàng chán nản với những cánh đồng của Andalusia, chàng có thể bán đàn cừu, và tiến về phía biển cả. Cùng lúc chàng cũng đã đủ về biển, chàng đã biết những phố thị khác rồi, những thiếu nữ khác, và những cơ hội khác nhau để vui sướng hạnh phúc. Ta không thể tìm thấy Thượng đế trong trường dòng, chàng nghĩ như thế, khi chàng nhìn mặt trời lên.\n\nBất cứ khi nào có thể, chàng tìm đến một con đường mới để du hành. Chàng chưa bao giờ ở trong ngôi giáo đường đổ nát trước đây, thay vì du hành qua những khu vực ấy nhiều lần. Thế giới thật bao la và vô tận; chàng chỉ có thể cho phép đàn cừu xuyên qua lối ấy trong một thời gian, và chàng sẽ khám phá những việc thích thú khác. Vấn đề là chúng không biết rằng chúng đang đi trên những con đường mới mỗi ngày. Chúng không thấy những cánh đồng mới mẻ và những mùa và thời tiết thay đổi. Tất cả chúng nghĩ về thực phẩm và nước uống.\n\nCó thể chúng ta cũng trên con đường ấy, chàng trai lẩm bẩm. Ngay cả ta – Ta có bao giờ nghỉ đến những thiếu nữ khác từ khi ta gặp cô gái con ông thương gia. Nhìn mặt trời, chàng tính toán rằng chàng sẽ đến Tarifa trước khi đứng bóng. Nơi ấy, chàng có thể đổi một cuốn sách mới dày hơn, rót rượu vang vào trong bình, cạo râu, và cắt tóc; chàng đã chuẩn bị cho một cuộc gặp gở với những cô gái, và chàng không muốn nghĩ việc có thể có những gã chăn cừu khác, với đàn cừu đông hơn, đã đến đấy trước chàng và nắm tay cô gái.\n\nCó thể có một giấc mơ hiện thực làm cho cuộc sống thích thú, chàng nghĩ, khi nhìn một lần nữa vị trí của mặt trời và nhìn bước chân của mình. Chàng bổng nhớ rằng, ở Tarifa, có một bà lão giải thích những giấc mơ.\n\n°\n\nBà lão đưa chàng đến một gian phòng phía sau nhà bà ta; nó tách biệt với phòng ở của bà bởi một bức màn chuỗi. Trong phòng trang trí một bức hình thánh tâm chúa Giê-su trên bàn, và hai cái ghế.\n\nBà lão ngồi xuống, và cũng bảo chàng ngồi xuống. Rồi thì bà ta chắp tay lại và cầu nguyện.\n\nNó giống như âm thanh cầu nguyện của những người Gypsy. Chàng trai đã có kinh nghiệm với những người Gypsy trên đường; họ cũng du hành, nhưng họ không có những đàn cừu. Người ta nói rằng, những người Gypsy chuyên sống để lừa gạt người khác. Nó cũng nói rằng Gypsy có thỏa thuận với ma quỷ, và họ bắt cóc trẻ con về khu trại thần bí của họ, buộc chúng làm nô lệ. Khi còn bé chàng luôn luôn sợ chết và sợ bị những người Gypsy bắt cóc, nổi ám ảnh này trở lại khi thấy bà lão nắm hai tay chàng trong đôi tay bà.\n\nNhưng bà ta có Trái tim thánh thiện của Chúa Giê-su ở đấy, chàng ta nghĩ, cố gắng trấn tỉnh chính mình. Chàng không muốn đôi tay chàng run lên, cho bà lão thấy chàng sợ. Chàng đọc thầm kinh Cha chúng tôi.\n\n“Rất thích thú” bà lão nói, không bao giờ rời mắt bà ta khỏi đôi tay của chàng, và rồi thì bà ta lại im lặng.\n\nChàng trai trở nên khiếp sợ. Đôi tay chàng run lên, và bà lão nhận biết điều ấy. Chàng nhanh chóng vung tay mình ra.\n\n“Tôi không đến đây để xem bói”, chàng nói, chàng cảm thấy hối hận. Chàng nghĩ ngay rằng tốt hơn là trả tiền rồi rời khỏi đây dù không học được gì, vì rằng chàng đã quá chú trọng đến giấc mơ tái diễn.\n\n“Cậu đã đến vì rằng cậu có thể học về những giấc mơ của cậu”, bà lão nói. “Và những giấc mơ là ngôn ngữ của Thượng đế. Khi ngài nói bằng ngôn ngữ của chúng ta, tôi có thể diễn dịch lại ngài đã nói gì. Nhưng nếu ngài nói bằng ngôn ngữ tâm linh, thì chỉ cậu mới có thể hiểu được mà thôi. Nhưng, bất cứ nó là gì, tôi cũng sẽ tính tiền cho cuộc nói chuyện này.”\n\nMột sự lừa đảo khác, chàng nghĩ. Nhưng chàng quyết định liều lĩnh một phen. Một người chăn cừu luôn luôn làm một cơ hội liều lĩnh với những con sói và với khô hạn, và điều ấy làm đời sống của một người chăn cừu thích thú hơn.\n\n“Tôi đã từng có cùng một giấc mơ hai lần”, chàng ta nói. “Tôi mơ thấy tôi ở trên cánh đồng với đàn cừu của tôi, khi một bé con xuất hiện và đùa với đàn cừu, tôi không thích người ta làm như vậy, vì đàn cừu sợ hải những người lạ. Nhưng trẻ con dường như có thể nô đùa với chúng mà không làm chúng sợ hải. Tôi không hiểu tại sao. Tôi không biết là làm thế nào thú vật biết tuổi tác của con người.”\n\n“Nói thêm cho tôi nghe về giấc mơ của cậu,” bà lão nói. “Tôi phải trở lại lo nấu ăn, và vì lẽ cậu không có nhiều tiền. Tôi không thể có nhiều thời gian với cậu.”\n\n“Cô bé con đến nô đùa với đàn cừu lặng lẻ một lúc,” chàng trai tiếp tục, có hơi khó chịu một tí. “Và đột nhiên, cô bé nắm hai tay tôi, và đưa tôi đến những kim tự tháp Ai Cập.”\n\nChàng dừng lại một lúc để xem bà lão có biết kim tự tháp là gì không. Nhưng bà ta không nó gì.\n\n“Rồi thì, tại những kim tự tháp Ai Cập,” – chàng ta nói ba chữ cuối cùng một cách thật chậm, để bà lão có thể hiểu – “cô bé nói với tôi, “Nếu anh đến đây, anh sẽ tìm thấy một kho tàng ẩn dấu.” Và , khi cô ta định chỉ cho tôi địa điểm chính xác của kho tàng, tôi bừng tỉnh dậy. Cả hai lần.”\n\nBà lão im lặng một lúc. Rồi thì bà cầm tay chàng trai và xem một cáchchăm chú cẩn thận.\n\n“Tôi sẽ không lấy tiền cậu bây giờ,” bà ta nói. “Nhưng tôi muốn một phần mười của kho tàng, nếu cậu tìm thấy nó.”\n\nChàng trai cười to sung sướng. Chàng sẽ có thể tiết kiệm được một ít tiền chàng có bởi vì giấc mơ của kho tàng ẩn dấu!\n\n“Nào, hãy diễn giải giấc mơ,’’ chàng nói.\n\n“Trước tiên, phải thề với tôi. Thể rằng cậu sẽ cho tôi một phần mười của kho tàng như một trao đổi với những gì tôi sẽ nói với cậu.”\n\nChàng chăn cừu đã thề như thế. Bà lão yêu cầu chàng thề một lần nữa trong khi nhìn vào bức hình Thánh tâm của Chúa Giê-su.\n\n“Nó là giấc mơ của ngôn ngữ thế giới,” bà ta nói. “Tôi có thể diễn giải nó, nhưng lời diễn giải rất khó. Đấy là tại sao tôi cảm thấy rằng tôi xứng đáng có một phần trong những gì cậu tìm thấy.”\n\n“Và đây là lời diễn giải: cậu phải đi đến những Kim tự tháp Ai Cập. Tôi chưa từng nghe về chúng, nhưng, nếu một bé con chỉ chúng cho cậu, chúng phải hiện hữu. Ở đấy cậu sẽ tìm thấy kho tàng và nó sẽ làm cậu trở nên một người giàu có.”\n\nChàng trai ngạc nhiên và rồi thì cáu kỉnh. Chàng không cần tìm bà lão cho việc này ! Nhưng rồi chàng ta nhớ rằng chàng không trả thù lao.\n\n“Tôi không muốn phí thời gian cho chuyện này”, chàng nói.\n\n“Tôi nói với cậu rằng giấc mơ của cậu là một giấc mơ khó. Nó là những vấn đề đơn giản trong đời sống nhưng thật ngoại lệ; chỉ những người thông minh mới có thể hiểu được. Và vì lẽ tôi không thông minh sáng suốt. Tôi phải học những thứ nghệ thuật khác, như là xem chỉ tay chẳng hạn.”\n\n“Ô, làm thế nào tôi đến được Ai Cập?”\n\n“Tôi chỉ diễn giải giấc mơ. Tôi không biết làm thế nào để nó biến thành hiện thực. Đó là tại sao tôi phải sống nhờ những gì con gái tôi cung cấp cho.”\n\n“Và nếu tôi chẳng bao giờ đến được Ai Cập?”\n\n“Thì tôi sẽ không có thù lao. Đây không phải là lần đầu tiên.”\n\nVà bà lão yêu cầu chàng ta rời khỏi nhà bà ta, nói rằng bà ta đã phí quá nhiều thời gian cho chàng.\n\n–\n\nChàng trai trở nên chán nản; và quyết định sẽ chẳng bao giờ tin vào những giấc mơ một lần nữa. Nhớ lại rằng còn hằng khối việc phải làm: phải vào chợ để kiếm cái gì cho vào bụng, đổi lấy một quyển sách mới dày hơn, và tìm một chiếc băng ghế để nếm chai rượu vang vừa mới mua. Ban ngày trời nóng, và rượu vang cũng được hâm nóng lại. Đàn cừu thì ở ngoài cổng của thành phố, trong chuồng của một người bạn. Chàng ta biết rất nhiều người trong thành phố. Đấy cũng là lời quyến rũ cho những cuộc hành trình của chàng – chàng luôn luôn kết thêm nhiều bạn mới, và không phải dành tất cả thời gian của mình với họ. Khi người ta thấy cùng những người mỗi ngày, va và điều ấy đã xảy ra với chàng trong trường dòng, họ cuối cùng trở thành một phần trong đời sống của người ấy. Và rồi thì họ muốn người ấy thay đổi. Nếu ai đấy không như là những gì họ muốn, những người khác trở nên tức giận. Mọi người dường như có một quan điểm rõ ràng rằng người kia nên hướng đời sống của mình như thế nào nhưng không ai nghĩ về hướng đi cho chính mình.Chàng ta quyết định chờ đợi cho đến khi mặt trời chìm sâu hơn một tí ở phía chân mây để hướng dẫn đàn cừu xuyên qua những cánh đồng. Ba ngày nữa từ bây giờ, chàng ta có thể thấy con gái người thương gia.\n\nChàng ta bắt đầu đọc quyển sách vừa mới mua. Ngay trong trang đầu nó diễn tả một buổi lể an tang. Và tên của những người tham dự rất khó đọc. Nếu có bao giờ viết một quyển sách, chàng ta nghĩ, chàng sẽ chẳng bao giờ nêu tên một người một lần, và vì thế người đọc sẽ chẳng phải lo lắng để nhớ hàng khối tên tuổi.\n\nKhi chàng ta cuối cùng có thể tập trung trên những gì mình đang đọc, chàng thích quyển sách hơn; buổi an tang đã diễn ra trong một ngày tuyết rơi, và chàng hân hoan chào đón cảm giác lạnh lẽo. Khi đang đọc, một ông lão ngồi bên cạnh chàng ta và cố gắng gợi chuyện.\n\n‘’Họ đang làm gì thế?’’ ông lão hỏi, chỉ vào những người trong khu chợ.\n\n‘’Làm việc’’, chàng ta trả lời khô khốc, tỏ vẻ đang tập trung trong việc đọc sách của chàng.\n\nThật sự chàng đang nghĩ về việc xén lông những con cừu trước mặt con gái người thương gia, để cô nàng có thể thấy chàng là người có thể làm những việc khó khăn. Chàng đã nghĩ tưởng về cảnh ấy nhiều lần; mỗi lần, cô bé trở nên hứng thú khi chàng ta giải thích rằng những con cừu phải được xén lông từ phía sau lên phía trước. Chàng ta cố gắng nhớ lại những câu chuyện hấp dẫn liên hệ đến việc chàng xén lông cừu. Hầu hết những chuyện ấy là từ những quyển sách chàng đọc, nhưng chàng sẽ kể chúng như từ những kinh nghiệm của chính chàng. Cô nàng sẽ chẳng bao giờ biết sự khác biệt, bởi vì cô ta không biết đọc.\n\nTrong khi ấy ông lão, vẫn cố gắng tiếp tục cuộc nói chuyện. Ông ta nói rằng ông mệt mõi và khát nước, và hỏi nếu chàng trai có thể cho ông ta một ít rượu trong bình rượu vang của chàng. Chàng ta trao cho ông bình rượu, hy vọng rằng ông sẽ để cho chàng yên tĩnh một mình.\n\nNhưng ông lão muốn noi chuyện, và ông hỏi chàng đang đọc quyển sách gì. Chàng trai mất kiên nhẫn để lịch sự và định dời sang một băng ghế khác, nhưng cha chàng đã từng dạy rằng nên tôn trọng những người già cả. Nên chàng đưa cho ông lão quyển sách – vì hai lý do: thứ nhất, tự chàng, không chắc đọc tựa đề thế nào; và thứ hai, là có thể ông lão không biết đọc, ông chắc chắn sẽ cảm thấy xấu hổ và quyết định tự chuyển sang một băng ghế khác.\n\n“Hmm…” ông lão nói, nhìn mọi phía của quyển sách, như có thể nó là những đối tượng lạ kỳ. “Đây là một quyển sách quan trọng, nhưng thật đau lòng.\'\'\n\nChàng trai ngạc nhiên. Ông lão biết đọc và đã đọc quyển sách ấy. Và nếu quyển sách đau lòng, như lời ông lão nói, chàng vẫn còn thời gian để đổi quyển sách khác.\n\n“Nó là một quyển sách nói cũng giống như những quyển sách khác trên thế giới đã nói”, ông lão tiếp tục. “Nó diễn tả những người không có khã năng để chọn lựa cho chính mình một cuộc sống cá nhân, những huyền thoại cá nhân. Và cuối cùng nó kết luận rằng mọi người tin tưởng một sự tin tưởng sai lầm vĩ đại của thế giới.”\n\n“Điều gì là sự tin tưởng sai lầm vĩ đại của thế giới?” chàng trai hỏi, và hoàn toàn ngạc nhiên.\n\n“Nó là như thế này: có một thời điểm nào đấy trong đời sống chúng ta, chúng ta không thể kiểm soát những gì xảy ra cho chúng ta, và đời sống chúng ta trở nên bị chi phối bởi định mệnh. Đó là một sự tin tưởng sai lầm vĩ đại của thế giới.”\n\n“Điều đó chẳng bao giờ xảy ra đối với tôi.” chàng trai nói. “Họ muốn tôi trở thành một tu sĩ, nhưng tôi quyết định trở thành một người chăn cừu.”\n\n“Tốt hơn đấy”, ông lão nói. “Bởi vì thật sự cậu muốn du hành”.\n\n“Ông lão biết những gì mình đang nghĩ”, chàng trai tự nói với mình. Trong khi ấy, ông lão vẫn đang lật những trang sách, dường như chưa muốn trao trả quyển sách lại tí nào. Chàng trai để ý rằng, áo quần ông lão rất lạ. Ông ta trông giống như những người Ả Rập, mà không thường thấy trong những vùng này. Châu Phi thì chỉ cách vài giờ từ Tarifa; chỉ phải vượt qua một eo biển hẹp bằng thuyền. Những người Ả Rập thường xuất hiện trong thành phố, mua sắm và ca ngâm những lời cầu nguyện của họ vài lần trong ngày.\n\n“Ông từ đâu đến?” chàng trai hỏi.\n\n“Từ nhiều nơi”.\n\n“Không ai có thể từ nhiều nơi,” chàng trai nói. “Tôi là một người chăn cừu, và tôi đi qua nhiều vùng,nhưng tôi chỉ đến từ một nơi – từ một thành phố gần một lâu đài cổ. Đấy là nơi tôi sinh ra.”\n\n“Tốt thôi, thế thì chúng ta có thể nói rằng lão sinh ra ở Salem.”\n\nChàng trai không biết Salem ở chốn nào, nhưng cũng không muốn hỏi, sợ rằng chàng sẽ phơi bày kiến thức kém cõi của mình. Chàng nhìn những người ở khu chợ một lúc; người ta đang đến và đi, và tất cả dường như rất bận rộn.\n\n“Thế thì, Salem giống thế nào?” chàng hỏi, cố gắng tìm thêm một số tin tức.\n\n“Nó giống như nó đã từng.”\n\nChưa có một dấu vết gì cả. Nhưng chàng biết rằng Salem không ở trong vùng Andalusia. Nếu có, thì chàng đã từng nghe nói đến.\n\n“Và ông đã làm gì ở Salem?” chàng thêm.\n\n“Lão làm gì ở Salem à?” Ông lão cười to. “À, ta là vua của Salem!”\n\nNgười ta thường nói những điều kỳ lạ, chàng nghĩ. Thỉnh thoảng tốt hơn là một người chăn cừu, không nói bất cứ điều gì. Và tốt hơn là tiếp tục một mình với quyển sách của mình. Người ta kể về những câu chuyện tuyệt diệu vào lúc bạn muốn nghe nó. Nhưng khi nói chuyện với người ta, họ nói những điều thật kỳ lạ mà bạn không biết làm thế nào để tiếp tục mẫu đối thoại.\n\n“Lão tên là Melchizedek,” ông lão nói. “Cậu có bao nhiêu con cừu?”\n\n“Đủ thôi”, chàng trai nói. Chàng có thể thấy là ông lão muốn biết thêm về cuộc sống của chàng.\n\n“À, thế thì, chúng ta có một vấn đề. Lão không thể giúp cậu nếu cậu cảm thấy cậu có đủ với đàn cừu.”\n\nChàng trai trở nên khó chịu. Chàng không yêu cầu giúp đở. Rõ là ông lão đòi uống rượu của chàng và đã bắt đầu cuộc nói chuyện.\n\n“Đưa lại tôi quyển sách,” chàng trai nói. \'\'Tôi phải đi và tập họp đàn cừu của tôi để lên đường.”\n\n“Đưa lão một phần mười đàn cừu của cậu,” ông lão nói, “và tôi sẽ nói với cậu làm thế nào để tìm kho tàng ẩn dấu.”\n\nChàng trai nhớ lại giấc mộng, và đột nhiên mọi thứ rõ ràng với chàng. Bà lão không lấy tiền thù lao, nhưng ông lão – có thể là chồng bà ta – đang cố gắng tìm cách để lấy thêm nhiều tiền hơn trong việc trao đổi những tin tức về những gì ngay cả không có thật. Ông lão này chắc chắn cũng là một người Gypsy.\n\nNhưng trước khi chàng có thể nói bất cứ gì, ông lão đứng lên, cầm lấy gậy, và bắt đầu viết trên cát của khu chợ. Có cái gì chiếu sáng lấp lánh từ ngực ông lão thật mãnh liệt làm chàng choá mắt ngay trong phút chốc. Với một thời khắc quá nhanh với những người trong lứa tuổi của chàng, chàng che đậy bất cứ điều gì với cái mũ của lão. Khi thị lực trở lại bình thường, chàng trai có thể đọc những gì ông lão đã viết trên cát.\n\nĐấy, trên cát của khu chợ của một thành phố nhỏ, chàng đọc tên của cha, mẹ và tên tu viện mà chàng đã từng học ở đấy. Chàng ta đọc tên cô gái con người thương gia, mà chàng chưa hề biết,và chàng đọc những thứ mà chàng chưa từng nói cho bất cứ ai nghe.', '2026-02-28 08:04:57'),
	(12, 5, 3, 'TA LÀ VUA CỦA SALEM', '“Tai Tại sao một ông vua lại nói chuyện với một người chăn cừu?” chàng trai hỏi, sợ và bối rối.\n\n“Có vài lý do. Nhưng để nói điều quan trọng nhất là cậu đã thành công trong việc khám phá Huyền thoại cá nhân của cậu.”\n\nChàng trai chẳng biết “Huyền thoại cá nhân của một người “là gì.\n\n“Nó là những gì cậu luôn luôn muốn hoàn thành. Mỗi người, khi họ trẻ, biết “Huyền thoại cá nhân” là gì, đấy là niềm khao khát, ước vọng hay tâm nguyện của mỗi người.\n\n“Tại thời điểm ấy của cuộc sống của họ, mọi thứ rõ ràng và mọi thứ là có thể. Họ không sợ để mơ ước, và mong mỏi khao khát mọi thứ họ muốn thấy xảy ra trong đời sống của họ. Nhưng, khi thời gian trôi qua, một năng lực huyền bí bắt đầu khống chế họ và nó sẽ không thể để cho họ nhận thấy Huyền thoại cá nhân của họ.”\n\nKhông có điều gì ông lão nói làm chàng trai cảm thấy có ý nghĩa gì nhiều. Nhưng chàng trai muốn biết “năng lực huyền bí” là gì; con gái người thương gia sẽ thật ấn tượng khi chàng kể cho cô nghe.\n\n‘’Nó là năng lực xuất hiện làm tiêu cực, nhưng thật sự chỉ cho người ta nhận thấy thế nào là “Huyền thoại cá nhân”. Nó chuẩn bị tâm linh và ý chí của cậu, bời vì có một chân lý vĩ đại trên hành tinh này: bất cứ cậu là ai, hay bất cứ nó là gì cậu làm, khi cậu thật sự muốn những gì, bời vì nó là khao khát nguyên sơ trong tâm linh của vũ trụ. Nó là sứ mệnh của cậu trên trái đất này.”\n\n“Ngay cả khi tất cả những gì cậu muốn làm là du hành? Hay kết hôn cùng con gái của người thương gia tơ sợi.’’\n\n“Vâng hay ngay cả đi tìm kiếm kho tàng. “Tâm linh của thế giới” được nuôi dưỡng bởi những người hạnh phúc và an lạc. Và ngay cả bởi sự bất hạnh, thèm muốn, và ganh tị. Để nhân thức vận mệnh một con người chỉ là nghĩa vụ, bổn phận hay trách nhiệm của người ấy. Tất cả là một.\n\n“Và khi cậu muốn điều gì, toàn thể vũ trụ hiệp sức lại để giúp cậu đạt đến điều ấy.’’\n\nCả hai người cùng im lặng một lúc, quán sát khu chợ và những người trong phố. Ông lão nói trước.\n\n“Tại sao cậu lại chăm sóc đàn cừu?”\n\n“Vì tôi muốn du hành.”\n\n“Khi còn là trẻ con, người đó cũng muốn du hành. Nhưng anh ta quyết định trước tiên là mua cửa hàng làm bánh và để dành một ít tiền qua một bên. Khi anh ta già, anh ta sẽ dùng tiền ấy để đi đến châu Phi. Anh ta không bao giờ nhận thấy rằng con người có thể, bất cứ lúc nào trong đời mình, làm bất cứ gì mình mơ ước.”\n\n“À, anh ta nghĩ như thế,” ông lão nói. “Nhưng những người làm bánh thì quan trọng hơn những người chăn cừu. Những người làm bánh có nhà, trong khi những người chăn cừu sống lang thang giữa trời mây. Các bậc cha mẹ tốt hơn là thấy con cái của họ thành thân với một người làm bánh hơn là một người chăn cừu.”\n\nChàng trai nghe nhói trong tim, nghĩ về con gái người thương gia. Chắc chắn có một người làm bánh trong phố.\n\nÔng lão tiếp tục, “Về lâu về dài, người ta nghĩ gì về những người chăn cừu và những người làm bánh trở nên quan trọng hơn cho chính “huyền thoại cá nhân” của họ.”\n\nÔng lão lật qua những trang sách, và đọc một trang nào đấy. Chàng trai chờ đợi, và rồi thì làm gián đoạn ông lão đang đọc như chính chàng từng bị làm đứt quảng. “Tại sao ông lại nói với tôi tất cả những điều này?’’\n\n“Bởi vì cậu đang cố gắng nhận thức “huyền thoại cá nhân của cậu. Và cậu đang ở ngay thời điềm mà cậu muốn vứt bỏ tất cả.”\n\n“Và đó là khi lão luôn xuất hiện trong hoàn cảnh như thế?”\n\n“Không phải luôn luôn trong cách này, nhưng lão luôn luôn xuất hiện trong một hình thức khác. Thỉnh thoảng lão xuất hiện trong hình thức của một giải pháp khác, hay một ý kiến tốt. Tại những lúc khác, tại thời điểm ác liệt, lão làm nó dễ dàng hơn để những việc xảy ra. Có những việc khác lão cũng làm, những hẩu hết mọi người không nhận biết lão đã làm những việc ấy.”\n\nÔng lão liên hệ đến việc, một tuần trước, ông bị thúc đẩy để xuất hiện trước một người thợ mõ, và dưới hình dáng của một hòn đá. Người thợ mõ đã từ bỏ tất cả để đi tìm ngọc lục bảo. Trong năm năm anh ta đã làm việc ở một dòng sông nào đấy, và đã thử nghiệm hằng trăm nghìn hòn đá để tìm ngọc lục bảo. Người thợ mõ gần như thất vọng hoàn toàn và muốn từ bỏ việc tìm ngọc, ngay tại lúc,nếu anh ta chỉ cần thử thêm một hòn đá nữa, chỉ một hòn nữa thôi, anh ta sẽ tìm thấy viên ngọc của anh ta. Vì lẽ, người thợ mõ đã hy sinh tất cả cho “huyền thoại cá nhân” của mình, ông lão quyết định tham dự vào. Ông ta chuyển biến mình thành một hòn đá lăn vào chân người thợ mõ. Người thợ mõ, với tất cả giận dữ và thất vọng của năm năm không kết quả, lượm hòn đá lên và vất qua một bên. Nhưng anh ta đã vung quá mạnh khiến hòn đá vở ra, và đấy, trong lòng hòn đá vở, là viên ngọc lục bảo đẹp nhất trên thế giới.\n\n“Người ta học, trong buổi đầu của cuộc đời họ, đấy là lý do cho sự hiện hữu của họ”, ông lão nói, với một chút gay gắt, cay đắng. “Cũng có lẻ đấy là tại sao người ta đã bỏ cuộc quá sớm. Nhưng nó là như thế.”\n\nChàng trai nhắc ông lão rằng ông ta đã nói những việc về kho tàng ẩn dấu.\n\n“Kho tàng bị che phủ bởi sức mạnh của dòng nước lũ, và nó bị chôn vùi bởi những lý do giống như vậy,”. Nếu cậu muốn học về kho tàng của chính cậu, cậu sẽ phải cho tôi một phần mười đàn cừu của cậu.”\n\n“Thế con một phần mười kho tàng của tôi thì thế nào?”\n\nÔng lão nhìn có vẽ bất mãn. “Nếu cậu bắt đầu bằng hứa hẹn những gì cậu ngay cả chưa có, cậu sẽ mất đi khát vọng để hành động trước việc tìm kiếm nó.”\n\nChàng trai nói với ông lão rằng chàng đã hứa cho một phần mười kho tàng cho bà lão Gypsy.\n\n“Gypsy là những chuyên gia tìm ra những người để làm những việc ấy,” ông lão thì thào. “Tốt đấy, trong bất kỳ trường hợp nào, cậu cũng đã học được rằng mọi thứ trong đời sống có cái giá của nó. Đây là những gì mà những Chiến sĩ của Ánh sáng cố gắng để dạy.”\n\nÔng lão đưa lại quyển sách cho chàng trai.\n\n“Ngày mai, cũng lúc này, hãy đem đến cho lão một phần mười của đàn cừu của cậu. Và lão sẽ nói cho cậu làm thế nào để tìm thấy kho tàng. Chúc một buổi trưa tốt lành.”\n\nVà ông ta biến mất ở một góc của khu chợ.\n\n°\n\nCHÀNG TRAI MỘT LẦN NỮA BẮT ĐẦU ĐỌC QUYỂN SÁCH CỦA MÌNH, nhưng chàng không thể nào tập trung được. Chàng bị căng thẳng và khó chịu, bởi vì biết rằng ông lão đúng. Chàng đi đến cửa hàng bánh và mua một ổ bánh mì, nghĩ rằng không biết có nên nói cho người thợ làm bánh những gì ông lão nói về anh ta hay không. Thỉnh thoảng tốt hơn là cứ để những sự việc như nó là, chàng ta nghĩ như thế, và quyết định không nói gì cả. Nếu chàng nói bất cứ gì, người thợ làm bánh có thể phải mất ba ngày để suy nghĩ về việc bỏ tất cả, mặc dù anh ta đã quen với cung cách của những sự việc như thế. Chàng có thể cưỡng lại một cách chắc chắn nguyên nhân làm cho người thợ làm bánh băn khoăn. Vì vậy chàng dạo vòng quanh khu phố, và tự tìm thấy một tòa nhà ở đấy, với một cửa sổ nơi ấy bán vé cho những người muốn đi châu Phi. Và chàng ta biết rằng Ai Cập ở Châu Phi.\n\n“Tôi có thể giúp gì cho cậu?” người đàn ông phía sau cửa sổ hỏi.\n\n“Có thể ngày mai”, chàng trai đáp, và rời đi. Nếu bán một con cừu, chàng ta có thể đủ tiền mua một vé qua bên kia bờ biển, đến Phi Châu. Ý nghĩ làm chàng ta khiếp đảm.\n\n“Một người nữa mơ mộng,” người bán vé nói với người phụ tá ông ta, nhìn chàng trai bước đi. “Cậu ta không có đủ tiền để du hành.”\n\nTrong khi đứng nơi cửa bán vé, chàng trai nhớ lại đàn cừu và quyết định chàng nến trở lại cuộc sống của người chăn cừu. Trong hai năm, chàng đã học mọi thứ của một người chăn cừu: chàng biết xén lông cừu thế nào, làm thế nào săn sóc những con cừu cái mang thai, và làm thế nào để bảo vệ những con cừu trước những con sói. Chàng ta biết tất cả những cánh đồng cỏ và những bải cỏ của Andalusia. Và chàng biết giá cá hợp lý cho từng con cừu trong đàn của chàng.\n\nChàng quyết định trở lại chuồng thú của bạn chàng bằng con đường dài nhất có thể. Khi chàng bước trở lại lâu đài của thành phố, chàng làm gián đoạn quảng đường trở lại, và trèo lên dốc đá dẫn đến đỉnh của bức tường thành. Từ đấy chàng có thể nhìn thấy Phi Châu từ xa. Ai đấy đã từng nói với chàng rằng từ đấy người Ma- rốc đã đến để chiếm toàn bộ Tây Ban Nha.Chàng có thể thấy toàn bộ thành phố nơi chàng ngồi kể cả khu chợ nơi chàng nói chuyện với ông lão. Nguyền rủa thời gian nói chuyện với ông lão, chàng nghĩ. Chàng chỉ đến phố này để tìm một người đàn bà có thể diễn giải giấc mơ của chàng. Cả bà lão lẫn ông lão đều không cảm xúc gì trước việc chàng là một người chăn cừu. Họ là những cá nhân cô đơn hay như những ẩn sĩ, những kẻ không tin tưởng vào những thứ gì, và không hiểu rằng những người chăn cừu đã trở nên lưu luyến với đàn cừu của họ. Chàng ta biết mọi thứ về từng thành viên trong đàn cừu của chàng: chàng biết con nào chân khập khểnh, con nào sẽ sinh trong vòng hai tháng tới, và con nào lười biếng nhất. Chàng biết xén lông chúng thế nào, và mổ thịt chúng thế nào. Nếu chàng rời đàn cừu, chúng sẽ đau khổ.\n\nGió đã nổi lên. Chàng biết gió này: người ta gọi nó là gió đông Địa Trung Hải, vì theo làn gió này người Ma-rốc đã đến từ Levant từ vùng cuối phía đông của Địa Trung Hải.\n\nLàn gió gia tăng cường độ. Giờ đây, tôi đang giữa đàn cừu và kho tàng của tôi, chàng trai nghĩ như thế. Chàng phải chọn lựa giữa những gì chàng đã quen thuộc và những gì chàng muốn có. Đấy cũng là cô gái con người thương gia, những cô ta không quan trọng như đàn cừu của chàng, bởi vì cô nàng không lệ thuộc vào chàng. Chàng chắc chắn rằng chẳng có gì khác với cô nàng vào ngày chàng xuất hiện: với nàng, mỗi ngày đều như nhau, và khi mỗi ngày đều giống như ngày kế tiếp, bởi vì người ta đã vô tình không nhận thấy những việc tốt lành xảy ra trong đời sống của họ mỗi ngày khi mặt trời lên.\n\nTôi đã lìa bố tôi, mẹ tôi, và phố thị lâu đài sau lưng. Họ đã quen với việc tôi lìa xa, và tôi cũng thế. Đàn cừu cũng sẽ với sự không có mặt của tôi ở đấy, chàng nghĩ như thế.\n\nMột đôi trai gái đã ngồi trên băng ghế nơi chàng nói chuyện với ông lão, và họ hôn nhau.\n\n“Người làm bánh…” chàng nói với chính mình, và không nghĩ trọn ý nghĩ. Làn gió đông của Địa Trung Hải vẫn tiếp tục mãnh liệt hơn, và chàng cảm thấy sức mạnh của nó trên mặt chàng. Làn gió ấy đã mang người Ma-rốc đến, vâng, những nó cũng mang đến mùi hương của sa mạc và của những người đàn bà che mặt. Nó đã từng mang với nó mồ hôi và những giấc mơ của những người đàn ông một lần ra đi vì điều chưa biết, và vì vàng và mạo hiểm- và vì những Kim tự tháp. Chàng cảm thấy ghanh tỵ với tự do của làn gió, và thấy rằng chàng có thể có thứ tự do như gió ấy. Không có gì có thể giữ chàng lại trừ chàng. Đàn cừu, cô gái, và những cánh đồng của Andalusia chỉ là những bước trên con đường đến “huyền thoại cá nhân” hay niềm mơ ước của chàng.\n\nNgày hôm sau, chàng trai gặp ông lão, lúc giữa trưa đứng bóng. Chàng mang theo chàng sáu con cừu.\n\n“Tôi ngạc nhiên,” chàng trai nói. “Bạn tôi mua liền tất cả những con cừu kia, anh ta nói rằng anh ta đã luôn mơ ước thành một người chăn cừu, và đấy là một điềm tốt. ’’\n\n“Nó luôn như thế”, ông lão nói. “Nó gọi là điểm chính yếu của niềm vui thích. Khi cậu chơi bài lần đầu tiên, cậu hầu như chắc chắn để thắng. Sự khởi đầu may mắn.”\n\n“Tại sao thế?”\n\n“Bời vì có một sức mạnh muốn cậu nhận thấy “huyền thoại cá nhân” của cậu; nó là mùi hương với vị nếm của sự thành công.”\n\nRồi thì ông lão bắt đầu kiểm soát đàn cừu, và ông ta thấy một con bị khập khiểng. Chàng nói rằng điều ấy không quan trọng, vì đấy là con cừu thông minh nhất đàn, và cho lông nhiều nhất.\n\n“Kho tàng ở đâu?” chang hỏi.\n\n“Nó ở Ai Cập, gần những Kim Tự Tháp.”\n\nChàng trai hoảng hốt giật mình. Bà lão cũng nói như thế. Nhưng bà chẳng đòi thù lao gì cả.\n\n“Để tìm thấy kho tàng, cậu sẽ phải theo những điềm lành. Thượng Đế đã chuẩn bị con đường cho mọi người tiến bước. Cậu chỉ phải đọc những điềm mà ngài đã chỉ cho cậu.”\n\nGiống như những con dế, và giống như con ngựa trời; những con bò sát và …\n\n“Đúng vậy,” ông lão nói, có thể đọc được tư tưởng chàng. “Như ông nội cậu đã dạy. Đây là những điềm tốt.”\n\nÔng lão giở nón ra, và chàng trai như bị đập vào mắt những gì chàng thấy. Ông lão mang một tấm giáp che ngực bằng vàng khối nạm những viên đá quý. Chàng trai nhớ lại ánh sáng chói mắt mà chàng đã chú ý ngày hôm trước.\n\nÔng lão thật sự là một vị vua! Ông phải cải trang để tránh chạm trán với những tên trộm.\n\nViên trắng là biểu lộ “vâng\'\' và viên đen “không”. Khi cậu không thể đọc những điềm chỉ dẫn, chúng sẽ giúp cậu việc ấy. Luôn luôn hỏi những câu hỏi đúng mục tiêu.\n\n“Nhưng, cậu có thể, cố gắng để tự quyết định chính mình. Kho tàng ở tại những Kim Tự Tháp; điều cậu đã biết. Nhưng lão cố nài nỉ thù lao sáu con cừu bởi vi lão giúp cậu để cậu quyết định rõ ràng tự chính mình.”\n\nChàng trai đặt những viên đá trong túi nhỏ của mình. Và từ lúc ấy, chàng sẽ tự mình làm những quyết định của chính mình.\n\n“Đừng quên là mọi thứ cậu phải giải quyết khi chạm trán là chỉ một thứ và không có thứ gì khác. Và đừng quên ngôn ngữ của những điềm chỉ dẫn. Và trên tất cả, đừng quên bước theo “huyền thoại cá nhân” hay niềm mong ước của mình và phải đi xuyên qua cho đến hồi kết cuộc.\n\n“Nhưng trước khi từ giả, lão muốn kể cho cậu nghe một câu chuyện nhỏ.”\n\n“Một người chủ gian hàng nào đấy gửi con ông ta để học về bí mật của hạnh phúc từ một ngươi thông thái nhất thế giới. Cậu bé vòng quanh qua một sa mạc trong bốn mươi ngày, và cuối cùng đến một lâu đài xinh đẹp, trên đỉnh một ngọn núi. Nơi nhà thông thái ở.\n\n“Tốt hơn là tìm một nguời thánh thiện, mặc dù vậy, người anh hùng của chúng ta, tiến vào phòng chính của lâu đài, thấy một sự ồn ào náo nhiệt của việc: những nguời trao đổi buôn bán vào ra, những người đang nói chuyện ở những góc phòng, một dàn nhạc đang hoà tấu nhạc nhẹ, và có một bàn chứa đầy những đĩa thức ăn tuyệt vời nhất của những vùng trên thế giới. Nhà thông thái trao đổi với mọi người, và cậu bé phải chờ hai giờ trước khi đến phiên cậu ta được sự chú ý của nhà thông thái.\n\n“Ông ta lắng nghe một cách cẩn trọng những gì cậu bé giải thích tại sao cậu đến, nhưng ông nói với rằng cậu không có thời gian, rồi thì ông sẽ giải thích với cậu bí mật của hạnh phúc. Ông ta khuyên cậu bé nên dạo vòng quanh cung điện và trở lại trong vòng hai tiếng đồng hồ.\n\n“Trong khi ấy, ta muốn yêu cầu cậu làm một việc,” nhà thông thái nói, đưa cho cậu bé một muỗng uống trà có hai giọt dầu . “Khi cậu dạo quanh, mang theo muỗng dầu này và không được phép để giọt dầu rơi rớt.”\n\n“Cậu bé bắt đầu leo lên và đi xuống nhiều cầu thang của cung điện, giữ mắt trên muỗng dầu. Sau hai giờ, cậu bé trở lại phòng của nhà thông thái.\n\n“\'À, nhà thông thái hỏi, \'cậu có thấy tấm thảm Ba Tư được treo trong phòng ăn của ta? Cậu có thấy khu vườn mà những nhà chuyên môn phải mất mười năm để tạo nên? Cậu có chú ý những quyển sách bằng da trong thư viện của ta không?\'\n\n“Cậu bé giật mình hoảng hốt, và thú thật rằng cậu không quán sát bất cứ thứ gì. Quan tâm duy nhất của cậu ta là làm thế nào để không làm rơi những giọt dầu mà nhà thông thái đã giao cho cậu.\n\n“Thế thì hãy trở lại và quán sát thế giới tuyệt vời của ta,\' nhà thông thái nói. “Cậu không thể tin tưởng một người nếu cậu không biết nhà cửa của ông ta.\'\n\n“An tâm, cậu bé cầm muỗng và trở lại khám phá cung điện, lần này quán sát xem sét tất cả những công trình nghệ thuật trên trần nhà và trên những bức tường. Cậu ta thấy ngôi vườn, những hòn non chung quanh cậu, những đoá hoa xinh đẹp, và nếm thử mọi thứ cậu chọn lựa. Khi trở lại với nhà thông thái, cậu ta kể lại mọi thứ chàng đã ngắm qua.\n\n“Nhưng những giọt dầu ta đã giao cho cậu đâu?” nhà thông thái hỏi.\n\n“Nhìn xuống chiếc muỗng đang cầm, cậu bé thấy những giọt dầu đã biến mất tự bao giờ.\n\n“Ồ, đây là một lời chỉ bảo duy nhất mà ta có thể cho cậu,\' nhà thông thái nhất trong những nhà thông thái nói. “Bí mật của hạnh phúc là thấy tất cả những điều kỳ diệu trên thế giới, và đừng bao giờ quên những giọt dầu trên muỗng.”\n\nChàng trai chăn cừu không nói gì cả. Chàng hiểu câu chuyện vị vua già kể cho chàng nghe. Chàng chăn cừu có thể thích du hành, nhưng chàng chẳng bao giờ nên quên đàn cừu của chàng.\n\nÔng lão nhìn chàng trai và, với hai tay nắm lại, làm một vài điệu bộ kỳ lạ trên đầu chàng trai. Rồi thì, dẫn đàn cừu đi.', '2026-02-28 08:05:49'),
	(13, 4, 1, 'Hành trình kiếm tìm lợi nhuận.', 'Trang trại giun đất\nĐầu tiên người ta không thèm để ý đến bạn, sau đó người ta chế nhạo bạn, tiếp đến\nngười ta tấn công bạn, rồi cuối cùng thì bạn thắng.\nGANDHI\nTôi tin rằng Gandhi không hề biết tôi là ai khi tôi mới chín tuổi. Và chắc chắn tôi cũng\nchẳng biết ông ta là ai. Nhưng nếu Gandhi biết về những ảo tưởng và ước mơ thời thơ ấu\ncủa tôi về việc kiếm thật nhiều, thật nhiều tiền bằng cách nuôi và bán giun đất với số lượng\nlớn ra thị trường, thì có lẽ ông ta cũng sẽ đưa ra những câu răn tương tự thế này để khích lệ\ntôi trở thành người bán giun đất hàng đầu thế giới.\nNhưng đáng buồn là Gandhi lại chẳng ghé qua nhà tôi để trao cho tôi lời khuyên và sự\nthông thái của ông. Thay vào đó, trong ngày sinh nhật lần thứ chín của tôi, tôi nói với bố\nmẹ rằng tôi muốn họ lái xe đưa tôi tới ngôi nhà của chúng tôi ở bắc Sonoma, tới nơi có nhà\ncung cấp giun đất nổi tiếng nhất cả nước lúc bấy giờ. Nhà cung cấp ấy chẳng hề biết rằng tôi\nđang ấp ủ giấc mơ trở thành đối thủ lớn nhất của họ.\nBố mẹ tôi đã trả 33,45 đô-la cho một chiếc hộp đựng bùn chứa khoảng 100 con giun đất.\nTôi nhớ đã đọc một cuốn sách nói rằng khi cắt đôi con giun thì hai phần đó sẽ tiếp tục sinh\ntrưởng thành hai con giun. Điều đó nghe có vẻ thú vị, nhưng như thế có nghĩa là tôi sẽ phải\nlàm rất nhiều việc. Vì vậy, thay vào đó, tôi vạch ra một kế hoạch tốt hơn: Tôi tự tạo ra “một\nhộp giun” trong vườn nhà mình, chiếc hộp về cơ bản giống như chiếc hộp cát, có lưới thép\nmỏng dưới đáy. Thay vì đổ cát, tôi đổ đầy bùn và cho hơn một trăm con giun đất vào đó, để\nchúng được thoải mái trườn bò và sinh sôi nảy nở.\nHàng ngày, tôi lấy một chút lòng đỏ trứng rồi vùi xuống hộp giun đất. Tôi cho rằng điều\nđó sẽ giúp cho những con giun đất sinh sôi nhanh hơn, vì tôi thấy nhiều vận động viên\nchuyên nghiệp thường ăn trứng gà sống trong bữa sáng. Bố mẹ tôi không tin việc bán giun\nđất có thể giúp tôi trở nên giàu có như tôi mơ ước, nhưng họ vẫn để tôi nuôi giun đất bằng\nlòng đỏ trứng. Tôi cho rằng lý do duy nhất cho việc đó là vì họ không muốn các con ăn lòng\nđỏ trứng chứa nhiều cholesterol. Nếu những con giun đất kia ăn lòng đỏ trứng thì có nghĩa\nlà anh em tôi sẽ chỉ ăn lòng trắng trứng có lượng cholesterol thấp. Mẹ tôi luôn trông chừng\nđể chúng tôi không ăn những thứ có thể làm tăng lượng cholesterol. Tôi nghĩ bà đã đọc\nđược bài báo nói về cholesterol và đã khiến bà lo sốt vó lên.\nSau ba mươi ngày nuôi giun đất bằng lòng đỏ trứng gà, tôi quyết định kiểm tra kết quả\ncông việc của mình. Tôi bới lớp bùn lên để xem có con giun con nào ra đời không. Nhưng\nchẳng có con giun con nào cả. Tệ hơn, tôi cũng chẳng tìm thấy bất cứ con giun to nào. Tôi\nmất một giờ đào bới cẩn thận tất cả các lớp bùn trong hộp. Những con giun đất đã biến mất.\nCó thể chúng đã bò ra ngoài qua các mắt lưới ở dưới đáy hộp. Cũng có thể chúng bị chim\năn mất khi chúng sà xuống ăn lòng đỏ trứng gà.\nCông cuộc làm giàu từ giun đất của tôi đã thất bại hoàn toàn. Tôi nói với bố mẹ rằng\nnuôi giun chẳng có gì thú vị, nhưng sự thật là tôi rất buồn vì đã thất bại. Nếu Thomas\nEdison còn sống, hẳn ông sẽ dừng lại trước cửa nhà tôi và động viên tôi bằng quan điểm của\nông về thất bại:\nCon đường dẫn tới thành công của tôi cũng đã trải qua nhiều thất bại.\nTHOMAS EDISON\nCó vẻ như ông còn đang bận rộn với những phát minh, sáng chế của mình, vì thế, cũng\ngiống như Gandhi, ông đã không ghé nhà tôi. hay cũng có khi họ đang bận rộn chơi với\nnhau chăng.\nLớn lên\nBố mẹ tôi đã di cư từ Đài Loan sang Mỹ để học cao học tại Đại học Illinois, nơi họ gặp\nnhau và kết hôn. Mặc dù tôi sinh ra tại Illinois, nhưng những ký ức duy nhất đọng lại trong\ntâm trí tôi về quãng thời gian sống ở đó là trò nhảy cầu cao ba mét sáu và trò bắt đom đóm.\nNhững ký ức thuở nhỏ thường rất mờ nhạt nhưng tôi chắc rằng hai ký ức đó không liên\nquan đến nhau, vì tôi không cho rằng hồi hai tuổi tôi có thể bắt được một chú đom đóm\nkhi đang lơ lửng giữa không trung.\nKhi tôi lên năm, bố tôi xin được việc ở California, vì thế, gia đình tôi chuyển tới quận\nMarin County, nơi có cây cầu Cổng Vàng bắc qua, phía bắc San Francisco. Chúng tôi sống ở\nthung lũng Lucas. Nhà tôi cách trang trại Skywalker Ranch hai mươi phút đi xe, nơi\nGeorge Lucas\n(1)\ntừng sinh sống và làm việc.\nBố mẹ tôi là những người Mỹ gốc Á điển hình. Bố tôi là kỹ sư hoá cho công ty Chevron,\ncòn mẹ tôi là người làm công tác xã hội. Họ đặt kỳ vọng rất lớn vào thành tích học tập của\ntôi cũng như hai cậu em trai. Andy kém tôi hai tuổi, và bốn năm sau khi chúng tôi chuyển\ntới California, cậu em út David của tôi ra đời.\nKhông có nhiều gia đình người châu Á sinh sống tại Marin County, nhưng bằng cách\nnào đó bố mẹ tôi vẫn kết thân được với mười gia đình ở đây và các ông bố bà mẹ cùng các\ncon vẫn thường tụ tập, cùng ăn tối và giải trí. Những đứa trẻ thì xem ti vi, còn các ông bố bà\nmẹ thì tụ tập trong phòng khách và trò chuyện rôm rả về thành tích của con mình. Đó là\nmột nét văn hoá của người châu Á: thành tích của con cái được các bậc phụ huynh sử dụng\nnhư một thước đo thành công và địa vị của mình. Chúng tôi giống như những con bài trong\ntay các bậc cha mẹ vậy.\nTheo các bậc cha mẹ người châu Á, thành tích được chia thành ba loại khác nhau.\nLoại một là các thành tích học tập: có học hàm học vị cao, được tặng thưởng hay được xã\nhội công nhận, đạt được điểm SAT cao hay có tên trong đội tuyển toán của trường. Điều\nquan trọng nhất của tất cả những loại thành tích này là con em họ sẽ ghi danh vào trường\nđại học nào. Harvard là trường đại học mang lại quyền “khoe con” tối thượng.\nLoại hai là các thành tích trong sự nghiệp: trở thành bác sĩ hay đạt được học vị Tiến sĩ\nđược xem là thành tích cao nhất, vì trong cả hai trường hợp đó thì có nghĩa là bạn sẽ trở\nthành “Tiến sĩ Hsieh” hay “Bác sĩ Hsieh”.\nLoại ba là sự tinh thông âm nhạc: đa số trẻ em châu Á bị buộc phải học piano, violon\nhoặc cả hai. Và mỗi khi các gia đình tụ tập, những đứa trẻ phải chơi nhạc cho các ông bố bà\nmẹ nghe sau bữa tối. Hoạt động này bề ngoài có vẻ như là giúp mọi người thư giãn, nhưng\nthực chất, đó chính là cách để các bậc phụ huynh so sánh con mình với con người khác.\nBố mẹ tôi, cũng giống như những ông bố bà mẹ châu Á khác, rất nghiêm khắc trong việc\nnuôi dạy tôi để chiến thắng trong cả ba loại thành tích trên. Tôi chỉ được xem tivi một tiếng\nmỗi tuần. Đạt điểm A trong tất cả các môn học là điều hiển nhiên và muốn tôi phải luyện\ncác bài thi SAT suốt những năm học trung học và phổ thông. SAT là bài thi chuẩn phải làm\nvào năm cuối phổ thông, điều kiện để vào đại học. Nhưng bố mẹ muốn tôi sớm chuẩn bị\ncho kỳ thi đó khi tôi mới chỉ học lớp sáu.\nỞ trường trung học, tôi chơi bốn loại nhạc cụ: piano, violon, kèn và trống. Trong suốt\nnhững năm học này, tôi phải tập luyện mỗi loại nhạc cụ ba mươi phút từ thứ hai đến thứ\nsáu và một tiếng vào thứ bảy và chủ nhật. Suốt mùa hè, tôi đã phải tập luyện một tiếng mỗi\nngày cho mỗi loại nhạc cụ, đến nỗi tôi tin rằng đó chính là hình phạt tàn ác nhất cho những\nđứa trẻ muốn được hưởng thụ phần “nghỉ” trong “nghỉ hè”.\nNhưng tôi đã tìm ra một cách để vẫn có thể tận hưởng những ngày nghỉ cuối tuần và kỳ\nnghỉ hè. Tôi thức dậy rất sớm, từ 6 giờ sáng, trong khi bố mẹ vẫn còn đang say giấc. Tôi đi\nxuống nhà, nơi đặt chiếc đàn piano. Rồi thay vì chơi piano thật sự, tôi bật băng ghi âm bài\nnhạc tôi đã chơi từ trước. Đến 7 giờ, tôi trở lên phòng mình, khoá cửa lại và bật băng ghi\nâm một tiếng tôi tập violon. Không phải chơi đàn nên tôi có thời gian rảnh để đọc tạp chí\nBoy’s Life (Cuộc đời của những cậu bé).\nVà chắc bạn có thể hình dung, thầy giáo dạy piano và violon của tôi không thể hiểu tại\nsao tôi chẳng hề tiến bộ chút nào. Có lẽ họ cho rằng tôi là một học sinh chậm tiến. Còn với\ntôi, tôi không hiểu việc học cách chơi những loại nhạc cụ này sẽ mang lại lợi ích gì.\n(Hy vọng mẹ tôi không nổi điên lên khi đọc được những dòng này. Có lẽ tôi nên trả lại\ncho bà khoản tiền bà đã đầu tư cho việc học piano và violon của tôi).\nBố mẹ tôi, đặc biệt là mẹ tôi, vẫn luôn hy vọng tôi sẽ học trường Y hoặc sẽ lấy bằng tiến sĩ.\nHọ tin rằng giáo dục chính thống là điều quan trọng nhất, nhưng với tôi, hai mươi năm đầu\nđời được vạch sẵn dường như quá kiểm soát và ngột ngạt.\nCòn tôi lại chỉ quan tâm tới việc kinh doanh và nghĩ ra nhiều cách để kiếm tiền. Khi tôi\nlớn lên, bố mẹ luôn bảo tôi không phải lo nghĩ gì về tiền, chỉ cần tập trung vào học hành.\nHọ hứa sẽ chi trả toàn bộ học phí cho đến khi tôi trở thành bác sĩ hoặc tiến sĩ. Họ cũng hứa\nsẽ mua bất cứ loại quần áo nào tôi muốn. Thật may mắn cho họ là tôi chẳng hứng thú gì với\nthời trang nên chẳng bao giờ tôi xin tiền mua quần áo cả.\nTôi luôn mơ mộng tới việc kiếm tiền, vì với tôi tiền sẽ mang lại sự tự do để làm bất cứ gì\nmình muốn trong quãng đời còn lại. Có công ty riêng cũng đồng nghĩa là tôi được thoải\nmái sáng tạo và sống theo cách tôi muốn.\nTôi đã tổ chức nhiều đợt bán hàng “xôn” trong nhà xe suốt thời tiểu học. Khi tôi đã bán\nhết những thứ đồ bỏ đi của bố mẹ, tôi hỏi bạn bè xem liệu họ có thứ đồ gì muốn bán không.\nChúng tôi tập hợp những thứ đó lại và pha nước chanh bán kèm. Ý tưởng của chúng tôi là,\nngay cả khi mọi người không mua gì, thì ít nhất chúng tôi cũng vẫn bán được nước chanh\ncho họ. Chúng tôi đã kiếm được tiền từ việc bán nước chanh chứ không phải từ những món\nhàng lặt vặt kia.\nỞ trường trung học, tôi lại tìm cách khác để kiếm tiền. Tôi tìm được công việc giao báo,\nnhưng tôi nhanh chóng nhận ra rằng công việc này chính là cách các tờ báo địa phương\nlách luật lao động trẻ em. Sau khi tính toán, tôi thấy mình chỉ kiếm được có 2 đô-la mỗi\ngiờ.\nTôi bỏ việc giao báo và quyết định tự làm bản tin. Mỗi bản tin sẽ dày hai mươi trang,\ngồm những câu chuyện tôi viết, những trò giải đố ô chữ và truyện cười. Tôi in bản tin trên\nnền giấy vàng cam sáng, đặt tên là The Gobbler (Gà trống tây) và bán với giá 5 đô-la. Tôi đã\nbán được bốn bản cho bạn bè ở trường. Tôi nhận ra mình cần phải có nhiều bạn bè hơn,\nnhững người có đủ tiền để mua các bản tin, hoặc tôi cần tìm ra doanh thu từ nhiều nguồn\nkhác nữa. Vì thế, khi đi cắt tóc, tôi đưa cho chú thợ cắt tóc một tờ The Gobbler và hỏi liệu\nchú có muốn mua cả trang quảng cáo của kỳ tới với giá 20 đô-la hay không.\nKhi chú ấy đồng ý mua, tôi biết mình có thể làm điều gì đó hơn thế. Tất cả những gì tôi\ncần làm là phải bán được thêm bốn trang quảng cáo nữa để có 100 đô-la, số tiền tôi chưa\ntừng nhìn thấy trong đời. Đầy tự tin sau vụ làm ăn đầu tiên, tôi tới các cửa hiệu ngay cạnh\nhiệu cắt tóc và hỏi liệu họ có muốn đăng quảng cáo trên tờ bản tin sắp tới của tôi hay không\n- tờ tạp chí sẽ làm cả nước choáng váng.\nNhưng họ đều từ chối theo cách lịch sự nhất có thể. Vài tuần sau, tôi cho ra lò bản tin\nThe Gobbler số thứ hai. Lần này, tôi chỉ bán được hai bản.\nTôi quyết định dừng vụ kinh doanh này lại.\nCông việc thì quá nhiều mà bạn bè tôi thì hết sạch tiền để mua rồi.\nCậu em Andy và tôi đã từng chờ đợi mỗi kỳ tạp chí Boy’s Life hàng tháng và đọc nó\nkhông sót một từ. Mục yêu thích của tôi nằm ở gần cuối cuốn tạp chí − mục rao vặt giúp đặt\nmua những sản phẩm thú vị tôi chưa từng thấy, nhưng tôi biết mình muốn có chúng vào\nmột ngày nào đó. Có đủ thứ đồ ảo thuật và những vật dụng mới (ban đầu, tôi đã nghĩ khái\nniệm “mới” là “thực sự rất mới, rất ngầu”), có cả một bộ dụng cụ để biến một chiếc máy hút\nbụi thành một chiếc tàu đệm khí nhỏ.\nNhưng điều khiến tôi thích thú nhất là trang quảng cáo lớn ở cuối cuốn tạp chí, trưng\nbày tất cả các phần thưởng bạn có thể nhận được bằng việc bán thiệp. Nghe có vẻ rất đơn\ngiản: chỉ đi dạo quanh nhà hàng xóm, bán thiệp Noel (loại thiệp mà ai cũng cần, kể cả tôi),\ngiành thật nhiều điểm và đổi điểm lấy cái ván trượt hay một thứ đồ chơi nào đó tôi chưa\ntừng có và giờ rất muốn có.\nVì thế, tôi quyết định đặt mua một số thiệp và một cuốn catalog. Lúc này vẫn là kỳ nghỉ\nhè nên tôi có rất nhiều thời gian để gõ cửa từng nhà và chào hàng. Điểm dừng chân đầu\ntiên là nhà hàng xóm ngay cạnh nhà tôi.\nTôi đưa cho bà chủ nhà cuốn catalog có tất cả các mẫu thiệp Noel. Bà ấy trả lời tôi rằng\nbây giờ mới là tháng tám, còn lâu bà mới cần đến thiệp Noel. Tôi nghĩ bà ấy đúng. Tôi thật\nngu ngốc khi đi bán thiệp Noel vào tháng tám, thế nên đó cũng chính là điểm dừng chân\ncuối cùng của tôi.\nTôi trở về nhà, cố gắng nghĩ ra một ý tưởng kinh doanh nào đó ít yếu tố mùa vụ hơn.\nỞ trường tiểu học, tôi có một người bạn thân tên là Gustav. Chúng tôi thường làm mọi\nviệc cùng nhau, tụ tập ở nhà và diễn kịch cho các bậc phụ huynh nghe, dạy cho nhau những\nngôn ngữ bí mật và mật mã, và đến nhà nhau ngủ lại mỗi tuần.\nMỗi lần tôi đến nhà Gustav chơi, cậu ta lại cho tôi mượn một cuốn sách có tên Free\nStuff for Kids (Đồ miễn phí cho trẻ). Đó là cuốn sách tuyệt nhất từ trước đến giờ. Trong đó\ncó hàng trăm vật dụng miễn phí hoặc có giá dưới 1 đô-la mà trẻ em có thể đặt hàng, bao\ngồm bản đồ miễn phí, giấy dán tường giá 50 xu hoặc những sản phẩm dùng thử. Để có được\nmột sản phẩm, bạn phải viết một bức thư bỏ trong phong bì và gửi đến một địa chỉ (theo tôi\nđược biết, đó là phong bì có dán địa chỉ riêng), ngay cả đối với những sản phẩm có giá dưới\n1 đô-la, bạn cũng phải làm như vậy. Gustav và tôi đã xem hết lượt cuốn sách và đặt hàng tất\ncả các vật dụng mà chúng tôi thấy hấp dẫn.\nSau mười phút đứng chào bán thiệp Noel, tôi trở về nhà, đọc lại những mục phân loại\ntrong cuốn tạp chí Boy’s Life và nhìn thấy một bộ dụng cụ làm khuy áo có giá 50 đô-la. Bộ\ndụng cụ đó sẽ giúp bạn biến bất cứ một tấm hình hoặc một mẩu giấy nào nào thành một\nchiếc khuy áo sơ mi. Giá để làm một chiếc khuy là 25 xu.\nTôi bước tới giá sách, lục ra tất cả những cuốn sách đã mượn của Gustav từ những năm\ntrước nhưng chưa trả lại cậu ấy, rồi tôi tìm xem trong những cuốn sách đó có viết về công ty\nnào từng bán khuy áo làm từ ảnh chưa. Chẳng có công ty nào cả.\nVới tâm trạng vô cùng hứng khởi, tôi đánh máy một bức thư gửi tới nhà xuất bản của\ncuốn sách, vờ rằng tôi là một doanh nghiệp sản xuất khuy áo và muốn xuất hiện trong lần\nxuất bản năm tới của cuốn sách. Để việc giả vờ này giống thật hơn, tôi đã thêm vài ký hiệu\n“Dept.FSFK” vào địa chỉ thư của mình. FSFK là mật mã của tôi, cho cụm từ “Free Stuff For\nKids” (Vật dụng miễn phí cho trẻ em). Điều kiện của tôi là bọn trẻ phải gửi một bức hình,\nmột phong bì ghi sẵn địa chỉ nhà và 1 đô-la. Tôi sẽ làm một chiếc khuy áo từ tấm hình và\ngửi lại cho chúng bằng chiếc phong bì đã ghi sẵn địa chỉ. Tôi lãi 75 xu cho mỗi đơn đặt\nhàng.\nHai tháng sau, tôi nhận được hồi âm của nhà xuất bản. Họ nói rằng đề nghị của tôi đã\nđược chọn để xuất hiện trong cuốn sách kỳ tới. Tôi nói với bố mẹ rằng tôi đã đặt mua bộ\ndụng cụ làm khuy áo với giá 50 đô-la, cộng thêm 50 đô-la nữa cho các phụ tùng và tôi sẽ trả\nlại tiền cho bố mẹ sau một trăm đơn đặt hàng đầu tiên.\nTôi không cho rằng bố mẹ tôi tin vào lời hứa đó. Trước đây họ cũng từng nghe tôi nói sẽ\nkiếm được nhiều tiền như thế nào nếu bán được bản tin The Gobbler hay sau khi bán được\nhàng trăm tấm thiệp Noel. Nhưng vì tôi vẫn đạt học sinh giỏi nên tôi nghĩ họ sẽ cho phép\ntôi đặt mua bộ dụng cụ và phụ tùng làm khuy áo kia, xem như là phần thưởng cho nỗ lực\ncủa tôi.\nHai tháng sau, tôi nhận được một cuốn sách Free Stuff For Kids phiên bản mới. Cảm\nxúc trào dâng khi thấy địa chỉ nhà mình được in trong cuốn sách. Tôi đưa cuốn sách cho bố\nmẹ và chờ đợi những đơn hàng đầu tiên trong lo lắng.\nNgười đưa thư luôn đi trên một con đường quen thuộc. Nhà tôi nằm gần chân đồi và\nông ấy luôn bắt đầu hành trình của mình từ chân đồi nhưng ở phía bên kia đường, đi lên\nphía trên, rẽ xung quanh và lại xuống chân đồi. Vì thế, mỗi lần nghe thấy tiếng xe của người\nđưa thư ở phía bên kia đường, tôi biết rằng hai mươi phút sau người đưa thư sẽ đi đến nhà\ntôi, tôi đứng chờ sẵn ở bên ngoài để nhận thư. Thông thường, thư sẽ đến vào khoảng 1 giờ\n36 phút chiều.\nHai tuần sau khi cuốn sách xuất bản, tôi nhận được đơn đặt hàng đầu tiên. Tôi hồi hộp\nmở phong bì ra, bên trong là bức ảnh của một bé gái mười hai tuổi mặc một chiếc váy sọc\nvuông màu đỏ đang ôm một chú cún xinh xắn. Quan trọng hơn cả là bên trong còn có tờ 1\nđô-la. Tôi đã có vụ làm ăn đầu tiên! Tôi biến bức hình thành một chiếc khuy áo rồi gửi lại\ncho cô bé bằng chiếc phong bì đã ghi sẵn địa chỉ nhà cô bé. Tối hôm đó, tôi háo hức kể cho\nbố mẹ nghe về đơn hàng này. Tôi nghĩ họ đã khá ngạc nhiên thậm chí khi tôi chỉ nhận được\n1 đơn đặt hàng này. Tôi đưa cho họ tờ 1 đô-la và ghi vào nhật ký rằng khoản nợ đã giảm\nxuống chỉ còn 99 đô-la.\nNgày tiếp theo, tôi nhận được hai đơn hàng. Qua một đêm mà doanh số đã nhân đôi.\nSuốt hơn một tháng sau, có nhiều ngày tôi nhận được tới hơn mười đơn hàng. Cuối tháng\nđầu tiên, tôi đã kiếm được hơn 200 đô-la. Tôi đã trả hết nợ và kiếm được khá nhiều tiền ở\nđộ tuổi của mình. Tuy nhiên, tôi phải mất một tiếng mỗi ngày để làm những chiếc khuy áo.\nVào những ngày có nhiều bài tập về nhà, tôi không có thời gian để làm khuy áo nên có khi\ntôi đã để đơn hàng dồn đống tới cuối tuần. Suốt những ngày cuối tuần, tôi phải dành đến\nbốn năm tiếng làm khuy áo. Kiếm được nhiều tiền thật là tuyệt, nhưng phải ngồi lì trong\nnhà thì chẳng thú vị chút nào. Vì thế, tôi quyết định đã đến lúc cần đầu tư mua một chiếc\nmáy làm khuy bán tự động có giá 300 đô-la để nâng cao hiệu quả và năng suất làm việc.\nCông việc kinh doanh khuy áo của tôi đã mang lại khoản thu nhập ổn định 200 đô-la\nhàng tháng trong suốt những năm tôi học trung học. Bài học lớn nhất mà tôi học được là\nbạn có thể tạo ra một doanh nghiệp thành công qua hình thức đặt hàng qua thư, mà không\ncần gặp mặt trực tiếp.\nĐôi lúc khi quá bận, tôi vẫn nhờ tới sự trợ giúp của các cậu em. Tốt nghiệp cấp hai, tôi\nbắt đầu cảm thấy chán ngán công việc làm khuy áo mỗi ngày, vì thế tôi quyết định nhường\ncông việc kinh doanh cho cậu em Andy. Lúc đó, tôi nghĩ rằng tôi sẽ bắt đầu một công việc\nkinh doanh qua thư đặt hàng khác mà tôi đam mê hơn\nVào thời điểm đó, tôi không thể tưởng tượng được rằng việc làm khuy áo sau này lại trở\nthành công việc kinh doanh của gia đình tôi. Vài năm sau, Andy truyền nghề cho cậu em út\ncủa chúng tôi, David. Vài năm sau, chúng tôi ngừng đăng quảng cáo trên cuốn sách Free\nStuff For Kids và kết thúc công việc kinh doanh. Bố tôi được thăng chức và ông phải\nchuyển đến Hồng Kông, vì thế ông đã đưa mẹ tôi và cậu em David đi theo. Chẳng còn anh\nchị em ruột nào để David truyền nghề nữa.\nGiờ nghĩ lại, lẽ ra chúng tôi nên có một kế hoạch truyền nghề tốt hơn.\nDịch vụ điện thoại\nTôi nhớ tới ý tưởng rằng ngày đầu tiên của cấp ba không khác gì ngày cuối cùng của cấp\nhai. Khi đó, tôi cảm thấy mình đã trưởng thành hơn và mọi thứ cũng khác so với trước vì\ngiờ đây tôi đã là học sinh cấp ba.\nMột ngày nọ, khi đang lang thang trong thư viện, tôi phát hiện ra một phòng máy tính\nkhuất bên hông thư viện. Tôi đến gặp giáo viên dạy vi tính, cô Gore, người đã khuyên tôi\nnên đăng ký vào lớp học Pascal của cô. Trước đó, tôi chưa từng nghe nói đến Pascal. Cô nói\nvới tôi rằng đó là một ngôn ngữ lập trình máy tính và việc tham gia lớp học sẽ giúp tôi\nchuẩn bị tốt cho kỳ thi khoa học máy tính AP toàn quốc. Tôi chẳng biết kỳ thi AP là gì\nngoại trừ một điều rằng nó sẽ khá ấn tượng trong hồ sơ vào đại học của mình. Hồi cấp hai,\ntôi đã tự học về ngôn ngữ lập trình BASIC và thấy rất thú vị, vì thế tôi quyết định đăng ký\nvào lớp học Pascal.\nTôi rất thích học lớp này và thường dành thời gian ăn trưa cũng như thời gian sau giờ\nhọc ở phòng máy tính. Hai năm sau, tôi đã đứng lớp dạy Pascal ngay tại đây cho các lớp học\nhè. Chỉ có vài người thường xuyên đến phòng máy và chúng tôi đã có khoảng thời gian dài\nhọc cùng nhau.\nChúng tôi đã được đến với thế giới của BBS. Tôi biết được rằng BBS là cụm từ viết tắt của\n“Bulletin Board System”\n(2)\n. Một trong những máy tính trong phòng được kết nối với một\nmodem qua đường dây điện thoại cố định. Thông qua modem này, máy tính này có thể gọi\ntới những máy tính khác để nói chuyện với nhau.\nChúng tôi có một danh sách những số điện thoại cho các hệ thống BBS khác nhau kết\nnối với chúng tôi và chúng tôi sẽ kết nối mỗi chiếc BBS mà sinh viên thường sử dụng tại\nphòng tiếp tân dưới khu vực cầu thang với hệ thống BBS điện tử công cộng. Bất cứ ai cũng\ncó thể để lại thông tin, thông báo, khởi đầu một cuộc thảo luận, tải dữ liệu hay tham gia\ntranh luận với các chủ đề khác nhau. Có thể nói đây là một phiên bản “tiền Internet” của\nCraigslist\n(3)\n.\nChúng tôi nhanh chóng khám phá ra rằng chiếc máy tính và đường dây điện thoại\nkhông chỉ dừng lại ở những cuộc gọi trong trường, vì thế chúng tôi bắt đầu tạo ra những\ncuộc kết nối đường dài tới các hệ thống BBS trong cả nước. Thật thú vị khi có thể tham gia\nvào các cuộc thảo luận với những người lạ đến từ Seatle, New York và Miami. Chúng tôi đã\ntiếp cận được với phần còn lại của thế giới một cách đầy bất ngờ mà trước đây chúng tôi\nchưa từng nghĩ là có tồn tại.\nMột ngày nọ, trong giờ ăn trưa, khi cô Gore đã ra ngoài, ai đó đã nghĩ ra ý tưởng rút\nmodem ra và cắm đường dây điện thoại vào. Chúng tôi không chắc làm như thế có được\nkhông, nhưng khi nhấc điện thoại lên, chúng tôi đã nghe thấy âm thanh kết nối. Bây giờ\nchúng tôi có thể gọi bất cứ cuộc điện thoại nào mình muốn mà không phải trả tiền. Chúng\ntôi cũng không biết nên gọi cho ai với sức mạnh bí ẩn mới mẻ này.\nTôi hỏi mọi người xem có ai đã từng nghe nói tới con số 976 chưa. Tôi đã nhìn thấy các\nmục quảng cáo trên tivi về con số 976 với các dịch vụ khác nhau. Ví dụ, bạn có thể gọi tới\n976-JOKE, để được nghe một câu chuyện cười trong ngày, bạn sẽ mất 99 xu cho một cuộc\ngọi. Vì vậy, chúng tôi thử gọi tới số 976-JOKE và được nghe một câu chuyện chẳng thú vị\nchút nào. Chúng tôi gọi lại số đó lần nữa và hy vọng sẽ được nghe một câu chuyện cười thú\nvị hơn, nhưng những gì chúng tôi nghe được vẫn như thế. Giờ nghĩ lại, tôi đã hiểu đó là câu\nchuyện cho mỗi ngày, chứ không phải câu chuyện cười mỗi phút.\nSau đó, chúng tôi bắt đầu bấm ngẫu nhiên và chờ đợi kết quả. Một trong những con số\nchúng tôi thử là 976- SEXY. Tôi nghe thấy một giọng ghi âm tự động nói rằng phí cho mỗi\nphút của dịch vụ là 2,99 đô-la và dịch vụ này chỉ dành cho người trưởng thành, rằng nếu tôi\ndưới 21 tuổi, tôi sẽ phải cúp máy ngay lập tức.\nTất nhiên, tôi đã không cúp máy. Điều này đã khơi gợi trí tò mò của tôi.\nMột phụ nữ trả lời điện thoại và bắt đầu nói chuyện với tôi bằng một giọng khêu gợi:\n“Anh yêu, anh có đang thấy ham muốn tình dục không?”\nHiển nhiên điều này thú vị hơn hẳn việc kết nối thông qua máy tính tới những người sử\ndụng BBS ở New York. Một thế giới hoàn toàn mới hiện ra trước mắt tôi.\n“À có”, tôi trả lời bằng chất giọng trầm nhất có thể.\nĐột nhiên, giọng nói khêu gợi kia bắt đầu trở nên đều đều, khó chịu, gợi cho tôi nhớ tới\ngiọng nói của cô giáo địa lý từng phạt tôi vì vào lớp muộn.\n“Anh đã qua tuổi 21 rồi chứ?”, cô ta hỏi tôi đầy nghi ngờ. Chắc giọng nói của tôi chưa đủ\nđộ trầm. Tuổi dậy thì thật là một giai đoạn rắc rối trong đời.\nTôi hít một hơi dài. “Ồ, tất nhiên rồi”, tôi trả lời đầy tự tin.\n“Ồ được thôi, vậy anh sinh năm nào?”\nTôi hoàn toàn bất ngờ. Hiển nhiên tôi đã không thể tính nhẩm đủ nhanh để lừa cô ta.\nHết đường rồi.\n“Hai mươi mốt năm trước!” Tôi gào lên và nhanh chóng cúp máy. Chúng tôi cùng cười\nnghiêng ngả. Vài phút sau, chúng tôi tính toán lại và luyện nói thật tự tin rằng chúng tôi\nsinh năm 1966. Chúng tôi muốn chắc chắn rằng chúng tôi sẽ không phạm phải bất cứ sai\nlầm nào trong những cuộc gọi tiếp theo.\nSuốt vài tuần sau, nhóm chúng tôi lại tập hợp tại phòng máy tính suốt giờ ăn trưa và\ntiếp tục gọi tới số 976- SEXY. Chúng tôi chỉ có thể gọi vào giờ ăn trưa vì đó là thời gian cô\nGore không có trong phòng. Chúng tôi là thành viên của một câu lạc bộ bí mật và nguyên\ntắc đầu tiên của câu lạc bộ ăn trưa tại phòng máy tính là bạn không được nói gì về câu lạc bộ\ncả.\nKhông ai biết chúng tôi đang làm gì.\nMột hôm, khi đang tụ tập cùng nhau trong giờ ăn trưa, chúng tôi rất ngạc nhiên vì cô\nGore vẫn chưa ra ngoài ăn trưa. Có thể cô còn việc gì đó phải làm cho xong, vì thế chúng tôi\nchỉ sử dụng máy tính để kết nối với các BBS khác trong khi chờ cô ra ngoài.\n“Này các chàng trai!”, cô Gore lên tiếng. Chúng tôi đều nhìn về phía cô. “Có ai trong số\ncác em từng gọi điện đến số 976-7399 không? Cô nhận được bảng kê cước điện thoại tháng\nvừa rồi và có khoảng 300 cuộc gọi từ modem tới số này. Cô đã thử gọi tới số này và đó\nkhông phải là một chiếc máy tính.”\nChúng tôi nhìn nhau rồi quay sang nhìn cô. Chắc chắn là chúng tôi đều cảm thấy tội lỗi,\nnhưng tất cả chúng tôi đều nhớ đến nguyên tắc đầu tiên của câu lạc bộ là hãy cố gắng tỏ ra\nthật vô can.\n“Hẳn là đã có nhầm lẫn gì đó”, cô Gore kết luận. “Cô sẽ gọi tới công ty điện thoại và yêu\ncầu họ kiểm tra lại tất cả các cước phí này. Cô không nghĩ có người nào lại có thể gọi nhiều\nđến thế.” Cô ấy đã không biết tới khả năng siêu phàm của chúng tôi.\nVà câu lạc bộ ăn trưa của phòng máy tính chấm dứt hoạt động từ đó.\nKinh tế học cơ bản\nGạt phòng máy tính sang một bên, tôi cố ép mình phải thích những điều thú vị tại\ntrường cấp ba này càng nhiều càng tốt. Tôi nghĩ rằng càng biết nhiều lĩnh vực thì càng hữu\ních.\nTôi tham gia nhiều lớp học ngoại ngữ, gồm tiếng Pháp, tiếng Tây Ban Nha, tiếng Nhật và\nthậm chí cả tiếng Latinh. Đối với môn giáo dục thể chất, thay vì học một môn thể thao\ntruyền thống, tôi quyết định học đấu kiếm (một phần do môn này chỉ phải học một buổi\nmỗi tuần). Tôi tham gia lớp học piano theo phong cách jazz để đáp ứng yêu cầu về âm nhạc\ncủa các bậc phụ huynh. Tôi còn tham gia câu lạc bộ cờ tướng và câu lạc bộ điện tử, nơi tôi\nđược học mã Morse và được cấp chứng chỉ vận hành trạm radio không chuyên.\nĐể hoàn thành nghĩa vụ cộng đồng, tôi tình nguyện làm việc tại một nhà hát tại địa\nphương và giúp biến nó thành một căn nhà ma khổng lồ. Trong suốt tuần lễ trước ngày lễ\nHalloween, tôi trở thành một hướng dẫn viên tình nguyện. Mỗi vị khách đến sẽ phải trả 15\nđô-la cho 20 phút tham quan ngôi nhà ma.\nTôi thực sự thích làm việc ở nhà hát, đặc biệt là ở hậu trường. Tôi từng là người vận\nhành đèn sân khấu cho những buổi biểu diễn tại trường học và thậm chí còn biểu diễn ảo\nthuật cùng với một người bạn trong cuộc thi tài năng. Một trong những công việc được trả\nlương của tôi khi học cấp ba là vận hành đèn sân khấu cho các nhà hát địa phương. Có cái\ngì đó đã cuốn hút tôi tham gia và mục tiêu duy nhất của tôi là tạo ra được những trải\nnghiệm và những hành trình đầy cảm xúc cho mọi người, và sau đó chẳng có gì ngoài\nnhững ký ức tốt đẹp còn mãi.\nLịch học cố định ở lớp và bài tập về nhà đã chiếm gần hết thời gian của tôi, vì thế tôi\nquyết định chọn lớp học dựa trên cơ sở lớp học ấy ảnh hưởng thế nào tới kế hoạch của tôi.\nCó một năm, tôi đã cố gắng sắp xếp lịch học để ngày thứ ba tôi chỉ phải học một lớp và được\nnghỉ gần như cả ngày. Tôi thương thuyết với thầy cô để họ cho phép tôi không phải đi học\nkhi tôi đã hoàn thành tốt tất cả các bài kiểm tra của họ.\nVới vấn đề bài tập về nhà, tôi cố gắng tìm ra những cách làm sáng tạo để giải những bài\ntập khó. Khi học về Shakespeare, một trong những nhiệm vụ của chúng tôi là phải sáng tác\nmột bài xon-nê. Một bài xon-nê gồm mười bốn dòng viết theo thể thơ năm tiết nhịp iambơ,\nnghĩa là mỗi dòng sẽ có những âm tiết được nhấn và không nhấn thay phiên nhau, đồng\nthời phải tuân theo những quy luật nhịp điệu nhất định. Tất cả dường như quá khó đối với\ntôi, vì thế tôi quyết định sẽ chỉ nộp mười bốn dòng mã Morse thay cho những dòng thơ –\nlà những dấu chấm và những dòng kẻ luân phiên nhau.\nTuỳ thuộc vào tâm trạng của giáo viên, tôi biết hoặc tôi sẽ được điểm A hoặc sẽ được\nđiểm F. May thay, giáo viên của tôi đã quyết định cho tôi một điểm A+++++++++++. Tôi\nnghĩ đó là khi tôi học được rằng ngay cả ở trường học, đôi lúc cũng nên mạo hiểm và suy\nnghĩ vượt ra ngoài khuôn khổ.\nMột trong những kỷ niệm không vui vẻ gì ở trường cấp ba của tôi là khi tôi bị đổ tội lấy\ntrộm thẻ ăn trưa của một bạn nào đó, thẻ đó tương đương với thẻ tín dụng cho những bữa\năn ở căng-tin. Tôi không biết vì sao thẻ ăn trưa của người khác lại nằm trong túi mình. Tôi\nđoán rằng có thể hôm qua, cô thu ngân đã vô tình đưa nhầm thẻ ăn trưa của ai đó cho tôi.\nDù là thế nào đi nữa thì tôi vẫn phải đứng trước Hội đồng xét xử, giống như một Ban hội\nthẩm, gồm có thầy hiệu trưởng và một vài thầy cô trong khoa.\nTôi được cho cơ hội biện hộ cho mình, nhưng tôi thực sự không biết biện hộ thế nào vì\ntôi không hiểu tại sao chiếc thẻ ăn trưa đó lại nằm trong túi mình. Thay vào đó, tôi bước\nvào phòng hội thẩm với niềm tin mù quáng rằng lẽ phải sẽ ủng hộ tôi khi tôi nói ra sự thật,\nvà đó chính xác là điều tôi đã làm. Nhưng thực tế, chẳng ai tin tôi cả và tôi bị đình chỉ học\nmột ngày. Tôi đã phải trả giá cho một tội lỗi mà mình không hề gây ra.\nTôi đã rút ra được một bài học từ trải nghiệm này rằng, đôi khi chỉ sự thật thôi chưa đủ,\nvà cách trình bày sự thật cũng quan trọng như sự thật. Trớ trêu thay, phương châm của\ntrường tôi là “Cái đẹp là chân lý, chân lý là cái đẹp”, dựa theo bài Ode on a Grecian Urn\n(Thơ ca ngợi cái lư Hy lạp cổ) của Keats.\nNgày hôm đó, tôi cảm thấy vô cùng chán nản.\nNgoài những hoạt động ở trường học, mối quan tâm lớn nhất của tôi thời trung học vẫn là\nlàm thế nào để kiếm được tiền. Tôi được thuê làm người thử nghiệm những trò chơi điện tử\ncho công ty điện ảnh Lucasfilm. Họ trả tôi 6 đô-la cho mỗi giờ chơi trò Indiana Jones và\nCuộc thập tự chinh cuối cùng. Đó là một công việc thú vị nhưng tôi chỉ kiếm được có 6 đôla mỗi giờ, vì thế khi tìm được một công việc khác lương cao hơn, tôi bỏ việc này ngay lập\ntức.\nVào năm cuối trung học, tôi đã tìm được công việc lập trình máy tính tại một công ty có\ntên GDI. Họ trả tôi 15 đô-la mỗi tiếng, một số tiền khá lớn đối với một cậu bé đang học\ntrung học. Công việc liên quan đến việc xây dựng một phần mềm cho phép các cơ quan\nchính phủ và các doanh nghiệp nhỏ có thể điền vào các mẫu biểu trên máy tính thay vì trên\ngiấy.\nĐể giải trí, thỉnh thoảng tôi lại trêu đùa ông chủ, một người Pháp lớn tuổi có mái tóc\nmàu bạch kim và giọng nói khá nặng. Ông rất thích uống trà và có thói quen cho cốc nước\nvào lò vi sóng đặt gần bàn làm việc của tôi, ấn nút và đó trở lại phòng của ông vì ông không\nmuốn phải chờ ba phút cho đến khi nước được hâm nóng. Sau ba phút, ông sẽ quay trở lại\nđể lấy nước pha trà.\nMột lần, tôi quyết định tắt lò vi sóng ngay khi ông quay đi. Vài phút sau, khi ông quay\nlại, cốc nước vẫn nguội. Ông tưởng mình đã quên ấn nút. Ông đặt lại ba phút và quay về\nphòng.\nNgay khi ông đi khỏi, tôi lại tắt lò vi sóng, khi ông quay lại lần thứ hai, cốc nước vẫn\nnguội. Ông lầm bầm rằng chiếc lò đã hỏng. Tôi phải cố gắng lắm mới không phì cười.\nÔng ta quyết định hâm nóng lại nước lần cuối. Lần này, để chắc ăn, ông ta đặt năm phút\nbước ra với vẻ mặt đầy khó hiểu và khó chịu.\nKhi ông quay lại, ông mở lò vi sóng ra và hét lên: “Cái gì thế này?!”, rồi bắt đầu cười.\nÔng nhìn quanh phòng và chỉ nhìn thấy sự vô tội trên gương mặt chúng tôi, bởi tất cả mọi\nngười đều không biết đến trò đùa này. Ông lấy cốc nước ra và chỉ cho mọi người thấy điều\ntôi đã làm năm phút trước đó.\nTách trà toàn là đá.\nMọi người trong phòng đều cười ngặt nghẽo. Tôi không nghĩ có ai trong chúng tôi từng\ncười nhiều như lần đó, và thật tuyệt khi chỉ với một trò đùa tếu nho nhỏ trong văn phòng\nmà tôi có thể khiến tâm trạng mọi người thoải mái đến vậy.\nTôi rất vui vì hôm đó tôi không bị đuổi việc.\nMặc dù việc kiếm tiền tại công ty GDI của tôi vẫn ổn, nhưng tôi vẫn luôn nhớ về quãng\nthời gian kinh doanh khuy áo qua thư và cái cảm giác hào hứng, mong đợi người đưa thư ở\ntrước cửa nhà. Tôi nghĩ công ty bán bộ dụng cụ làm khuy cho tôi chắc hẳn cũng kinh doanh\nthành công, vì tôi đặt hàng từ trang quảng cáo của bìa cuốn tạp chí Boys’ Life.\nVì thế, tôi quyết định mình nên cố gắng bán thứ gì đó tương tự. Tôi đã đọc một số cuốn\nsách ảo thuật trong thời gian rảnh rỗi, vì vậy tôi có ý tưởng sẽ biểu diễn một trò ảo thuật,\nmột đồng xu sẽ biến mất, lẫn vào miếng cao su. Thực ra đó là một trò khá hay. Khi mọi\nngười xem tôi biểu diễn trò này, họ rất ngạc nhiên và muốn biết tại sao tôi làm được như\nvậy. Ngoài một đồng xu, một chiếc cốc và một chiếc dây cao su, thứ duy nhất cần cho trò\nnày chính là một miếng nhựa vuông mà các nha sĩ cũng dùng và họ gọi là “miếng ngăn nha\nkhoa”.\nTôi đã tìm hiểu và biết được rằng nếu mua những miếng ngăn này với số lượng lớn thì\ntôi có thể mua với giá 20 xu. Đăng một quảng cáo ở trang cuối cuốn tạp chí Boys’ Life mất\n800 đô-la, nếu tôi định giá trò ảo thuật này là 10 đô-la, thì tôi sẽ hoàn vốn sau 80 đơn đặt\nhàng thôi.\nMọi thứ dường như quá đơn giản. Thời còn kinh doanh khuy áo, tôi đã nhận được từ hai\nđến ba trăm đơn hàng mỗi tháng. Tôi cho rằng cuốn tạp chí Boys’ Life có số lượng độc giả\nlớn hơn cuốn sách Free Stuff for Kids. Hơn nữa, trò ảo thuật kỳ diệu này là một trò hoàn\ntoàn mới so với những chiếc khuy áo kia. Với hai trăm đơn đặt hàng, chi phí đầu vào của\ntôi chỉ là 40 đô-la, mà tôi sẽ thu được món lời trị giá 1.160 đô-la. Nếu có ba trăm đơn đặt\nhàng, tôi sẽ thu được lợi nhuận 2.140 đô-la. Tôi đã khám phá ra sự thú vị của việc bán được\ncác sản phẩm với giá bán và tỷ lệ lãi gộp cao.\nTôi đã phải trả 800 đô-la cho tạp chí Boys’ Life để được quảng cáo trong hai tuần, nhưng\ntôi coi đó là một vụ đầu tư. Dù sẽ phải mất một thời gian để bài quảng cáo của tôi được in\nra, và vài tháng nữa để nhận được các đơn đặt hàng, nhưng tôi vẫn kiên nhẫn và suy ngẫm\ntrong quá trình chờ đợi.\nSau một quãng thời gian tưởng chừng dài vô tận, thì cuối cùng người đưa thư cũng xuất\nhiện cùng với bài quảng cáo của tôi được đăng trong cuốn tạp chí Boys’ Life. Nó được đăng\nở một vị trí đẹp và một tuần sau đó, tôi bắt đầu nhận được đơn đặt hàng đầu tiên. Dường\nnhư tôi đã kiếm được 10 đô-la bằng con đường dễ dàng nhất từ trước đến nay và tôi háo hức\nchờ đợi những đơn đặt hàng tiếp theo.\nTuy nhiên, điều đó đã chẳng bao giờ tới.\nĐó là đơn đặt hàng duy nhất tôi nhận được cho việc kinh doanh trò ảo thuật kỳ diệu qua\nthư. Từ thành công trong việc kinh doanh khuy áo, tôi cứ tưởng rằng tôi là ông vua bất khả\nchiến bại của những đơn hàng qua thư, nhưng thực tế cho thấy tất cả chỉ là vì tôi đã gặp\nmay mà thôi.\nTôi đã học được một bài học vô giá trong sự ảm đạm buồn rầu. Và mỉa mai thay, tôi vừa\nmới học được thuật ngữ hubris trong môn học lịch sử Hy Lạp. Nó có nghĩa là “cảm giác\nphóng đại quá mức niềm tự hào hay sự tự tin thái quá”, và nó đã khiến nhiều vị anh hùng\nHy Lạp thất bại thảm hại.\nTôi cũng học được rằng sẽ là tổn thất lớn nếu đánh cược trang trại với một cái gì đó mà\nkhông tính toán. Giờ nghĩ về điều này, tôi đã không chỉ đánh cược với một trang trại.\nTám trăm đô-la tương đương với hai mươi tư trang trại giun đất.\nTrường đại học\nTôi đã nộp đơn vào các trường đại học Brown, UC Berkeley, Stanford, MIT, Princeton,\nCornell, Yale và Harvard. Tôi được nhận vào tất cả các trường này. Sự lựa chọn đầu tiên của\ntôi là Brown vì trường này có chuyên ngành quảng cáo, một ngành có vẻ liên quan nhiều\ntới kinh doanh hơn bất kỳ ngành học nào ở các trường khác.\nTuy nhiên, bố mẹ tôi lại muốn tôi học trường Harvard vì trường đó nổi tiếng nhất, đặc\nbiệt với cộng đồng người châu Á. Vì thế, tôi quyết định theo học trường này.\nThứ đầu tiên tôi mua khi tới Harvard là tivi. Tôi không còn bị bố mẹ hạn chế thời gian\nxem phim một giờ mỗi tuần như trước nữa, vì thế, tôi đã xem tivi bốn tiếng mỗi ngày trong\nsự tự do mới. Tôi phát hiện ra rằng trong khi tôi dành thời gian xem tivi thì những sinh\nviên khác trong ký túc xá lại đang bận rộn với những trò đùa như tháo hết giấy vệ sinh\ntrong nhà vệ sinh nữ hay đổ đầy nước trà nóng vào bồn tắm của giám thị (vị giám thị này\ntất nhiên là chẳng thấy vui vẻ gì).\nTôi sắp xếp lịch để chỉ phải lên lớp từ 9 giờ sáng đến 1 giờ chiều vào thứ hai, tư, sáu, còn\nthì hoàn toàn rảnh rỗi vào thứ ba và thứ năm. Sự sắp xếp này có vẻ là một ý tưởng tuyệt vời\nvề mặt lý thuyết nhưng phải trở thành một con cú đêm, và tôi quyết định sẽ theo một lịch\nbiểu kỳ lạ kéo dài 48 tiếng. Theo lịch đó, tôi sẽ thức 32 tiếng liên tục và rồi ngủ liền 16 tiếng\nsau đó.\nVào những ngày phải lên lớp, tiếng chuông báo thức lúc 8 giờ sáng là thứ âm thanh khó\nchịu nhất trên thế giới này. Tôi sẽ đập mạnh vào cái nút báo chuông và tự nhủ rằng mình\nsẽ trốn tiết học đầu tiên, rồi sẽ mượn vở những sinh viên khác để chép lại bài. Một tiếng\nsau đó, tôi lại thuyết phục mình rằng lập luận ban đầu cũng đúng với những tiết học sau, vì\nthế, tôi sẽ trốn luôn buổi học ngày hôm đó. Lúc đó, tôi định sẽ đến học tiết thứ ba, nhưng\ntôi lại lý luận rằng mình đã trốn hai tiết học kia rồi, bỏ thêm một vài tiết nữa có sao đâu.\nCuối cùng, mỗi khi định đi học, tôi lại tìm được một lý do nào đó để trốn. Lợi ích từ việc đi\nhọc dường như không được tôi đánh giá cao.\nVì thế, về cơ bản, tôi đã không đi học trong suốt năm thứ nhất. Vì tôi chẳng bao giờ nhấc\nnổi mình dậy đúng giờ, tôi quá lười để dậy tắm rửa và đi học trước giờ ăn trưa. Tôi đã ăn rất\nnhiều đồ ăn đủ cho cả ngày và ngấu nghiến tất cả các tập phim Days of our lives (Những\ntháng ngày trong cuộc đời chúng ta).\nTôi đã dành phần lớn thời gian năm thứ nhất để tham gia các hoạt động với những\nngười bạn sống cùng ký túc, gọi là khu Canaday A. Chúng tôi cùng nhau xem phim, chơi\ngame và tán chuyện. Có sẵn cảm hứng từ những ngày làm bản tin Gobbler, tôi đã lập ra bản\ntin Canaday A. Chúng tôi có một nhóm nòng cốt gồm mười lăm người, đoàn kết và gắn bó.\nHầu hết chúng tôi đều không kết bạn ngoài nhóm và cố gắng gắn kết với nhau trong suốt\nbốn năm đại học.\nGiống như hồi học phổ thông, tôi cố gắng kiếm nhiều tiền nhất có thể khi học đại học ít\nmà vẫn đạt được điểm số cao. Tôi tham gia một số lớp học như Ngôn ngữ ký hiệu kiểu Mỹ,\nNgôn ngữ học và tiếng Quan thoại (tôi vẫn nói chuyện với bố mẹ bằng thứ tiếng này). Để\nhoàn thành các môn điều kiện cốt yếu, tôi đã ghi danh vào một lớp học về Kinh Thánh. Tin\ntốt lành là môn học này không có bài tập về nhà và cũng chẳng chấm điểm, nên tôi đã\nchẳng bao giờ đến lớp. Tin xấu là việc xếp loại của tôi sẽ dựa vào bài thi cuối kỳ, nhưng tôi\nlại chẳng chuẩn bị gì cho nó, vì chẳng bao giờ tôi mở bất cứ cuốn sách bắt buộc phải đọc\nnào trong suốt khoá học. Tôi nghĩ rằng kỹ năng tôi được mài giũa nhiều nhất trong trường\nchính là kỹ năng trì hoãn.\nHai tuần trước khi làm bài thi cuối kỳ, giáo sư phát một danh sách gồm hàng trăm chủ\nđề có thể sẽ là bài kiểm tra. Chúng tôi được thông báo rằng, năm trong số những chủ đề này\nsẽ được lựa chọn ngẫu nhiên cho bài kiểm tra và chúng tôi phải viết một vài đoạn văn về\nnhững chủ đề đó.\nTrong vòng hai tuần, tôi không có cách nào đọc hết tất cả các cuốn sách được yêu cầu\nđọc trong cả một học kỳ, và tôi cũng chẳng sợ bị trượt môn học.\nNhưng có câu: cái khó ló cái khôn. Ở Harvard, chúng tôi có thể sử dụng máy tính để\nđăng nhập vào những nhóm tin điện tử (electronic newsgroups), tương tự như hệ thống\nbảng tin điện tử (BBS) mà tôi từng kết nối thời trung học. Tôi gửi một tin nhắn tới các\nnhóm tin điện tử và mời tất cả các sinh viên Harvard cũng học lớp Kinh Thánh kia tham\ngia vào một cuộc nghiên cứu quy mô lớn chưa từng thấy, vì điều này sẽ rất thiết thực.\nĐối với những người quan tâm, tôi sẽ giao cho mỗi người nghiên cứu kỹ lưỡng ba trong\nsố hàng trăm chủ đề có thể sẽ được lựa chọn. Sau đó, mỗi người sẽ gửi qua email cho tôi\nnhững đoạn văn họ viết về ba chủ đề có thể là đề bài trong kỳ thi cuối kỳ. Tôi tổng hợp bài\nviết của họ, phô-tô, đóng lại thành tập rồi bán với giá 20 đô-la mỗi tập. Bạn chỉ có thể mua\nmột tập nếu bạn đã đóng góp vào đó ba chủ đề.\nKhi tin nhắn được gửi đi, có rất nhiều người quan tâm, vì thế tôi nhận được rất nhiều\ncâu trả lời cho mỗi chủ đề từ những sinh viên khác nhau. Chẳng cần phải đọc bất cứ cuốn\nsách nào hay tự viết, tôi vẫn có được những bài nghiên cứu đầy đủ nhất từ trước đến nay, và\nmọi người cũng nhận thấy nó thật hữu ích. The Crimson, tờ báo của trường chúng tôi, đã\nviết một bài về kinh nghiệm của nhóm nghiên cứu thực tiễn này, còn tôi thì đã hoàn thành\nrất tốt bài thi cuối kỳ.\nTôi đã khám phá ra sức mạnh của nguồn lực đám đông (crowdsourcing\n(4)).\nTôi còn làm nhiều việc khác nhau trong năm thứ nhất đại học.\nTôi tham gia vào cộng đồng làm phim, kiếm tiền bằng cách trình chiếu các bộ phim tại\ncác giảng đường đại học rồi bán vé cho sinh viên. Tôi đến thăm trang trại của một người\nbạn, ban ngày thì học cách vắt sữa, đến tối thì bị ngã và phải khâu vết thương trên cằm khi\ncố học trượt băng. Tôi không chắc việc vắt sữa bò hay mấy mũi khâu trong phòng cấp cứu,\ncái nào đáng sợ hơn.\nTôi giành được vé xem buổi hòa nhạc đầu tiên trên đài phát thanh địa phương và xem\nbuổi biểu diễn của U2 trong tua Zoo TV của họ. Tôi làm nhiều việc khác nhau trong trường,\nbao gồm việc phụ bếp cho các đám cưới hoặc phục vụ ở quầy rượu, sau khi đã hoàn thành\nbốn tiếng học tại Harvard Bartending School và lấy được chứng chỉ Mixology. Tôi cũng\ntham gia nhiều công việc lập trình máy tính khác nhau, bao gồm những việc làm cho Hội\nsinh viên trường Harvard, làm việc tại công ty Spinnaker Software và tham gia khóa thực\ntập mùa hè tại Microsoft.\nMột trong những công ty tôi đã làm là BBN, nơi đã phát triển công nghệ mà sau này trở\nthành xương sống của mạng Internet. BBN đã ký hợp đồng với các cơ quan chính phủ, vì\nthế tôi phải trải qua một cuộc kiểm tra nhân thân để có được bậc Bí mật, thấp hơn Tối mật\nmột bậc. Dường như mức độ bảo mật của chính phủ quá cao đến nỗi phải phân loại tên của\nchúng như thế này.\nPhần lớn công việc của tôi tại BBN là vào trong một căn phòng lớn và tách biệt với bên\nngoài với mức độ bảo mật rất cao, thể hiện ở huy hiệu điện tử và những mã số bí mật để đi\nqua những cánh cửa khác nhau. Tôi không được phép mang bất cứ thứ gì ra ngoài căn\nphòng này, đặc biệt là những thiết bị điện tử hay bất cứ dữ liệu truyền thông điện tử nào\nkhác.\nMột mùa hè, tôi quyết định băng qua con sông nối liền Cambridge và Boston để khám\nphá thành phố này. Tôi lang thang qua những địa điểm du lịch của Boston, đến thăm\nGuardian Angels (Thiên thần hộ mệnh), tổ chức có nhiệm vụ ngăn ngừa và chống lại tội ác.\nTôi quyết định trở thành thành viên của tổ chức này trong vài tháng với công việc tuần tra\nhệ thống tàu điện ngầm và các ngõ hẻm của Boston.\nTên của tôi trong tổ chức là “Bí mật”. Ban đầu, tôi nghĩ rằng đó là vì tôi từng nhắc tới\ncông việc bí mật của tôi tại các tổ chức chính phủ, nhưng sau đó tôi biết được rằng một\ntrong những thành viên kỳ cựu của tổ chức muốn đặt tên cho tôi là “Bí mật Trung Hoa cổ\nđại”.\nSuốt những năm học đại cương và chuyên ngành ở đại học, tôi nhận thấy mình đã liên\ntục bỏ lỡ công việc kinh doanh, vì thế tôi đảm nhiệm việc quản lý Quincy House Grille, một\nkhu ăn uống, nằm dưới tầng trệt của ký túc xá Quincy House. Toà nhà này có khoảng ba\ntrăm sinh viên sinh sống và Quincy House Grille là nơi sinh viên tụ tập chơi bóng và ăn\nđêm.\nMột trong những người bạn cùng phòng với tôi, Sanjay, phụ trách quán cùng tôi. Chúng\ntôi chịu trách nhiệm lên thực đơn và định giá, đặt hàng từ các nhà cung cấp, thuê nhân\nviên và thường xuyên tự chuẩn bị đồ ăn.\nVào thời gian đó, thành phố ra chỉ thị cấm mở những quán ăn nhanh gần các trường đại\nhọc, vì thế tôi phải đi tàu điện ngầm đến trạm gần nhất có cửa hàng McDonald’s. Tôi nói\nchuyện với người quản lý ở đó và ông ta bán cho tôi một trăm chiếc bánh hamburger và\nbánh ngọt McDonald’s. Tôi dùng xe tải chở chúng về khu ký túc. Đó là hành trình thường\nxuyên của tôi trong vài tháng sau đó. Vì chẳng có cửa hàng nào gần khu ký túc này bán\nbánh hamburger của McDonald’s nên tôi có thể bán với giá 3 đô-la một chiếc trong khi chỉ\nmất 1 đô-la chi phí.\nNhưng rồi tôi cũng thấy mệt nhoài với những chuyến đi hàng ngày tới cửa hàng\nMcDonald’s, vì thế tôi quyết định tìm xem liệu có cách nào chuyển sang kinh doanh bánh\npizza không. Tôi biết rằng kinh doanh bánh pizza sẽ thu được lãi rất lớn. Chỉ mất chưa đầy\n2 đô-la để làm một chiếc bánh pizza cỡ lớn nhưng lại có thể bán với giá 10 đô-la (thậm chí\ncòn cao hơn nữa). Và thậm chí, bán từng miếng bánh pizza cũng có thể kiếm được nhiều\ntiền. Sau khi hỏi han một số người, tôi biết được rằng phải mất 2.000 đô-la để đầu tư mua\nlò nướng. Cho rằng vụ này đáng để mạo hiểm, tôi hít thật sâu và viết một tấm séc trị giá\n2.000 đô-la.\nTôi muốn tạo ra những điều đặc biệt cho quán, nơi mà mọi người muốn đến chơi nên đã\nthức trắng nhiều đêm để ghi lại các các chương trình MTV vào băng video, tạm dừng ghi\nbất cứ lúc nào xuất hiện quảng cáo, vì đây là thời kỳ trước khi truyền hình phát triển mạnh.\nNhững băng video này hoá ra lại là một thành công lớn, kết hợp với việc chào bán bánh\npizza, doanh số bán hàng của chúng tôi đã tăng gấp ba lần so với cùng kỳ năm trước. Phi vụ\nđầu tư 2.000 đô-la được hoàn vốn trong vòng vài tháng.\nChính nhờ việc kinh doanh pizza mà tôi đã gặp Alfred, người sau này cùng gia nhập\nZappos với tư cách là giám đốc tài chính (CFO) và giám đốc điều hành (COO) của công ty.\nThực ra, Alfred là khách hàng số 1 của chúng tôi. Đêm nào cũng vậy, anh luôn đặt mua một\nchiếc pizza bò rắc tiêu cỡ lớn.\nỞ trường đại học, chúng tôi đặt cho anh ta hai biệt danh là “Thùng nước lèo” và “Quái\nvật”. Sở dĩ có biết danh này là vì lần nào nhóm chúng tôi đi ăn ở nhà hàng (thường thì có\nmười người đi ăn đêm tại khu bán đồ ăn Trung Quốc, gọi là khu Kông), anh ta cũng ăn hết\nsạch sành sanh thức ăn thừa trong đĩa của cả mọi người nữa. Tôi thầm cảm ơn việc mình\nkhông phải ở chung phòng để khỏi phải dùng chung nhà tắm với con người này.\nVì vậy với tôi, chẳng có gì là lạ khi tối nào anh ta cũng đặt mua một chiếc pizza bò rắc\ntiêu cỡ lớn. Nhưng thỉnh thoảng anh ta lại trở lại sau vài tiếng và đặt mua thêm một chiếc\npizza bò rắc tiêu cỡ lớn nữa. Lúc đó, tôi chỉ nhủ thầm: “Ồ, anh chàng này có thể ăn được hết\nmà.”\nVài năm sau tôi phát hiện ra rằng Alfred mua bánh pizza rồi bán từng miếng cho những\nngười bạn cùng phòng. Đó là lý do tại sao chúng tôi lại quyết định thuê anh làm giám đốc\ntài chính và giám đốc điều hành của Zappos.\nVài năm trước, chúng tôi làm phép tính và biết được rằng, mặc dù tôi kiếm được nhiều\ntiền từ kinh doanh bánh pizza hơn Alfred, nhưng anh ta lại kiếm được nhiều hơn tôi gấp\nmười lần trong mỗi giờ đồng hồ nhờ bán từng miếng bánh pizza. (Anh ta cũng chịu ít rủi ro\nhơn tôi. Tên trộm nào đó đã cuỗm mất chiếc máy nướng bánh trị giá 2.000 đô-la của tôi.\nĐến cuối năm, tính ra thì tôi chỉ kiếm được 2 đô-la mỗi giờ).\nLúc đó, tôi không biết rằng mối quan hệ liên quan tới bánh pizza của chúng tôi lại là\ntiền đề cho những cơ hội kinh doanh hàng triệu đô sau này.\nVào năm cuối của thời sinh viên, Sanjay đã giới thiệu cho tôi một thứ gọi là tổ hợp\nWorld Wide Web (mạng lưới toàn cầu). Tôi nghĩ đó là một thứ rất thú vị để khám phá vào\nthời điểm đó, nhưng đã không chú tâm nhiều vào nó.\nLúc đó, mục tiêu hầu hết sinh viên năm cuối, trong đó có cả tôi, là cố gắng kiếm được việc\nlàm trước khi tốt nghiệp. Rất nhiều công ty từ khắp nơi trên đất nước và từ các ngành khác\nnhau ào ào đến Harvard để tuyển dụng nên chúng tôi chẳng phải đi xa để phỏng vấn tìm\nviệc.\nRất nhiều bạn cùng phòng tôi đã nộp đơn vào ngân hàng hay những công việc tư vấn\nquản trị, những công việc được xem là “ngon”. Với tôi, những việc này thật nhàm chán và\ntôi đã nghe đâu đó rằng thời gian làm việc của những vị trí này kéo dài tới mười sáu tiếng\nmột ngày.\nVì vậy, Sanjay và tôi quyết định nộp đơn vào các công ty công nghệ. Mục tiêu của tôi là\ntìm được một công việc lương cao. Tôi không quan tâm đến chức danh cụ thể của công việc\nđó là gì, công ty nào tôi sẽ làm việc, nền văn hoá của công ty đó như thế nào hay tôi sẽ sống\nở đâu.\nTôi chỉ quan tâm đến việc đó là một công việc lương cao và không phải làm nhiều.', '2026-02-28 08:13:53'),
	(14, 4, 2, 'Được cái này, mất cái kia.', 'Bước ra đời thực\nCả Sanjay và tôi đều được công ty Oracle mời vào làm việc.\nTôi cũng nhận được một vài lời mời khác, nhưng tôi đã dễ dàng chấp nhận vào làm ở\nOracle. Không chỉ bởi mức lương họ đề nghị trả cho tôi là cao nhất (40 nghìn đô-la một\nnăm, mức lương khá cao đối với một sinh viên mới tốt nghiệp vào năm 1995), mà bởi họ\ncòn chi trả cho việc chuyển toàn bộ đồ đạc của tôi trong những năm học đại học về\nCalifornia, cộng thêm việc cho phép Sanjay và tôi cùng sống trong một ngôi nhà chung cư\nmiễn phí vài tuần trong thời gian chúng tôi tham gia khóa tập huấn dành cho nhân viên\nmới.\nTôi đã cảm thấy mình thành công. Tôi đã chiến thắng trong trò chơi mà tôi đã đặt mục\ntiêu từ thời còn học đại học: kiếm được việc làm với mức lương thật cao. Khi so công việc\ncủa mình với công việc của những người bạn cùng phòng, rõ ràng là tôi và Sanjay kiếm\nđược nhiều tiền hơn.\nVài tháng sau, Sanjay và tôi tham gia chương trình tập huấn nhân viên mới của Oracle.\nChương trình này kéo dài ba tuần và chúng tôi được tập huấn cùng với hai mươi sinh viên\nmới tốt nghiệp khác. Ba tuần tập huấn nhanh chóng trôi qua. Về cơ bản, đó là chương trình\nlập trình dữ liệu nhanh. Chúng tôi được thử thách và tham gia vào những dự án thú vị. Tôi\nhọc hỏi được rất nhiều điều, làm quen được với nhiều bạn bè, và quan trọng hơn là kiếm\nđược nhiều tiền. Kết thúc khoá tập huấn, chúng tôi mong chờ được gặp ông chủ mới để bắt\nđầu công việc.\nThực ra, tôi hoàn toàn không biết công việc hay điều mình mong đợi là gì. Tôi chưa tìm\nhiểu chút gì về Oracle cả. Tôi chỉ biết là họ cử người đến phỏng vấn tôi ở trường đại học và\nhọ ấn tượng với thành tích học tập của tôi. Họ thực sự không biết tôi là ai và tôi cũng vậy.\nTôi chỉ biết rằng chức danh của tôi là “kỹ sư phần mềm” và họ trả cho tôi 40 nghìn đô-la\nmột năm.\nVào ngày làm việc đầu tiên tại Oracle, tôi được dẫn tới bàn làm việc của mình, trao đổi\nvới tôi về công việc, nhiệm vụ và trách nhiệm. Về cơ bản, tôi phải làm thử nghiệm để đảm\nbảo chất lượng kỹ thuật và kiểm tra hồi quy. Tôi không hiểu công việc đó có ý nghĩa gì\nnhưng cũng chẳng sao. Miễn là tôi vẫn kiếm được tiền. Và chỉ trong vòng một tuần, tôi\nnhận thấy công việc đó kiếm tiền dễ dàng như thế nào.\nTất cả những gì tôi phải làm là thực hiện một vài thử nghiệm mỗi ngày. Mất khoảng\nnăm phút để thiết lập một thử nghiệm, và sau đó khoảng ba giờ để cho thử nghiệm tự chạy,\ntrong thời gian đó, tôi sẽ chỉ ngồi và chờ nó chạy xong. Vì vậy, tôi chỉ có thể chạy hai hoặc\nba thử nghiệm một ngày. Tôi cũng nhận ra rằng chẳng ai theo dõi thời gian tôi đến hoặc rời\nkhỏi văn phòng. Tôi nghĩ rằng có lẽ chẳng ai thực sự biết tôi là ai.\nVài tháng đầu, tôi cảm thấy mình quá may mắn. Tôi không thể tin được rằng tôi được\ntrả công cao để làm những việc chả mất tí sức nào. Sanjay và tôi đã thuê được một căn hộ\nchỉ mất bảy phút đi bộ tới văn phòng và chúng tôi lại một lần nữa trở thành những người\nbạn cùng phòng.\nLịch làm việc của tôi trong một tuần như sau:\n10:00 – Có mặt tại bàn làm việc.\n10:05 – Bắt đầu tiến hành chạy thử nghiệm.\n10:10 – Kiểm tra email, gửi email cho bạn bè trong chương trình tập huấn.\n11:30 – Về nhà ăn trưa.\n12:30 – Chợp mắt một lúc.\n1:45 – Quay lại văn phòng.\n2:00 – Chạy thử nghiệm\n2:05 – Kiểm tra email, trả lời email của các bạn trong chương trình tập huấn.\n4:00 – Về nhà.\nTôi thấy mình may mắn khi có một lịch làm việc nhẹ nhàng như vậy, trong khi Sanjay\nkhông bao giờ về nhà trước 7 giờ tối. Thỉnh thoảng, tôi hỏi thăm công việc của cậu ấy thế\nnào nhưng cậu ấy chỉ nhún vai và nói những câu đại loại như “Vẫn ổn. Chẳng có gì thú vị\ncả.”\nTôi nói với cậu ấy rằng công việc của tôi cũng chẳng có gì thú vị, và chúng tôi nên cùng\nnhau làm gì đó vào các buổi tối và cuối tuần cho vui và chống lại sự nhàm chán. Lúc đó,\nWorld Wide Web đã dần phổ biến hơn. Sanjay là một nhà thiết kế đồ họa giỏi, vì thế chúng\ntôi có thể làm gì đó bên ngoài như thiết kế trang web cho các công ty khác.\nÝ tưởng kinh doanh riêng nghe có vẻ thú vị. Chúng tôi quyết định đặt tên công ty là\nInternet Marketing Solutions (Giải pháp Marketing trên Internet), viết tắt là IMS. Chúng\ntôi tự thiết kế trang web riêng, kéo thêm một đường dây điện thoại nữa cho căn hộ và tới\nKinko đặt in danh thiếp. Chúng tôi đã sẵn sàng tìm kiếm khách hàng.\nChúng tôi lên kế hoạch tìm kiếm khách hàng: Đầu tiên, chúng tôi sẽ tiếp cận với các\nphòng thương mại địa phương và đề nghị thiết kế miễn phí trang web cho họ. Sau đó,\nchúng tôi được phép nói với tất cả các doanh nghiệp địa phương rằng phòng thương mại là\nkhách hàng của chúng tôi (mà không nhắc đến việc chúng tôi đã làm miễn phí) để thu hút\ncàng nhiều doanh nghiệp càng tốt và tiền sẽ nhanh chóng chảy về.\nVì vậy, đó chính là ưu tiên số một của chúng tôi. Chúng tôi phải làm thế nào để các\nphòng thương mại địa phương đồng ý cho thiết kế trang web của họ. Mặc dù lời rao hàng\ncủa chúng tôi là thiết kế miễn phí, song việc tiếp cận họ qua điện thoại vẫn không thuận lợi,\nvì thế tôi phải gặp họ trực tiếp. Tôi hẹn gặp họ lúc 12 rưỡi, cũng phù hợp với lịch làm việc ở\nOracle.\nTới ngày hẹn, tôi vô cùng lo lắng. Tôi chưa bao giờ thành công với việc kinh doanh qua\nđiện thoại và tôi biết nhiệm vụ của tôi bây giờ là phải thuyết phục được rằng họ cần có một\ntrang web và rằng chúng tôi là chính đối tác thích hợp. Tôi biết rằng hình thức bên ngoài\nrất quan trọng, vì thế tôi rời Oracle để về ăn trưa lúc 11 rưỡi, tôi đi về nhà trước tiên, mặc bộ\nvét và thắt cà vạt mà tôi đã mặc trong lễ tốt nghiệp. Tôi cũng không quên mang theo vài\ntấm danh thiếp. Tôi còn mang một số tờ mẫu mà Sanjay thiết kế và in ra từ vài ngày trước.\nDù tôi hơi căng thẳng nhưng cuộc gặp đã diễn ra suôn sẻ. Họ chấp nhận với điều kiện\nmọi thứ chúng tôi làm cho họ đều miễn phí. Vài tuần sau, những giờ nghỉ trưa của tôi kéo\ndài hơn, tôi dành thời gian cho phòng thương mại, để đảm bảo rằng họ hài lòng với những\ngì chúng tôi làm. Sanjay thức đêm nhiều hơn và đôi khi cậu ấy còn thức trắng đêm để thiết\nkế trang web. Tôi là nhân viên kinh doanh và hỗ trợ khách hàng, cậu ấy là người thiết kế và\ntạo ra sản phẩm. Chúng tôi là một nhóm làm việc rất hiệu quả.\nChúng tôi bàn giao trang web cho phòng thương mại chỉ trong vòng một tháng, và giờ\nlà lúc chúng tôi yêu cầu các khách hàng khác phải trả tiền. Mục tiêu đầu tiên của chúng tôi\nlà Hillsdale, khu thương mại lớn nằm trên con phố chúng tôi sinh sống. Chúng tôi nghĩ\nrằng đó là lựa chọn đúng đắn nếu chúng tôi có thể biến họ thành khách hàng của mình, vì\nsau đó chúng tôi có thể tiếp cận với những cửa hàng nhỏ bên trong và nói với họ rằng\nHillsdale là khách hàng của chúng tôi, và đương nhiên họ cũng nên như vậy.\nTrong vài tháng tiếp theo, tôi dần dần dành ít thời gian ở văn phòng Oracle hơn vì phải\nđi gặp lãnh đạo của Hillsdale và các doanh nghiệp nhỏ khác. Cuối cùng, chúng tôi cũng\nthuyết phục được Hillsdale trả 2.000 đô-la để việc thiết kế, quản lý và điều hành trang web\ncho họ.\nChúng tôi đã làm được! Chúng tôi đã thực sự có được khách hàng đầu tiên. Chúng tôi\nđã có thể từ bỏ cái công việc không mong đợi và nhàm chán ở Oracle để dành toàn thời\ngian điều hành công việc kinh doanh của mình.\nVì vậy, chúng tôi quyết định đó là việc phải làm.\nTôi đã làm hỏng cái buổi sáng mà tôi gặp ông chủ của Oracle để xin nghỉ việc. Sau khi trì\nhoãn đến nửa tiếng, cuối cùng tôi cũng quyết tâm đi xuống phòng ông ấy. Tôi đã sẵn sàng\nthông báo điều đó. Qua cửa sổ văn phòng, ông ấy thấy tôi đang đến và nhìn lên. Chúng tôi\nnhìn nhau. Tôi thấy tim mình đập thình thịch. Rồi ông ấy nhìn sang chỗ khác. Tôi liếc\nnhìn xung quanh và nhận ra ông ấy đang nói chuyện với ai đó trong phòng, vì vậy, tôi\nkhông thể thông báo tin mình muốn nghỉ ngay lúc này được. Tôi như vớ được chiếc phao\ncứu sinh và tiếp tục rảo bước qua văn phòng ông, vờ rằng tôi chỉ đang trên đường đến nhà\nvệ sinh dưới sảnh.\nTôi rửa tay và chờ trong phòng vệ sinh vài phút cho có vẻ như đúng là tôi đang đi vệ\nsinh. Sau đó, tôi lại đi ngang qua phòng ông chủ, trở lại bàn làm việc của mình và lại dành\nnửa tiếng gửi thư cho bạn bè. Tôi tính toán rằng 30 phút là thời gian đủ cho cuộc nói\nchuyện của ông chủ, nhưng rồi tôi quyết định đợi thêm 15 phút nữa cho chắc ăn, sau đó tôi\nlại rảo bước tới văn phòng ông một lần nữa.\nVì lý do nào đó, lần này tôi thậm chí còn cảm thấy lo lắng hơn. Tôi nghĩ có thể do tôi\nkhông biết chắc liệu ông ấy có còn đang tiếp chuyện người vừa nãy nữa hay không. Nếu ông\nấy vẫn đang tiếp chuyện người đó, chắc tôi sẽ lại vờ là mình đi vệ sinh. Và có lẽ ông ấy chỉ\nđơn giản nghĩ rằng tôi có vấn đề nghiêm trọng với cái bàng quang hay dạ dày mà thôi.\nCũng có thể ông ấy sẽ thấy thật là lạ khi mà tôi chỉ sử dụng cái nhà vệ sinh ngay gần văn\nphòng ông thay vì cái nhà vệ sinh gần chỗ tôi. Nhưng cũng có thể ông ấy nghĩ rằng cái nhà\nvệ sinh gần chỗ tôi đã có người sử dụng hoặc bị sao đó. Tôi chắc rằng tất cả những ý nghĩ\nnày sẽ xuất hiện trong đầu ông ấy, nhưng tôi cố gắng thuyết phục bản thân rằng chẳng sao\ncả, dù thế nào thì hôm nay cũng sẽ là ngày làm việc cuối cùng của tôi. Nhưng tâm trí tôi bị\nám ảnh rằng tất cả những gì ông ấy còn nhớ sau mười năm nữa chỉ là việc tôi đã sử dụng cái\nnhà vệ sinh ở bên trái tòa nhà rất nhiều lần trong một khoảng thời gian ngắn. Đó thực sự là\nmột thảm họa.\nVì vậy, tôi phải làm thế nào đó để chắc chắn rằng ký ức cuối cùng của ông ta về tôi không\nphải là “gã trai kỳ quặc luôn có nhu cầu đi vệ sinh nhiều”. Tôi có một kế hoạch. Tôi sẽ đi\nthẳng vào văn phòng ông ta và báo tin luôn. Vì vậy, tôi tiến bước, tự nhủ rằng không bao\ngiờ được quay lại. Để chắc chắn rằng chúng tôi sẽ không nhìn nhau một cách khó xử như\ntrước, lần này, tôi sẽ đi sát tường để ông ấy không thể nhìn thấy tôi đang bước tới từ xa.\nTim tôi lại đập liên hồi, lần này tôi thấy cửa phòng mở. Cuối cùng, tôi cũng đứng trước\ncánh cửa ấy, tôi nhìn vào trong, đã sẵn sàng nói với ông ấy rằng tôi đến xin nghỉ việc.\nNhưng chẳng có ai ở trong phòng cả.\nĐây thực sự là lần xin nghỉ việc khó khăn nhất trong đời tôi. Tôi đoán là ông ấy đã ra\nngoài gặp khách hoặc đi ăn trưa, vì thế, tôi quyết định cũng đi ăn trưa. Tôi sẽ quay trở lại\nvào buổi chiều để xin nghỉ việc lần thứ ba.\nVì vậy, tôi thở dài và quay lại. Và đâm sầm vào ông chủ đang đứng sau lưng tôi.\n“Tony? Cậu đang tìm tôi à?”, ông ấy hỏi.\nTôi chưa hề chuẩn bị tinh thần cho tình huống này. Tôi đang mải mê nghĩ đến những\nmón ăn tôi sẽ gọi ở Taco Bell. Ngạc nhiên và bối rối, tôi vội vã nhỏ nhẻ: “Không ạ, xin lỗi\nông” và bước đi thật nhanh để cố không gợi lên chút nghi ngờ nào cho ông ta.\nTại Taco Bell, tôi đã đi đến hai quyết định quan trọng. Tôi quyết định sẽ thử suất ăn đôi\ncủa nhà hàng, và điều đó hóa ra lại thực sự có hiệu quả kinh ngạc đối với cái bụng của tôi.\nTôi cũng quyết định sẽ để đến ngày mai mới xin nghỉ. Rõ ràng có những dấu hiệu cho thấy\nhôm nay không phải là ngày thích hợp.\nKhi trở lại văn phòng vào buổi chiều, tôi cảm thấy thoải mái hơn nhiều vì biết rằng tôi\nkhông phải tìm cách xin thôi việc nữa. Tôi hướng đến nhà vệ sinh ngay cạnh văn phòng tôi\nnhưng chỉ được chào đón bằng một tấm biển treo trên cửa đề rằng nhà vệ sinh đang được\ndọn dẹp và vui lòng sử dụng nhà vệ sinh khác – một trong số đó là phòng vệ sinh ngay cạnh\nphòng ông chủ.\nMay mắn cho tôi là bây giờ tôi đã quá thông thạo với vị trí của nhà vệ sinh này nên tôi\ncứ thẳng tiến. Khi đến gần nhà vệ sinh, tôi thấy ông chủ đang ngồi một mình trong phòng\nvà cánh cửa thì đang rộng mở. Tôi lập tức quyết định rằng cần phải kết thúc mọi việc ở đây,\nvì thế, trước khi kịp nghĩ lại, tôi buộc mình phải bước thật nhanh vào phòng ông ấy.\n“Ngài có thể cho tôi vài phút được không?”, tôi cất tiếng hỏi, rồi đóng cửa lại và ngồi\nxuống đối diện ông chủ. Giờ thì hết cách thoái lui rồi.\n“Tôi vừa... quyết định sẽ thôi việc”, tôi ngập ngừng nói. Tôi đã làm việc ở Oracle được\nnăm tháng nhưng tôi chưa thực sự làm được gì ra hồn ở đây cả. Tôi không biết ông chủ của\ntôi đã đón nhận cái tin này như thế nào. Tôi lo rằng ông ấy sẽ thất vọng vì tôi đã làm cho\nOralce khá lâu rồi, vậy mà giờ lại muốn ra đi. Hoặc có thể ông ấy đã biết tôi thường nghỉ\ntrưa lâu hơn và cũng có thể ông ấy đang mừng thầm vì tôi sắp nghỉ việc. Hoặc cũng có thể\nông ta chẳng thèm quan tâm. Ba giây sau ông ấy đáp lời mà tôi có cảm tưởng như là ba\nphút.\n“Ồ! Hẳn là cậu sẽ làm một công việc khác! Chắc đó sẽ là một cơ hội tốt!” Ông ấy tỏ ra rất\nháo hức và mừng cho tôi. Hẳn là ông ta nghĩ rằng tôi sẽ làm việc cho một công ty được đầu\ntư hàng triệu đô-la từ quỹ đầu tư mạo hiểm đây.\nTôi không dám nói với ông rằng chỉ là do tôi chán Oracle và muốn có thời gian thực\nhiện các cuộc gọi bán hàng cho doanh nghiệp thiết kế trang web mà tôi và Sanjay gây dựng\nnên từ phòng khách của chúng tôi. Với tốc độ phát triển hồi đó, thực ra chúng tôi kiếm\nđược ít hơn rất nhiều so với khi còn làm cho Oracle.\nNhưng chúng tôi muốn được điều hành công việc kinh doanh của riêng mình và làm\nchủ số phận. Đó không hẳn là vì tiền, mà bởi công việc đó không nhàm chán. Bây giờ, cả\nSanjay và tôi đều đã chính thức thôi việc, và chúng tôi đã sẵn sàng bước sang một chương\nmới trong cuộc đời mình. Chúng tôi không biết việc đó sẽ dẫn chúng tôi đến đâu, nhưng\nbất kể đó là nơi nào, chúng tôi biết rằng, nơi đó sẽ tốt hơn chứ không nhàm chán và thất\nvọng.\nChúng tôi đã sẵn sàng cho một cuộc phiêu lưu mạo hiểm.\nKhởi nghiệp\nThực ra, cuộc phiêu lưu đang chờ đợi chúng tôi đã bắt đầu từ lâu. Chúng tôi thường ngồi\nvòng tròn trong căn hộ để thiết kế các trang web và ra ngoài tìm kiếm thêm khách hàng\nmột tuần một lần.\nĐến cuối tuần đầu tiên, tôi nhận ra một điều là cả hai chúng tôi đều không thực sự đam\nmê công việc thiết kế trang web. Chúng tôi thích ý tưởng được làm chủ và tự điều hành\ndoanh nghiệp của riêng mình, nhưng thực tế cho thấy chẳng có gì thú vị cả.\nBố mẹ tôi không hiểu vì sao tôi lại bỏ việc ở Oracle mà chẳng có kế hoạch cụ thể nào cho\nnhững việc cần làm tiếp theo. Khi tôi nói với bố rằng Sanjay và tôi định thành lập một\ndoanh nghiệp thiết kế trang web, ông nói với tôi rằng chẳng có cơ sở nào để doanh nghiệp\ncủa chúng tôi sẽ trở nên lớn mạnh theo đúng nghĩa. Vào lúc đó, chỉ sau một tuần, cả Sanjay\nvà tôi đều bắt đầu tự hỏi liệu quyết định rời Oracle có đúng hay không.\nNhững tuần tiếp sau thật sự căng thẳng và có phần chán nản. Chúng tôi bắt đầu dành\nphần lớn thời gian chỉ để sục sạo các trang web nhằm chống lại sự nhàm chán và tiêu\nkhiển. Hồi đầu, nhìn Sanjay ngủ đến trưa trặt ra vẫn chưa dậy cũng khá thú vị. Nhưng\nchúng tôi đang bắt đầu phát điên lên.\nMay thay, cả hai chúng tôi đều có tiền tiết kiệm từ những công việc thời sinh viên nên\nkhông phải lo đến việc trả tiền thuê nhà từ giờ đến tận cuối năm. Chúng tôi không biết\nmình muốn làm gì nhưng chúng tôi đã biết được điều mình không muốn làm. Chúng tôi\nkhông muốn làm việc cho Oracle nữa. Chúng tôi không muốn làm bất cứ công việc thiết kế\ntrang web nào nữa. Chúng tôi không muốn thực hiện bất kỳ cuộc gọi bán hàng nào nữa. Và\nchúng tôi cũng không muốn trí óc mình nhàn rỗi.\nVì thế, chúng tôi dành nhiều ngày đêm cố gắng tìm ra ý tưởng kinh doanh trên Internet\nvĩ đại tiếp theo, nhưng chúng tôi thực sự không tìm được bất kỳ ý tưởng hay ho nào. Một\nngày cuối tuần, trong tâm trạng buồn chán, chúng tôi quyết định tiến hành lập trình để thử\nnghiệm ý tưởng mà chúng tôi gọi là Internet Link Exchange, nghĩa là Trao đổi liên kết trên\nInternet (ILE) mà sau này chúng tôi đổi tên thành LinkExchange.\nÝ tưởng đằng sau LinkExchange được hình thành khá đơn giản. Nếu bạn đang có một\ntrang web, thì bạn có thể đăng ký dịch vụ của chúng tôi miễn phí. Khi đăng ký, trang web\ncủa bạn sẽ được chèn một đoạn mã đặc biệt để cho các đoạn quảng cáo tự động hiển thị trên\nđó.\nMỗi khi có người truy cập vào trang web của bạn và thấy một trong những mục quảng\ncáo, bạn sẽ được nửa điểm. Như vậy, nếu có một nghìn người truy cập vào trang web của\nbạn mỗi ngày thì bạn sẽ thu được 500 điểm mỗi ngày. Với 500 điểm này, trang web của bạn\nsẽ được quảng cáo 500 lần miễn phí trên mạng lưới LinkExchange, do đó, đây là một cách\ntuyệt vời vì bạn không phải tốn tiền cho quảng cáo mà vẫn thu được lợi nhuận. Năm trăm\nlần quảng cáo khác nên để chúng tôi giữ. Ý tưởng là chúng tôi sẽ phát triển mạng lưới\nLinkExchange một thời gian cho đến khi có đủ sự nổi tiếng để bán cho những tập đoàn lớn.\nSanjay và tôi đã hoàn thành tất cả các chương trình thử nghiệm trong vòng hơn một\ntuần và chúng tôi sẽ gửi email tới năm mươi trang web yêu thích của chúng tôi – những\ntrang web mà chúng tôi tìm thấy khi lướt web, hỏi xem họ có sẵn lòng thử nghiệm dịch vụ\nmới của chúng tôi hay không.\nThật bất ngờ, một nửa số trang web chúng tôi gửi email tới đã đồng ý giúp đỡ chúng tôi\nthử nghiệm dịch vụ trong vòng hai mươi tư tiếng. Khi có người truy cập vào các trang web\nvà nhìn thấy banner quảng cáo, tin tức về LinkExchange bắt đầu lan truyền. Chỉ trong một\ntuần, chúng tôi nhận ra rằng dự án đó ban đầu chỉ nhằm giúp chúng tôi chống lại sự buồn\nchán nhưng giờ có vẻ sẽ có tiềm năng trở thành cái gì đó rất lớn. Chúng tôi quyết định tập\ntrung toàn bộ sức mạnh, biến LinkExchange thành một doanh nghiệp thành công.\nNăm tháng tiếp theo trôi đi rất nhanh. Ngày càng có nhiều trang web đăng ký sử dụng\ndịch vụ của chúng tôi. Chúng tôi không còn phải lo lắng về việc kiếm tiền nữa. Chúng tôi\nchỉ tập trung vào việc phát triển mạng lưới LinkExchange. Chúng tôi háo hức với việc tạo\nra thứ gì đó lớn mạnh nhanh chóng và nhiều người thực sự thích sử dụng nó.\nSanjay và tôi làm việc thâu đêm suốt sáng, chia ra một nửa thời gian lập trình máy tính\nvà nửa còn lại trả lời email khách hàng. Chúng tôi cố gắng trả lời tất cả các email được gửi\nđến càng nhanh càng tốt. Thường thì chúng tôi có thể trả lời email chỉ trong vòng mười\nphút và mọi người rất ngạc nhiên khi nhận được hồi âm của chúng tôi.\nCó thời điểm chúng tôi không thể trả lời kịp tất cả các email gửi đến, nên một người bạn\nđến chơi đã quyết định sẽ giúp trả lời những bức thư đó và cuối cùng ở lại luôn với chúng\ntôi. Đó là khoảng thời gian tuyệt vời, thú vị và kỳ diệu đối với tất cả chúng tôi. Chúng tôi\nbiết chúng tôi đang làm điều gì đó lớn lao, tuy rằng không thực sự biết nó sẽ trở thành cái\ngì nữa. Ngày tháng trở nên lẫn lộn với nhau, chúng tôi thật sự không biết hôm nay là thứ\nmấy trong tuần.\nMột ngày tháng 8 năm 1996, chúng tôi nhận được một cú điện thoại từ một người tự\nxưng là Lenny. Anh ta gọi từ New York và nói rằng muốn mua quảng cáo trên hệ thống của\nchúng tôi và còn xem xét khả năng mua lại công ty của chúng tôi. Sanjay và tôi đã đồng ý\năn tối với anh ta vào tuần sau tại San Francisco.\nChúng tôi gặp nhau ở Tony Roma – chuỗi nhà hàng chuyên về các món ăn từ thịt thỏ.\nLenny giới thiệu về mình giống như một “Bigfoot”\n(1) vậy – được thể hiện rõ ở cả tên công ty\ncũng như biệt danh của anh ta. Anh ta gọi đồ uống Kahlua, vì vậy tôi cũng gọi đồ uống cùng\nloại. Tuy nhiên, Sajay lại tránh xa thứ đồ uống đó. Sajay và Kahlua chưa bao giờ có mối\nquan hệ tốt với nhau kể từ cái đêm mà các bạn cùng phòng thời đại học mãi mãi gọi là\n“Kahlua đêm”, khi mà anh đã nốc rất nhiều Kahlua (sau đó thì nôn ọe trong phòng vệ sinh\nmà chúng tôi dùng chung với các bạn cùng phòng).\nLenny nói với chúng tôi rằng anh muốn đưa cho chúng tôi một đề nghị: một triệu đô-la\ntiền mặt và cổ phiếu để chúng tôi bán LinkExchange cho Bigfoot. Như một phần của giao\ndịch, Lenny muốn chúng tôi chuyển đến New York để làm việc cho Bigfoot. Sanjay và tôi\nnhìn nhau, cả hai đều choáng váng. LinkExchange chỉ mới được thành lập có năm tháng\nmà giờ đây chúng tôi lại có cơ hội bán nó với giá một triệu đô-la. Đây có thể là một cơ hội\nđổi đời cho chúng tôi. Chúng tôi nói với Lenny rằng chúng tôi muốn có vài ngày để suy\nnghĩ về đề nghị đó, nhưng từ duy nhất mà tôi có thể nghĩ trong đầu là “Ồ!”.\nSanjay và tôi đã dành 24 tiếng để nói về những gì chúng tôi nên làm. Chúng tôi thực sự\ntin rằng LinkExchange có tiềm năng phát triển hơn nữa, nhưng cũng khó có thể từ chối\nmột số tiền lớn như vậy. Vì thế, chúng tôi quyết định nói với Lenny rằng chúng tôi sẽ bán\ncông ty với giá hai triệu đô-la tiền mặt. Như thế, Sanjay và tôi, mỗi người sẽ kiếm được một\ntriệu đô-la chỉ sau năm tháng làm việc. Tôi đã đọc được ở đâu đó rằng bạn sẽ ở vị thế\nthương thuyết tốt nhất nếu bạn không quan tâm kết quả là gì và bạn không thua. Với mức\ngiá hai triệu đô-la, dù sao tôi cũng sẽ cảm thấy vui hơn bất kể vụ giao dịch có thành công\nhay không.\nKhi chúng tôi nói ra điều đó, Lenny không nghĩ rằng chúng tôi đáng giá hai triệu đô-la\n(và tôi cũng không nghĩ rằng anh ta thực sự có đủ hai triệu đô-la), vì thế chúng tôi thống\nnhất sẽ đi theo hai con đường khác nhau nhưng vẫn giữ liên lạc với nhau.\n“LinkExchange là một cơ hội tuyệt vời trong cuộc đời các anh”, Lenny nói. “Tôi từng\nkiếm được rất nhiều tiền, nhưng cũng mất rất nhiều khi tôi quyết định đánh cược với trang\ntrại hiện tại của tôi thay vì lấy tiền. Tôi mong rằng các anh sẽ may mắn.”\nSanjay và tôi có động lực hơn bao giờ hết khi chắc chắn rằng LinkExchange sẽ thành\ncông. Chúng tôi phải chứng minh được rằng Lenny đã sai.\nKhi ngày càng có nhiều người đăng ký dịch vụ của chúng tôi, Sanjay và tôi nhận ra rằng\nchúng tôi cần nhiều sự giúp đỡ hơn cả về dịch vụ khách hàng và về lập trình máy tính.\nNgoài việc thuyết phục bạn bè – những người đã ghé thăm chúng tôi, không quay về nhà\nnữa mà ở lại giúp chúng tôi trả lời email, chúng tôi còn bắt đầu tìm kiếm nhiều lập trình\nviên máy tính khác.\nTôi nhớ hồi đại học, tôi từng tham gia vào cuộc thi lập trình máy tính quốc tế. Mỗi\ntrường đại học được phép cử một đội gồm những lập trình viên giỏi nhất để thi đấu với các\ntrường đại học khác. Đội của tôi đã giành giải nhất trong cuộc thi đó. Tôi quyết định sẽ gặp\nHadi – một trong những sinh viên trong đội tuyển của tôi để xem cậu ấy có muốn gia nhập\nLinkExchange không.\nThời còn đi học, tôi biết được rằng Hadi thích ảo thuật, vì thế chúng tôi từng bàn nhau\nvề ý tưởng sẽ tổ chức chương trình biểu diễn ảo thuật trên giảng đường để có thêm thu\nnhập. Chúng tôi ảo tưởng rằng chúng tôi sẽ trở thành bộ đôi David Copperfield mới, nhưng\nrốt cuộc, chúng tôi chẳng làm được trò trống gì vì cũng quá bận rộn rồi.\nKhi tôi liên lạc lại với Hadi, tôi đã hỏi cậu ta có muốn gia nhập LinkExchange không, và\ntôi cung cấp tất cả những thông tin về việc chúng tôi đã lớn mạnh nhanh như thế nào, lời\nđề nghị mua lại với mức giá một triệu đô-la mà chúng tôi đã từ chối và hệ thống này thú vị\nra sao. Cậu ấy trả lời rằng đó thật sự là một công việc thú vị nhưng cậu ấy quá bận rộn với\ncông việc ở Seattle, làm cho hãng Microsoft, là nhóm trưởng của nhóm phụ trách trình\nduyệt web Internet Explorer để cạnh tranh với các trình duyệt của Netscape, vì thế không\nthể gia nhập nhóm chúng tôi được.\nTuy nhiên, cậu ấy nói với tôi rằng cậu ấy có người em sinh đôi, và cũng làm công việc\nnhư thế. Cậu ấy nói rằng, họ giống hệt nhau và hồi ở trường đại học, họ thường thay nhau\nđi phỏng vấn và vờ là người kia nếu một trong hai người quá bận rộn. Tôi tự hỏi không biết\nliệu có khi nào người này đi hẹn hò hộ người kia hay không.\n“Như vậy... về cơ bản, cậu muốn bọn tớ thuê cậu em của cậu à?”, tôi hỏi.\n“Ừ.”\n“Chuyện hai người thay nhau đi phỏng vấn là sự thật à?”\n“Đúng vậy.”\n“OK, nghe được đây. Thế cậu em đó tên là gì?”\n“Ali”.\nSau khi gặp Ali tại căn hộ của chúng tôi, Sanjay và tôi quyết định nhận cậu ta là thành\nviên thứ ba của LinkExchange, và chúng tôi đã mở một văn phòng thực sự tại San\nFrancisco. Mỗi người trong chúng tôi đều bắt đầu mời bạn bè gia nhập LinkExchange, từng\nngười một và họ đều đồng ý.\nTính đến tháng 12 năm đó, LinkExchange đã có tới 25 nhân viên và hầu hết đều là bạn\nbè của chúng tôi. Đó cũng chính là lúc Jerry Yang – người đồng sáng lập Yahoo!, đánh\ntiếng muốn gặp chúng tôi. Yahoo! vừa có đợt IPO rất thành công trị giá hơn một tỷ đô-la\nhồi đầu năm. Jerry là người tiên phong trong ngành công nghiệp Internet điên rồ nhất thời\nbấy giờ, vì thế, tất cả chúng tôi đều háo hức gặp một người nổi danh về Internet. Chúng tôi\nhy vọng có thể ký kết được vài hợp đồng quảng cáo với Yahoo! để thúc đẩy cho sự tăng\ntrưởng của chúng tôi.\nNhưng thực ra, Jerry chẳng hề quan tâm tới việc ký kết hợp đồng quảng cáo với chúng\ntôi, mà anh ta muốn mua lại chúng tôi – một cú sốc đối với chúng tôi. Chúng tôi phải đợi\ncho đến khi kỳ nghỉ lễ kết thúc vì tất cả các thành viên trong ban điều hành đều đang đi\nnghỉ. Vì thế, chúng tôi thống nhất sẽ bàn bạc lại vào tháng giêng năm sau.\nSau kỳ nghỉ năm mới, anh ta đến gặp chúng tôi trong căn hộ cũ của chúng tôi và nói với\nSanjay, Ali và tôi về số tiền họ sẵn sàng trả cho việc mua lại LinkExchange.\n“Hai mươi triệu đô-la”.\nTôi đã phải rất cố gắng để giữ bình tĩnh. Ý nghĩ đầu tiên vụt lên trong đầu tôi là “Ôi trời\nơi!”. Ý nghĩ thứ hai thoáng qua trong đầu tôi chính là “Tôi mừng huýnh lên vì đã không\nbán công ty cho Lenny năm tháng trước.”\nChúng tôi nói với Jerry rằng chúng tôi sẽ suy nghĩ về lời đề nghị đó và sẽ trả lời anh ta\nsau vài ngày. Tình huống này giống hệt lần trước, chỉ khác là số tiền mua lớn hơn nhiều.\nRất nhiều là đằng khác.\nNhững ngày sau đó đầy ắp lo lắng. Chúng tôi đã kể cho những thành viên còn lại của\ncông ty về những gì đã xảy ra, và rằng Sanjay, Ali và tôi sẽ là những người đưa ra quyết định\ncuối cùng. Nếu chúng tôi nhận 20 triệu đô-la, thì từ giờ đến cuối đời, tôi sẽ chẳng cần phải\nlàm gì nữa cả.\nTheo kinh nghiệm, tôi đã lên danh sách tất cả những việc tôi sẽ làm khi có nhiều tiền:\n• Tôi sẽ mua một ngôi nhà ở San Francisco để có một nơi sinh sống và có thể gọi là nhà\ncủa mình thay vì phải đi thuê nhà và sống chung với người bạn cùng phòng.\n• Tôi sẽ mua một chiếc tivi màn hình lớn và sẽ xây dựng một nhà hát.\n• Tôi muốn có nhiều những kỳ nghỉ nhỏ (những kỳ nghỉ cuối tuần kéo dài) bất cứ khi\nnào và đến những nơi như Las Vegas, New York, Miami và Los Angeles.\n• Tôi sẽ mua một chiếc máy tính mới.\n• Tôi sẽ lại lập ra một công ty khác vì tôi thực sự hào hứng với ý tưởng xây dựng và phát\ntriển một thứ gì đó.\nTôi rất ngạc nhiên khi thấy danh sách này quá ngắn, và điền thêm những việc khác thực\nsự khá khó khăn với tôi. Với số tiền tiết kiệm được từ những công việc trước, tôi đã có thể\nmua tivi, máy tính và hưởng những kỳ nghỉ ngắn. Chỉ là tôi chưa bao giờ tự mình làm\nnhững việc đó mà thôi.\nTôi cũng đã gây dựng được một công ty mà tôi rất yêu thích. Giờ đây sẽ thật là ngu ngốc\nkhi tôi lại bán đi công ty mà tôi vô cùng yêu thích, để rồi bắt đầu gây dựng lại một công ty\nkhác. Trừ mỗi việc tôi sẽ có một ngôi nhà cho riêng mình thay vì đi thuê, tôi nhận ra rằng\ntôi đã có đủ điều kiện để mua tất cả những gì tôi muốn.\nNhững câu nói của Lenny cứ vang vọng trong đầu tôi: “LinkExchange là một cơ hội\ntuyệt vời trong cuộc đời các anh”. Tôi biết tận sâu trong trái tim mình rằng, ngay cả khi\nchúng tôi thất bại thì theo đuổi cơ hội đó vẫn là một việc làm đúng đắn. Nó còn quan trọng\nhơn việc được sở hữu một ngôi nhà của riêng mình khi mới ở cái tuổi 23. Việc trở thành\nchủ nhân của một ngôi nhà là việc có thể để lại sau.\nTôi đã tâm sự với Sanjay và Ali về những suy nghĩ của tôi và họ đều đưa ra cùng một\nquyết định. Chúng tôi vẫn còn trẻ. Chúng tôi vẫn có thể mạo hiểm.\nHôm sau, chúng tôi tổ chức một cuộc họp toàn công ty để thông báo về quyết định của\nchúng tôi.\n“Các bạn biết đấy, chúng tôi đã nhận được một lời đề nghị mua lại công ty từ Yahoo!, và\nmấy ngày hôm nay chúng tôi đã suy đi nghĩ lại xem có nên chấp thuận hay không.” Tôi cất\nlời. Hẳn bạn đang hình dung ra sự căng thẳng bao trùm cả căn phòng. “Và chúng tôi đã\nquyết định từ chối lời đề nghị của họ.”\nNhìn quanh phòng, tôi vô cùng ngạc nhiên khi thấy giường như có một niềm tin tưởng\nnào đó đang hiện hữu trên khuôn mặt của các nhân viên. “Chúng ta đang ở trong một thời\nkhắc rất trọng đại”, tôi tiếp tục. “Ngành công nghiệp Internet đang bùng nổ. Các công ty\nnhư Netscape, eBay, Amazon và Yahoo! đang làm thay đổi lịch sử nhân loại. Trước đó,\nchưa từng có nhiều công ty thành công trong thời gian ngắn như vậy. Chúng ta có cơ hội\ntrở thành một trong những công ty như thế.”\nTôi không biết vì sao, nhưng vì một lý do nào đó mà tôi bắt đầu thấy cảm xúc dâng trào.\nGiọng tôi trở nên run run. Tôi cố gắng nói những lời cuối cùng và nhanh chóng kết thúc\ncuộc họp, nếu không tôi sẽ khóc mất:\n“Sẽ chẳng bao giờ có một năm 1997 nào khác nữa.”\nĐó là thời điểm chúng tôi chống lại cả thế giới, và chúng tôi chắc chắn rằng mình sẽ\nchiến thắng.\nNhững tháng sau đó diễn ra khá mơ hồ. Theo một cách nào đó, chúng tôi cảm thấy dường\nnhư có ai đó luôn dõi theo để đảm bảo chúng tôi không phạm phải bất cứ sai lầm nào.\nMichael Moritz đến từ Sequoia Capital – hãng có vốn liên doanh do Yahoo! tài trợ, trở\nthành thành viên hội đồng quản trị và đầu tư ba triệu đô-la để mua 20% cổ phiếu trong\ncông ty. Ngày càng có nhiều trang web đăng ký sử dụng dịch vụ và chúng tôi bắt đầu ký kết\nnhững hợp đồng quảng cáo lớn đem lại doanh thu cho công ty. Chúng tôi tuyển dụng rất\nnhiều nhân viên thông minh và đam mê nghề nghiệp (rất nhiều người trong số họ là bạn\nbè của nhân viên trong công ty). Chúng tôi làm việc cùng nhau rất vui vẻ. Chúng tôi đang ở\ntrên đỉnh cao của thế giới.\nTôi không biết từ khi nào đã có một truyền thống vui tại LinkExchange. Mỗi tháng một\nlần, tôi gửi email đến toàn thể nhân viên trong công ty để thông báo cho họ biết rằng\nchúng tôi sẽ có một cuộc họp quan trọng và rằng một số nhà đầu tư và các thành viên hội\nđồng quản trị sẽ tham dự, tất cả mọi người đều được yêu cầu mặc vest và thắt cà vạt vào\nngày hôm đó.\nNhưng tất cả các nhân viên, trừ những người mới vào làm, đều biết rằng đó không hẳn\nlà buổi họp công việc thực sự, và rằng họ không cần phải mặc vest hay thắt cà vạt. Lý do\nthực sự của cuộc họp đó là chúng tôi có thể giới thiệu và làm quen với tất cả những nhân\nviên mới – những người vừa mới gia nhập LinkExchange trong tháng qua.\nVì vậy, cứ mỗi tháng một lần, tất cả các nhân viên mới đều xuất hiện ở văn phòng trong\ntrang phục com-lê và thắt cà vạt. Và rồi họ nhận ra rằng họ chính là mục tiêu trong trò đùa\ncủa cả công ty. Trong cuộc họp buổi chiều, tất cả các nhân viên mới đều được gọi đứng lên\ngiữa phòng để làm một số việc gây cười.\nSau vụ đầu tư của Sequoia, chúng tôi đề nghị Michael Moriz tham dự cuộc họp đầu tiên\nvà mời ông đứng ra giữa phòng cùng với sáu nhân viên mới được tuyển vào công ty tháng\ntrước.\nSau khi từng người tự giới thiệu về mình xong, chúng tôi giới thiệu về Moritz một cách\ntrang trọng, rồi chúng tôi hô hào mọi người cùng nắm tay nhau và nhảy theo điệu nhạc cho\nmột trò chơi.\nNếu bạn từng biết bất cứ điều gì về Moritz trên các phương tiện truyền thông, thì bạn sẽ\nbiết rằng ông vốn là một nhà báo người Anh, sau đó trở thành nhà đầu tư mạo hiểm, rất\nthông minh, đúng mực và sống nội tâm. Vì thế, mọi người đều rất háo hức khi chứng kiến\ncảnh ông ấy sẵn sàng đứng giữa phòng cùng với các nhân viên mới khác. Một số người còn\nmang cả đài ra và bật to để tất cả mọi người cùng vỗ tay cổ vũ. Rồi nhạc bắt đầu nổi lên. Đó\nlà bài Macarena.\nTôi không thể nghĩ ra từ nào để diễn tả cảnh tượng Moritz bị ép phải nhảy điệu\nMacarena như thế nào. Có thể xem đây là một trong những cảnh tượng kỳ lạ nhất từ trước\nđến nay. Tất cả mọi người trong phòng này đều vỗ tay tán dương và cười nói, và khi kết\nthúc bản nhạc tôi đã cười chảy cả nước mắt.\nTôi nhìn khắp phòng, thấy niềm hạnh phúc hiện hữu trên khuôn mặt của tất cả mọi\nngười và tự nhủ, “Không thể tin đây là sự thật”. Đó không hẳn là vì cảnh tượng Moritz nhảy\nđiệu Macarena, cũng không phải vì tất cả mọi người trong phòng đều đang nói cười vui vẻ.\nMà bởi tất cả những gì đã xảy ra trong năm qua. Nó dường như không có thật vậy.\nNói theo ngôn ngữ trong phim Người đàn bà đẹp, tôi đang sống trong thế giới cổ tích.\nPhát triển nhanh chóng\nNgay sau khi chúng tôi nhận được khoản đầu tư từ Sequoia, tôi tới gặp Alfred, anh\nchàng vẫn mua pizza của tôi hồi đại học, để xem liệu anh ta có muốn làm việc toàn thời\ngian cùng chúng tôi không. Nhưng có vẻ anh ta đang rất bận rộn với việc lấy bằng Tiến sĩ về\nthống kê ở Stanford. Với tôi, điều đó dường như là thứ nhàm chán thứ hai trên thế giới\n(thứ nhàm chán nhất đối với tôi chính là việc nhìn sơn khô vào buổi tối, trời tối đến nỗi\nkhó mà biết được sơn có màu gì).\nHơn hai năm trước, tôi đã cố gắng nghĩ ra mô hình kinh doanh nào đó mà chúng tôi có\nthể làm việc cùng nhau. Một trong những ý tưởng hồi đó của tôi là mở cửa hàng bán bánh\nsandwich Subway cùng với Alfred ở một nơi nào đó trong khuôn viên trường Stanford.\nThời bấy giờ, Subway là một trong những thương hiệu nhượng quyền phát triển nhanh\nnhất ở Mỹ, một phần là do phí nhượng quyền và các chi phí ban đầu thấp. Alfred thực sự\nthích làm việc đó cùng tôi nhưng lại phát hiện ra rằng vào thời gian đó, Stanford không\ncho phép các hoạt động thương mại diễn ra trong khuôn viên trường đại học.\nKhi Sanjay và tôi bắt đầu gây dựng LinkExchange, tôi đã hỏi Alfred xem liệu cậu ấy có\nmuốn tham gia không. Cậu ấy cho rằng nó quá mạo hiểm vào thời điểm đó và sợ rằng bố\nmẹ cậu ấy sẽ phát điên lên khi biết cậu không chuyên tâm lấy bằng, vì thế chúng tôi thống\nnhất giữ liên lạc với nhau và để cậu làm việc với tư cách là chuyên gia tư vấn cho chúng tôi.\nTuy nhiên, lần này, Alfred lại có vẻ quan tâm hơn. Tôi nghĩ có thể vì cậu ấy biết được\nrằng chúng tôi đã có ba triệu đô-la đầu tư của Sequoia trong tài khoản và câu ấy đã nhận ra\nrằng tấm bằng tiến sĩ chẳng phải thứ mình thực sự cần. Cậu ấy bắt đầu làm việc toàn thời\ngian tại LinkExchange từ năm 1997 với tư cách là Phó chủ tịch Tài chính.\nMười bảy tháng tiếp theo, tất cả chúng tôi đều ngủ rất ít. Chúng tôi phát triển không\nngừng và tuyển dụng nhiều nhân viên nhanh nhất có thể. Chúng tôi đã tận dụng hết mạng\nlưới bạn bè của nhân viên, vì vậy, chúng tôi bắt đầu tuyển dụng tất cả những ai sẵn sàng làm\nviệc cho chúng tôi.\nVăn phòng của chúng tôi trở nên chật chội, vì thế chúng tôi thuê thêm văn phòng khác\nở các tầng khác nữa. Thậm chí chúng tôi còn mở văn phòng đại diện ở New York và\nChicago. Cảm giác thật lạ khi đi dạo xung quanh văn phòng và gặp những người hoàn toàn\nxa lạ. Có vẻ như chúng tôi đã tuyển được rất nhiều nhân viên mới mỗi tuần. Tôi không chỉ\nkhông nhớ hết tên và công việc mà mọi người đang làm, mà thậm chí tôi còn không nhớ\nnổi khuôn mặt họ. Đi lên rồi lại đi xuống cầu thang trong toà nhà, tôi không biết chắc liệu\nnhững người tôi gặp là làm việc cho LinkExchange hay cho những công ty khác cũng thuê\ntrong toà nhà này.\nVào thời điểm đó, tôi không thấy có vấn đề gì bất ổn cả. Nếu có, thì việc không nhận ra\nđược mọi người do sự lớn mạnh vượt bậc chỉ khiến mọi thứ có vẻ thú vị hơn và giống như\nmột chất kích thích đối với chúng tôi. Nhưng giờ nghĩ lại, đó chính là dấu hiệu cảnh báo rõ\nràng cho những gì sắp xảy ra.\nVấn đề nằm ở chỗ chúng tôi không biết rằng cần phải chú trọng nhiều hơn đến văn hoá\ncông ty. Trong suốt năm đầu tiên, chúng tôi đã thuê bạn bè và người thân của chúng tôi –\nnhững người muốn xây dựng nên một điều gì đó thú vị và vui vẻ. Dù không thực sự ý thức\nvề điều đó, nhưng chúng tôi đã cùng nhau tạo nên một nền văn hoá công ty mà tất cả\nchúng tôi đều mong muốn trở thành một phần của nó.\nSau này, khi chúng tôi tăng trưởng vượt quá con số hai mươi lăm thành viên, chúng tôi\nđã phạm sai lầm khi tuyển dụng những người muốn gia nhập công ty vì những lý do khác.\nMay mắn là những người được nhận vào làm việc cho chúng tôi đều rất thông minh và có\nnăng động. Tuy nhiên, nhiều người trong số họ vào đây vì mục đích kiếm thật nhiều tiền\nhoặc tạo dựng sự nghiệp hay có được lý lịch công việc tốt. Họ muốn dành vài năm làm việc\nchăm chỉ cho LinkExchange rồi sau đó sẽ nộp hồ sơ vào một công ty khác. Hoặc, nếu mọi\nthứ diễn ra suôn sẻ, họ sẽ kiếm được nhiều tiền và nghỉ hưu. Chúng tôi tiếp tục phát triển\nvà thuê thêm ngày càng nhiều nhân viên, và tính đến năm 1998, chúng tôi đã có hơn một\ntrăm nhân viên.\nMột ngày nọ, tôi tỉnh dậy sau khi đã nhấn nút chuông báo thức tới sáu lần. Tôi định tắt\ntiếp lần thứ bảy thì chợt nhớ ra điều gì đó. Lần cuối cùng tôi tắt chuông báo thức là hồi còn\nlàm việc tại Oracle. Lần này, tôi cũng đang kinh hãi với việc dậy đi làm ở LinkExchange.\nĐây thực sự là một hiện thực rất khó chịu đối với tôi. Tôi là một trong những người sáng\nlập ra LinkExchange, nhưng giờ tôi lại không còn hứng thú muốn đến công ty nữa. Tôi ít\nkhi rơi vào tình trạng này. Mới một năm rưỡi trước thôi, tôi còn phát biểu trước các nhân\nviên của mình rằng: “Sẽ không bao giờ có một năm 1997 nào khác nữa”. Làm sao mọi thứ\nlại có thể thay đổi nhanh chóng như vậy chứ? Chuyện gì đã xảy ra? Làm sao từ một môi\ntrường “mọi người vì một người, một người vì mọi người” lại trở thành một nơi toàn chuyện\nchính trị, địa vị và những lời đồn thổi?\nNhớ lại năm qua, tôi không thể nghĩ ra được điều gì đã khiến cho mọi thứ không còn\nthú vị như trước. Tôi không thể xác định được đích xác nhân viên nào đã hủy hoại nền văn\nhoá công ty.\nNền văn hoá này dường như đã chết bởi hàng nghìn vết cắt hay bởi trò tra tấn bằng nước\ncủa Trung Quốc\n(2)\n. Từng giọt từng giọt, từng ngày một, mỗi giọt nước hay một quyết định\ntuyển dụng sai lầm sẽ chẳng gây hại gì nhiều, và vấn đề chẳng có gì to tát. Nhưng những\ngiọt nước tích tụ lại sẽ trở thành một sự tra tấn dã man.\nTôi không biết mình nên làm gì bây giờ. Tôi cố gắng không nghĩ đến những điều đó vì\ntrước mắt còn có một vấn đề cấp thiết khác cần phải giải quyết: nền kinh tế đang suy thoái\n(vấn đề tiền tệ của Nga và sự sụp đổ của quỹ chống rủi ro Long Term Capital mà tôi không\nsao hiểu nổi), và công ty không có đủ tiền mặt để tiếp tục hoạt động nếu doanh thu đột\nnhiên giảm xuống. Chúng tôi bắt đầu chuẩn bị cho đợt IPO để tăng vốn, nhưng khủng\nhoảng tài chính Nga đã xoá sổ khả năng đó. Chúng tôi cần tạo ra quỹ dự phòng như quỹ bảo\nhiểm để phòng trường hợp kinh tế tiếp tục diễn biến xấu đi. Nếu không, chúng tôi có thể sẽ\nbị phá sản trước khi hết năm.\nHai năm trước, chúng tôi đã xây dựng được mối quan hệ khá tốt đẹp với những người\ncủa Yahoo!, Netscape và Microsoft. Công ty nào cũng quan tâm đến tất cả những gì chúng\ntôi đang làm và tính toán những cơ hội hợp tác chiến lược với chúng tôi. (Tôi chưa bao giờ\nthật sự hiểu được “mối quan hệ hợp tác chiến lược” là gì và nó khác với mối quan hệ đối tác\nthường xuyên ở chỗ nào, nhưng tất cả mọi người đều nói cụm từ đó nghe có vẻ thông thái\nhơn vì vậy chúng tôi rất thích sử dụng cụm từ đó.)\nThật kinh ngạc, cả ba công ty đó đều nói rằng họ rất quan tâm đến việc đầu tư vào quỹ\ndự phòng của chúng tôi. Thậm chí Netscape và Microsoft đều nói rằng họ còn quan tâm\nđến việc mua công ty.\nChúng tôi nói với họ rằng mức giá bán thấp nhất cũng phải là 250 triệu đô-la. Tôi không\nbiết vì sao chúng tôi lại nghĩ ra con số đó nhưng nó có vẻ hợp lý với tôi, và tôi đoán rằng đó\nlà một dấu hiệu tốt khi cả Netscape và Microsoft đều nói họ muốn tiếp tục đàm phán.\nHọ sa vào một cuộc chiến bỏ thầu.\nCuối cùng, Microsoft đưa ra con số lớn nhất – 265 triệu đô-la – nhưng có vài điều kiện\nđi kèm. Họ muốn Sanjay, Ali và tôi phải ở lại với LinkExchange ít nhất là mười hai tháng\nnữa. Nếu tôi ở lại mãi mãi, tôi sẽ nhận được 40 triệu đô-la. Nếu không, tôi sẽ phải chia tay\nvới 20% của số tiền đó.\nDù không còn thấy hứng thú với LinkExchange nữa nhưng tôi nghĩ mình vẫn có thể ở\nlại thêm một năm với mức giá đề nghị kia. Tôi chỉ phải làm nốt những công việc còn lại để\nkhông bị sa thải thôi.\nỞ lại nhưng không thực sự phải làm gì là tình huống giống với nhiều trường hợp ở\nThung lũng Silicon trong các kịch bản mua lại. Thực tế, thậm chí có một cụm từ mà giới\ndoanh nhân thường dùng để miêu tả tình huống này là: “Cầm quyền thời bình”.\nViệc ký kết hợp đồng diễn ra sau vài tuần chúng tôi thương lượng với Microsoft. So với\nnhững vụ mua lại Microsoft đã thực hiện trước đây, vụ mua lại LinkExchange này được\nthực hiện trong thời gian ngắn kỷ lục, mặc dù có vài tấn kịch ở hậu trường.\nQua đó, tôi rút ra được bài học về hành vi và tính cách con người. Tiền là thứ dễ làm bộc\nlộ bản chất con người. Tôi nhận thấy lòng tham của vài người gia nhập công ty ngay trước\nkhi có cuộc thương lượng với Microsoft. Họ chỉ chăm chăm thương thuyết có lợi cho bản\nthân mà chẳng màng đến rủi ro và tổn thất của những người khác trong công ty. Nhiều tấn\nkịch đã diễn ra khi có những người bắt đầu chiến đấu với nhau để kiếm thật nhiều tiền cho\nbản thân.\nVề phía tôi, tôi quyết định bước ra khỏi tấn kịch này. Tôi cho rằng bán công ty là một\nviệc làm đúng đắn bởi tôi chắc chắn không bao giờ còn muốn làm việc cùng những người\nnày nữa. Tôi chỉ phải ở đây thêm mười hai tháng nữa thôi.\nMột ngày đầu tháng 11 năm 1998, Sanjay và tôi đi ăn trưa cùng nhau tại một nhà hàng\nxa văn phòng LinkExchange. Vụ thu mua công ty đã được thông báo trên báo chí vài tuần\ntrước đó nhưng thỏa thuận vẫn chưa chính thức hoàn tất. Khi chúng tôi ăn xong, Alfred gọi\nvào di động của tôi và nói rằng văn phòng đã chính thức bị đóng cửa. Thỏa thuận đã hoàn\ntất.\nTôi nhìn sang Sanjay và báo tin cho cậu ấy. “Ồ, tớ đoán là thỏa thuận đã hoàn tất rồi”,\ntôi nói. Cả hai chúng tôi đều nghĩ như vậy. Chúng tôi không vui mừng, và cũng chẳng hề\nthấy thoải mái. Chúng tôi biết người ngoài có thể nghĩ chúng tôi đang nhảy dựng lên vì\nsung sướng chứ không phải đang có một tâm trạng ngậm ngùi pha lẫn thư thái kỳ lạ thế\nnày. Niềm đam mê với LinkExchange đã biến mất từ lâu. Giờ đây, chúng tôi sẽ phải làm\nviệc mà không có chút đam mê và động lực nào trong mười hai tháng nữa.\n“Tớ nghĩ chúng ta nên quay lại văn phòng lần nữa”, tôi nói.\n“Được thôi.”\nVà chúng tôi đã làm như vậy, trong lặng lẽ.\nĐiều khiển hành trình\nCá cược về bản chất vẫn là cá cược. Nếu thua cược, tôi sẽ phải trả giá.\nVào ngày tốt nghiệp đại học, bạn bè tôi đã cá cược với tôi. Họ cược rằng tôi sẽ trở thành\ntriệu phú trong vòng mười năm, và nếu điều đó xảy ra, thì chúng tôi sẽ đi du lịch cùng\nnhau và tôi sẽ phải bao toàn bộ chi phí cho chuyến đi. Nếu chuyện đó không xảy ra, chúng\ntôi vẫn sẽ đi du lịch cùng nhau nhưng họ sẽ góp tiền lại để trả toàn bộ chi phí cho tôi. Với\ntôi, nó giống như việc mình đã nắm chắc phần thắng: hoặc là tôi sẽ trở thành một triệu phú\nhoặc là tôi sẽ nhận được một chuyến du lịch miễn phí. Dù thế nào thì tôi cũng sẽ được vui\nvẻ, vì thế tôi đã đồng ý cá cược.\nĐó là vào đầu năm 1999, tất cả chúng tôi đã bay đến Florida, bắt đầu hành trình ba ngày\ntrên biển tới Bahamas. Tôi cũng mời vài người bạn khác nữa đi cùng và chúng tôi có tất cả\nmười lăm người. Tôi chưa bao giờ đi trên một con tàu nên đã vô cùng ngạc nhiên khi nhìn\nthấy con tàu lớn như vậy. Nó có một hộp đêm, mười quán bar, bể bơi và năm nhà hàng có\nđủ mọi đồ ăn. Chúng tôi đã rất vui vẻ bên nhau, cùng ăn uống, tiệc tùng, rồi lại ăn uống,\ntiệc tùng. Nó giống như một cuộc hội trường mà không có bất cứ phần nào nhàm chán.\nChúng tôi quyết định sẽ đến hộp đêm vào đêm cuối cùng của chuyến đi để uống rượu và\nkhiêu vũ suốt đêm. Trong mắt những người tham gia chuyến đi này, tôi là người có tất cả –\nthành công và hạnh phúc. Bạn bè tôi nhận xét rằng tôi dường như tự tin hơn trước và chúc\nmừng tôi về việc tôi bán công ty cho Microsoft.\nMột giờ sáng, DJ thông báo rằng quán sẽ phục vụ lần cuối cùng, sau đó quán bar và hộp\nđêm sẽ đóng cửa. Khi mọi người trong quán đều hướng về phía quán bar để gọi đồ uống lần\ncuối trước khi đêm qua đi, thì tôi tự đứng dậy để tránh bị xô đẩy và để tận hưởng khoảnh\nkhắc này. Nếu bốn năm về trước có ai đó nói với tôi rằng tôi sẽ trở thành một triệu phú và\năn mừng trên một chiếc du thuyền thế này, tôi sẽ chẳng thể tin nổi.\nKhi đồ uống đã cạn, tiếng nhạc đã lắng xuống và bạn bè cũng đã nâng cốc chúc tụng\nnhau, một giọng nói thầm thì trong tâm trí tôi nhắc đi nhắc lại câu hỏi tôi từng trăn trở khi\ncùng Sanjay quay lại văn phòng vào cái ngày thỏa thuận bán công ty cho Microsoft hoàn\ntất: Bây giờ là cái gì đây? Cái gì tiếp theo?\nVà sau đó là liên tiếp những câu hỏi: Thành công là gì? Hạnh phúc là gì? Tôi đang làm\nviệc vì điều gì?\nTôi vẫn không có câu trả lời. Vì thế tôi lại đến quán bar, gọi một chai vodka và chạm cốc\nvới Sanjay. Việc đi tìm câu trả lời hãy gác lại sau.\nSau chuyến du lịch biển, tôi cảm thấy dường như tôi đã trở thành một cái máy tự động:\ndậy muộn, có mặt ở văn phòng trong vài tiếng chỉ để kiểm tra email và trở về nhà rất sớm.\nThỉnh thoảng, tôi lại lấy cớ để không phải đến văn phòng.\nTôi có rất nhiều thời gian rảnh và tôi chẳng biết phải làm gì.\nVì thế, tôi có rất nhiều thời gian suy ngẫm. Tôi đã mua mọi thứ mình muốn: một nơi để\nở, một chiếc tivi màn hình lớn và xây dựng một rạp hát. Tôi bắt đầu đến Vegas vào cuối\ntuần để chơi bài poker. Tôi chơi bài không phải vì tiền mà vì thách thức tìm ra cách thức để\nthắng được trò chơi. Chơi poker là trò duy nhất ở sòng bạc bạn có thể chơi với những người\nchơi thay vì nhà cái, do đó, bạn sẽ thắng dài dài miễn là bạn giỏi hơn người chơi trung bình\nở cùng bàn.\nNhưng phần lớn thời gian rảnh rỗi của tôi được dành để tự vấn và suy ngẫm. Tôi không\ncần nhiều tiền hơn nữa, vậy cái gì là tốt cho tôi? Tôi còn chẳng chi tiêu hết số tiền tôi có.\nVậy tại sao tôi lại phải làm việc cho Microsoft, cầm quyền trong hoà bình và cố gắng để\nkiếm thêm chút tiền nữa chứ?\nTôi lên danh sách những điều hạnh phúc nhất trong cuộc đời mình và nhận ra rằng\nchẳng có giai đoạn nào liên quan đến tiền cả. Tôi hiểu ra rằng việc gây dựng sự nghiệp và\ntrở nên sáng tạo làm tôi hạnh phúc. Liên lạc với bạn bè và tán chuyện thâu đêm khiến tôi\nhạnh phúc. Bày những trò đùa ma mãnh với những người bạn thân cùng trường trung học\nkhiến tôi vui. Ăn một củ khoai nướng sau khi bơi khiến tôi vui. Dưa chuột muối khiến tôi\nvui (Mặc dù tôi không hiểu vì sao lại như vậy. Tôi nghĩ có thể vì nó ngon và vì tôi thích nói\n“dưa chuột muối” chăng.)\nTôi nghĩ về việc chúng tôi đã bị xã hội và nền văn hoá này tẩy não dễ dàng như thế nào\nđể không suy nghĩ nữa mà chỉ cần mặc định thừa nhận rằng càng nhiều tiền thì càng thành\ncông và hạnh phúc, trong khi hạnh phúc chính là thực sự tận hưởng cuộc sống này.\nTôi nghĩ về việc tôi đã thích thú thế nào khi gây dựng, phát triển và thực hiện những\nđiều mình đam mê. Có rất nhiều cơ hội để gây dựng và phát triển sự nghiệp, đặc biệt khi\ncông nghệ Internet đang bùng nổ và chẳng thể có đủ thời gian để theo đuổi tất cả các ý\ntưởng. Nhưng tôi lại ở đây, lãng phí thời gian, lãng phí cuộc đời mình để kiếm thêm chút\ntiền mặc dù tôi đã có rất nhiều tiền, đủ dùng cho hết phần đời còn lại. Rất nhiều thứ làm\nbiến đổi thế giới. Chúng tôi đang ở đêm trước của không chỉ thế kỷ mới mà còn của thiên\nniên kỷ mới. Thế giới đang thay đổi mạnh mẽ không ngừng, và tôi đã bỏ lỡ những thay đổi\nđó chỉ để kiếm thêm chút tiền trong khi đã có đủ số tiền mình cần.\nVà tôi ngừng suy xét bản thân để bắt đầu tự vấn:\n“Sẽ chẳng bao giờ có một năm 1999 nào khác nữa. Mình định làm gì cho năm nay?”\nTôi đã biết câu trả lời. Trong khoảnh khắc đó, tôi đã chọn cách thành thật với chính\nmình và quyết định từ bỏ số tiền Microsoft trả để giữ chân tôi.\nVài ngày sau, tôi đến văn phòng, gửi email tạm biệt công ty và bước ra khỏi cửa. Tôi\nchưa biết mình sẽ làm gì nhưng chắc chắn là tôi sẽ làm một điều gì đó. Tôi không định ăn\nkhông ngồi rồi và để cuộc đời cũng như thế giới trôi qua lãng phí. Có thể người ta cho rằng\ntôi thật điên rồ khi từ bỏ số tiền đó. Có lẽ là đúng vậy, đưa ra quyết định đó cũng thật điên\nrồ, nhưng như thế mới đúng.\nLúc đó, tôi không biết được rằng đó chính là bước ngoặt trong cuộc đời tôi. Tôi đã quyết\nđịnh không theo đuổi tiền bạc mà bắt đầu theo đuổi niềm đam mê của mình.\nTôi đã sẵn sàng bước sang một trang mới trong cuộc đời.', '2026-02-28 08:14:29'),
	(15, 17, 1, 'NHỮNG TÌNH HUỐNG KHÓ XỬ NƠI CÔNG SỞ', '1. CÁC CUỘC THẢO LUẬN THƯỜNG GẶP VỀ VẤN ĐỀ QUẢN LÝ VÀ\nGIÁM SÁT\nHòa giải giữa các nhân viên, phản ứng thích hợp trước yêu cầu giữ bí mật về\ncác thông tin cá nhân, cũng như đưa ra lời khuyên trước mỗi bữa tiệc do\ncông ty tổ chức, tất cả đều là một phần công việc của nhà lãnh đạo và quản\nlý. Tuy nhiên, những điều tưởng chừng đơn giản như vậy có thể trở thành\nvấn đề đau đầu đối với các nhà quản lý dễ tính nhưng lại không lường trước\nđược những rắc rối phát sinh từ lời khuyên mà họ đưa ra.\nBạn hãy coi chương này như một khóa học Quản lý cơ bản. Những gợi ý và\nchiến lược quản lý trong chương này sẽ giúp bạn giải quyết các vấn đề thông\nthường nhưng cũng đầy nguy hiểm đang chờ đợi phía trước. Những ví dụ\nnày không chỉ giúp bạn quản lý hiệu quả hơn mà còn giúp nhân viên của bạn\nhọc cách quản lý hiệu quả khi được đặt vào vị trí lãnh đạo trong tương lai.\nTình huống 1: Hòa giải tranh cãi giữa các nhân viên\nCác nhà quản lý đều cảm thấy không hài lòng về các vấn đề căng thẳng giữa\nnhân viên cũng như những mâu thuẫn chưa được giải quyết. Hãy đối mặt với\nvấn đề này: Thường thì bạn đã có quá nhiều việc cần giải quyết mà không\nliên quan tới cảm giác khó chịu, tức giận cũng như lo lắng khiến bạn cảm\nthấy mình như là một trọng tài hơn là người giám sát.\nTuy nhiên, do nhu cầu giữ chân những nhân viên giỏi, nhà quản lý phải tìm\ncách giúp những người có mâu thuẫn hòa hợp trở lại, nếu không họ sẽ phải\nđối mặt với tình trạng nhân viên bỏ việc thường xuyên. Dù vậy, thực tế là\ncác thành viên trong nhóm của bạn thường lựa chọn cách thức ít đối đầu với\nnhau nhất − tránh nhau ra − hơn là trực tiếp giải quyết vấn đề gây mâu thuẫn.\nVới vai trò nhà quản lý, bạn phải can thiệp như một người hòa giải để đảm\nbảo hạn chế va chạm giữa những nhân viên có mâu thuẫn với nhau, để không\ndẫn đến tình trạng sụt giảm hiệu quả công việc hay bỏ việc.\nCoi như mâu thuẫn đó không tồn tại hay để nhân viên tự giải quyết mâu\nthuẫn có thể là một biện pháp an toàn khi khúc mắc giữa các cá nhân nảy\nsinh lần đầu; tuy nhiên, bạn phải can thiệp khi vấn đề thường xuyên xảy ra.\nGiải pháp\nKhi hai thành viên trong nhóm mâu thuẫn với nhau, bạn hãy gặp riêng từng\nngười và giải thích bạn định xử lý vấn đề như thế nào:\nSam, tôi muốn gặp riêng anh và tôi cũng sẽ làm thế với Christina sau khi nói\nchuyện xong với anh. Tôi muốn anh hiểu cách thức chúng ta cùng giải quyết\nvấn đề căng thẳng giữa anh với Christina.\nĐầu tiên, tôi muốn nghe ý kiến của anh, và sau đó tôi sẽ chia sẻ lại với\nChristina. Tôi cũng sẽ nghe ý kiến của Christina và nói với anh trước khi cả\nba chúng ta cùng gặp gỡ. Bằng cách này, mọi người sẽ hiểu được vấn đề của\nngười khác, nguyên nhân gây ra mâu thuẫn, từ đó bàn bạc và đề xuất cách\ngiải quyết.\nNói ngắn gọn, chúng ta sẽ giải quyết vấn đề này trong ba cuộc gặp: Thứ nhất\nlà cuộc gặp này giữa chúng ta. Tiếp theo tôi sẽ gặp Christina, và gặp lại anh\nđể trao đổi về ý kiến phản hồi của cô ấy. Cuối cùng là cuộc nói chuyện giữa\nba chúng ta vào chiều nay. Mọi người đều sẽ biết rõ vấn đề, và chúng ta sẽ\ngiải quyết mâu thuẫn này như những người trưởng thành, tôn trọng lẫn nhau.\nAnh đã rõ ý định của tôi chưa?\nTrong cuộc nói chuyện với Sam, hãy hỏi anh ta lý do khiến Christina có suy\nnghĩ tiêu cực. Hãy hỏi Sam về điều anh ta muốn cải thiện trong mối quan hệ\nvới Christina, cũng như điều mà anh ta sẵn lòng thay đổi trong cách ứng xử\nđể có được thái độ tốt hơn từ phía đồng nghiệp trong tương lai. Tương tự,\nsau khi gặp Christina, hãy tìm hiểu ý kiến của cô ấy và chia sẻ cảm nhận đó\nvới Sam.\nCuộc gặp thứ ba là thời điểm quan trọng để tìm ra giải pháp. Bạn cần hiểu\nnhân viên sẽ cảm thấy lo lắng rằng quan hệ giữa họ có thể trở nên căng thẳng\nhơn, vì vậy hãy đặt ra những quy định cơ bản sau:\nSam và Christina, tôi có hai quy định cơ bản mà tất cả chúng ta đều phải\ntuân thủ trước khi bắt đầu trao đổi.\nQuy tắc thứ nhất là hai bạn không nên giữ lại bất cứ suy nghĩ nào. Đây là cơ\nhội để các bạn nói rõ tất cả mọi chuyện, và nếu giữ lại điều gì đó, cả hai sẽ\nbỏ lỡ cơ hội vàng để chia sẻ suy nghĩ của mình. Hai bạn sẽ không còn cơ hội\nnào khác để giải quyết những vấn đề dồn nén cũng như nỗi thất vọng. Sau\nbuổi gặp hôm nay, tôi vui mừng chào đón cả hai đến công ty như thể đó là\nngày làm việc đầu tiên. Từ thời điểm này, tôi yêu cầu hai bạn phải có trách\nnhiệm cải thiện mối quan hệ công việc giữa hai người. Cả hai đã hiểu chưa?\n[Vâng].\nThứ hai, mọi điều cần chia sẻ phải được nói sau khi cân nhắc lợi ích của\nnhau với tinh thần phê phán mang tính xây dựng. Không được công kích\nnhau cũng như không cần thiết phải tự vệ trong buổi gặp này; đây thực sự là\nmột buổi nói chuyện nhạy cảm mà cả hai bạn cần phải đặt mình vào hoàn\ncảnh của mỗi người và lắng nghe suy nghĩ của nhau. Cả hai bạn có đồng ý\nvới những quy định cơ bản này không? [Vâng].\nMột buổi gặp gỡ với các quy định như vậy sẽ giảm bớt cảm giác lo lắng\ncũng như tức giận cho những người tham dự. Nó cũng cho bạn cơ hội tiến\nhành một phương pháp nhẹ nhàng khi giải quyết những vấn đề về quan hệ\ngiữa các cá nhân.\nGhi chú đặc biệt\nTrong buổi họp nhóm, đôi lúc bạn sẽ thấy từng nhân viên trực tiếp chia sẻ\nnhững điều lo lắng của họ với bạn − người trung gian, như thể người còn lại\nkhông ở đó. Cuộc nói chuyện ở ngôi thứ ba “anh ta - cô ta” cần phải được\nchuyển thành cuộc nói chuyện “tôi - anh/chị”. Để làm được điều này, bạn\nhãy dừng cuộc nói chuyện ngay khi một trong số những người tham dự bắt\nđầu nói về người kia theo cách này. Bạn hãy yêu cầu người đó nói trực tiếp\nvới người còn lại như thể bạn không có mặt ở đó. Lúc đầu, điều này có vẻ\nkhó khăn với những người tham dự, đặc biệt khi họ cảm thấy quá bức xúc,\nnhưng nói chuyện trực tiếp sẽ hiệu quả nhất. Cuối cùng, bạn hãy giúp họ giải\nquyết vấn đề giữa họ.\nNgoài ra, bạn nên khuyến khích nhân viên sử dụng những cụm từ như “cảm\nnhận của tôi là” hay “anh/chị có hiểu tại sao tôi lại có cảm giác như vậy\nkhông?” Cảm giác không có đúng sai, chỉ là cảm giác mà thôi. Vì cảm nhận\nvẫn là sự thật cho đến khi nó được chứng minh, mỗi nhân viên đều phải có\ntrách nhiệm thay đổi cách suy nghĩ về nhau bất chấp sự tồn tại của những\nsuy nghĩ đã hình thành từ trước đó.\nBạn nên biết rằng cảm giác có lỗi sẽ khiến họ nhận một phần trách nhiệm\ntrong rắc rối nào đó, đồng thời có trách nhiệm đóng vai trò là hạt giống thiện\nchí góp phần chữa lành những vết thương dai dẳng. Ví dụ, nếu Christina cảm\nthấy tồi tệ về mối quan hệ với Sam, cô ấy chia sẻ với Sam lý do gây nên cảm\ngiác như vậy, thừa nhận cả hai đều có trách nhiệm trong đó, và Sam cũng\nphản ứng tích trước thiện chí của Christina.\nGiành được trái tim của đối thủ, nghĩa là bạn đã chiến thắng. Bạn sẽ biết\nmình đã làm được điều đó chưa khi hai nhân viên nói chuyện với nhau, nhất\ntrí rằng mối quan hệ của họ có vấn đề, và sẵn lòng giải quyết. Cách can thiệp\nvề quản lý như vậy thông thường không phải là những cuộc điều tra sự thật\nmà là những khóa đào tạo về tính nhạy cảm, trong đó thẳng thắn và thiện chí\nsẽ giải quyết các vấn đề phát sinh. Hãy kết thúc cuộc gặp theo cách sau:\nChristina và Sam, cả hai bạn đều đã lắng nghe những suy nghĩ của nhau. Tôi\nkhông yêu cầu cả hai phải trở thành bạn tốt của nhau, nhưng tôi đòi hỏi các\nbạn từ giờ phải thẳng thắn và tôn trọng nhau trong công việc.\nTôi sẽ kết thúc cuộc gặp này bằng hai câu hỏi. Thứ nhất, các bạn có cam kết\nvới tôi từ giờ sẽ đối xử với nhau bằng thiện chí theo hướng tích cực không?\nThứ hai, cả hai phải hiểu nếu không cải thiện tình trạng này và gây ảnh\nhưởng tới hoạt động của công ty, tôi sẽ có những hình thức kỷ luật nặng hơn\nthay vì gặp gỡ như thế này không?\nBạn đã trao cho cả hai nhân viên cơ hội được bày tỏ và chia sẻ cảm nhận của\nmình. Bạn sẽ kết thúc cuộc gặp bằng một thông điệp mang tính xây dựng khi\ncả hai đồng ý thay đổi cách cư xử. Đồng thời, bạn cũng tạo ra suy nghĩ tích\ncực khi giúp cả hai ý thức được rằng nếu vấn đề này xảy ra một lần nữa, họ\nsẽ phải chịu hình thức kỷ luật nặng hơn − cảnh cáo bằng văn bản. Chúc\nmừng bạn! Bạn đã xử lý mâu thuẫn giữa các bên như những người trưởng\nthành và buộc họ có trách nhiệm giải quyết vấn đề về mối quan hệ giữa họ.\nTuy nhiên, hãy nhớ rằng dù quan tâm đến mức nào, bạn cũng không thể\nkiểm soát được sự khác biệt giữa họ mà chỉ họ mới có thể làm được điều đó.\nBạn cũng có thể tạo ra một diễn đàn giúp giải quyết những mâu thuẫn giữa\nnhân viên với nhau, và là nơi nhân viên thảo luận về những điểm tốt của\nnhau. Thiết lập một nền văn hóa cởi mở đồng nghĩa với giải quyết các vấn đề\nvề quan hệ trong một môi trường an toàn cũng như tôn trọng nhân phẩm của\nnhau. Nó góp phần tăng cường vai trò lãnh đạo của bạn và tạo cho bạn danh\ntiếng với tư cách một nhà quản lý công bằng. Không có công thức nào giữ\nchân nhân viên tốt hơn là thể hiện sự tôn trọng và ân cần lắng nghe họ.\nTình huống 2: Phản ứng thích hợp với những yêu cầu nói chuyện “bí mật”\nĐã bao giờ nhân viên gặp bạn và yêu cầu được nói chuyện riêng chưa?\nNhiều nhà quản lý nhiệt tình luôn vui vẻ chấp nhận yêu cầu của nhân viên\nmà không xem xét kỹ bản chất của vấn đề. Trên thực tế, bạn cần rất cẩn thận\nkhi hứa hẹn giữ bí mật trước khi biết rõ điều mà nhân viên chuẩn bị tiết lộ\nvới bạn vì lý do: Do bản chất, nên một số vấn đề nhất định cần được tiết lộ\nngay lập tức. Đơn giản là bạn không có quyền giữ bí mật vấn đề này trong\nbất kỳ hoàn cảnh nào, đồng thời hứa hẹn giữ bí mật có thể khiến bạn tiến\nthoái lưỡng nan khi mất lòng tin nơi cấp dưới.\nDưới đây là một số tình huống có thật mà những nhà quản lý ngây thơ vô\ntình mắc phải, khi không nhận ra họ có trách nhiệm phải thông báo thông tin\nnày với phòng nhân sự hay bộ phận pháp chế của công ty:\nJohn, tôi thực sự lo lắng cho Marlene. Có vẻ như cô ấy đang bị người giám\nsát quấy rầy, và cô ấy không muốn phàn nàn hay làm ầm mọi chuyện. Tôi\ncảm thấy tệ thay cho cô ấy, nhưng cô ấy sẽ gặp rắc rối lớn nếu biết tôi nói\nchuyện này với người khác. Thật khó xử! Marlene biết tôi đã tình cờ nghe\nđược những lời bức xúc của cô ấy, nhưng có lẽ cô ấy nghĩ rằng tôi sẽ giữ bí\nmật chuyện này. Tôi cũng không muốn cô ấy biết tôi đã tiết lộ điều này với\nanh.\nVic, ngày hôm nay quá tồi tệ với tôi. Nói thật, nếu giờ mà bị ai đó làm phiền,\ncó thể tôi sẽ sẵn sàng phá hỏng một ngày của họ.\nMillie, mặc dù không phải việc của tôi, nhưng hình như Doris đang làm việc\ncho đối thủ cạnh tranh của công ty vào các ngày cuối tuần thì phải. Đừng nói\nđiều gì cả! Tôi không muốn cô ấy gặp rắc rối hay mất đi nguồn thu nhập\nthêm đó, nhưng tôi phân vân liệu cô ấy có cung cấp bất kỳ thông tin mật nào\ncủa công ty cho các đối thủ cạnh tranh không?\nGiải pháp\nNhững tình huống này cho thấy mối nguy hiểm thực sự − đối với cả công ty\ncũng như bạn − khi hứa giữ bí mật trước khi biết rõ bản chất vấn đề. Đó là\nbởi nhân viên thường không nhận ra điều họ đang yêu cầu bạn làm khi đề\nnghị bạn giữ bí mật trước khi nói chuyện. Khi một nhân viên đề nghị nói\nchuyện riêng với bạn, hãy trả lời theo cách sau:\nLaura, tôi rất vui khi được nói chuyện riêng với chị, nhưng điều này còn phụ\nthuộc vào bản chất vấn đề. Tôi không thể giữ bí mật nếu điều chị nói với tôi\nliên quan tới một trong ba vấn đề sau: (1) hành vi quấy rối hay phân biệt đối\nxử; (2) nguy cơ bạo lực ở nơi làm việc, hay (3) xung đột lợi ích công ty. Nếu\nchuyện chị chuẩn bị nói liên quan tới bất kỳ điều nào trong số đó, tôi không\nthể giữ bí mật được và phải có trách nhiệm tiết lộ nó. Vì vậy, trước khi nói\nbất kỳ điều gì với tôi, chị hãy suy nghĩ kỹ và hiểu trách nhiệm quản lý của\ntôi. Bây giờ chị có còn muốn nói chuyện riêng với tôi nữa không?\nĐiều này nghe có vẻ hơi nghiêm túc, đặc biệt nếu bạn biết rõ về nhân viên\nđó. Nhưng hãy nhớ rằng bạn không có quyền giữ bí mật những vấn đề có\nảnh hưởng tiêu cực đến công ty. Ngoài ra, bạn cần nhớ rằng mức threshold\nthấp thường được sử dụng đi sử dụng lại trong các vụ kiện tụng về quấy rối\nhay phân biệt đối xử: Khi bất kỳ người giám sát hay thành viên ban quản lý\nnào được thông báo về một vấn đề thì theo luật pháp, toàn bộ công ty cũng\nphải được thông báo về vấn đề đó. Đây thực sự là một gánh nặng lớn đặt trên\nvai bạn nếu việc kiện tụng dựa trên thực tế là bạn là người giám sát duy nhất\nđược thông báo về vấn đề nghiêm trọng đó. Điều này còn được sử dụng một\ncách khôn ngoan khi luật sư bên nguyên viện dẫn việc bạn biết về vấn đề này\nđồng nghĩa giám đốc điều hành của công ty cũng được thông báo về vấn đề\nđó.\nHãy nhớ rằng bạn không được trả lời như thế này: “Vâng, tôi không tiết lộ vì\nnhân viên đó yêu cầu tôi giữ bí mật!” Đó thực sự là hồi chuông báo tử với\nbạn, và bất kỳ luật sư biện hộ dày dạn kinh nghiệm nào (đại diện cho công ty\ncủa bạn) đều sẽ nhíu mày khi nghe thấy điều đó và cố vấn cho công ty bạn\ngiải quyết vụ việc bên ngoài phạm vi tòa án. Tóm lại, bạn không có bất kỳ\nlời biện hộ thỏa đáng nào và chỉ có thể đưa ra lý do bào chữa thiếu sức\nthuyết phục nhất bởi “nhân viên của tôi đề nghị tôi giữ bí mật vấn đề đó”, nó\nrõ ràng vi phạm trách nhiệm ủy thác mà công ty giao phó cho bạn, và mọi\nngười, trừ những người giám sát thiếu kinh nghiệm cũng như chưa qua thử\nthách, đều biết việc này. Đây thực sự là một đòn giáng mạnh vào bạn và\ncông ty đồng thời cũng là điều mà bạn muốn tránh bằng bất cứ giá nào.\nTương tự, sau khi hứa hẹn giữ bí mật với nhân viên nào đó, bạn thực sự\nkhông muốn tìm đến phòng nhân sự và tiết lộ nhân viên đã kín đáo đe dọa\nbạo lực. Tất nhiên, bạn phải tiết lộ thông tin đó vì lo sợ xảy ra bạo lực ở nơi\nlàm việc cũng như lo lắng cho sự an toàn của người khác. Tuy nhiên, nhân\nviên đó sẽ biết bạn là người duy nhất nghe được “lời bình luận” đó (cũng là\nlời đe dọa), và nó cũng báo trước những rắc rối xảy ra với bạn trong việc bảo\nvệ an toàn và sức khỏe bản thân. Hãy bổ sung vấn đề quan trọng này vào\ncẩm nang quản lý doanh nghiệp giúp bạn biết cách phản ứng khi gặp những\ntình huống tương tự.\nTình huống 3: Thăng chức cho nhân viên vào vai trò giám sát lần đầu tiên\nCó gì khó khăn khi thăng chức cho một nhân viên vào vai trò giám sát lần\nđầu tiên? Thực ra, điều này còn phụ thuộc cách nhìn nhận của bạn. Tất\nnhiên, thật tuyệt vời khi đề bạt cấp dưới vào vị trí quản lý, nhưng các nhà\nquản lý mới cần được quán triệt trước khi bạn chính thức bổ nhiệm họ.\nTại sao lại như vậy? Bởi vì nếu họ nghĩ đơn giản là họ được thăng chức và\nkiếm được nhiều tiền hơn trong khi vẫn làm công việc tương tự như trước thì\nhọ đã nhầm. Việc bổ nhiệm vào vị trí giám sát đòi hỏi phải có những kỹ\nnăng và chiến lược hoàn toàn mới và nếu công ty muốn đầu tư và đề bạt họ\nthì bạn có quyền kỳ vọng ở họ trong tương lai. Do đó, đây có thể là một\nthông điệp mà bạn cảm thấy khó truyền tải còn nhân viên của bạn khó tiếp\nnhận. Tuy nhiên, thông thường bạn sẽ phát hiện ra rằng việc tạo cho người\ngiám sát mới được bổ nhiệm một nhận thức mới sẽ góp phần quan trọng giúp\nhọ hoàn thành và phát huy vai trò mới của mình.\nTuy nhiên, bạn đừng ngạc nhiên nếu ban đầu nhân viên đó thể hiện sự phản\nkháng hay thách thức. Họ sẽ nghĩ tại sao công ty lại thăng chức cho họ nếu\nhọ không làm tốt công việc, và tại sao bạn lại phá hỏng niềm vui cùng sự\nhứng thú bằng việc nêu ra tất cả những điểm yếu của họ?\nGiải pháp\nTrong cuộc nói chuyện, bạn cần đưa ra những đánh giá trung thực và cân\nnhắc về mức độ hoàn thành công việc từ trước đến nay của nhân viên đó\ncùng với những kỳ vọng đối với họ ở vị trí mới. Điều này có thể khiến nhân\nviên cảm thấy đôi chút khó chịu nhưng lại giúp người đó nhìn nhận về vị trí\nhiện tại, kết quả đạt được và mục tiêu phấn đấu. Vì vậy, có thể bạn sẽ muốn\nkết cấu cuộc nói chuyện theo cách sau:\nHeidi, tôi muốn thảo luận về việc thăng chức cho chị trong thời gian tới.\nChắc là chị rất mong chờ điều đó, nhưng trước khi hoàn tất các thủ tục giấy\ntờ và chị được chính thức thăng chức, tôi muôn nói chuyện thẳng thắn và cởi\nmở với chị về kỳ vọng của tôi đối với chị trong vai trò mới. Điều này hợp lý\nchứ? [Vâng].\nTrước giờ, chị luôn là một sinh viên ưu tú. Chị làm việc chăm chỉ, nghiêm\ntúc, sẵn sàng hoàn thành nhiệm vụ với thái độ tích cực. Chị luôn thông báo\ncho tôi biết tiến trình công việc cũng như báo cáo với tôi nếu chị không thể\nhoàn thành công việc đúng thời hạn hay gặp phải những trì hoãn không\nlường trước được, và tôi luôn đánh giá cao điều đó. Thực tế thì đây là lý do\nkhiến tôi luôn ủng hộ việc đề bạt chị vào vai trò quản lý.\nTuy nhiên, tôi muốn chị biết quan điểm của tôi về vấn đề này và tôi cũng\nkhông định dọa nạt chị. Đây là một cuộc nói chuyện cởi mở và chân thành\nmà tôi muốn chị tham gia và thấu hiểu; nhưng sẽ có một vài điều hơi khó\nnghe, vì vậy tôi muốn chị hãy tiếp cận vấn đề một cách cởi mở. Như vậy có\ncông bằng với chị không? [Vâng].\nTốt. Vậy hãy bắt đầu bằng điều tôi kỳ vọng ở chị: Nếu chị chấp thuận lời đề\nnghị thăng chức này, chị sẽ giám sát công việc của những người hiện tại\nđang là đồng sự của chị. Điều đó đồng nghĩa với việc một số người trong đó\nsẽ cảm thấy ghen tỵ với chị. Và chị sẽ phải giữ một khoảng cách nhất định\nnhằm tạo ra ranh giới rõ ràng giữa chị và họ.\nĐầu tiên, chị cần ăn mặc chuyên nghiệp và tinh tế hơn. Cho tới nay, chị vẫn\nmặc quần áo phù hợp với một nhân viên bình thường. Nhưng tôi nghĩ rằng\nkiểu quần áo đó không thích hợp với một thành viên ban quản lý. Một vài\nngười trong nhóm của chị rất biết cách ăn mặc, mặc dù tôi không nghĩ là họ\nmặc đẹp hơn chị, tuy nhiên nếu chị không cẩn thận, cấp dưới có thể khiến\nchị mất mặt. Hình ảnh của chị rất quan trọng, và tôi muốn chị suy nghĩ về\nhình ảnh mà chị muốn tạo dựng đối với cấp dưới cũng như cấp trên. Điều\nnày có hợp lý không? [Vâng.]\nĐược rồi. Tiếp theo, chị cần chọn bạn bè cẩn thận hơn. Tôi không thể nói với\nchị nên chọn ai làm bạn và cũng không yêu cầu chị phải chọn bạn như thế\nnào. Nhưng tôi nghĩ chị nên mở rộng phạm vi quan hệ của mình với các\nquản lý khác cũng như với các trưởng khoa. Hãy thể hiện mối quan hệ với\ncấp trên, và người khác sẽ coi trọng chị hơn. Chị có hiểu không? [Vâng].\nCuối cùng và cũng là quan trọng nhất, tôi cần chị đánh giá lại bản thân và\nchịu trách nhiệm về những dự án chị đảm nhận cũng như cấp dưới của chị.\nTóm lại, cho tới giờ chị luôn là một sinh viên xuất sắc. Nhưng tôi không cần\nmột sinh viên mà là một giáo viên. Và sự kỳ vọng của tôi ở một giáo viên\nhoàn toàn khác biệt so với một sinh viên.\nVới những người mới bắt đầu, tôi cần chị chỉ dẫn chứ không phải giám sát.\nTôi mong chị dám làm những công việc mạo hiểm nhưng tính toán kỹ lưỡng,\nvà được đồng ý trước. Tôi cần chị phải có tiếng nói quyết định, dù tôi biết\ntrước giờ chưa ai kỳ vọng chị làm những công việc đó. Tuy nhiên, việc thăng\nchức lần này sẽ thay đổi tất cả. Mọi người thường nói rằng cuộc đời bắt đầu\nkhi bước ra khỏi vùng an toàn của riêng mình, và tôi mong lúc này chị hãy\ntiến vào giai đoạn đó.\nLiệu chị đã sẵn sàng dạy học bằng cách soạn giáo án, cung cấp cho sinh viên\ncác thông tin mới, đưa ra những lời nhắc nhở xác đáng cũng như đương đầu\nvới các vấn đề phát sinh chưa? Liệu chị có đủ cương quyết để kỷ luật, tinh\ngiản biên chế hay chấm dứt hợp đồng với cấp dưới, những người mà hiện tại\nchị coi như bạn thân? Liệu tôi có thể tin tưởng chị tự đổi mới trước những\nthách thức sắp tới? [Vâng, anh có thể tin tưởng ở tôi.]\nĐó là những kỳ vọng của tôi dành cho chị, và chị cần chắc chắn mình đã sẵn\nsàng cải thiện khả năng nhằm đáp ứng những kỳ vọng đó. Tôi đề bạt những\nngười thành công vào những vị trí thành công. Tuy nhiên, ở đây cũng tồn tại\nrủi ro, giống như bất kỳ thay đổi nào trong cuộc sống, và chị cần chắc chắn\nđã sẵn sàng đối mặt với thách thức.\nChị không cần phải trả lời tôi ngay bây giờ. Tôi muốn chị suy nghĩ cẩn thận\nvề vấn đề này và trả lời tôi vào ngày mai. Hãy nhớ rằng chị không đơn độc\nvà tôi sẽ luôn giúp đỡ chị. Nhưng trước khi đồng ý thăng chức, hãy đảm bảo\nlà chị đã hiểu rõ những kỳ vọng của tôi cũng như khả năng đáp ứng những\nkỳ vọng đó của chị. Đừng bỏ lỡ cơ hội này, và hãy chuẩn bị sẵn sàng để\nbước lên một nấc thang mới trong sự nghiệp của mình. Khi gặp lại tôi vào\nsáng mai, tôi muốn thấy những biểu hiện thuyết phục rằng chị đã sẵn sàng\ncho vị trí mới. Chị có còn câu hỏi nào không?\nCuộc nói chuyện đã đưa ra rất nhiều thông tin. Và tất nhiên không cần thiết\nphải đề cập tới tất cả những vấn đề cụ thể này; văn phòng sạch sẽ gọn gàng,\ncách nói chuyện thân thiện, tránh thái độ đối đầu là những tiêu chí cơ bản.\nĐiều quan trọng là bạn cần đánh giá trung thực hiệu quả làm việc của nhân\nviên đó cho tới nay cũng như những kỳ vọng của bạn trong tương lai. Lúc\nđầu, sự thẳng thắn của bạn có thể khiến người nghe khó chấp nhận nhưng nó\nlại là điểm tựa thuận lợi cho sự phát triển trong công việc của họ. Đó là điều\nmà tất cả những người lãnh đạo sáng suốt và vị tha cần có.\nTình huống 4: Hội chứng người giám sát mới\nỞ cấp độ quản lý phòng, khi một trong ba đồng nghiệp làm việc lâu năm với\nnhau bỗng nhiên được thăng chức lên giám đốc và có quyền chỉ đạo hai\nngười còn lại, sự khó xử và ghen ghét sẽ phát sinh. Mặc dù cảm thấy mừng\ncho người bạn vừa được thăng chức, nhưng những cảm xúc đó của hai người\nđồng nghiệp có thể làm xấu đi mối quan hệ giữa họ.\nNgoài ra, người quản lý mới sẽ cảm thấy có lỗi vì mình được thăng chức\ntrong khi hai người còn lại thì không. Cảm giác có lỗi của người đó kết hợp\nvới cảm giác khó chịu của hai người còn lại có thể tạo thành vấn đề trong\nmối quan hệ giữa ba người.\nGiải pháp\nKhi sự căng thẳng và ghen ghét được thể hiện, người giám sát mới thường\nphản ứng theo một trong hai cách sau: Anh ta (1) sẽ tìm cách xoa dịu hai\nngười kia và xin lỗi vì việc anh ta được thăng chức bằng cách cho phép hai\nngười cấp dưới toàn quyền làm những gì họ muốn, hay (2) sử dụng biện\npháp cứng rắn, tận dụng mọi cơ hội để thiết lập quyền kiểm soát lên nhóm.\nTất nhiên, cả hai cách trên đều phát sinh vấn đề và cần được giải quyết\nnhanh chóng, triệt để.\nTravis, tôi cần nói chuyện về việc anh nhậm chức giám đốc. Hãy nói với tôi\nmọi thứ diễn ra như thế nào, đặc biệt là phản ứng của hai đồng nghiệp cũ −\nJannie và Heather − về vị trí mới của anh.\nBạn đừng ngạc nhiên khi nghe Travis nói là mọi việc vẫn thuận buồm xuôi\ngió, hãy xác nhận lại điều bạn nghe được từ các thành viên khác: Anh ta tận\ndụng mọi cơ hội để xoa dịu hai người kia hoặc hoàn toàn kiểm soát tất cả\nnhững việc họ làm. Trong tình huống thứ nhất, hãy nói:\nTravis, tôi vui mừng khi anh thấy mọi việc vẫn diễn ra suôn sẻ. Tuy nhiên,\ntôi muốn nói về điều mà một số người đang bàn tán. Nghe nói một vài người\ntrong số các nhân viên của anh thấy anh tỏ ra có lỗi với Jannie và Heather,\nkhi anh được thăng chức còn họ thì không. Điều đó thật dễ hiểu, được biết\nđến là Hội chứng người giám sát mới. Thường thì người mới được thăng\nchức cố xoa dịu những đồng nghiệp cũ hoặc cho phép họ làm bất cứ điều gì\nhọ muốn mà không đưa ra nhiều mệnh lệnh hay hướng dẫn. Liệu điều đó có\nđang diễn ra trong nhóm của anh không?\nCách nói chuyện và giọng điệu của bạn không cần phải gay gắt hay mang\ntính phán xét. Bạn đơn giản đang cố gắng giúp Travis giải quyết vấn đề và\ntạo điều kiện cho anh ta chia sẻ lý do khiến anh ta mang cảm giác có lỗi hay\nlưỡng lự khi phải quản lý công việc của những đồng nghiệp cũ.\nMặt khác, nếu nghe thấy rằng Travis đang áp dụng biện pháp cứng rắn để\nđối phó với các đồng nghiệp cũ, bạn có thể bắt đầu cuộc nói chuyện theo\ncách sau:\nTravis, tôi vui mừng khi anh thấy mọi việc vẫn diễn ra suôn sẻ. Tuy nhiên,\ntôi muốn nói về điều mà một số người đang bàn tán. Nghe nói rằng một vài\nngười trong số nhân viên của anh nhận thấy dường như anh đang áp dụng\ncác biện pháp cứng rắn đối với Jannie và Heather. Một nhân viên phàn nàn là\nanh ta cảm thấy bối rối vì anh đối xử với họ bằng thái độ kẻ cả và đối địch\nkhi làm việc cùng.\nTôi hiểu bây giờ hai người đó thuộc quyền quản lý của anh, nhưng chúng ta\nhãy thảo luận về cách thức điều hành bộ phận này. Quan trọng hơn, chúng ta\nhãy trao đổi về danh tiếng anh muốn tạo dựng với các nhân viên trong vai trò\ngiám sát bộ phận cũng như văn hóa nơi làm việc trong bộ phận do anh quản\nlý.\nNếu Travis thuộc quyền quản lý của bạn, bạn có toàn quyền thảo luận về vai\ntrò giám sát bộ phận của anh ta. Bạn cũng có quyền trao đổi với anh ta về\nđiều một số người đang bàn tán. Nói chuyện thẳng thắn và chân thành với\nTravis, bạn sẽ nhận thấy anh ta có thể sửa đổi theo những gợi ý mang tính\nxây dựng của bạn và sẵn sàng biến trách nhiệm anh ta mới đảm trách thành\nlợi ích cho hai đồng nghiệp cũ cũng như với toàn bộ nhóm anh ta quản lý.\nTình huống 5: Đón nhận nhân viên có vấn đề về kỷ luật\nViệc hòa nhập với nhân viên chuyển đến từ bộ phận khác khá phổ biến trong\nhoạt động kinh doanh. Tất nhiên, tuyển nhân viên từ bộ phận khác đang có ý\nđịnh thay đổi công việc là một chuyện; giúp người nào đó từ bộ phận khác\nhòa nhập vào nhóm của bạn do việc tái cơ cấu hay các sáng kiến của công ty\n− đặc biệt nếu người đó có vấn đề về thái độ làm việc hay mức độ hoàn\nthành công việc − lại là chuyện khác. Nghiêm trọng hơn, đôi khi bạn sẽ phải\nxử lý nhân viên mới gia nhập nhóm với một danh sách các kỳ vọng thiếu\nthực tế mà người giám sát cũ của họ hứa hẹn.\n“Sếp tôi hứa tăng 10% tiền thưởng cho tôi trong năm nay. Lời hứa đó vẫn\ncòn có hiệu lực chứ?”\n“Nghe nói là tôi sẽ được thăng chức vào tháng tới, đúng dịp kỷ niệm ngày tôi\nbắt đầu làm việc tại công ty. Anh sẽ đề bạt tôi vào vị trí nào vậy?”\n“Vâng, đúng là tôi phải nhận hình thức kỷ luật cảnh cáo vì điều mà sếp cũ\ncủa tôi gọi là mức độ hoàn thành công việc hạn chế, cũng chỉ vì bà ta không\nưa gì tôi.”\nHãy nhớ rằng đây là công việc bạn cần giải quyết khi giữ vai trò quản lý.\nNhững việc này có khi còn chiếm nhiều thời gian và khiến bạn lo lắng hơn\nquá trình hòa nhập về văn hóa nơi làm việc khi kết hợp nhân viên cũ và nhân\nviên mới. Khi nhân viên gặp rắc rối, hãy dành thời gian lắng nghe ý kiến và\nquan tâm tới những yêu cầu của họ nhưng đừng hứa hẹn gì cho tới khi bạn\ntìm hiểu rõ ràng sự việc qua nhiều nguồn thông tin.\nGiải pháp\nViệc người quản lý cũ hứa hẹn thăng chức hay tăng lương có thể là sự thật vì\nnó được ghi lại bằng văn bản và được người đứng đầu bộ phận nhân sự hay\ntài chính thông qua trước đó. Tuy nhiên, thường là bạn sẽ thấy những điều\nnhư vậy dựa trên ước đoán của nhân viên, vì vậy hãy cẩn trọng và khiến họ\nbình tĩnh hơn với những đòi hỏi của mình trong khi tìm hiểu vấn đề kỹ càng\nhơn.\nKhông may thay, bạn bắt buộc phải thông báo với nhân viên mới rằng người\nquản lý cũ, phòng nhân sự hay tài chính không thừa nhận đã đưa ra quyết\nđịnh đó, vì vậy nhân viên sẽ không được tăng lương hay thăng chức.\nGene, tôi đã tìm hiểu đề xuất thăng chức từ trợ lý lên điều phối viên của chị.\nTrên thực tế, sau khi trao đổi cùng Mark ở bộ phận tài chính, Carson ở\nphòng nhân sự và Ashley, quản lý cũ của chị, tôi e rằng đề xuất này của chị\nchưa được chính thức thông qua. Ashley có ý định đề bạt chị nhưng như chị\nbiết đấy, nếu không có sự đồng ý của phòng nhân sự và tài chính thì đề xuất\nnày vẫn thuộc danh sách xét duyệt.\nKhông may thay, hiện tại tôi không thể thăng chức cho chị do công ty đang\ntiến hành thắt chặt ngân sách và mối quan hệ công việc giữa tôi với chị vẫn\nchưa được kiểm nghiệm. Nếu chị muốn trao đổi với Mark, Carson hay\nAshley, họ luôn sẵn lòng tiếp đón chị. Tôi chỉ có thể nói với chị điều họ trao\nđổi với tôi và thông báo cho chị ý định giải quyết vấn đề này của tôi với tư\ncách là người quản lý mới của chị. Tôi tiếc rằng mình không thể đem đến tin\ntức tốt lành hơn cho chị.\nTrong những trường hợp này, bạn hãy nói cho nhân viên đó biết người mà\nbạn trao đổi cùng, điều họ nói và lý do dẫn đến nhầm lẫn. Bạn nên khẳng\nđịnh tất cả các bên đều đồng ý với quyết định trên và để nhân viên trực tiếp\nnói chuyện với những người có trách nhiệm đó nếu muốn. Hãy nhớ rằng bạn\nkhông tham gia vào việc ra quyết định mà chỉ đơn giản truyền đạt lại điều họ\nthông báo với bạn, và bạn sẵn lòng đánh giá tình hình dưới góc nhìn cởi mở\nvà tích cực.\nTuy nhiên, đôi khi bạn phải giải quyết vấn đề phức tạp hơn. Những nhân\nviên được chuyển đến nhóm của bạn với hình thức kỷ luật cảnh cáo do hiệu\nquả làm việc kém, thường xuyên nghỉ làm hay có hành vi không thích hợp\ncó thể đem đến những thách thức lớn cho bạn. Trong trường hợp này, hãy\nsao chép những bản kỷ luật cảnh cáo, cho họ xem ngay trước buổi gặp gỡ cá\nnhân và nói chuyện thẳng thắn với họ. Cách tốt nhất để giải quyết vấn đề là\nnói chuyện thẳng thắn và dựa trên lý lẽ xác đáng. Bạn có thể mở đầu cuộc\nnói chuyện với nhân viên theo cách sau:\nMichelle à, thông thường mọi vấn đề đều có tính hai mặt và không cần bàn\ncãi thêm về tính xác thực của những văn bản này nữa. Những văn bản này\nhoàn toàn xác thực bởi nó được lưu trong hồ sơ cá nhân cùng chữ ký của\nanh. Điều tôi quan tâm bây giờ là làm cách nào chúng ta có thể cải thiện tình\nhình và khiến mọi việc tốt đẹp hơn, một mặt để giúp chị tiến bộ, mặt khác\ncần thừa nhận rằng những việc xảy ra trước kia là thật và “mang tính chủ ý”\nở mức độ nào đó. Hãy chia sẻ với tôi ý định của chị nhằm giải quyết hài hòa\nhai thực tế này.\nĐiều bạn quan tâm lúc này là phản ứng của cá nhân nhân viên đó với những\nbản kỷ luật cảnh cáo. Nếu cô ấy từ chối trách nhiệm và đổ lỗi cho người\nkhác, có lẽ bạn phải giải quyết trường hợp nhân viên mắc “hội chứng mình\nchỉ là nạn nhân” và không chịu nhận trách nhiệm. Ngược lại, nếu nhân viên\nđó thừa nhận sai lầm, nhận trách nhiệm về hành động của mình và cam kết\nkhông mắc phải những sai sót tương tự trong tương lai, bạn đã gần hoàn\nthành nhiệm vụ. Nhân viên đó đã thể hiện thái độ chín chắn trong công việc\nvà có xu hướng nhìn nhận vấn đề tổng quát hơn để tránh mắc phải những sai\nlầm đó.\nBạn không nên đánh giá thấp giá trị của những cơ hội giúp nhân viên mới\nhòa nhập vào nhóm do bạn quản lý. Hiếm khi bạn có cơ hội như vậy để\nchứng tỏ khả năng lãnh đạo của mình, đồng thời hồ sơ cá nhân của bạn sẽ\nghi nhận thêm một ưu điểm. Khả năng giúp người khác vượt qua giai đoạn\nkhó khăn và thể hiện những kỹ năng lãnh đạo quan trọng trong một môi\ntrường kinh doanh đầy thách thức như hiện nay là yêu cầu tiên quyết và là\nlợi thế mà bạn có thể áp dụng trong bất cứ tình huống công việc nào.\nTình huống 6: Chấm dứt các vấn đề về thái độ\nGiải quyết các vấn đề về thái độ của nhân viên là một trong những thách\nthức mà nhà quản lý thường gặp nhất. Bạn biết mình có vấn đề cần xử lý khi\nbạn nhận thấy thái độ không tôn trọng của nhân viên được thể hiện bằng\nhành động nhướn lông mày, thở dài và các cử chỉ khác.\nNhà quản lý có xu hướng tránh đối đầu với các nhân viên hay cáu giận. Tuy\nnhiên, cảm giác cáu giận kéo dài thường dẫn đến việc nhân viên đó bị mọi\nngười công khai lảng tránh và cô lập. Đôi khi những cảm xúc dồn nén đó\ndẫn đến việc cãi vã nơi công cộng khi giọt nước tràn ly và sự việc vượt khỏi\ntầm kiểm soát.\nGiải pháp\nKhi giải quyết vấn đề thường gặp này, bạn cần ghi nhớ hai điều quan trọng.\nThứ nhất, nói chuyện riêng với nhân viên đó về đánh giá của bạn đối với\nhành vi của cô ấy. Hãy nói cụ thể và vẽ nên một bức tranh tổng quát bằng\nngôn từ để nhân viên đó có thể hiểu rõ về những thái độ cần thay đổi. Hãy đề\nnghị cô ấy giúp giải quyết vấn đề đang tồn tại và cả hai cần cam kết lắng\nnghe ý kiến của nhau cũng như cải thiện tình hình. Thứ hai, tránh dùng\nnhững từ ngữ như thái độ trong cuộc nói chuyện và thay thế nó bằng những\ntừ như cách ứng xử hay cư xử, những từ chung chung và khách quan hơn.\nĐiều thú vị là từ thái độ mang tính chủ quan, kích động và thường làm tăng\nmâu thuẫn do nó tạo ra cảm giác tức giận. Vì vậy, bạn cần tránh dùng từ đó\ntrong cuộc nói chuyện hay văn bản kỷ luật.\nKhi bạn cố gắng giải quyết vấn đề về cách giao tiếp với một trong những\nnhân viên của mình, hãy vẽ ra một bức tranh tổng quát bằng ngôn từ như\nsau:\nLisa, tôi cần chị giúp chuyện này. Tôi cảm thấy chị có vẻ tức giận với tôi hay\nvới ai đó trong nhóm. Có thể tôi nhận định sai nhưng đó là đánh giá chân\nthực về cảm xúc chị thể hiện. Tôi không biết điều gì khiến chị khó chịu như\nthế và hãy cho tôi biết nếu tôi có thể giúp chị.\nChị làm tôi cảm thấy khó xử trước mặt các thành viên khác khi nhướn mày,\nthở dài và nói: “Được thôi, tôi sẽ làm!” Ngôn ngữ cơ thể của chị cũng đầy\nkhiêu khích khi chị vênh mặt lên và chống tay vào hông.\nHay chị thấy việc tôi yêu cầu chị phải hoàn thành công việc đúng kế hoạch là\nkhông thích hợp? Tôi có phải theo dõi sát thời hạn hoàn thành dự án của chị\nhay chị phải có trách nhiệm thông báo với tôi về tiến độ dự án? Chị cảm thấy\nthế nào khi là người quản lý và một trong số nhân viên của chị phản ứng\ntheo cách đó ngay trước mặt những người khác? Chị cảm thấy thế nào nếu\ntôi phản ứng lại đòi hỏi của chị với giọng điệu và hành động như vậy? Chị\ncó thấy tôi thiếu tôn trọng chị hay tôi phải hạ mình trước chị, nhất là trước\nmặt những người khác trong nhóm?\nHãy chú ý đến những điểm nổi bật trong đoạn nói chuyện trên: “Chị làm tôi\ncảm thấy…” và “Chị cảm thấy thế nào…” là những cụm từ thường được sử\ndụng khiến người khác cảm thấy có lỗi. Cảm giác không đúng hay sai − nó\nchỉ là chính nó. Khi kết hợp những cụm từ như vậy với một tuyên bố cởi mở\nnhư “Chúng ta có cảm nhận khác biệt về vấn đề này,” nhân viên thường sẵn\nlòng lắng nghe ý kiến của bạn. Mọi vấn đề đều có tính hai mặt, và thường là\nnhân viên sẽ không phủ nhận trách nhiệm của mình nếu nó được trao đổi\nmột cách thích hợp. Tuy nhiên, điều nhân viên mong muốn là người quản lý\nlắng nghe và quan tâm tới mình. Do đó, hãy nắm bắt cơ hội này để giải quyết\nvấn đề thông qua trao đổi bằng tuyên bố chấm dứt đối đầu và lắng nghe với\nthái độ khách quan.\nTình huống 7: Lời khuyên trước một bữa tiệc hay buổi dã ngoại do công ty\ntổ chức\nĐôi khi, đảm nhiệm vai trò nhà quản lý cũng giống làm cha mẹ. Trước khi tổ\nchức một sự kiện gia đình trọng đại, bạn cần nhắc nhở con cái để bảo đảm là\nchúng chuẩn bị đầy đủ mọi thứ và có thái độ đúng đắn bởi vì chỉ cần một lời\nbình luận bất cẩn hay một sai lầm có thể gây ra hậu quả tai hại với bản thân\nchúng cũng như với các thành viên khác trong gia đình. Đã bao nhiêu lần cha\nmẹ bạn hay chính bạn suy nghĩ về một tình huống như vậy và thở dài tự hỏi\n“Không biết chúng đang nghĩ gì nữa?”.\nTất nhiên, mọi người không mong chúng ta đóng vai trò cha mẹ thực sự ở\nnơi làm việc, nhưng cũng không mấy khác biệt khi chúng ta có cảm giác\nđang đảm nhận trách nhiệm tương tự với vai trò là người giám sát hay quản\nlý. Các bữa tiệc công ty, các buổi dã ngoại hay hoạt động bên ngoài giúp tạo\nbầu không khí vui vẻ và tươi mới cũng như là cách để nhân viên hiểu nhau\nhơn bên ngoài công sở. Tuy nhiên, những lời nhận xét bất cẩn hay thái độ\nkhông đúng mực có thể khiến tình cảm sứt mẻ. Không ngạc nhiên khi bạn\nnghe kể về những người bị sa thải sau một bữa tiệc công ty do say rượu và\nđưa những lời nhận xét không đúng mực − chuyện vẫn thường xuyên xảy ra\ntrong môi trường kinh doanh hiện nay.\nGiải pháp\nTrước khi tổ chức một sự kiện của công ty như một bữa tiệc, hãy gặp gỡ toàn\nthể nhân viên để giúp họ “giữ tỉnh táo”, đặc biệt nếu bữa tiệc phục vụ đồ\nuống có cồn. Bạn có thể mở đầu như sau:\nChào mọi người. Tôi muốn có một cuộc họp ngắn trước bữa tiệc đêm nay.\nĐây là lúc nghỉ ngơi, nhưng tôi muốn dành vài phút để chia sẻ với tất cả bạn\ncách thức tốt nhất để kiểm soát bản thân và điều bạn nên làm nếu rơi vào\ntình huống khó xử hay cảm thấy khó chịu vì bất cứ lý do nào. Tôi muốn nhắc\nnhở mọi người rằng bữa tiệc sẽ phục vụ đồ uống có cồn và mỗi người sẽ\nđược dùng hai ly. Nhưng không có nghĩa là bạn phải sử dụng cả hai ly này,\nvà đồ uống nhẹ có thể là lựa chọn thay thế sau khi bạn suy nghĩ về điều tôi\nsắp nói.\nVâng, các bữa tiệc đồng nghĩa với vui vẻ và thoải mái. Và tôi cũng không\nmuốn cảnh báo quá nhiều về những hành vi không thích hợp trong bữa tiệc\ntối nay và khiến mọi người mất vui trước khi nó bắt đầu. Tuy nhiên, cần có\ngiới hạn về cách ứng xử tại bữa tiệc, vì nhiều người đã hủy hoại con đường\nsự nghiệp tươi sáng của mình chỉ qua một đêm bất cẩn. Thực tế, nhiều người\nthậm chí còn bị mất việc chỉ vì mất bình tĩnh tại một bữa tiệc. Vì vậy, trước\nkhi tự do vui vẻ trong bữa tiệc, mọi người hãy nhớ ba nguyên tắc sau:\nNguyên tắc thứ nhất: Mỗi người có trách nhiệm kiểm soát bản thân về mọi\nhành vi và cách ứng xử như đang ở nơi làm việc, và đó là nguyên tắc mà ai\ncũng phải tuân thủ. Không may thay, nhiều nhân viên quên đi cách hành xử\nđúng đắn tại các bữa tiệc do uống quá nhiều hay tự biến mình thành trò hề.\nSau đó, họ tự hỏi tại sao mình lại bị kỷ luật hay sa thải vào ngay ngày hôm\nsau vì mọi thứ đã vượt ra khỏi tầm kiểm soát.\nNguyên tắc thứ hai: Đây là một sự kiện liên quan đến công việc − không\nphải là một buổi tiệc tự do thoải mái và do đó sẽ áp dụng những quy tắc công\nsở. Vì vậy, chúng tôi sẽ thực hiện một số điều giúp các bạn vượt qua những\ncám dỗ. Đầu tiên, chúng tôi phục vụ nhiều loại đồ uống không cồn cũng như\nthức ăn giàu protein, giúp giảm hấp thụ cồn vào cơ thể.\nTiếp theo, chúng tôi sẽ thu chìa khóa ô tô vào đầu bữa tiệc, và chúng tôi sẽ\nsớm dừng phục vụ đồ uống có cồn. Chúng tôi sẽ trả lại chìa khóa xe khi bạn\nsẵn sàng rời khỏi bữa tiệc và chắc chắn là bạn cũng như người thân của bạn\nđều tỉnh táo.\nChúng tôi cũng phân công người hướng dẫn điều hành bữa tiệc và tài xế để\nđưa những người bị say về nhà nếu cần thiết. Công ty cũng sẽ gọi taxi hay\nthậm chí thu xếp phòng khách sạn nếu có ai bị say rượu. Do đó, các bạn sẽ\nkhông được phép lái xe khi không tỉnh táo.\nNguyên tắc thứ ba: Nếu bạn rơi vào một tình huống khó chịu khi người nào\nđó đang hành động giống như một kẻ ngốc, hãy đến gặp tôi hay bất kỳ ai ở\nphòng nhân sự. Khi có những hành động không thích hợp hay hành vi quấy\nrối, thì những quy tắc tại nơi làm việc cũng được áp dụng vào bữa tiệc. Nếu\nbạn cảm thấy bất tiện vì nguyên nhân nào, hãy cáo lỗi và đến gặp tôi ngay −\ncho dù người có hành vi không thích hợp đó là một quản lý cấp cao.\nĐây là một sự kiện vui vẻ, và không phải tất cả mọi quản lý đều nói chuyện\nnhư vậy với nhân viên trước bữa tiệc. Với tư cách là người quản lý nhân sự,\ntôi sẽ giúp đỡ bạn bất cứ điều gì. Hãy tận hưởng khoảng thời gian vui vẻ, kết\nbạn, mở rộng các mối quan hệ của mình cũng như chia sẻ những câu chuyện\nhài hước. Nhưng đừng làm bất kỳ điều gì khiến bạn tỉnh dậy vào sáng hôm\nsau và than thở: “Trời ơi! Mình đã làm gì và đã nghĩ cái quái gì vậy?”\nBạn kết thúc cuộc nói chuyện với nhân viên bằng một lưu ý không mấy vui\nvẻ nhưng không sao. Nếu nhân viên nghe được những lời nhắc nhở về sự\nthận trọng, bạn đã hoàn thành công việc của mình. Đừng cảm thấy có lỗi.\nNhân viên sẽ tự biết cách tạo ra bầu không khí vui vẻ mà không cần bạn hay\nngười nào khác giúp đỡ. Điều quan trọng là nhân viên của bạn đã sẵn sàng\nđối phó với bất kỳ tình huống nào xảy ra nhờ khả năng lãnh đạo chủ động và\ncân nhắc cẩn thận mọi tính huống của bạn.\n2. DIỆN MẠO CÁ NHÂN VÀ NHỮNG TRƯỜNG HỢP TIẾN THOÁI\nLƯỠNG NAN NƠI CÔNG SỞ\nNội dung của chương này không có ý thiếu tôn trọng hay bất kính. Mọi\nngười cảm thấy không thoải mái khi giải quyết những vấn đề phổ biến nơi\ncông sở và thường phớt lờ chúng. Đó là cách thức ít gây ra sự chống đối\nnhất, và nhiều nhà quản lý thường tránh đối đầu − nhất là nếu họ hy vọng\nvấn đề này sẽ tự nhiên mất đi. Nhưng bạn có trách nhiệm như thế nào với\ncác nhân viên cũng như toàn bộ công ty khi xảy ra những tình huống khó xử\nnơi công sở? Quan trọng hơn, bạn nên nói gì để giải quyết vấn đề mà không\nkhiến nhân viên liên quan cảm thấy bị xúc phạm hay bối rối?\nCó lẽ bạn từng chứng kiến một tình huống như thế này: Một vài nhân viên\nđến gặp bạn vì một đồng nghiệp của họ có vấn đề về hơi thở và mùi cơ thể.\nHay một nhân viên đến công ty với mái tóc rối bù, trông như vừa mới ngủ\ndậy, hoặc một nhân viên có một lỗ khuyên mới trên mặt hay một hình xăm ở\nnơi dễ nhận thấy. Thật tuyệt khi bạn có thể sử dụng một cuốn hướng dẫn giải\npháp trong những trường hợp đó. Tuy nhiên, thông thường bạn cần đưa ra\nmột giải pháp riêng biệt cho từng trường hợp cụ thể mà bạn phải đối mặt.\nTình huống 8: Mái tóc rối bù\nMái tóc rối bù có thể là kết quả của màu tóc mới, phong cách phóng túng và\nkhông được chải chuốt, hay đó có thể là bất cứ điều gì khác mà chúng ta làm\nvới mái tóc của mình. Nếu một nhân viên xuất hiện trông như thể vừa đút\nngón tay vào ổ cắm điện hay trưng diện kiểu tóc xoăn xấu xí so với kiểu tóc\nbình thường, bạn cần giải quyết tình huống này bằng cách sử dụng một vài\nbiện pháp khéo léo sẽ được trình bày ở phần tiếp theo.\nGiải pháp\nNhạo báng hay làm cho người khác xấu hổ nơi công cộng chỉ khiến họ thêm\noán trách và tức giận. Mục đích của bất cứ biện pháp quản lý nhân viên nào\ntrong những tình huống như thế này là đảm bảo nhân viên đó được đối xử\ntôn trọng. Vì vậy, chúng ta có thể giải quyết tình huống này bằng cách không\nquan trọng hóa vấn đề và sử dụng cách nói hài hước:\nLeslie, đến phòng gặp tôi vài phút nhé. Tôi có một vài điều muốn chia sẻ với\nchị, và tôi không muốn làm chị tổn thương hay lúng túng. Chuyện này chỉ\nriêng hai chúng ta biết. Leslie, có lẽ mái tóc của chị được tạo kiểu hơi quá.\nGần đây chị có ghé tiệm Opal’s Hair Palace không? Chị đừng để ý khi tôi\nnói rằng có vẻ như chị đang mang đến một thông điệp nào đó bởi vì mái tóc\ncủa chị mang phong cách khá là dữ dội. Theo tôi thì tốt nhất là giải quyết\nriêng vấn đề này với chị trước khi có ai đó phàn nàn. Vậy chị định làm gì với\nthứ này (chỉ vào chiếc mũ ni)?\nThông thường bạn sẽ thấy nhân viên đó bối rối và xin lỗi. “Ôi, sáng nay tôi\nđến phòng tập thể dục rồi không kịp chải đầu. Tôi sẽ vào nhà vệ sinh để chải\nlại tóc và chắc chắn là từ giờ sẽ ăn mặc gọn gàng và chú ý đến mái tóc của\nmình hơn khi đến công ty. Tôi xin lỗi vì điều này. Ai có ý kiến gì về mái tóc\ncủa tôi không? Tôi thấy xấu hổ quá!”\nNhưng bạn sẽ giải quyết ra sao nếu nhân viên đó nhìn bạn như thể bạn là một\ngã điên và tỏ ra tự hào về mái tóc mới của mình? Nếu bạn e ngại nhân viên\nđó cảm thấy khó chịu hay nếu họ không có phản ứng tích cực với cách giải\nquyết được đưa ra trước đó, hãy hạ thấp giọng và thảo luận vấn đề nghiêm\ntúc hơn.\nLeslie, đó không phải là kiểu tóc bình thường của chị. Và tôi tôn trọng phong\ncách ăn mặc của mỗi người. Tuy nhiên, ở công sở có một vài giới hạn mà\nmọi người thường phải tuân thủ − khách hàng có thể khó chịu, danh tiếng\ncủa công ty, đánh giá về công ty trong cộng đồng kinh doanh cũng như\nnhững điều tương tự. Chị có nghĩ rằng có thể một vài người cảm thấy kiểu\ntóc rối bù của chị hơi lạc lõng so với hình ảnh chung của công ty không?\nCách tốt nhất là dẫn con ngựa tới chỗ uống nước thay vì ép buộc nó uống\nnước. Nếu nhân viên nhận thấy điều bạn nói hợp lý và nghe theo những gợi\ný của bạn, cô ấy sẽ nhận trách nhiệm và sửa lại mái tóc của mình. Tuy nhiên,\nnếu vẫn thấy nhân viên tỏ vẻ chống đối hay thách thức, bạn có quyền đưa ra\nkỳ vọng cũng như quy định, hướng dẫn của công ty.\nLeslie, xin lỗi nhưng tôi không đồng ý với quan điểm của chị. Tôi gọi chị\nvào đây để chúng ta có thể nói chuyện riêng với nhau, và tôi muốn giải quyết\nvấn đề này bằng thái độ tôn trọng. Tuy nhiên, nếu chị khăng khăng mình có\nquyền để kiểu tóc này, tôi không thể đồng ý với chị. Nếu chị không để kiểu\ntóc khác gọn gàng hơn − giống kiểu tóc bình thường của chị − thì tôi sẽ phải\ntrao đổi với phòng nhân sự (hay giám đốc) về cách giải quyết tốt nhất cho\nvấn đề này.\nTuy nhiên, tôi muốn trao đổi về đề xuất của tôi với phòng nhân sự. Tôi cho\nphép chị nghỉ làm có lương hết ngày hôm nay để quyết định liệu chị có\nmuốn tiếp tục làm công việc này và thấy rằng yêu cầu của tôi hợp lý hay\nquyết định thôi việc.\nTôi luôn tôn trọng quyết định của chị. Nhưng chị cần phải hiểu rằng nếu chị\nkhông ăn mặc phù hợp, đây sẽ như yêu cầu thôi việc của chị. Trước hết, tôi\nmuốn trao đổi với phòng nhân sự trước khi cho phép chị nghỉ hết ngày hôm\nnay để suy nghĩ về toàn bộ vấn đề, nhưng tôi muốn chị hiểu quan điểm của\ntôi về vấn đề này. Chị hãy tạm dừng làm việc với khách hàng cho đến khi tôi\ntrao đổi xong với phòng nhân sự. Tôi sẽ thông báo ngay lại với chị.\nTrong trường hợp này, bạn không bắt buộc phải trả lương cho nhân viên làm\nviệc theo giờ. Tuy nhiên, bạn sẽ thấy đề nghị nghỉ có trả lương là một bước\nkhôn ngoan. Nó cho thấy bạn là một nhà quản lý khôn ngoan, kiên nhẫn và\nbiết cảm thông. Điều này khiến nhân viên cảm thấy có lỗi (thay vì tức giận).\nNgược lại, nếu quyết định cho nhân viên đó nghỉ làm không lương, bạn chỉ\ncần tính lương đến thời điểm người đó rời khỏi công ty. Đối với lao động trả\nlương theo ngày, bạn nên trả lương cho toàn bộ ngày làm việc đó. Nếu\nkhông nhân viên có thể kiện công ty về vấn đề lương bổng và giờ làm việc,\nđiều có thể đặt công ty bạn vào vấn đề pháp lý nghiêm trọng.\nNgoài ra, bạn nên thể hiện rõ ràng yêu cầu với nhân viên cũng như bình tĩnh\ngiải thích hậu quả từ hành động của họ. Bạn không cần vội vàng quyết định\nchấm dứt hợp đồng lao động với nhân viên khi họ không tuân thủ quy định\ncủa công ty (nếu công ty có quy định về trang phục) hay không chịu phục\ntùng (vì không tuân thủ hướng dẫn). Thay vào đó, hãy cho phép nhân viên tự\nquyết định điều chỉnh theo tiêu chuẩn ăn mặc thông thường và tiếp tục làm\nviệc tại công ty hay chấp nhận nghỉ việc. Đừng nghiêm trọng hóa vấn đề hay\ntỏ ra vội vàng mà hãy giải quyết bình tĩnh và tôn trọng cùng với yêu cầu và\nkết quả rõ ràng.\nLưu ý đặc biệt\nTrước khi buộc nhân viên tạm thời nghỉ việc để suy nghĩ, bạn hãy trao đổi\nvới phòng nhân sự hay ban giám đốc. Cuối cùng, khi sự việc tiến triển đến\nmức phải chấm dứt hợp đồng lao động, bạn sẽ không muốn tự mình phải\ngánh chịu tất cả trách nhiệm. Trước khi chính thức cho nhân viên tạm nghỉ\nviệc để cân nhắc liệu người đó có muốn tiếp tục công việc hay không, hãy\nchắc chắn bạn đã thông báo cho tất cả các bên có trách nhiệm về ý định của\nmình.\nTình huống 9: Ăn mặc không thích hợp\nTrong tình huống này, giả sử một nhân viên nữ mặc một chiếc áo quá hở\nhang đi làm. Cuộc nói chuyện này cũng có thể áp dụng trong trường hợp\nnhân viên nam mặc quần cạp trễ.\nGiải pháp\nCách thức thông thường để giải quyết các tình huống khó xử nơi công sở là\ngọi riêng nhân viên đó vào văn phòng và bày tỏ mối lo ngại của bạn theo\ncách thích hợp. Tuy nhiên, trong trường hợp nhân viên nữ ăn mặc quá mát\nmẻ, nhà quản lý nam nên mời một quản lý nữ tham gia trao đổi để tránh bị\nđánh giá là phân biệt đối xử với nữ giới hay nghiêm trọng hơn là bị cáo buộc\nquấy rối tình dục. Bạn có thể mở đầu cuộc nói chuyện như sau:\nPhyllis, tôi muốn trao đổi vài điều với chị về cách ăn mặc nơi công sở. Tôi\ncũng mời Joan tham dự cuộc nói chuyện này. Tôi không muốn làm chị khó\nchịu và cũng hơi ngại khi nói về vấn đề này bởi nó liên quan đến bộ quần áo\nkhá “mát mẻ” mà chị mặc hôm nay. Tôi e rằng trang phục của chị có thể\nkhiến một vài khách hàng cảm thấy không thoải mái. Chị có thể giúp tôi giải\nquyết vấn đề này không?\nNhân viên này có thể phản ứng tích cực khi nói: “Xin lỗi, nhưng tôi không\nnghĩ là bộ quần áo này quá hở hang. Anh thực sự cho rằng bộ quần áo này\nkhông phù hợp à?” Sau đó bạn có thể trả lời, “Bình thường thì bộ quần áo\nnày rất đẹp, nhưng khi chị cúi xuống thì nó lại khá là hở hang. Tôi không\nmuốn làm chị bối rối, cũng không muốn khách hàng cảm thấy khó chịu. Vì\nthế, chúng ta cần tìm ra phương án tốt nhất cho vấn đề này.”\nKết cục hợp lý nhất có thể là, “Tôi xin lỗi nếu bộ quần áo này khiến mọi\nngười cảm thấy không thoải mái. Vì không có bộ quần áo nào nữa ở công ty,\ntôi sẽ về nhà và thay bộ khác. Tôi sẽ trở lại trong khoảng 45 phút.” Theo đó,\ncô ấy đã tiếp thu góp ý và sẽ cân nhắc lại về cách ăn mặc mỗi ngày. Một kết\ncục tốt đẹp!\nTuy nhiên, sẽ ra sao nếu nhân viên đó phản đối lời góp ý nhẹ nhàng của bạn:\n“Tôi thấy bộ quần áo này hoàn toàn phù hợp và không hề làm ai khó chịu cả.\nTôi rất tiếc nếu anh không thích bộ quần áo này, nhưng tôi thấy công ty\nkhông có quy định về trang phục.” Khi đó, bạn hãy cẩn thận vì nhân viên có\nthể có động cơ thầm kín hay chỉ đơn giản muốn thách thức bạn. Trong cả hai\ntrường hợp, bạn đều cần giúp đỡ, đặc biệt nếu bạn là người giám sát nam.\nHãy để nhân viên biết bạn đang lắng nghe điều cô ấy nói nhưng bạn muốn\ntrao đổi thêm với phòng nhân sự (hoặc các bộ phận liên quan khác như bộ\n\n\n', '2026-02-28 08:22:25'),
	(16, 2, 1, 'TÔNG QUAN VÊ FACEBOOK MARKETING', 'Pacebook cho đến thời điểm hiện tại đã được coi là một mạng xẫ\nhội lớn nhất thế giới, họ gẩn như là một quốc gia thu nhỏ, góp\nphần vào việc tạo tự do cho con người và nỗ lực trong việc tạo ra\nmột thế giới phẳng, noi không có khoảng cách giữa thế giới thực\nvà thế giới Internet.\nDưới đây là số liệu thống kê tháng 8/2013 của Facebook về người dùng\nvà xu hướng người dùng. Có đến 1,1 5 tỷ người dùng và 699 triệu người\ndùng sử dụng hàng ngày.\n\n► Trung bình I người ( ó tham gia và like 89 group/Fanpage.\n► Thời gian trung bình của một người sử dụng Pnccbook chu 1 ngày\nlà 20 phút.\n► Trung bình mỗi người có 141,5 người bạn.\n► Có tất cả 50 Iriệu Fanpage.\n► Tổng cộng 240 tỷ bức ảnh dã dưực upload lên.\n► 350 triệu bức ảnh dược upload hàng ngày.\n► Tổng số bài hát và album dược chia sỏ lên tới 110 triệu lượt.\n► 48% nhưng người từ 18-34 tuổi nghĩ đốn viộc chcck íacobook dầu\nliôn khi hụ thức: dậy mỗi sáng.\n► 250 triộu người dùng chơi gamo; tròn íacebook mỗi tháng, gamt\'\ndược chưi nhiồu nhất: Candy Crush Saga, TripAdvisơr và Farmvillc 2.\n► Cú kốl nối lới 130 triệu tài khoan Inslagram, dăng nhiều hơn 40\ntriệu bức tính mỗi ngày lừ Instagram.\n\nTrung Đức < r 13\n\n14 -> Facebook Marketing từ A đến z\n\nThông qua các số liệu trên chúng ta có thể thấy về mức độ phổ biến\ncủa Facebook lớn đến nhường nào, và tại sao chúng ta phải cố gắng thử\ntưởng tượng ra việc Facebook không tồn tại làm gì? Khi mà điều đó là vô\nlý, hoặc nếu có, chắc hẳn phải có 1 mạng xã hội tốt hơn cả Facebook ở\nthì tương lai. Còn cá nhân tôi thì khuyên các bạn hãy nghĩ, hãy tưởng\ntượng đến việc Facebook có thể giúp được gì cho chúng ta? Nhiều hơn là\nrelationship, conversation... ?\n\nCJ (!■?\n1 «"■\' •\n\nI.il ĩ\n-»IV «vir ì ĩ >á\'I |V 1 ■ 1/*i V\n\n/A> :v \',t I lỉ-.iy -fep I*-.»,- 11:: í, n .i t f -■ - ^ * 1\nỉ > \'-\'ja w * tru y Cfcp m toi-not Iữ .111M Ị " p " l\n\nJ B K B H B M B S B B E a k f\nc ĩ\nỆ h :\n‘ ì-ẨII\n\n"Ọ ■ nịụẬỊtti Ifil’ScRUSlv\'T\n^ r r r v L ....\n\n§SỊ í ?\nMm■I\nIMf m\nr ị\n■ I\n\nTheo số liệu thống kế năm 2013, Việt Nam có tới 31 triệu người sử dụng\nInternet, 66% truy cập Internet mỗi ngày. Và 86% người dùng Internet\ncó thói quen truy cập mạng xã hội. Tức là có đến 26,66 triệu người dùng\nmạng xã hội. Đến tháng 8/2013, tại Việt Nam đã có 19,6 triệu người\ndùng Facebook, chiếm 21,42% dân số và chiếm tới 71,4% người sử\ndụng Internet. Việt Nam đang là nước đứng thứ 16 trên thế giới về tỷ lệ\ntăng trưởng lượng người sử dụng Facebook tính đến tháng 7/2013 (Theo\nkết quả nghiên cứu của Soqialbakers & SocialTimes.Me -2013).\n\nFacebook giúp chúng ta làm MARKETING hiệu quả hơn!\nBạn có biết cứ 3s lại có một người dùng mới trên Facebook, và 81 % sử\ndụng mạng xẵ hội để xác nhận quyết định mua hàng?\n\nr £ h\nì\n79% người dùng Internet đã từng ghé thăm\ncác website bán hàng Online\no o 61% ĐÃ TỪNG MUA SẮM TRỰC TUYỂN\n\nĐầu tiên, chúng ta phải hiểu làm Marketing trên mạng xã hội Facebook,\nhay Pacebook Marketing là gì?\n\n(1 ) Facc\'book Marketing là việc bạn có sàn phẩm, dịch vụ; (2) bạn tìm ra\nnhu cầu của người dùng, khách hàng dối với sản phẩm, dịch vụ của bạn\nlà gì, họ thực sự cần diều gì hoặc có thể nhận dược: gì từ san phẩm dịc h\nvu do; (3) và dấp ứng nhu cầu của họ; (4) nhằm lăng lợi nhuận hoặc\nlăng lợi ích; (5) ihông qua mạng xã hội Facobook.\n\nCó rất nhiều cách để bạn có thể đến được với người dùng cuối (End-\nUser): Follower, Fan, User, Customer,... Bạn có thể hòa vào dòng cảm xúc\n\nhoặc chạm đến ngưỡng tri thức của họ, bạn làm gì cũng được... Miễn là\nkhông phải hack, spam, làm trái luật,... thì đó là bạn đang làm Facebook\nMarketing.\n\nTrung Đức <r 15\n\n16 -> Facebook Marketing từ A đến z\n\nSơ đồ tổng quan về Facehook Marketing 2013 - 2014\n\nTrong Facebook Marketing chúng ta sẽ chia ra làm 2 nhóm đối tượng,\n1 là những người có nhu cầu làm Marketing (Facebook Marketer), 2 là\nnhóm người dùng (Facebook User).\n\n1.1 Facebook Marketer\nĐó là những người muốn...\n\n► Muốn phát triển thương hiệu cá nhân (hình tượng cá nhân) thông\nqua Lài khoản cá nhân (profile).\n► Muốn lăng hiệu quá kinh doanh hoặc lợi ích thông qua lài khoan\ncá nhân (profile).\n\n► Muốn phát triển thương hiệu doanh nghiộp thông qua tài khoan\nc á nhân (proíilc) - lliường íl dùng.\n► Muốn phái triển thương hiệu c á nhân (hình tượng C\'á nhân) thông\nqua hanpago - thường dành cho người nổi tiếng, có sức ảnh hưởng.\n► Muốn phát triển thương hiộu doanh nghiộp thông qua Rinpage -\nhrands lớn dồu c:ó mìíl tròn đây.\n► Muốn phát triển kinh doanh thông qua Fanpage - rất nhiều c ông\nly, cửa hàng, t á nhân có cli(.)n kônh này.\n► Muốn phát triổn kế hoạc:h phi lợi nhuận (di đến lợi ích về sau)\nthóng qua Fanpagt; - những ranpagt; tình yôu, nghộ thuật sống...\n► Muốn phát triển cộng dồng nhằm xây dựng và củng cố thương\nhiệu cá nhân (hình tượng cá nhân).\n► Muốn phát triển cộng dồng nhằm xây dựng và củng cố thương\nhiộu doanh nghiệp.\n► Muôn phát triổn cộng đồng nhằm phục vụ người dùng sản phẩm\ncủa tôi thòng qua Group.\n► Muôn phát triển cộng dồng với mục. đích phi lợi nhuận (di dốn lợi\ních vỏ sau) thòng qua Group.\n► Muốn phát triển thương hiộu doanh nghiệp thông qua Event - lổ\nchức; các sự kiộn,...\n► Muốn phát triển thương hiệu cá nhân thông qua kivent.\n► Muốn phái triổn kinh doanh thông qua tivcnl.\n\nTrung Đức <- 17\n\n18 Facebook Marketing từ A đến z\n\n► Muốn phái triển triển thương hiệu doanh nghiộp thông qua các\nCUỘC\' thi (conlcst) trên các pmíik\'/group/Fanpag(\'/event.\n► Muốn phát triổn kinh doanh thông qua các cuộc thi (contosl) trên\ncác proíi le/group/Fanpag(?/evc\'nt.\n► Muốn phái triển cộng đồng với mục đích phi lợi nhuận (đi dốn lợi\ních vẻ sau) Irên các proíilc/group/ranpugo/event.\n\nVà bạn đang ở phần nào trong danh sách trên?\nNgoài ra còn khá nhiều cái muốn bất chính khác; như việc muôn phát\ntriển cộng đồng đ ể chửi bới, làm trò nhảm, muốn thêm nhiều bạn bè\nbằng cách tạo profile girl xinh,... những cái này tôi xin phép không đê\ncập đến.\n\n1.2 FacebookUser\n\nKhi chúng ta biết mình muốn gì đã là một thành công, và việc tìm ra một\n(hoặc nhiều) người để chúng ta có thể thỏa mãn nhu cầu của họ lại là\nmột thành công mới, hay đơn giản là tìm ra nhu cầu của người dùng đối\nvới sản phẩm của chúng ta - tất nhiên là trên kênh Facebook.\nVà mục đích cuối cùng là giá trị.chuyển đổi (convert):\n\n► Profile: user-follower, user-friend, follower-friend, user-\ncustomer, fol lower-customer, friend-customer.\n\n► Fanpage: user-fan, user-customer, fan-customer.\n► Group: user-member, member-customer.\n► Event: user-member, user-customer\n► Contest: user-member\n\nTức là, từ những người dùng Facebook xa lạ, từ những khách vãng lai ở\nđâu đó, điều mà một người Facebook Marketer cần là biến người dùng\nđó thành người like Fanpage của mình, thành người follow mình, thành\nmember trong cộng đồng của mình, tham gia vào sự kiện của mình,\ntham gia vào cuộc thi của mình,...\nVà làm sao để làm được điều đó, khi chúng ta đã xác định được mục tiêu\nvà đối tượng mục tiêu?\n\nTrung Đức <r T9\n\n20 -> Facebook Marketing từ A đến Z\n\n1.3 Facebook Marketing Strategy\n\nCó rất nhiều cách để những Facebook Marketer có thể đi được đến trái\ntim, hay túi tiền của Facebook User, nhưng chúng ta có thể tóm gọn nó\nlại trong 3 cách sau:\na. Application\n\nFacebook Application sẽ được chia làm 2 loại chính theo nhu cầu của\nFacebook Marketer:\n+ App Quality: Với những app chất lượng, chi phí và thời gian bỏ ra là\nrất lớn, vì thế việc của người làm Facebook Marketer là nghiên cứu đặc\ntính sản phẩm/dịch vụ, tìm ra điểm khác biệt. Nghiên cứu sâu về hành\nvi và nhận thức của người dùng trên Facebook, thể hiện rõ thông điệp,\nđiểm khác biệt, hay việc đáp ứng được nhu cầu người dùng ra bên ngoài,\nmọi thứ đều cần phải đúng quy trình và chuẩn xác. Vì không có ai muốn\ntiền của mình bỏ ra nhiều mà không thu về được nhiều cả.\nĐặc điểm của những App này là mang lại giá trị cho người dùng (tiền\nthưởng, quà tặng,...), chi phí đầu tư lớn, đầu tư xây dựng nội dung, giao\ndiện đồ họa đẹp mắt, có khả năng tương tác, có yếu tố lan truyền cao,\nhiệu ứng tích cực, và ứng dụng hoạt động ngay trên nền facebook...\n+ App Low: Với những app kém chất lượng, chi phí và thời gian bỏ ra\nlà ít (không đáng kể) app dạng này mọc ra như nấm, biến thiên đủ trò,\nnhưng biến kiểu gì thì biến cũng chỉ dừng lại ở mức hiển thị định dạng\nText, hoặc Image. Những app này thường có xu hường "lừa" người chơi,\nChiến lược Facebook Marketing có sử dụng\nApps là chiến dịch rất hiệu quả và cũng rất\ndài hơi. Trong chiến dịch Facebook Marketing\n\nApplication thường sẽ có 3 nhóm chính: User-\nMarketer-Developer App.\n\ntạo cho họ cảm giác tò mò, ví dụ như những app: Lúc nào bạn chết, Ai\nhay vào tường nhà bạn, Mách nhỏ,...\nTuy không mang lại giá trị cho người dùng nhưng những app này cũng\nđánh được vào tâm lý của họ, cộng với việc sử dụng một số thủ thuật,\nApp Low có yếu tố lan truyền khá cao, và ứng dụng thường không hoạt\nđộng trên nền facebook mà hoạt động ở một trang nào đó, nền trắng tinh\nkèm theo một hình có nhiệm vụ CTA (Call to action) ở chính giữa giao\ndiện website.\n\nb. Ads\nVới những ưu điểm vượt trội của mình về người dùng và mức độ tương\ntác, Facebook là một thị trường béo bở với tất cả các bên. Không có lý\ndo gì Facebook bỏ qua dịch vụ cho phép người dùng mua quảng cáo sản\nphẩm/dịch vụ của họ.\n+ Cách thức hoạt động của quảng cáo tacebook\nCác doanh nghiệp trả tiền cho Facebook để hiển th.i quảng cáo cho\nnhững người có thể quan tâm đến nội dung của họ.\n\no\nMột doanh nghiệp\ntạo một quảng cáo\n\n©\nFacebook được trả tiền\nđể hiện thị quảng cáo\n\n©\nNgười phù hợp để\nxem quảng cáo\n\nHãy nói rằng có một phòng tập\nthể dục ở gần nhà bạn. Người\nchủ tạo một quảng cáo để mọi\nngười đến tập miễn phí.\n\nNgười chủ gửi quảng cáo đến\nFacebook và mô tả ai sẽ nhìn\nthây nó: những người sống gần\nđây hoặc thích đến đây.\n\nBạn sẽ nhìn thấy quảng cáo\nnếu bạn sống ỡ thị trấn\nvà thích chạy.\n\n+ ƯU điểm của quảng cáo facebook\na. Luôn hướng đến đúng đối tượng là khách hàng tiềm năng\nBạn hoàn toàn có thể điều chỉnh hướng đối tượng cho các\n\nTrung Đức 21\n\n22 -ỳ Facebook Marketlng từ A đến z\n\nchiến dịch quảng cáo íacebook của mình. Trong đó bao gồm\nviệc định hướng các đối tượng nào sẽ thấy được quảng cáo\nnhư: giới tính, độ tuổi, địa lý, ngôn ngữ, sở thích. Hay nhắm\ntrực tiếp đến những đối tượng (người dùng) bạn chỉ định.\nb. Chỉ trả tiền khi có người mong muôn sử dụng dịch vụ của bạn\nFacebook cho bạn lựa chọn hình thức quảng cáo CPC (cost\nper click) hoặc CPM (cost per impression). Với CPC, bạn chỉ\nphải trả tiền cho những người click vào quảng cáo của bạn\nmà thôi. Với CPM bạn cũng ch? trả tối thiểu từ 0.03$/1000\nlần hiển thị mẫu quảng cáo (tương dượng 600đ/1000 lần\nhiển thị). Đây là mức chi phí rất hợp lý.\nc. Tính linh hoạt cao:\n► Điều chỉnh chiến dịch dễ dàng. Bạn hoàn toàn có thể\nchuyển đổi giữa hai hình thức trả phí từ CPC sang CPM và\nngược lại. Hơn nữa, các thông số khác cũng được điều chỉnh\ndễ dàng để chiến dịch của bạn tối ưu hơn.\n► Nội dung quảng cáo íacebook hiển thị hình ảnh và lời\ngiới thiệu kèm theo. Đây là một hình thức quảng cáo tiên\ntiến và được nhiều công ty áp dụng để đưa hình ảnh doanh\nnghiệp đến với nhiều người.\n► Nội dung quảng cáo íacebook có thể kèm theo cả các\ntương tác của bạn bè người dùng với sản phẩm/dịch vụ đó\nđể tăng độ tin cậy.\nd. Không phụ thuộc ngân sách\nBạn không nhất thiết phải trả một ngân sách cố định. Tùy\nvào tình hình thực tế, bạn có thể yêu cầu điều chỉnh ngân\nsách hàng ngày hoặc hàng tháng cho phù hợp với chiến\ndịch của mình.\n\n! e. Phân phối quảng cáo hợp lỷ\n\\ Facebook luôn đảm bảo rằng quảng cáo trên facebook được\nI phân bổ đều đặn dựa trên ngân sách của bạn. Sẽ không có\n! trường hợp quảng cáo tập trung quá nhiều vào người này mà\nI không xuất hiện ở người khác. Do đó, quảng cáo của bạn sẽ\n! luôn xuất hiện đến các khách hàng tiềm năng.\n+ Các dạng quảng cáo facebook\nBoost Post\nLà hình thức quảng bá các\nthông tin được cập nhật từ\nFanpage tới một số lượng\nngười dùng nhất định đã\n"Like" page trước đó. Bởi\ntrên thực tế, nếu người dùng\nđã like page nhưng không\ntham gia tương tác với page,\ntimeline Facebook (màn hình\nhiển thị nội dung cập nhật từ\nbạn bè) của họ sẽ không hiện\ncác cập nhật của page.\nKhi người quản trị page đồng ý chi trả một số tiền nhất định để quảng bá\nnội dung vừa cập nhật từ page, Facebook sẽ đảm bảo việc nội dung đó\nsẽ được hiển thị trên timeline của những người dùng đã Like page bất kể\ncó tham gia tương tác với page hay không.\nVà thông thường, số lượng view tổng cộng sẽ lớn hơn số lượng view độc\nnhất do nội dung được quảng bá này sẽ hiển thị nhiều lần trên timeline\ncủa fan.\nFacebook Ads\nFacebook Ads hay còn được gọi là Sponsored Ads (quảng cáo được tài\n\nBoost Your Post\nIts easy to bflffirt ¥«wr posts so «w e peopte M# them n « Ị\nfeed. It only esses 4W.Q00 »s*ỉ seated,\nwarn More\nA uitlcrarr • (tier\n\n»1\n, fiwpfci you tbrwjgih tw getng ! \'J\nm“ «39,000 ;\nfeLPeopfe 4$,<3OT.98,SOO.................... oTtgj\nUs»*«» "\ntiw buềgpk mẳ ismềm ểttoíấrê ta ỉtrnvặ %ềM.\n\n\'B ữ M t\n\nTrung Đức <- 23\n\n24 -> Facebook Marketing từ A đến z\n\ntrợ) là các quảng cáo được hiển thị tại các vị trí đặt quảng cáo cố định\ntrên website. Và điểm khác biệt lớn nhất giữa Facebook Ads và Facebook\nPromoted Post chính là việc Facebook Ads sẽ được hiển thj đối với một\nnhóm người dùng cụ thể với các tiêu chuẩn đề ra trước đó. Trong khi\nFacebook Promoted Post chỉ hiển thị tới người dùng đã bấm Like page.\nVà tất nhiên, trong số những người dùng nhìn thấy Facebook Ads, chắc\nchắn sẽ có một lượng người dùng nhất định đã là fan của page. Và cũng\ngiống như hình thức thứ nhất, Facebook Ads có thể được hiển thị rất\nnhiều lần cho cùng một người dùng.\n\n► Tham gia vào bài viết trên\ntrang : Quảng bá bài viết cụ thể\ntrên Fanpage của bạn tăng lượt\nview, share.\n► Số lượt thích trang : Tăng like\ncho Fanpage của bạn.\n► Truy cập vào trang web : Tạo\nquảng cáo để mọi người truy cập\ntrực tiếp vào website của bạn.\n- ► Lựa chọn quảng cáo hiển thị cột bên phải hoặc. Irôn c a bang tin\n(nếu bạn có Fanpage).\n► Chuyển đổi trang web : Tạo pixel lấy code add vào website của\nbạn và theo dõi tỉ lệ chuyển đổi đến 1 trang mà bạn mong muốn. ,í\nQuảng cáo sẽ được hiển thị.\nLượt cài ứng dụng : Tạo quảng cáo đề khuyến khích mọi người cài\nđặt ứng dụng của bạn.\n\\ 0 Page Post Engagement\n! 0 Page tikes\nj ^ Clicks to Website\ns <§) Website Conversions\nI $ App Installs\ni ^ App Engagement\ni HJ, Event Responses\ni f i Offer Claims\n\n► Tham gia ứng dụng : tạo quang cáo đổ cỏ them hoạt dộng trên\nứng dụng l-\'acobook của bạn. (lách tạo quảng cáo tương lự lượt cài\nứng dụng.\n► Tham gia sự kiện : Tạo quảng cáo c\'lể quàng bá sự kiện\n► Yêu cầu nhận Ưu dãi : T.ạo quảng cáo dể quảng bá khuyến mại.\n\nc. Content\nPhần cuối cùng, cũng là phần quan trọng trong mỗi chiến lược Marketing\nOnline nói chung, hay Facebook Marketing nói riêng, đó là CONTENT\n(nội dung). Content là yếu tố dễ dàng nhất để đạt được đến độ lan truyền\nnội dung, lan truyền cảm xúc (Viral Marketing).\n\nCO N TEN T STR A TE G Y\nP O S T S E N G A G E M E N T S C O R E\n\nTrung Đức 4- 25\n\n26 -> Facebook Marketing từ A đến z\n\nMột Số loại content phổ biến:\n\n► Cập nhật sân phẩm/dịch vụ lừ các. slore.\n► Nội dung LÍU đ ã i.\n► Bài viết dạng câu hỏi dể người dọc có hành dộng comment Irả lời.\n► Tổ chức cuộc thi.\n► Tổ chức sự kiện.\n► Nội dung mang tính xã hội.\n► Thông tin về các thương hiệu.\n► Nội dung giao dịch cụ thổ.\n► Các loại nội dung khác.\n\nĐể làm Content tốt, ngoài việc phân tích Insight đối tượng mục tiêu, bạn\ncần phải có khả năng viết tốt (Copywriting).\n\n1 .A EdgeRank\n\nEdge Rank »MSMB\n\nUe w e\nV«*\n■ D\ne\niii « # « s\n\nRank Affinity\nThe score between\nme viewing user and\nthe edge creator.\n\nWeight\nTlie weight tor tills\nedge type.\n(Comment, UKe, etc).\n\nDecay\nThe decay t.ictoi\nbased on hew tong ago\nthe edge was created\n\na. Edgerank 1.0\nEdgerank là thuật toán được sử dụng bởi facebook nhằm xác định "Nơi\nnào?" và "Những bài viết nào?" sẽ xuất hiện trên trang News Feed của\nngười dùng cá nhân. Ban đầu có 3 biến chính được được sử dụng trong\nthuật toán: Affinity, Weight, Time-Decay.\n+ Affinity: Điểm sấlôi cuốn (sự thân thuộc)\nThể hiện ở mỗi quan hệ, tức là Facebook sẽ xác định ưu tiên hiển thị trên\nNews Feed của bạn những người có mỗi quan hệ chặt chẽ, ở đây là anh\nem, bố mẹ, ông bà, vợ chồng, những người mà bạn thường xuyên tương\ntác comment, like, share. Mối quan hệ càng chặt chẽ, thì khi người đó\npost bài, tỷ lệ hiển thị trên News Feed càng cao.\n+ Weight: Trọng số tương tác\nNhư tôi đã nói ở trên, với mỗi Fanpage hay tài khoản cá nhân, sẽ có\nsắp xếp Ưu tiên về thể loại bài đăng, tùy vào tương tác của người dùng,\nFacebook sẽ đánh giá thể loại bài post mà Fanpage này hiệu quả, qua đó\n\nTrung Đức 27\n\n28 -> Facebook Marketing từ A đến z\n\nsẽ ảnh hưởng đến tổng thể thuật toán. Do vậy, bất kỳ một thể loại nào\ncũng có thể có lượng Reach cao, chứ không riêng gì Photos hay Text.\n+ Time-Decay\nCái này đơn giản là Facebook sẽ Ưu tiên hiển thị những thông tin mới,\nnhững thông tin mới thì điểm số Time-Decay sẽ cao, và ngược lại, thông\ntin càng cũ thì chỉ số Time-Decay càng thấp.\n\nb. Ẽdgerank 2.0\nSau này Facebook cập nhật lại thuật toán Edgerank, có điều chỉnh và\nthêm các chỉ số.\n\n+ Last actor: 50 tương tác gần nhất.\n+ Edge Weight: Trọng số tương tác.\n+ Story Bumping: Hiển thị bài viết bạn chưa xem .\nVà tất nhiên những chì số không có dưới đây không có nghĩa là không\nđược tính đến.\nDễ hình dung nhất của chỉ số Last actor là khi bạn tương tác với một\nngười nào đó (chat/like/comment/share) thì lập tức khung chat của bạn\nsẽ hiện lên người đó mỗi khi họ online.\nViệc một người không online trong thời gian quá lâu sẽ dẫn đến tình\ntrạng bỏ qua những nội dung hay, phù hợp với họ, facebook đã giải quyết\nvấn đề đó bằng việc đưa ra chỉ số Story Bumping.\n\nc. NFO (News Feed Optimization)\nNếu Google có những thuật toán riêng để hiển thị kết quả tìm kiếm hay\nthường được gọi là SEO ( Search Engine Optimization) thì Facebook có\n\nNFO ( News Feed Optimization). Hai công việc này cơ bản giống nhau\nvề mục đích: cố gắng tiếp cận User ở trang đầu tiên ( page 1 on Google\n& News Feed), và cách thức thực hiện: làm hài lòng thuật toán hay yêu\ncầu của 2 bạn Google & Facebook. NFO đơn giản là cách thỏa mãn\nEdgeRank để tăng tì lệ hiển thị ở News Feed.\n\n1.5 Tóm lược nội dung\n\nNăm 2 0 1 3 dã dánh dấu nhừng bước phái triển mạnh mẽ của công\nnghệ số, truyền thông da phương tiện, markeíing Online và íacebook\nmarketing. Fucobook sẽ liếp tục thay dổi, họ hoặc là cần phải dáp\nứng nhu cầu của ngươi dùng, hoặc là cần phải lạo ra những nhu cầu\nmoi, vì ngươi dùng luôn luôn e.ó xu hướng thay (lồi nhu Ccầu của mình\ntheo thơi gian, nhận lliứe, cộng dồng,...\nTacebook Marketing lúc dó sẽ ihực sự là một chiến trương dành cho\nnhững ngươi làm Fae.ebool< Markcting, Facebool< sơ trỏ nên thông\nminh hơn, nhiều cạnh tranh giừa những Facebool< Marketer hơn,\nnhững ngươi hỗ trự kỹ thuật cùng sè thông minh hon, nội dung (la\ndạng hơn, Vcà quan trọng là người dùng cũng sẽ thông minh hơn.\n\nVà để cho nội dung sách được xuyên suốt, cũng như những hướng dẫn\nđược mạch lạc. Hầu hết những thao tác và nội dung hiển thị trên hình\nảnh sẽ mặc định là ngôn ngữ English (US). Bạn có thể chuyển sang ngôn\nngữ English (US) để thao tác, hoặc dịch sang tiếng Việt với những tùy\nchọn tương tự.', '2026-02-28 08:38:03'),
	(17, 3, 1, 'TÔNG QUAN VÊ FACEBOOK MARKETING', 'Pacebook cho đến thời điểm hiện tại đã được coi là một mạng xẫ\nhội lớn nhất thế giới, họ gẩn như là một quốc gia thu nhỏ, góp\nphần vào việc tạo tự do cho con người và nỗ lực trong việc tạo ra\nmột thế giới phẳng, noi không có khoảng cách giữa thế giới thực\nvà thế giới Internet.\nDưới đây là số liệu thống kê tháng 8/2013 của Facebook về người dùng\nvà xu hướng người dùng. Có đến 1,1 5 tỷ người dùng và 699 triệu người\ndùng sử dụng hàng ngày.\n\n► Trung bình I người ( ó tham gia và like 89 group/Fanpage.\n► Thời gian trung bình của một người sử dụng Pnccbook chu 1 ngày\nlà 20 phút.\n► Trung bình mỗi người có 141,5 người bạn.\n► Có tất cả 50 Iriệu Fanpage.\n► Tổng cộng 240 tỷ bức ảnh dã dưực upload lên.\n► 350 triệu bức ảnh dược upload hàng ngày.\n► Tổng số bài hát và album dược chia sỏ lên tới 110 triệu lượt.\n► 48% nhưng người từ 18-34 tuổi nghĩ đốn viộc chcck íacobook dầu\nliôn khi hụ thức: dậy mỗi sáng.\n► 250 triộu người dùng chơi gamo; tròn íacebook mỗi tháng, gamt\'\ndược chưi nhiồu nhất: Candy Crush Saga, TripAdvisơr và Farmvillc 2.\n► Cú kốl nối lới 130 triệu tài khoan Inslagram, dăng nhiều hơn 40\ntriệu bức tính mỗi ngày lừ Instagram.\n\nTrung Đức < r 13\n\n14 -> Facebook Marketing từ A đến z\n\nThông qua các số liệu trên chúng ta có thể thấy về mức độ phổ biến\ncủa Facebook lớn đến nhường nào, và tại sao chúng ta phải cố gắng thử\ntưởng tượng ra việc Facebook không tồn tại làm gì? Khi mà điều đó là vô\nlý, hoặc nếu có, chắc hẳn phải có 1 mạng xã hội tốt hơn cả Facebook ở\nthì tương lai. Còn cá nhân tôi thì khuyên các bạn hãy nghĩ, hãy tưởng\ntượng đến việc Facebook có thể giúp được gì cho chúng ta? Nhiều hơn là\nrelationship, conversation... ?\n\nCJ (!■?\n1 «"■\' •\n\nI.il ĩ\n-»IV «vir ì ĩ >á\'I |V 1 ■ 1/*i V\n\n/A> :v \',t I lỉ-.iy -fep I*-.»,- 11:: í, n .i t f -■ - ^ * 1\nỉ > \'-\'ja w * tru y Cfcp m toi-not Iữ .111M Ị " p " l\n\nJ B K B H B M B S B B E a k f\nc ĩ\nỆ h :\n‘ ì-ẨII\n\n"Ọ ■ nịụẬỊtti Ifil’ScRUSlv\'T\n^ r r r v L ....\n\n§SỊ í ?\nMm■I\nIMf m\nr ị\n■ I\n\nTheo số liệu thống kế năm 2013, Việt Nam có tới 31 triệu người sử dụng\nInternet, 66% truy cập Internet mỗi ngày. Và 86% người dùng Internet\ncó thói quen truy cập mạng xã hội. Tức là có đến 26,66 triệu người dùng\nmạng xã hội. Đến tháng 8/2013, tại Việt Nam đã có 19,6 triệu người\ndùng Facebook, chiếm 21,42% dân số và chiếm tới 71,4% người sử\ndụng Internet. Việt Nam đang là nước đứng thứ 16 trên thế giới về tỷ lệ\ntăng trưởng lượng người sử dụng Facebook tính đến tháng 7/2013 (Theo\nkết quả nghiên cứu của Soqialbakers & SocialTimes.Me -2013).\n\nFacebook giúp chúng ta làm MARKETING hiệu quả hơn!\nBạn có biết cứ 3s lại có một người dùng mới trên Facebook, và 81 % sử\ndụng mạng xẵ hội để xác nhận quyết định mua hàng?\n\nr £ h\nì\n79% người dùng Internet đã từng ghé thăm\ncác website bán hàng Online\no o 61% ĐÃ TỪNG MUA SẮM TRỰC TUYỂN\n\nĐầu tiên, chúng ta phải hiểu làm Marketing trên mạng xã hội Facebook,\nhay Pacebook Marketing là gì?\n\n(1 ) Facc\'book Marketing là việc bạn có sàn phẩm, dịch vụ; (2) bạn tìm ra\nnhu cầu của người dùng, khách hàng dối với sản phẩm, dịch vụ của bạn\nlà gì, họ thực sự cần diều gì hoặc có thể nhận dược: gì từ san phẩm dịc h\nvu do; (3) và dấp ứng nhu cầu của họ; (4) nhằm lăng lợi nhuận hoặc\nlăng lợi ích; (5) ihông qua mạng xã hội Facobook.\n\nCó rất nhiều cách để bạn có thể đến được với người dùng cuối (End-\nUser): Follower, Fan, User, Customer,... Bạn có thể hòa vào dòng cảm xúc\n\nhoặc chạm đến ngưỡng tri thức của họ, bạn làm gì cũng được... Miễn là\nkhông phải hack, spam, làm trái luật,... thì đó là bạn đang làm Facebook\nMarketing.\n\nTrung Đức <r 15\n\n16 -> Facebook Marketing từ A đến z\n\nSơ đồ tổng quan về Facehook Marketing 2013 - 2014\n\nTrong Facebook Marketing chúng ta sẽ chia ra làm 2 nhóm đối tượng,\n1 là những người có nhu cầu làm Marketing (Facebook Marketer), 2 là\nnhóm người dùng (Facebook User).\n\n1.1 Facebook Marketer\nĐó là những người muốn...\n\n► Muốn phát triển thương hiệu cá nhân (hình tượng cá nhân) thông\nqua Lài khoản cá nhân (profile).\n► Muốn lăng hiệu quá kinh doanh hoặc lợi ích thông qua lài khoan\ncá nhân (profile).\n\n► Muốn phát triển thương hiệu doanh nghiộp thông qua tài khoan\nc á nhân (proíilc) - lliường íl dùng.\n► Muốn phái triển thương hiệu c á nhân (hình tượng C\'á nhân) thông\nqua hanpago - thường dành cho người nổi tiếng, có sức ảnh hưởng.\n► Muốn phát triển thương hiộu doanh nghiộp thông qua Rinpage -\nhrands lớn dồu c:ó mìíl tròn đây.\n► Muốn phát triển kinh doanh thông qua Fanpage - rất nhiều c ông\nly, cửa hàng, t á nhân có cli(.)n kônh này.\n► Muốn phát triổn kế hoạc:h phi lợi nhuận (di đến lợi ích về sau)\nthóng qua Fanpagt; - những ranpagt; tình yôu, nghộ thuật sống...\n► Muốn phát triển cộng dồng nhằm xây dựng và củng cố thương\nhiệu cá nhân (hình tượng cá nhân).\n► Muốn phát triển cộng dồng nhằm xây dựng và củng cố thương\nhiộu doanh nghiệp.\n► Muôn phát triổn cộng đồng nhằm phục vụ người dùng sản phẩm\ncủa tôi thòng qua Group.\n► Muôn phát triển cộng dồng với mục. đích phi lợi nhuận (di dốn lợi\ních vỏ sau) thòng qua Group.\n► Muốn phát triển thương hiộu doanh nghiệp thông qua Event - lổ\nchức; các sự kiộn,...\n► Muốn phát triển thương hiệu cá nhân thông qua kivent.\n► Muốn phái triổn kinh doanh thông qua tivcnl.\n\nTrung Đức <- 17\n\n18 Facebook Marketing từ A đến z\n\n► Muốn phái triển triển thương hiệu doanh nghiộp thông qua các\nCUỘC\' thi (conlcst) trên các pmíik\'/group/Fanpag(\'/event.\n► Muốn phát triổn kinh doanh thông qua các cuộc thi (contosl) trên\ncác proíi le/group/Fanpag(?/evc\'nt.\n► Muốn phái triển cộng đồng với mục đích phi lợi nhuận (đi dốn lợi\ních vẻ sau) Irên các proíilc/group/ranpugo/event.\n\nVà bạn đang ở phần nào trong danh sách trên?\nNgoài ra còn khá nhiều cái muốn bất chính khác; như việc muôn phát\ntriển cộng đồng đ ể chửi bới, làm trò nhảm, muốn thêm nhiều bạn bè\nbằng cách tạo profile girl xinh,... những cái này tôi xin phép không đê\ncập đến.\n\n1.2 FacebookUser\n\nKhi chúng ta biết mình muốn gì đã là một thành công, và việc tìm ra một\n(hoặc nhiều) người để chúng ta có thể thỏa mãn nhu cầu của họ lại là\nmột thành công mới, hay đơn giản là tìm ra nhu cầu của người dùng đối\nvới sản phẩm của chúng ta - tất nhiên là trên kênh Facebook.\nVà mục đích cuối cùng là giá trị.chuyển đổi (convert):\n\n► Profile: user-follower, user-friend, follower-friend, user-\ncustomer, fol lower-customer, friend-customer.\n\n► Fanpage: user-fan, user-customer, fan-customer.\n► Group: user-member, member-customer.\n► Event: user-member, user-customer\n► Contest: user-member\n\nTức là, từ những người dùng Facebook xa lạ, từ những khách vãng lai ở\nđâu đó, điều mà một người Facebook Marketer cần là biến người dùng\nđó thành người like Fanpage của mình, thành người follow mình, thành\nmember trong cộng đồng của mình, tham gia vào sự kiện của mình,\ntham gia vào cuộc thi của mình,...\nVà làm sao để làm được điều đó, khi chúng ta đã xác định được mục tiêu\nvà đối tượng mục tiêu?\n\nTrung Đức <r T9\n\n20 -> Facebook Marketing từ A đến Z\n\n1.3 Facebook Marketing Strategy\n\nCó rất nhiều cách để những Facebook Marketer có thể đi được đến trái\ntim, hay túi tiền của Facebook User, nhưng chúng ta có thể tóm gọn nó\nlại trong 3 cách sau:\na. Application\n\nFacebook Application sẽ được chia làm 2 loại chính theo nhu cầu của\nFacebook Marketer:\n+ App Quality: Với những app chất lượng, chi phí và thời gian bỏ ra là\nrất lớn, vì thế việc của người làm Facebook Marketer là nghiên cứu đặc\ntính sản phẩm/dịch vụ, tìm ra điểm khác biệt. Nghiên cứu sâu về hành\nvi và nhận thức của người dùng trên Facebook, thể hiện rõ thông điệp,\nđiểm khác biệt, hay việc đáp ứng được nhu cầu người dùng ra bên ngoài,\nmọi thứ đều cần phải đúng quy trình và chuẩn xác. Vì không có ai muốn\ntiền của mình bỏ ra nhiều mà không thu về được nhiều cả.\nĐặc điểm của những App này là mang lại giá trị cho người dùng (tiền\nthưởng, quà tặng,...), chi phí đầu tư lớn, đầu tư xây dựng nội dung, giao\ndiện đồ họa đẹp mắt, có khả năng tương tác, có yếu tố lan truyền cao,\nhiệu ứng tích cực, và ứng dụng hoạt động ngay trên nền facebook...\n+ App Low: Với những app kém chất lượng, chi phí và thời gian bỏ ra\nlà ít (không đáng kể) app dạng này mọc ra như nấm, biến thiên đủ trò,\nnhưng biến kiểu gì thì biến cũng chỉ dừng lại ở mức hiển thị định dạng\nText, hoặc Image. Những app này thường có xu hường "lừa" người chơi,\nChiến lược Facebook Marketing có sử dụng\nApps là chiến dịch rất hiệu quả và cũng rất\ndài hơi. Trong chiến dịch Facebook Marketing\n\nApplication thường sẽ có 3 nhóm chính: User-\nMarketer-Developer App.\n\ntạo cho họ cảm giác tò mò, ví dụ như những app: Lúc nào bạn chết, Ai\nhay vào tường nhà bạn, Mách nhỏ,...\nTuy không mang lại giá trị cho người dùng nhưng những app này cũng\nđánh được vào tâm lý của họ, cộng với việc sử dụng một số thủ thuật,\nApp Low có yếu tố lan truyền khá cao, và ứng dụng thường không hoạt\nđộng trên nền facebook mà hoạt động ở một trang nào đó, nền trắng tinh\nkèm theo một hình có nhiệm vụ CTA (Call to action) ở chính giữa giao\ndiện website.\n\nb. Ads\nVới những ưu điểm vượt trội của mình về người dùng và mức độ tương\ntác, Facebook là một thị trường béo bở với tất cả các bên. Không có lý\ndo gì Facebook bỏ qua dịch vụ cho phép người dùng mua quảng cáo sản\nphẩm/dịch vụ của họ.\n+ Cách thức hoạt động của quảng cáo tacebook\nCác doanh nghiệp trả tiền cho Facebook để hiển th.i quảng cáo cho\nnhững người có thể quan tâm đến nội dung của họ.\n\no\nMột doanh nghiệp\ntạo một quảng cáo\n\n©\nFacebook được trả tiền\nđể hiện thị quảng cáo\n\n©\nNgười phù hợp để\nxem quảng cáo\n\nHãy nói rằng có một phòng tập\nthể dục ở gần nhà bạn. Người\nchủ tạo một quảng cáo để mọi\nngười đến tập miễn phí.\n\nNgười chủ gửi quảng cáo đến\nFacebook và mô tả ai sẽ nhìn\nthây nó: những người sống gần\nđây hoặc thích đến đây.\n\nBạn sẽ nhìn thấy quảng cáo\nnếu bạn sống ỡ thị trấn\nvà thích chạy.\n\n+ ƯU điểm của quảng cáo facebook\na. Luôn hướng đến đúng đối tượng là khách hàng tiềm năng\nBạn hoàn toàn có thể điều chỉnh hướng đối tượng cho các\n\nTrung Đức 21\n\n22 -ỳ Facebook Marketlng từ A đến z\n\nchiến dịch quảng cáo íacebook của mình. Trong đó bao gồm\nviệc định hướng các đối tượng nào sẽ thấy được quảng cáo\nnhư: giới tính, độ tuổi, địa lý, ngôn ngữ, sở thích. Hay nhắm\ntrực tiếp đến những đối tượng (người dùng) bạn chỉ định.\nb. Chỉ trả tiền khi có người mong muôn sử dụng dịch vụ của bạn\nFacebook cho bạn lựa chọn hình thức quảng cáo CPC (cost\nper click) hoặc CPM (cost per impression). Với CPC, bạn chỉ\nphải trả tiền cho những người click vào quảng cáo của bạn\nmà thôi. Với CPM bạn cũng ch? trả tối thiểu từ 0.03$/1000\nlần hiển thị mẫu quảng cáo (tương dượng 600đ/1000 lần\nhiển thị). Đây là mức chi phí rất hợp lý.\nc. Tính linh hoạt cao:\n► Điều chỉnh chiến dịch dễ dàng. Bạn hoàn toàn có thể\nchuyển đổi giữa hai hình thức trả phí từ CPC sang CPM và\nngược lại. Hơn nữa, các thông số khác cũng được điều chỉnh\ndễ dàng để chiến dịch của bạn tối ưu hơn.\n► Nội dung quảng cáo íacebook hiển thị hình ảnh và lời\ngiới thiệu kèm theo. Đây là một hình thức quảng cáo tiên\ntiến và được nhiều công ty áp dụng để đưa hình ảnh doanh\nnghiệp đến với nhiều người.\n► Nội dung quảng cáo íacebook có thể kèm theo cả các\ntương tác của bạn bè người dùng với sản phẩm/dịch vụ đó\nđể tăng độ tin cậy.\nd. Không phụ thuộc ngân sách\nBạn không nhất thiết phải trả một ngân sách cố định. Tùy\nvào tình hình thực tế, bạn có thể yêu cầu điều chỉnh ngân\nsách hàng ngày hoặc hàng tháng cho phù hợp với chiến\ndịch của mình.\n\n! e. Phân phối quảng cáo hợp lỷ\n\\ Facebook luôn đảm bảo rằng quảng cáo trên facebook được\nI phân bổ đều đặn dựa trên ngân sách của bạn. Sẽ không có\n! trường hợp quảng cáo tập trung quá nhiều vào người này mà\nI không xuất hiện ở người khác. Do đó, quảng cáo của bạn sẽ\n! luôn xuất hiện đến các khách hàng tiềm năng.\n+ Các dạng quảng cáo facebook\nBoost Post\nLà hình thức quảng bá các\nthông tin được cập nhật từ\nFanpage tới một số lượng\nngười dùng nhất định đã\n"Like" page trước đó. Bởi\ntrên thực tế, nếu người dùng\nđã like page nhưng không\ntham gia tương tác với page,\ntimeline Facebook (màn hình\nhiển thị nội dung cập nhật từ\nbạn bè) của họ sẽ không hiện\ncác cập nhật của page.\nKhi người quản trị page đồng ý chi trả một số tiền nhất định để quảng bá\nnội dung vừa cập nhật từ page, Facebook sẽ đảm bảo việc nội dung đó\nsẽ được hiển thị trên timeline của những người dùng đã Like page bất kể\ncó tham gia tương tác với page hay không.\nVà thông thường, số lượng view tổng cộng sẽ lớn hơn số lượng view độc\nnhất do nội dung được quảng bá này sẽ hiển thị nhiều lần trên timeline\ncủa fan.\nFacebook Ads\nFacebook Ads hay còn được gọi là Sponsored Ads (quảng cáo được tài\n\nBoost Your Post\nIts easy to bflffirt ¥«wr posts so «w e peopte M# them n « Ị\nfeed. It only esses 4W.Q00 »s*ỉ seated,\nwarn More\nA uitlcrarr • (tier\n\n»1\n, fiwpfci you tbrwjgih tw getng ! \'J\nm“ «39,000 ;\nfeLPeopfe 4$,<3OT.98,SOO.................... oTtgj\nUs»*«» "\ntiw buềgpk mẳ ismềm ểttoíấrê ta ỉtrnvặ %ềM.\n\n\'B ữ M t\n\nTrung Đức <- 23\n\n24 -> Facebook Marketing từ A đến z\n\ntrợ) là các quảng cáo được hiển thị tại các vị trí đặt quảng cáo cố định\ntrên website. Và điểm khác biệt lớn nhất giữa Facebook Ads và Facebook\nPromoted Post chính là việc Facebook Ads sẽ được hiển thj đối với một\nnhóm người dùng cụ thể với các tiêu chuẩn đề ra trước đó. Trong khi\nFacebook Promoted Post chỉ hiển thị tới người dùng đã bấm Like page.\nVà tất nhiên, trong số những người dùng nhìn thấy Facebook Ads, chắc\nchắn sẽ có một lượng người dùng nhất định đã là fan của page. Và cũng\ngiống như hình thức thứ nhất, Facebook Ads có thể được hiển thị rất\nnhiều lần cho cùng một người dùng.\n\n► Tham gia vào bài viết trên\ntrang : Quảng bá bài viết cụ thể\ntrên Fanpage của bạn tăng lượt\nview, share.\n► Số lượt thích trang : Tăng like\ncho Fanpage của bạn.\n► Truy cập vào trang web : Tạo\nquảng cáo để mọi người truy cập\ntrực tiếp vào website của bạn.\n- ► Lựa chọn quảng cáo hiển thị cột bên phải hoặc. Irôn c a bang tin\n(nếu bạn có Fanpage).\n► Chuyển đổi trang web : Tạo pixel lấy code add vào website của\nbạn và theo dõi tỉ lệ chuyển đổi đến 1 trang mà bạn mong muốn. ,í\nQuảng cáo sẽ được hiển thị.\nLượt cài ứng dụng : Tạo quảng cáo đề khuyến khích mọi người cài\nđặt ứng dụng của bạn.\n\\ 0 Page Post Engagement\n! 0 Page tikes\nj ^ Clicks to Website\ns <§) Website Conversions\nI $ App Installs\ni ^ App Engagement\ni HJ, Event Responses\ni f i Offer Claims\n\n► Tham gia ứng dụng : tạo quang cáo đổ cỏ them hoạt dộng trên\nứng dụng l-\'acobook của bạn. (lách tạo quảng cáo tương lự lượt cài\nứng dụng.\n► Tham gia sự kiện : Tạo quảng cáo c\'lể quàng bá sự kiện\n► Yêu cầu nhận Ưu dãi : T.ạo quảng cáo dể quảng bá khuyến mại.\n\nc. Content\nPhần cuối cùng, cũng là phần quan trọng trong mỗi chiến lược Marketing\nOnline nói chung, hay Facebook Marketing nói riêng, đó là CONTENT\n(nội dung). Content là yếu tố dễ dàng nhất để đạt được đến độ lan truyền\nnội dung, lan truyền cảm xúc (Viral Marketing).\n\nCO N TEN T STR A TE G Y\nP O S T S E N G A G E M E N T S C O R E\n\nTrung Đức 4- 25\n\n26 -> Facebook Marketing từ A đến z\n\nMột Số loại content phổ biến:\n\n► Cập nhật sân phẩm/dịch vụ lừ các. slore.\n► Nội dung LÍU đ ã i.\n► Bài viết dạng câu hỏi dể người dọc có hành dộng comment Irả lời.\n► Tổ chức cuộc thi.\n► Tổ chức sự kiện.\n► Nội dung mang tính xã hội.\n► Thông tin về các thương hiệu.\n► Nội dung giao dịch cụ thổ.\n► Các loại nội dung khác.\n\nĐể làm Content tốt, ngoài việc phân tích Insight đối tượng mục tiêu, bạn\ncần phải có khả năng viết tốt (Copywriting).\n\n1 .A EdgeRank\n\nEdge Rank »MSMB\n\nUe w e\nV«*\n■ D\ne\niii « # « s\n\nRank Affinity\nThe score between\nme viewing user and\nthe edge creator.\n\nWeight\nTlie weight tor tills\nedge type.\n(Comment, UKe, etc).\n\nDecay\nThe decay t.ictoi\nbased on hew tong ago\nthe edge was created\n\na. Edgerank 1.0\nEdgerank là thuật toán được sử dụng bởi facebook nhằm xác định "Nơi\nnào?" và "Những bài viết nào?" sẽ xuất hiện trên trang News Feed của\nngười dùng cá nhân. Ban đầu có 3 biến chính được được sử dụng trong\nthuật toán: Affinity, Weight, Time-Decay.\n+ Affinity: Điểm sấlôi cuốn (sự thân thuộc)\nThể hiện ở mỗi quan hệ, tức là Facebook sẽ xác định ưu tiên hiển thị trên\nNews Feed của bạn những người có mỗi quan hệ chặt chẽ, ở đây là anh\nem, bố mẹ, ông bà, vợ chồng, những người mà bạn thường xuyên tương\ntác comment, like, share. Mối quan hệ càng chặt chẽ, thì khi người đó\npost bài, tỷ lệ hiển thị trên News Feed càng cao.\n+ Weight: Trọng số tương tác\nNhư tôi đã nói ở trên, với mỗi Fanpage hay tài khoản cá nhân, sẽ có\nsắp xếp Ưu tiên về thể loại bài đăng, tùy vào tương tác của người dùng,\nFacebook sẽ đánh giá thể loại bài post mà Fanpage này hiệu quả, qua đó\n\nTrung Đức 27\n\n28 -> Facebook Marketing từ A đến z\n\nsẽ ảnh hưởng đến tổng thể thuật toán. Do vậy, bất kỳ một thể loại nào\ncũng có thể có lượng Reach cao, chứ không riêng gì Photos hay Text.\n+ Time-Decay\nCái này đơn giản là Facebook sẽ Ưu tiên hiển thị những thông tin mới,\nnhững thông tin mới thì điểm số Time-Decay sẽ cao, và ngược lại, thông\ntin càng cũ thì chỉ số Time-Decay càng thấp.\n\nb. Ẽdgerank 2.0\nSau này Facebook cập nhật lại thuật toán Edgerank, có điều chỉnh và\nthêm các chỉ số.\n\n+ Last actor: 50 tương tác gần nhất.\n+ Edge Weight: Trọng số tương tác.\n+ Story Bumping: Hiển thị bài viết bạn chưa xem .\nVà tất nhiên những chì số không có dưới đây không có nghĩa là không\nđược tính đến.\nDễ hình dung nhất của chỉ số Last actor là khi bạn tương tác với một\nngười nào đó (chat/like/comment/share) thì lập tức khung chat của bạn\nsẽ hiện lên người đó mỗi khi họ online.\nViệc một người không online trong thời gian quá lâu sẽ dẫn đến tình\ntrạng bỏ qua những nội dung hay, phù hợp với họ, facebook đã giải quyết\nvấn đề đó bằng việc đưa ra chỉ số Story Bumping.\n\nc. NFO (News Feed Optimization)\nNếu Google có những thuật toán riêng để hiển thị kết quả tìm kiếm hay\nthường được gọi là SEO ( Search Engine Optimization) thì Facebook có\n\nNFO ( News Feed Optimization). Hai công việc này cơ bản giống nhau\nvề mục đích: cố gắng tiếp cận User ở trang đầu tiên ( page 1 on Google\n& News Feed), và cách thức thực hiện: làm hài lòng thuật toán hay yêu\ncầu của 2 bạn Google & Facebook. NFO đơn giản là cách thỏa mãn\nEdgeRank để tăng tì lệ hiển thị ở News Feed.\n\n1.5 Tóm lược nội dung\n\nNăm 2 0 1 3 dã dánh dấu nhừng bước phái triển mạnh mẽ của công\nnghệ số, truyền thông da phương tiện, markeíing Online và íacebook\nmarketing. Fucobook sẽ liếp tục thay dổi, họ hoặc là cần phải dáp\nứng nhu cầu của ngươi dùng, hoặc là cần phải lạo ra những nhu cầu\nmoi, vì ngươi dùng luôn luôn e.ó xu hướng thay (lồi nhu Ccầu của mình\ntheo thơi gian, nhận lliứe, cộng dồng,...\nTacebook Marketing lúc dó sẽ ihực sự là một chiến trương dành cho\nnhững ngươi làm Fae.ebool< Markcting, Facebool< sơ trỏ nên thông\nminh hơn, nhiều cạnh tranh giừa những Facebool< Marketer hơn,\nnhững ngươi hỗ trự kỹ thuật cùng sè thông minh hon, nội dung (la\ndạng hơn, Vcà quan trọng là người dùng cũng sẽ thông minh hơn.\n\nVà để cho nội dung sách được xuyên suốt, cũng như những hướng dẫn\nđược mạch lạc. Hầu hết những thao tác và nội dung hiển thị trên hình\nảnh sẽ mặc định là ngôn ngữ English (US). Bạn có thể chuyển sang ngôn\nngữ English (US) để thao tác, hoặc dịch sang tiếng Việt với những tùy\nchọn tương tự.', '2026-02-28 08:39:16');

-- Dumping structure for table book_store.reviews
CREATE TABLE IF NOT EXISTS `reviews` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `book_id` int NOT NULL,
  `rating` int NOT NULL,
  `comment` text,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_user_book` (`user_id`,`book_id`),
  KEY `fk_reviews_book` (`book_id`),
  CONSTRAINT `fk_reviews_book` FOREIGN KEY (`book_id`) REFERENCES `books` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_reviews_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `reviews_chk_1` CHECK ((`rating` between 1 and 5))
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

